package com.sampleapp.ui;

import com.sampleapp.core.app.AppConfig;
import com.sampleapp.data.cache.ItemTypeCache;
import com.sampleapp.data.repository.*;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.TokenManager;
import com.sampleapp.ui.workspace.WorkspaceDataService;

import java.util.concurrent.CompletableFuture;
import java.util.function.Consumer;

/**
 * Service facade used by workspaces to access data and trigger actions.
 * Implemented in the app module to bridge UI with business logic.
 * <p>
 * All data retrieval methods may be called from any thread. UI callers must
 * marshal results to the FX thread with {@code Platform.runLater()}.
 */
public interface AppServices {

    // ---- Character lifecycle ----

    /**
     * Start the EVE SSO login flow (opens browser). Returns a future that completes
     * when the login is done (with character ID) or fails.
     */
    CompletableFuture<Integer> addCharacter();

    /**
     * Remove a character and all associated data.
     */
    void removeCharacter(int characterId);

    /**
     * Refresh the OAuth token for a character.
     */
    CompletableFuture<Void> refreshCharacterToken(int characterId);

    /**
     * Full ESI sync for a character.
     */
    CompletableFuture<Void> syncCharacter(int characterId);

    // ---- Data access (returns DB data) ----

    CharacterRepository getCharacterRepository();

    WalletRepository getWalletRepository();

    AssetRepository getAssetRepository();

    MarketOrderRepository getMarketOrderRepository();

    ContractRepository getContractRepository();

    ItemTypeCache getItemTypeCache();

    // ---- Workspace data service for workspaces that need it ----

    WorkspaceDataService getWorkspaceDataService();

    // ---- ESI access ----

    EsiClient getEsiClient();

    TokenManager getTokenManager();

    // ---- Configuration ----

    AppConfig getAppConfig();

    // ---- Event subscription ----

    /**
     * Subscribe to sync completion events. Callback receives the sync type name.
     * Callback is invoked on the FX thread.
     */
    void onSyncCompleted(Consumer<String> callback);
}

