264	    private void refreshCharacterData(int characterId) {
265	        if (characterId <= 0) {
266	            Platform.runLater(this::clearAllFields);
267	            return;
268	        }
269	
270	        Thread.ofVirtual().name("char-workspace-load").start(() -> {
271	            try {
272	                loadCharacterInfo(characterId);
273	                loadSkillsAndAttributes(characterId);
274	                loadRoles(characterId);
275	                loadCorporationHistory(characterId);
276	                loadStandings(characterId);
277	            } catch (Exception e) {
278	                log.error("Failed to load character workspace data for {}", characterId, e);
279	            }
280	        });
281	    }
282	
283	    /**
284	     * Load character public info from ESI (name, birthday, race, security status, etc.)
285	     * and corporation info for the corporation tab.
286	     */
287	    private void loadCharacterInfo(int characterId) {
288	        EsiClient esi = appServices.getEsiClient();
289	
290	        try {
291	            // Public endpoint - no token needed
292	            EsiResponse<CharacterInfo> charResp = esi.characters.getCharacter(characterId).join();
293	
294	            if (charResp.isSuccess() && charResp.data() != null) {
295	                CharacterInfo info = charResp.data();
296	
297	                // Also look up corp/alliance names from AppState if available
298	                String corpName = "Corp ID: " + info.corporationId();
299	                String allianceName = info.allianceId() != null ? "Alliance ID: " + info.allianceId() : "None";
300	                for (var ci : appState.getCharacters()) {
301	                    if (ci.characterId() == characterId) {
302	                        if (!ci.corporationName().isEmpty()) corpName = ci.corporationName();
303	                        if (!ci.allianceName().isEmpty()) allianceName = ci.allianceName();
304	                        break;
305	                    }
306	                }
307	
308	                String raceName = RACE_NAMES.getOrDefault(info.raceId(), "Race ID: " + info.raceId());
309	                String birthday = info.birthday() != null ? formatDate(info.birthday()) : "--";
310	                String secStatus = info.securityStatus() != null
311	                        ? String.format("%.2f", info.securityStatus()) : "--";
312	                String bloodline = "Bloodline ID: " + info.bloodlineId();
313	                String title = info.title() != null && !info.title().isEmpty() ? info.title() : "";
314	
315	                final String fCorpName = corpName;
316	                final String fAllianceName = allianceName;
317	
318	                Platform.runLater(() -> {
319	                    String displayName = title.isEmpty() ? info.name() : info.name() + " - " + title;
320	                    nameValue.setText(displayName);
321	                    corpValue.setText(fCorpName);
322	                    allianceValue.setText(fAllianceName);
323	                    secStatusValue.setText(secStatus);
324	                    birthdayValue.setText(birthday);
325	                    raceValue.setText(raceName);
326	                    bloodlineValue.setText(bloodline);
327	                    ancestryValue.setText("--"); // ESI v5 does not include ancestry
328	                    locationValue.setText("--"); // Would need location endpoint
329	                    shipValue.setText("--");     // Would need ship endpoint
330	                });
331	
332	                // Now load corporation info
333	                loadCorporationInfo(info.corporationId(), info.allianceId());
334	            } else {
335	                // Fallback to DB / AppState
336	                loadFromDbFallback(characterId);
337	            }
338	        } catch (Exception e) {
339	            log.warn("ESI character info call failed for {}, falling back to DB", characterId, e);
340	            loadFromDbFallback(characterId);
341	        }
342	    }
343	
344	    private void loadFromDbFallback(int characterId) {
345	        try {
346	            var charRepo = appServices.getCharacterRepository();
347	            var charOpt = charRepo.findById(characterId);
348	
349	            Platform.runLater(() -> {
350	                if (charOpt.isPresent()) {
351	                    var ch = charOpt.get();
352	                    nameValue.setText(ch.name());
353	                    corpValue.setText(ch.corporationId() != null ? "Corp ID: " + ch.corporationId() : "--");
354	                    allianceValue.setText(ch.allianceId() != null ? "Alliance ID: " + ch.allianceId() : "--");
355	                    corpNameValue.setText(ch.corporationId() != null ? "Corp ID: " + ch.corporationId() : "--");
356	                } else {
357	                    for (var info : appState.getCharacters()) {
358	                        if (info.characterId() == characterId) {
359	                            nameValue.setText(info.name());
360	                            corpValue.setText(info.corporationName().isEmpty() ? "--" : info.corporationName());
361	                            allianceValue.setText(info.allianceName().isEmpty() ? "--" : info.allianceName());
362	                            corpNameValue.setText(info.corporationName().isEmpty() ? "--" : info.corporationName());
363	                            break;
364	                        }
365	                    }
366	                }
367	            });
368	        } catch (Exception e) {
369	            log.error("DB fallback also failed for character {}", characterId, e);
370	        }
371	    }
372	
373	    /**
374	     * Load corporation public info from ESI.
375	     */
376	    private void loadCorporationInfo(int corporationId, Integer allianceId) {
377	        EsiClient esi = appServices.getEsiClient();
378	
379	        try {
380	            EsiResponse<CorporationInfo> corpResp = esi.corporations.getCorporation(corporationId).join();
381	
382	            if (corpResp.isSuccess() && corpResp.data() != null) {
383	                CorporationInfo corp = corpResp.data();
384	
385	                String alliance = corp.allianceId() != null ? "Alliance ID: " + corp.allianceId() : "None";
386	                // Try to use the alliance name from AppState
387	                if (corp.allianceId() != null) {
388	                    for (var ci : appState.getCharacters()) {
389	                        if (!ci.allianceName().isEmpty()) {
390	                            alliance = ci.allianceName();
391	                            break;
392	                        }
393	                    }
394	                }
395	
396	                final String fAlliance = alliance;
397	
398	                Platform.runLater(() -> {
399	                    corpNameValue.setText(corp.name());
400	                    tickerValue.setText(corp.ticker() != null ? "[" + corp.ticker() + "]" : "--");
401	                    ceoValue.setText("CEO ID: " + corp.ceoId());
402	                    corpAllianceValue.setText(fAlliance);
403	                    memberCountValue.setText(NUM_FMT.format(corp.memberCount()));
404	                    taxRateValue.setText(String.format("%.1f%%", corp.taxRate() * 100));
405	                    urlValue.setText(corp.url() != null && !corp.url().isEmpty() ? corp.url() : "--");
406	                    descriptionValue.setText(corp.description() != null && !corp.description().isEmpty()
407	                            ? stripHtml(corp.description()) : "--");
408	                    descriptionValue.setWrapText(true);
409	                    descriptionValue.setMaxWidth(400);
410	                });
411	            }
412	        } catch (Exception e) {
413	            log.warn("Failed to load corporation info for corp {}", corporationId, e);
414	        }
415	    }
416	
417	    /**
418	     * Load skills (total SP) and attributes from ESI. Requires auth token.
419	     */
420	    private void loadSkillsAndAttributes(int characterId) {
