422	        TokenManager tm = appServices.getTokenManager();
423	
424	        String token;
425	        try {
426	            token = tm.getValidToken(characterId).join();
427	        } catch (Exception e) {
428	            log.warn("Could not get token for character {}, skipping skills/attributes", characterId, e);
429	            return;
430	        }
431	
432	        // Skills
433	        try {
434	            EsiResponse<CharacterSkills> skillsResp = esi.skills.getSkills(characterId, token).join();
435	            if (skillsResp.isSuccess() && skillsResp.data() != null) {
436	                CharacterSkills sk = skillsResp.data();
437	                Platform.runLater(() -> {
438	                    totalSpValue.setText(NUM_FMT.format(sk.totalSp()));
439	                    unallocatedSpValue.setText(sk.unallocatedSp() != null
440	                            ? NUM_FMT.format(sk.unallocatedSp()) : "0");
441	                });
