525	            // Public endpoint - no token needed
526	            EsiResponse<List<CorporationHistory>> histResp =
527	                    esi.characters.getCorporationHistory(characterId).join();
528	
529	            if (histResp.isSuccess() && histResp.data() != null) {
530	                List<CorporationHistory> history = histResp.data();
531	                List<HistoryEntry> entries = new ArrayList<>();
532	
533	                // History is sorted by recordId descending (newest first)
534	                for (int i = 0; i < history.size(); i++) {
535	                    CorporationHistory h = history.get(i);
536	                    String corpDisplay = "Corp ID: " + h.corporationId();
537	                    if (h.isDeleted() != null && h.isDeleted()) {
538	                        corpDisplay += " (closed)";
