540	                    String start = h.startDate() != null ? formatDate(h.startDate()) : "--";
541	                    // End date is the start date of the next (more recent) entry,
542	                    // or "Present" for the most recent entry
543	                    String end = (i == 0) ? "Present" :
544	                            (history.get(i - 1).startDate() != null
545	                                    ? formatDate(history.get(i - 1).startDate()) : "--");
