package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.data.repository.CharacterRepository;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.EsiResponse;
import com.sampleapp.esi.TokenManager;
import com.sampleapp.esi.dto.*;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.text.NumberFormat;
import java.time.OffsetDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.Map;

/**
 * Character workspace with tabs for Info, Corporation, Roles, History, Attributes, and Standings.
 * Loads character data from ESI on activation and after sync events.
 */
public class CharacterWorkspace extends Workspace {

    private static final DateTimeFormatter DATE_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");
    private static final NumberFormat NUM_FMT = NumberFormat.getNumberInstance(Locale.US);

    private static final Map<Integer, String> RACE_NAMES = Map.of(
            1, "Caldari", 2, "Minmatar", 4, "Amarr", 8, "Gallente"
    );

    private final AppServices appServices;

    // Info tab labels
    private Label nameValue, corpValue, allianceValue, secStatusValue,
            birthdayValue, raceValue, bloodlineValue, ancestryValue,
            locationValue, shipValue;

    // Corporation tab labels
    private Label corpNameValue, tickerValue, ceoValue, corpAllianceValue,
            memberCountValue, taxRateValue, urlValue, descriptionValue;

    // Attributes tab labels
    private Label intelValue, percValue, charismaValue, willpowerValue,
            memoryValue, bonusRemapValue, nextRemapValue,
            totalSpValue, unallocatedSpValue;

    // Roles tab
    private TableView<RoleEntry> rolesTable;
    private ObservableList<RoleEntry> rolesData = FXCollections.observableArrayList();

    // History tab
    private TableView<HistoryEntry> historyTable;
    private ObservableList<HistoryEntry> historyData = FXCollections.observableArrayList();

    // Standings tab
    private TableView<StandingEntry> standingsTable;
    private ObservableList<StandingEntry> standingsData = FXCollections.observableArrayList();

    public CharacterWorkspace(AppState appState, AppServices appServices) {
        super(appState);
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createInfoTab(),
                createCorporationTab(),
                createRolesTab(),
                createHistoryTab(),
                createAttributesTab(),
                createStandingsTab()
        );

        // Listen for sync completion to refresh data
        appServices.onSyncCompleted(syncType -> {
            int charId = appState.getSelectedCharacterId();
            if (charId > 0) {
                refreshCharacterData(charId);
            }
        });
    }

    private Tab createInfoTab() {
        var tab = new Tab("Info");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(8);
        grid.setPadding(new Insets(15));

        nameValue = createValueLabel("--");
        corpValue = createValueLabel("--");
        allianceValue = createValueLabel("--");
        secStatusValue = createValueLabel("--");
        birthdayValue = createValueLabel("--");
        raceValue = createValueLabel("--");
        bloodlineValue = createValueLabel("--");
        ancestryValue = createValueLabel("--");
        locationValue = createValueLabel("--");
        shipValue = createValueLabel("--");

        String[] labels = {"Name:", "Corporation:", "Alliance:", "Security Status:",
                "Birthday:", "Race:", "Bloodline:", "Ancestry:", "Location:", "Ship:"};
        Label[] values = {nameValue, corpValue, allianceValue, secStatusValue,
                birthdayValue, raceValue, bloodlineValue, ancestryValue,
                locationValue, shipValue};

        for (int i = 0; i < labels.length; i++) {
            grid.add(createFieldLabel(labels[i]), 0, i);
            grid.add(values[i], 1, i);
        }

        var scrollPane = new ScrollPane(grid);
        scrollPane.setFitToWidth(true);
        tab.setContent(scrollPane);
        return tab;
    }

    private Tab createCorporationTab() {
        var tab = new Tab("Corporation");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(8);
        grid.setPadding(new Insets(15));

        corpNameValue = createValueLabel("--");
        tickerValue = createValueLabel("--");
        ceoValue = createValueLabel("--");
        corpAllianceValue = createValueLabel("--");
        memberCountValue = createValueLabel("--");
        taxRateValue = createValueLabel("--");
        urlValue = createValueLabel("--");
        descriptionValue = createValueLabel("--");

        String[] labels = {"Corporation:", "Ticker:", "CEO:", "Alliance:",
                "Member Count:", "Tax Rate:", "URL:", "Description:"};
        Label[] values = {corpNameValue, tickerValue, ceoValue, corpAllianceValue,
                memberCountValue, taxRateValue, urlValue, descriptionValue};

        for (int i = 0; i < labels.length; i++) {
            grid.add(createFieldLabel(labels[i]), 0, i);
            grid.add(values[i], 1, i);
        }

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createRolesTab() {
        var tab = new Tab("Roles");
        rolesTable = new TableView<>(rolesData);

        var nameCol = new TableColumn<RoleEntry, String>("Role");
        nameCol.setPrefWidth(200);
        nameCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().role()));

        var locationCol = new TableColumn<RoleEntry, String>("Location");
        locationCol.setPrefWidth(150);
        locationCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().location()));

        var typeCol = new TableColumn<RoleEntry, String>("Type");
        typeCol.setPrefWidth(120);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().type()));

        rolesTable.getColumns().addAll(nameCol, locationCol, typeCol);
        rolesTable.setPlaceholder(new Label("No roles assigned"));

        tab.setContent(rolesTable);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createHistoryTab() {
        var tab = new Tab("History");
        historyTable = new TableView<>(historyData);

        var corpCol = new TableColumn<HistoryEntry, String>("Corporation");
        corpCol.setPrefWidth(250);
        corpCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().corporation()));

        var startCol = new TableColumn<HistoryEntry, String>("Start Date");
        startCol.setPrefWidth(150);
        startCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().startDate()));

        var endCol = new TableColumn<HistoryEntry, String>("End Date");
        endCol.setPrefWidth(150);
        endCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().endDate()));

        historyTable.getColumns().addAll(corpCol, startCol, endCol);
        historyTable.setPlaceholder(new Label("No corporation history"));

        tab.setContent(historyTable);
        return tab;
    }

    private Tab createAttributesTab() {
        var tab = new Tab("Attributes");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(8);
        grid.setPadding(new Insets(15));

        intelValue = createValueLabel("--");
        percValue = createValueLabel("--");
        charismaValue = createValueLabel("--");
        willpowerValue = createValueLabel("--");
        memoryValue = createValueLabel("--");
        bonusRemapValue = createValueLabel("--");
        nextRemapValue = createValueLabel("--");

        String[] attrs = {"Intelligence:", "Perception:", "Charisma:", "Willpower:",
                "Memory:", "Bonus Remaps:", "Next Remap:"};
        Label[] values = {intelValue, percValue, charismaValue, willpowerValue,
                memoryValue, bonusRemapValue, nextRemapValue};

        for (int i = 0; i < attrs.length; i++) {
            grid.add(createFieldLabel(attrs[i]), 0, i);
            grid.add(values[i], 1, i);
        }

        // SP totals
        grid.add(new Separator(), 0, attrs.length, 2, 1);
        totalSpValue = createValueLabel("--");
        unallocatedSpValue = createValueLabel("--");
        grid.add(createFieldLabel("Total SP:"), 0, attrs.length + 1);
        grid.add(totalSpValue, 1, attrs.length + 1);
        grid.add(createFieldLabel("Unallocated SP:"), 0, attrs.length + 2);
        grid.add(unallocatedSpValue, 1, attrs.length + 2);

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createStandingsTab() {
        var tab = new Tab("Standings");
        standingsTable = new TableView<>(standingsData);

        var entityCol = new TableColumn<StandingEntry, String>("Entity");
        entityCol.setPrefWidth(250);
        entityCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().entity()));

        var typeCol = new TableColumn<StandingEntry, String>("Type");
        typeCol.setPrefWidth(100);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().type()));

        var standingCol = new TableColumn<StandingEntry, String>("Standing");
        standingCol.setPrefWidth(100);
        standingCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().standing()));

        standingsTable.getColumns().addAll(entityCol, typeCol, standingCol);
        standingsTable.setPlaceholder(new Label("No standings data"));

        tab.setContent(standingsTable);
        return tab;
    }

    private void refreshCharacterData(int characterId) {
        if (characterId <= 0) {
            Platform.runLater(this::clearAllFields);
            return;
        }

        Thread.ofVirtual().name("char-workspace-load").start(() -> {
            try {
                loadCharacterInfo(characterId);
                loadSkillsAndAttributes(characterId);
                loadRoles(characterId);
                loadCorporationHistory(characterId);
                loadStandings(characterId);
            } catch (Exception e) {
                log.error("Failed to load character workspace data for {}", characterId, e);
            }
        });
    }

    /**
     * Load character public info from ESI (name, birthday, race, security status, etc.)
     * and corporation info for the corporation tab.
     */
    private void loadCharacterInfo(int characterId) {
        EsiClient esi = appServices.getEsiClient();

        try {
            // Public endpoint - no token needed
            EsiResponse<CharacterInfo> charResp = esi.characters.getCharacter(characterId).join();

            if (charResp.isSuccess() && charResp.data() != null) {
                CharacterInfo info = charResp.data();

                // Also look up corp/alliance names from AppState if available
                String corpName = "Corp ID: " + info.corporationId();
                String allianceName = info.allianceId() != null ? "Alliance ID: " + info.allianceId() : "None";
                for (var ci : appState.getCharacters()) {
                    if (ci.characterId() == characterId) {
                        if (!ci.corporationName().isEmpty()) corpName = ci.corporationName();
                        if (!ci.allianceName().isEmpty()) allianceName = ci.allianceName();
                        break;
                    }
                }

                String raceName = RACE_NAMES.getOrDefault(info.raceId(), "Race ID: " + info.raceId());
                String birthday = info.birthday() != null ? formatDate(info.birthday()) : "--";
                String secStatus = info.securityStatus() != null
                        ? String.format("%.2f", info.securityStatus()) : "--";
                String bloodline = "Bloodline ID: " + info.bloodlineId();
                String title = info.title() != null && !info.title().isEmpty() ? info.title() : "";

                final String fCorpName = corpName;
                final String fAllianceName = allianceName;

                Platform.runLater(() -> {
                    String displayName = title.isEmpty() ? info.name() : info.name() + " - " + title;
                    nameValue.setText(displayName);
                    corpValue.setText(fCorpName);
                    allianceValue.setText(fAllianceName);
                    secStatusValue.setText(secStatus);
                    birthdayValue.setText(birthday);
                    raceValue.setText(raceName);
                    bloodlineValue.setText(bloodline);
                    ancestryValue.setText("--"); // ESI v5 does not include ancestry
                    locationValue.setText("--"); // Would need location endpoint
                    shipValue.setText("--");     // Would need ship endpoint
                });

                // Now load corporation info
                loadCorporationInfo(info.corporationId(), info.allianceId());
            } else {
                // Fallback to DB / AppState
                loadFromDbFallback(characterId);
            }
        } catch (Exception e) {
            log.warn("ESI character info call failed for {}, falling back to DB", characterId, e);
            loadFromDbFallback(characterId);
        }
    }

    private void loadFromDbFallback(int characterId) {
        try {
            var charRepo = appServices.getCharacterRepository();
            var charOpt = charRepo.findById(characterId);

            Platform.runLater(() -> {
                if (charOpt.isPresent()) {
                    var ch = charOpt.get();
                    nameValue.setText(ch.name());
                    corpValue.setText(ch.corporationId() != null ? "Corp ID: " + ch.corporationId() : "--");
                    allianceValue.setText(ch.allianceId() != null ? "Alliance ID: " + ch.allianceId() : "--");
                    corpNameValue.setText(ch.corporationId() != null ? "Corp ID: " + ch.corporationId() : "--");
                } else {
                    for (var info : appState.getCharacters()) {
                        if (info.characterId() == characterId) {
                            nameValue.setText(info.name());
                            corpValue.setText(info.corporationName().isEmpty() ? "--" : info.corporationName());
                            allianceValue.setText(info.allianceName().isEmpty() ? "--" : info.allianceName());
                            corpNameValue.setText(info.corporationName().isEmpty() ? "--" : info.corporationName());
                            break;
                        }
                    }
                }
            });
        } catch (Exception e) {
            log.error("DB fallback also failed for character {}", characterId, e);
        }
    }

    /**
     * Load corporation public info from ESI.
     */
    private void loadCorporationInfo(int corporationId, Integer allianceId) {
        EsiClient esi = appServices.getEsiClient();

        try {
            EsiResponse<CorporationInfo> corpResp = esi.corporations.getCorporation(corporationId).join();

            if (corpResp.isSuccess() && corpResp.data() != null) {
                CorporationInfo corp = corpResp.data();

                String alliance = corp.allianceId() != null ? "Alliance ID: " + corp.allianceId() : "None";
                // Try to use the alliance name from AppState
                if (corp.allianceId() != null) {
                    for (var ci : appState.getCharacters()) {
                        if (!ci.allianceName().isEmpty()) {
                            alliance = ci.allianceName();
                            break;
                        }
                    }
                }

                final String fAlliance = alliance;

                Platform.runLater(() -> {
                    corpNameValue.setText(corp.name());
                    tickerValue.setText(corp.ticker() != null ? "[" + corp.ticker() + "]" : "--");
                    ceoValue.setText("CEO ID: " + corp.ceoId());
                    corpAllianceValue.setText(fAlliance);
                    memberCountValue.setText(NUM_FMT.format(corp.memberCount()));
                    taxRateValue.setText(String.format("%.1f%%", corp.taxRate() * 100));
                    urlValue.setText(corp.url() != null && !corp.url().isEmpty() ? corp.url() : "--");
                    descriptionValue.setText(corp.description() != null && !corp.description().isEmpty()
                            ? stripHtml(corp.description()) : "--");
                    descriptionValue.setWrapText(true);
                    descriptionValue.setMaxWidth(400);
                });
            }
        } catch (Exception e) {
            log.warn("Failed to load corporation info for corp {}", corporationId, e);
        }
    }

    /**
     * Load skills (total SP) and attributes from ESI. Requires auth token.
     */
    private void loadSkillsAndAttributes(int characterId) {
        EsiClient esi = appServices.getEsiClient();
        TokenManager tm = appServices.getTokenManager();

        String token;
        try {
            token = tm.getValidToken(characterId).join();
        } catch (Exception e) {
            log.warn("Could not get token for character {}, skipping skills/attributes", characterId, e);
            return;
        }

        // Skills
        try {
            EsiResponse<CharacterSkills> skillsResp = esi.skills.getSkills(characterId, token).join();
            if (skillsResp.isSuccess() && skillsResp.data() != null) {
                CharacterSkills sk = skillsResp.data();
                Platform.runLater(() -> {
                    totalSpValue.setText(NUM_FMT.format(sk.totalSp()));
                    unallocatedSpValue.setText(sk.unallocatedSp() != null
                            ? NUM_FMT.format(sk.unallocatedSp()) : "0");
                });
            }
        } catch (Exception e) {
            log.warn("Failed to load skills for character {}", characterId, e);
        }

        // Attributes
        try {
            EsiResponse<CharacterAttributes> attrResp = esi.skills.getAttributes(characterId, token).join();
            if (attrResp.isSuccess() && attrResp.data() != null) {
                CharacterAttributes attr = attrResp.data();
                Platform.runLater(() -> {
                    intelValue.setText(String.valueOf(attr.intelligence()));
                    percValue.setText(String.valueOf(attr.perception()));
                    charismaValue.setText(String.valueOf(attr.charisma()));
                    willpowerValue.setText(String.valueOf(attr.willpower()));
                    memoryValue.setText(String.valueOf(attr.memory()));
                    bonusRemapValue.setText(attr.bonusRemaps() != null
                            ? String.valueOf(attr.bonusRemaps()) : "0");
                    nextRemapValue.setText(attr.accruedRemapCooldownDate() != null
                            ? formatDate(attr.accruedRemapCooldownDate()) : "Available now");
                });
            }
        } catch (Exception e) {
            log.warn("Failed to load attributes for character {}", characterId, e);
        }
    }

    /**
     * Load character roles from ESI and populate the Roles table.
     */
    private void loadRoles(int characterId) {
        EsiClient esi = appServices.getEsiClient();
        TokenManager tm = appServices.getTokenManager();

        String token;
        try {
            token = tm.getValidToken(characterId).join();
        } catch (Exception e) {
            log.warn("Could not get token for character {}, skipping roles", characterId, e);
            return;
        }

        try {
            EsiResponse<CharacterRoles> rolesResp = esi.characters.getRoles(characterId, token).join();
            if (rolesResp.isSuccess() && rolesResp.data() != null) {
                CharacterRoles cr = rolesResp.data();
                List<RoleEntry> entries = new ArrayList<>();

                if (cr.roles() != null) {
                    for (String role : cr.roles()) {
                        entries.add(new RoleEntry(formatRoleName(role), "Global", "Role"));
                    }
                }
                if (cr.rolesAtHq() != null) {
                    for (String role : cr.rolesAtHq()) {
                        entries.add(new RoleEntry(formatRoleName(role), "HQ", "Role at HQ"));
                    }
                }
                if (cr.rolesAtBase() != null) {
                    for (String role : cr.rolesAtBase()) {
                        entries.add(new RoleEntry(formatRoleName(role), "Base", "Role at Base"));
                    }
                }
                if (cr.rolesAtOther() != null) {
                    for (String role : cr.rolesAtOther()) {
                        entries.add(new RoleEntry(formatRoleName(role), "Other", "Role at Other"));
                    }
                }

                Platform.runLater(() -> rolesData.setAll(entries));
            }
        } catch (Exception e) {
            log.warn("Failed to load roles for character {}", characterId, e);
        }
    }

    /**
     * Load corporation history from ESI and populate the History table.
     */
    private void loadCorporationHistory(int characterId) {
        EsiClient esi = appServices.getEsiClient();

        try {
            // Public endpoint - no token needed
            EsiResponse<List<CorporationHistory>> histResp =
                    esi.characters.getCorporationHistory(characterId).join();

            if (histResp.isSuccess() && histResp.data() != null) {
                List<CorporationHistory> history = histResp.data();
                List<HistoryEntry> entries = new ArrayList<>();

                // History is sorted by recordId descending (newest first)
                for (int i = 0; i < history.size(); i++) {
                    CorporationHistory h = history.get(i);
                    String corpDisplay = "Corp ID: " + h.corporationId();
                    if (h.isDeleted() != null && h.isDeleted()) {
                        corpDisplay += " (closed)";
                    }
                    String start = h.startDate() != null ? formatDate(h.startDate()) : "--";
                    // End date is the start date of the next (more recent) entry,
                    // or "Present" for the most recent entry
                    String end = (i == 0) ? "Present" :
                            (history.get(i - 1).startDate() != null
                                    ? formatDate(history.get(i - 1).startDate()) : "--");

                    entries.add(new HistoryEntry(corpDisplay, start, end));
                }

                Platform.runLater(() -> historyData.setAll(entries));
            }
        } catch (Exception e) {
            log.warn("Failed to load corporation history for character {}", characterId, e);
        }
    }

    /**
     * Load standings from ESI and populate the Standings table.
     */
    private void loadStandings(int characterId) {
        EsiClient esi = appServices.getEsiClient();
        TokenManager tm = appServices.getTokenManager();

        String token;
        try {
            token = tm.getValidToken(characterId).join();
        } catch (Exception e) {
            log.warn("Could not get token for character {}, skipping standings", characterId, e);
            return;
        }

        try {
            EsiResponse<List<Standing>> standResp =
                    esi.characters.getStandings(characterId, token).join();

            if (standResp.isSuccess() && standResp.data() != null) {
                List<Standing> standings = standResp.data();
                List<StandingEntry> entries = new ArrayList<>();

                for (Standing s : standings) {
                    String entity = s.fromType() + " ID: " + s.fromId();
                    String type = s.fromType() != null ? formatFromType(s.fromType()) : "--";
                    String value = String.format("%.2f", s.standing());
                    entries.add(new StandingEntry(entity, type, value));
                }

                Platform.runLater(() -> standingsData.setAll(entries));
            }
        } catch (Exception e) {
            log.warn("Failed to load standings for character {}", characterId, e);
        }
    }

    private void clearAllFields() {
        nameValue.setText("--");
        corpValue.setText("--");
        allianceValue.setText("--");
        secStatusValue.setText("--");
        birthdayValue.setText("--");
        raceValue.setText("--");
        bloodlineValue.setText("--");
        ancestryValue.setText("--");
        locationValue.setText("--");
        shipValue.setText("--");
        corpNameValue.setText("--");
        tickerValue.setText("--");
        ceoValue.setText("--");
        corpAllianceValue.setText("--");
        memberCountValue.setText("--");
        taxRateValue.setText("--");
        urlValue.setText("--");
        descriptionValue.setText("--");
        intelValue.setText("--");
        percValue.setText("--");
        charismaValue.setText("--");
        willpowerValue.setText("--");
        memoryValue.setText("--");
        bonusRemapValue.setText("--");
        nextRemapValue.setText("--");
        totalSpValue.setText("--");
        unallocatedSpValue.setText("--");
        rolesData.clear();
        historyData.clear();
        standingsData.clear();
    }

    // ---- Helpers ----

    private Label createFieldLabel(String text) {
        var label = new Label(text);
        label.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
        return label;
    }

    private Label createValueLabel(String text) {
        var label = new Label(text);
        label.setStyle("-fx-text-fill: #CCCCCC;");
        return label;
    }

    private static String formatDate(OffsetDateTime dt) {
        return dt.format(DATE_FMT);
    }

    /**
     * Convert ESI role names like "Station_Manager" to "Station Manager".
     */
    private static String formatRoleName(String role) {
        if (role == null) return "--";
        return role.replace("_", " ");
    }

    /**
     * Convert ESI from_type values to readable form.
     */
    private static String formatFromType(String fromType) {
        return switch (fromType) {
            case "agent" -> "Agent";
            case "npc_corp" -> "NPC Corp";
            case "faction" -> "Faction";
            default -> fromType;
        };
    }

    /**
     * Strip basic HTML tags from corporation descriptions.
     */
    private static String stripHtml(String html) {
        if (html == null) return "";
        return html.replaceAll("<[^>]*>", "").replaceAll("&amp;", "&")
                .replaceAll("&lt;", "<").replaceAll("&gt;", ">")
                .replaceAll("&quot;", "\"").replaceAll("&#39;", "'")
                .trim();
    }

    // ---- Table row records ----

    private record RoleEntry(String role, String location, String type) {}
    private record HistoryEntry(String corporation, String startDate, String endDate) {}
    private record StandingEntry(String entity, String type, String standing) {}

    @Override
    public String getTitle() { return "Character"; }

    @Override
    public void onActivated() {
        log.debug("Character workspace activated");
        refreshCharacterData(appState.getSelectedCharacterId());
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Character changed to: {}", characterId);
        refreshCharacterData(characterId);
    }
}

