package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.data.repository.MarketOrderRepository;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Market Orders workspace with tabs for Active Orders and Order History.
 * Populates from MarketOrderRepository and resolves type names via ItemTypeCache.
 */
public class MarketOrdersWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final AppServices appServices;

    // Active orders summary labels
    private Label buyOrdersValue, sellOrdersValue, totalEscrowValue, totalValueLabel;

    private TableView<MarketOrderRepository.MarketOrderRow> activeTable;
    private TableView<MarketOrderRepository.MarketOrderRow> historyTable;

    public MarketOrdersWorkspace(AppState appState, AppServices appServices) {
        super(appState);
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createActiveOrdersTab(),
                createOrderHistoryTab()
        );

        appServices.onSyncCompleted(syncType -> {
            if ("orders".equalsIgnoreCase(syncType) || "full".equalsIgnoreCase(syncType)) {
                refreshData(appState.getSelectedCharacterId());
            }
        });
    }

    @SuppressWarnings("unchecked")
    private Tab createActiveOrdersTab() {
        var tab = new Tab("Active Orders");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Summary bar
        buyOrdersValue = createSummaryValueLabel("--");
        sellOrdersValue = createSummaryValueLabel("--");
        totalEscrowValue = createSummaryValueLabel("--");
        totalValueLabel = createSummaryValueLabel("--");

        var summary = new HBox(20);
        summary.getChildren().addAll(
                createSummaryLabel("Buy Orders:", buyOrdersValue),
                createSummaryLabel("Sell Orders:", sellOrdersValue),
                createSummaryLabel("Total Escrow:", totalEscrowValue),
                createSummaryLabel("Total Value:", totalValueLabel)
        );

        // Orders table
        activeTable = new TableView<>();

        var typeCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Type");
        typeCol.setPrefWidth(60);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().isBuyOrder() ? "Buy" : "Sell"));

        var itemCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(cd -> new SimpleStringProperty(
                appServices.getItemTypeCache().getName(cd.getValue().typeId())
                        .orElse("Type " + cd.getValue().typeId())));

        var priceCol = new TableColumn<MarketOrderRepository.MarketOrderRow, Number>("Price");
        priceCol.setPrefWidth(120);
        priceCol.setCellValueFactory(cd -> new SimpleDoubleProperty(cd.getValue().price()));

        var volCol = new TableColumn<MarketOrderRepository.MarketOrderRow, Number>("Volume");
        volCol.setPrefWidth(80);
        volCol.setCellValueFactory(cd -> new SimpleIntegerProperty(cd.getValue().volumeTotal()));

        var remainCol = new TableColumn<MarketOrderRepository.MarketOrderRow, Number>("Remaining");
        remainCol.setPrefWidth(80);
        remainCol.setCellValueFactory(cd -> new SimpleIntegerProperty(cd.getValue().volumeRemain()));

        var locationCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Location");
        locationCol.setPrefWidth(200);
        locationCol.setCellValueFactory(cd -> new SimpleStringProperty(
                "Station " + cd.getValue().locationId()));

        var expiresCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Expires");
        expiresCol.setPrefWidth(100);
        expiresCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().duration() + "d"));

        var rangeCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Range");
        rangeCol.setPrefWidth(80);
        rangeCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().range() != null ? cd.getValue().range() : "--"));

        activeTable.getColumns().addAll(typeCol, itemCol, priceCol, volCol, remainCol,
                locationCol, expiresCol, rangeCol);
        activeTable.setPlaceholder(new Label("No active market orders"));
        VBox.setVgrow(activeTable, Priority.ALWAYS);

        vbox.getChildren().addAll(summary, activeTable);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createOrderHistoryTab() {
        var tab = new Tab("Order History");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Filter controls
        var filterBox = new HBox(10);
        var typeFilter = new ComboBox<String>();
        typeFilter.getItems().addAll("All", "Buy", "Sell");
        typeFilter.setValue("All");
        var stateFilter = new ComboBox<String>();
        stateFilter.getItems().addAll("All", "Fulfilled", "Cancelled", "Expired");
        stateFilter.setValue("All");
        var refreshBtn = new Button("Refresh");
        filterBox.getChildren().addAll(
                new Label("Type:"), typeFilter,
                new Label("State:"), stateFilter,
                refreshBtn
        );

        // Wire refresh button
        refreshBtn.setOnAction(e -> refreshData(appState.getSelectedCharacterId()));

        // History table
        historyTable = new TableView<>();

        var typeCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Type");
        typeCol.setPrefWidth(60);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().isBuyOrder() ? "Buy" : "Sell"));

        var itemCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(cd -> new SimpleStringProperty(
                appServices.getItemTypeCache().getName(cd.getValue().typeId())
                        .orElse("Type " + cd.getValue().typeId())));

        var priceCol = new TableColumn<MarketOrderRepository.MarketOrderRow, Number>("Price");
        priceCol.setPrefWidth(120);
        priceCol.setCellValueFactory(cd -> new SimpleDoubleProperty(cd.getValue().price()));

        var volCol = new TableColumn<MarketOrderRepository.MarketOrderRow, Number>("Volume");
        volCol.setPrefWidth(80);
        volCol.setCellValueFactory(cd -> new SimpleIntegerProperty(cd.getValue().volumeTotal()));

        var stateCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("State");
        stateCol.setPrefWidth(80);
        stateCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().state() != null ? cd.getValue().state() : "--"));

        var issuedCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Issued");
        issuedCol.setPrefWidth(130);
        issuedCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().issued().format(DT_FMT)));

        var locationCol = new TableColumn<MarketOrderRepository.MarketOrderRow, String>("Location");
        locationCol.setPrefWidth(200);
        locationCol.setCellValueFactory(cd -> new SimpleStringProperty(
                "Station " + cd.getValue().locationId()));

        historyTable.getColumns().addAll(typeCol, itemCol, priceCol, volCol, stateCol,
                issuedCol, locationCol);
        historyTable.setPlaceholder(new Label("No order history"));
        VBox.setVgrow(historyTable, Priority.ALWAYS);

        vbox.getChildren().addAll(filterBox, historyTable);
        tab.setContent(vbox);
        return tab;
    }

    private void refreshData(int characterId) {
        if (characterId <= 0) {
            clearSummary();
            activeTable.setItems(FXCollections.observableArrayList());
            historyTable.setItems(FXCollections.observableArrayList());
            return;
        }

        Thread.ofVirtual().name("orders-load").start(() -> {
            try {
                var orderRepo = appServices.getMarketOrderRepository();
                List<MarketOrderRepository.MarketOrderRow> active = orderRepo.findActiveByCharacter(characterId);
                List<MarketOrderRepository.MarketOrderRow> history = orderRepo.findHistoryByCharacter(characterId);

                long buyCount = active.stream().filter(MarketOrderRepository.MarketOrderRow::isBuyOrder).count();
                long sellCount = active.size() - buyCount;
                double escrow = active.stream()
                        .filter(MarketOrderRepository.MarketOrderRow::isBuyOrder)
                        .mapToDouble(o -> o.price() * o.volumeRemain())
                        .sum();
                double totalVal = active.stream()
                        .mapToDouble(o -> o.price() * o.volumeRemain())
                        .sum();

                Platform.runLater(() -> {
                    buyOrdersValue.setText(String.valueOf(buyCount));
                    sellOrdersValue.setText(String.valueOf(sellCount));
                    totalEscrowValue.setText(String.format("%,.0f ISK", escrow));
                    totalValueLabel.setText(String.format("%,.0f ISK", totalVal));
                    activeTable.setItems(FXCollections.observableArrayList(active));
                    historyTable.setItems(FXCollections.observableArrayList(history));
                });
            } catch (Exception e) {
                log.error("Failed to load orders for character {}", characterId, e);
            }
        });
    }

    private void clearSummary() {
        buyOrdersValue.setText("--");
        sellOrdersValue.setText("--");
        totalEscrowValue.setText("--");
        totalValueLabel.setText("--");
    }

    private HBox createSummaryLabel(String label, Label valueLabel) {
        var box = new HBox(5);
        var lbl = new Label(label);
        lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
        box.getChildren().addAll(lbl, valueLabel);
        return box;
    }

    private Label createSummaryValueLabel(String text) {
        var val = new Label(text);
        val.setStyle("-fx-text-fill: #CCCCCC;");
        return val;
    }

    @Override
    public String getTitle() { return "Market Orders"; }

    @Override
    public void onActivated() {
        log.debug("Market Orders workspace activated");
        refreshData(appState.getSelectedCharacterId());
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Market Orders: character changed to {}", characterId);
        refreshData(characterId);
    }
}

