package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.data.repository.WalletRepository;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Wallet workspace with Personal and Corporation tabs.
 * Corporation wallet is feature-gated (requires Standard+).
 * Populates from WalletRepository data.
 */
public class WalletWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final FeatureGate featureGate;
    private final AppServices appServices;

    private Label balanceLabel;
    private TableView<WalletRepository.WalletJournalRow> journalTable;

    public WalletWorkspace(AppState appState, FeatureGate featureGate, AppServices appServices) {
        super(appState);
        this.featureGate = featureGate;
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createPersonalTab(),
                createCorporationTab()
        );

        // Auto-refresh when wallet sync completes
        appServices.onSyncCompleted(syncType -> {
            if ("wallet".equalsIgnoreCase(syncType) || "full".equalsIgnoreCase(syncType)) {
                refreshData(appState.getSelectedCharacterId());
            }
        });
    }

    @SuppressWarnings("unchecked")
    private Tab createPersonalTab() {
        var tab = new Tab("Personal");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Balance display
        var balanceBox = new HBox(20);
        balanceLabel = new Label("Balance: --");
        balanceLabel.setStyle("-fx-font-size: 18; -fx-font-weight: bold; -fx-text-fill: #4EC9B0;");
        balanceBox.getChildren().add(balanceLabel);

        // Filter controls
        var filterBox = new HBox(10);
        var typeFilter = new ComboBox<String>();
        typeFilter.getItems().addAll("All", "Market Transaction", "Contract",
                "Bounty", "Insurance", "Corporation Tax");
        typeFilter.setValue("All");
        var fromDate = new DatePicker();
        fromDate.setPromptText("From");
        var toDate = new DatePicker();
        toDate.setPromptText("To");
        filterBox.getChildren().addAll(
                new Label("Type:"), typeFilter,
                new Label("From:"), fromDate,
                new Label("To:"), toDate
        );

        // Journal table
        journalTable = new TableView<>();
        var dateCol = new TableColumn<WalletRepository.WalletJournalRow, String>("Date");
        dateCol.setPrefWidth(150);
        dateCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().date().format(DT_FMT)));

        var typeCol = new TableColumn<WalletRepository.WalletJournalRow, String>("Type");
        typeCol.setPrefWidth(150);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().transactionType()));

        var amountCol = new TableColumn<WalletRepository.WalletJournalRow, Number>("Amount");
        amountCol.setPrefWidth(120);
        amountCol.setCellValueFactory(cd -> new SimpleDoubleProperty(cd.getValue().amount()));

        var balCol = new TableColumn<WalletRepository.WalletJournalRow, Number>("Balance");
        balCol.setPrefWidth(120);
        balCol.setCellValueFactory(cd -> new SimpleDoubleProperty(cd.getValue().balance()));

        var descCol = new TableColumn<WalletRepository.WalletJournalRow, String>("Description");
        descCol.setPrefWidth(300);
        descCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().description() != null ? cd.getValue().description() : ""));

        journalTable.getColumns().addAll(dateCol, typeCol, amountCol, balCol, descCol);
        journalTable.setPlaceholder(new Label("No wallet transactions"));
        VBox.setVgrow(journalTable, Priority.ALWAYS);

        vbox.getChildren().addAll(balanceBox, filterBox, journalTable);
        tab.setContent(vbox);
        return tab;
    }

    private Tab createCorporationTab() {
        var tab = new Tab("Corporation");

        if (!featureGate.isFeatureAvailable(FeatureSet.CORPORATION_WALLET,
                SubscriptionTier.STANDARD)) {
            tab.setContent(new FeatureLockedPane(
                    "Corporation Wallet", "Standard"));
        } else {
            var vbox = new VBox(10);
            vbox.setPadding(new Insets(10));

            // Division selector
            var divBox = new HBox(10);
            var divCombo = new ComboBox<String>();
            divCombo.getItems().addAll("Division 1", "Division 2", "Division 3",
                    "Division 4", "Division 5", "Division 6", "Division 7");
            divCombo.setValue("Division 1");
            var balLabel = new Label("Balance: --");
            balLabel.setStyle("-fx-font-size: 16; -fx-font-weight: bold; -fx-text-fill: #4EC9B0;");
            divBox.getChildren().addAll(new Label("Division:"), divCombo, balLabel);

            // Transaction table
            var table = new TableView<>();
            var dateCol = new TableColumn<>("Date");
            dateCol.setPrefWidth(150);
            var typeCol = new TableColumn<>("Type");
            typeCol.setPrefWidth(150);
            var amountCol = new TableColumn<>("Amount");
            amountCol.setPrefWidth(120);
            var balCol = new TableColumn<>("Balance");
            balCol.setPrefWidth(120);
            var charCol = new TableColumn<>("Character");
            charCol.setPrefWidth(150);
            var descCol = new TableColumn<>("Description");
            descCol.setPrefWidth(250);

            table.getColumns().addAll(dateCol, typeCol, amountCol, balCol, charCol, descCol);
            table.setPlaceholder(new Label("No corporation wallet data"));
            VBox.setVgrow(table, Priority.ALWAYS);

            vbox.getChildren().addAll(divBox, table);
            tab.setContent(vbox);
        }

        return tab;
    }

    private void refreshData(int characterId) {
        if (characterId <= 0) {
            balanceLabel.setText("Balance: --");
            journalTable.setItems(FXCollections.observableArrayList());
            return;
        }

        Thread.ofVirtual().name("wallet-load").start(() -> {
            try {
                var walletRepo = appServices.getWalletRepository();

                // Load balance
                var balances = walletRepo.findBalancesByCharacter(characterId);
                double totalBalance = balances.stream()
                        .mapToDouble(WalletRepository.WalletBalanceRow::balance)
                        .sum();

                // Load journal entries
                List<WalletRepository.WalletJournalRow> journal =
                        walletRepo.findJournalByCharacter(characterId);

                Platform.runLater(() -> {
                    balanceLabel.setText(String.format("Balance: %,.2f ISK", totalBalance));
                    journalTable.setItems(FXCollections.observableArrayList(journal));
                });
            } catch (Exception e) {
                log.error("Failed to load wallet data for character {}", characterId, e);
            }
        });
    }

    @Override
    public String getTitle() { return "Wallet"; }

    @Override
    public void onActivated() {
        log.debug("Wallet workspace activated");
        refreshData(appState.getSelectedCharacterId());
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Wallet: character changed to {}", characterId);
        refreshData(characterId);
    }
}

