        var tab = new Tab("Queue");
        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Queue summary
        queueCountValue = createSummaryValueLabel("--");
        trainingTimeValue = createSummaryValueLabel("--");
        finishesValue = createSummaryValueLabel("--");

        var summaryBox = new HBox(20);
        summaryBox.getChildren().addAll(
                createInfoLabel("Skills in queue:", queueCountValue),
                createInfoLabel("Training time:", trainingTimeValue),
                createInfoLabel("Finishes:", finishesValue)
        );

        // Queue table
        queueTable = new TableView<>();
        var posCol = new TableColumn<>("#");
        posCol.setPrefWidth(40);
        var skillCol = new TableColumn<>("Skill");
        skillCol.setPrefWidth(200);
        var levelCol = new TableColumn<>("Level");
        levelCol.setPrefWidth(60);
        var startCol = new TableColumn<>("Start");
        startCol.setPrefWidth(150);
        var endCol = new TableColumn<>("End");
        endCol.setPrefWidth(150);
        var durationCol = new TableColumn<>("Duration");
        durationCol.setPrefWidth(120);

        @SuppressWarnings("unchecked") var queueCols = queueTable.getColumns();
        queueCols.addAll(posCol, skillCol, levelCol, startCol, endCol, durationCol);
        queueTable.setPlaceholder(new Label("Skill queue is empty"));
        VBox.setVgrow(queueTable, Priority.ALWAYS);

        vbox.getChildren().addAll(summaryBox, queueTable);
        tab.setContent(vbox);
        return tab;
    }

    private void refreshData(int characterId) {
        if (characterId <= 0) {
            queueCountValue.setText("--");
            trainingTimeValue.setText("--");
            finishesValue.setText("--");
            return;
        }
        // Skills data will be populated once the skills sync populates a SkillRepository.
        // For now, reset to placeholder indicating no data yet.
        log.debug("Refreshing skills data for character {}", characterId);
        queueCountValue.setText("0");
        trainingTimeValue.setText("N/A");
        finishesValue.setText("N/A");
    }

    private HBox createInfoLabel(String label, Label valueLabel) {
        var box = new HBox(5);
        var lbl = new Label(label);
        lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
        box.getChildren().addAll(lbl, valueLabel);
        return box;
    }

    private Label createSummaryValueLabel(String text) {
        var val = new Label(text);
        val.setStyle("-fx-text-fill: #CCCCCC;");
        return val;
    }

    @Override
    public String getTitle() { return "Skills"; }

    @Override
    public void onActivated() {
        log.debug("Skills workspace activated");
        refreshData(appState.getSelectedCharacterId());
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Skills: character changed to {}", characterId);
        refreshData(characterId);
    }
}

