343	    private void calculateTax(String amountStr, String accountingStr, String brokerStr,
344	                              String corpStandingStr, String factionStandingStr) {
345	        try {
346	            double amount = Double.parseDouble(amountStr.replace(",", ""));
347	            int accountingLevel = Integer.parseInt(accountingStr);
348	            int brokerLevel = Integer.parseInt(brokerStr);
349	            double corpStanding = Double.parseDouble(corpStandingStr);
350	            double factionStanding = Double.parseDouble(factionStandingStr);
351	
352	            double salesTax = TaxService.calculateSalesTax(amount, accountingLevel);
353	            double brokerFee = TaxService.calculateBrokerFee(amount, brokerLevel,
354	                    factionStanding, corpStanding);
355	            double totalFees = salesTax + brokerFee;
356	            double netAmount = amount - totalFees;
357	
358	            salesTaxResultLabel.setText(formatIsk(salesTax));
359	            brokerFeeResultLabel.setText(formatIsk(brokerFee));
360	            totalFeesLabel.setText(formatIsk(totalFees));
361	            netAmountLabel.setText(formatIsk(netAmount));
362	        } catch (NumberFormatException ex) {
363	            salesTaxResultLabel.setText("Invalid input");
364	            brokerFeeResultLabel.setText("--");
365	            totalFeesLabel.setText("--");
366	            netAmountLabel.setText("--");
367	        }
368	    }
