421	    private static String formatIsk(double amount) {
422	        if (Math.abs(amount) >= 1_000_000_000) {
423	            return String.format("%.2fB ISK", amount / 1_000_000_000.0);
424	        } else if (Math.abs(amount) >= 1_000_000) {
425	            return String.format("%.2fM ISK", amount / 1_000_000.0);
426	        } else if (Math.abs(amount) >= 1_000) {
427	            return String.format("%.2fK ISK", amount / 1_000.0);
428	        }
429	        return String.format("%.2f ISK", amount);
430	    }
