471	    private void updateOverviewSummary(List<JournalEntry> entries) {
472	        if (entries.isEmpty()) {
473	            totalBalanceLabel.setText("0 ISK");
474	            income30dLabel.setText("0 ISK");
475	            expenses30dLabel.setText("0 ISK");
476	            netProfit30dLabel.setText("0 ISK");
477	            return;
478	        }
479	
480	        // Latest balance from most recent entry
481	        double latestBalance = entries.get(0).balance();
482	        totalBalanceLabel.setText(formatIsk(latestBalance));
483	
484	        // Sum income and expenses from all loaded entries
485	        double income = 0;
486	        double expenses = 0;
487	        for (var entry : entries) {
488	            if (entry.amount() > 0) {
489	                income += entry.amount();
490	            } else {
491	                expenses += Math.abs(entry.amount());
492	            }
493	        }
494	        income30dLabel.setText(formatIsk(income));
495	        expenses30dLabel.setText(formatIsk(expenses));
496	        netProfit30dLabel.setText(formatIsk(income - expenses));
497	    }
