499	    @SuppressWarnings("unchecked")
500	    private void updateBalanceChart(List<JournalEntry> entries) {
501	        balanceChart.getData().clear();
502	        if (entries.isEmpty()) return;
503	
504	        var series = new XYChart.Series<String, Number>();
505	        series.setName("Balance");
