package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.JournalEntry;
import com.sampleapp.core.model.ProfitModel;
import com.sampleapp.core.service.TaxService;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.chart.CategoryAxis;
import javafx.scene.chart.LineChart;
import javafx.scene.chart.NumberAxis;
import javafx.scene.chart.XYChart;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Accounting workspace with 6 tabs: Overview, Groups, Import/Export,
 * Profit Tracker, Tax Calculator, and Reports.
 */
public class AccountingWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final WorkspaceDataService dataService;

    // Overview
    private Label totalBalanceLabel;
    private Label income30dLabel;
    private Label expenses30dLabel;
    private Label netProfit30dLabel;
    private final ObservableList<JournalEntry> recentEntries = FXCollections.observableArrayList();
    private LineChart<String, Number> balanceChart;

    // Profit Tracker
    private final ObservableList<ProfitModel> profitList = FXCollections.observableArrayList();

    // Tax Calculator result labels
    private Label salesTaxResultLabel;
    private Label brokerFeeResultLabel;
    private Label totalFeesLabel;
    private Label netAmountLabel;

    public AccountingWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createOverviewTab(),
                createGroupsTab(),
                createImportExportTab(),
                createProfitTrackerTab(),
                createTaxCalculatorTab(),
                createReportsTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createOverviewTab() {
        var tab = new Tab("Overview");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Summary cards
        var summaryBox = new HBox(20);
        var balCard = createSummaryCard("Total Balance", "--", "#4EC9B0");
        totalBalanceLabel = (Label) balCard.getChildren().get(1);
        var incCard = createSummaryCard("Income (30d)", "--", "#4EC9B0");
        income30dLabel = (Label) incCard.getChildren().get(1);
        var expCard = createSummaryCard("Expenses (30d)", "--", "#F44747");
        expenses30dLabel = (Label) expCard.getChildren().get(1);
        var netCard = createSummaryCard("Net Profit (30d)", "--", "#CCCCCC");
        netProfit30dLabel = (Label) netCard.getChildren().get(1);
        summaryBox.getChildren().addAll(balCard, incCard, expCard, netCard);

        // Balance chart
        var xAxis = new CategoryAxis();
        xAxis.setLabel("Date");
        var yAxis = new NumberAxis();
        yAxis.setLabel("ISK");
        balanceChart = new LineChart<>(xAxis, yAxis);
        balanceChart.setTitle("Balance History");
        balanceChart.setPrefHeight(300);
        balanceChart.setCreateSymbols(false);
        VBox.setVgrow(balanceChart, Priority.ALWAYS);

        // Recent transactions
        var recentLabel = new Label("Recent Transactions");
        recentLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #CCCCCC; -fx-font-size: 14;");

        var table = new TableView<JournalEntry>();
        var dateCol = new TableColumn<JournalEntry, String>("Date");
        dateCol.setPrefWidth(130);
        dateCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().date() != null ? c.getValue().date().format(DT_FMT) : "--"));
        var descCol = new TableColumn<JournalEntry, String>("Description");
        descCol.setPrefWidth(300);
        descCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().description() != null ? c.getValue().description() : "--"));
        var amountCol = new TableColumn<JournalEntry, Number>("Amount");
        amountCol.setPrefWidth(120);
        amountCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().amount()));
        var groupCol = new TableColumn<JournalEntry, String>("Type");
        groupCol.setPrefWidth(120);
        groupCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().transactionType() != null ? c.getValue().transactionType() : "--"));
        table.getColumns().addAll(dateCol, descCol, amountCol, groupCol);
        table.setItems(recentEntries);
        table.setPrefHeight(200);

        vbox.getChildren().addAll(summaryBox, balanceChart, recentLabel, table);
        tab.setContent(new ScrollPane(vbox));
        return tab;
    }

    private Tab createGroupsTab() {
        var tab = new Tab("Groups");

        var splitPane = new SplitPane();

        // Left: group list
        var groupList = new ListView<String>();
        groupList.getItems().addAll("Trading", "Manufacturing", "Mining",
                "Ratting", "Mission Running", "Exploration", "PI", "Other");

        // Right: group transactions
        var rightPane = new VBox(10);
        rightPane.setPadding(new Insets(10));
        var table = new TableView<JournalEntry>();
        var dateCol = new TableColumn<JournalEntry, String>("Date");
        dateCol.setPrefWidth(130);
        dateCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().date() != null ? c.getValue().date().format(DT_FMT) : "--"));
        var descCol = new TableColumn<JournalEntry, String>("Description");
        descCol.setPrefWidth(250);
        descCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().description() != null ? c.getValue().description() : "--"));
        var amountCol = new TableColumn<JournalEntry, Number>("Amount");
        amountCol.setPrefWidth(120);
        amountCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().amount()));
        table.getColumns().addAll(dateCol, descCol, amountCol);
        table.setPlaceholder(new Label("Select a group"));
        VBox.setVgrow(table, Priority.ALWAYS);
        rightPane.getChildren().add(table);

        splitPane.getItems().addAll(groupList, rightPane);
        splitPane.setDividerPositions(0.25);

        tab.setContent(splitPane);
        return tab;
    }

    private Tab createImportExportTab() {
        var tab = new Tab("Import/Export");

        var vbox = new VBox(15);
        vbox.setPadding(new Insets(15));

        // Import section
        var importLabel = new Label("Import Transactions");
        importLabel.setStyle("-fx-font-weight: bold; -fx-font-size: 14; -fx-text-fill: #CCCCCC;");
        var importBox = new HBox(10);
        var importFormatCombo = new ComboBox<String>();
        importFormatCombo.getItems().addAll("CSV", "EVE Clipboard", "jEveAssets");
        importFormatCombo.setValue("CSV");
        var importBtn = new Button("Import File...");
        var pasteBtn = new Button("Paste from Clipboard");
        importBox.getChildren().addAll(new Label("Format:"), importFormatCombo,
                importBtn, pasteBtn);

        // Export section
        var exportLabel = new Label("Export Transactions");
        exportLabel.setStyle("-fx-font-weight: bold; -fx-font-size: 14; -fx-text-fill: #CCCCCC;");
        var exportBox = new HBox(10);
        var exportFormatCombo = new ComboBox<String>();
        exportFormatCombo.getItems().addAll("CSV", "JSON", "Excel");
        exportFormatCombo.setValue("CSV");
        var fromDate = new DatePicker();
        fromDate.setPromptText("From");
        var toDate = new DatePicker();
        toDate.setPromptText("To");
        var exportBtn = new Button("Export...");
        exportBox.getChildren().addAll(new Label("Format:"), exportFormatCombo,
                new Label("From:"), fromDate, new Label("To:"), toDate, exportBtn);

        vbox.getChildren().addAll(importLabel, importBox,
                new Separator(), exportLabel, exportBox);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createProfitTrackerTab() {
        var tab = new Tab("Profit Tracker");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var filterBox = new HBox(10);
        var fromDate = new DatePicker();
        fromDate.setPromptText("From");
        var toDate = new DatePicker();
        toDate.setPromptText("To");
        var refreshBtn = new Button("Calculate");
        filterBox.getChildren().addAll(
                new Label("From:"), fromDate,
                new Label("To:"), toDate,
                refreshBtn
        );

        var table = new TableView<ProfitModel>();
        var itemCol = new TableColumn<ProfitModel, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().typeName() != null ? c.getValue().typeName() : "Type #" + c.getValue().typeId()));
        var boughtCol = new TableColumn<ProfitModel, Number>("Cost");
        boughtCol.setPrefWidth(100);
        boughtCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().cost()));
        var soldCol = new TableColumn<ProfitModel, Number>("Revenue");
        soldCol.setPrefWidth(100);
        soldCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().revenue()));
        var profitCol = new TableColumn<ProfitModel, Number>("Profit");
        profitCol.setPrefWidth(120);
        profitCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().profit()));
        var marginCol = new TableColumn<ProfitModel, String>("Margin %");
        marginCol.setPrefWidth(80);
        marginCol.setCellValueFactory(c -> {
            double revenue = c.getValue().revenue();
            double cost = c.getValue().cost();
            double margin = cost > 0 ? ((revenue - cost) / cost) * 100.0 : 0;
            return new SimpleStringProperty(String.format("%.1f%%", margin));
        });
        var taxCol = new TableColumn<ProfitModel, Number>("Taxes");
        taxCol.setPrefWidth(80);
        taxCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().taxes()));

        table.getColumns().addAll(itemCol, boughtCol, soldCol, profitCol, marginCol, taxCol);
        table.setItems(profitList);
        table.setPlaceholder(new Label("Set date range and click Calculate"));
        VBox.setVgrow(table, Priority.ALWAYS);

        refreshBtn.setOnAction(e -> {
            int charId = appState.getSelectedCharacterId();
            if (charId <= 0) return;
            refreshBtn.setDisable(true);
            dataService.getProfitSummary(charId, fromDate.getValue(), toDate.getValue())
                    .thenAccept(data -> Platform.runLater(() -> {
                        profitList.setAll(data);
                        refreshBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to load profit data", ex);
                            refreshBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(filterBox, table);
        tab.setContent(vbox);
        return tab;
    }

    private Tab createTaxCalculatorTab() {
        var tab = new Tab("Tax Calculator");

        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));

        grid.add(new Label("Transaction Amount:"), 0, 0);
        var amountField = new TextField();
        amountField.setPromptText("ISK amount");
        grid.add(amountField, 1, 0);

        grid.add(new Label("Accounting Skill Level:"), 0, 1);
        var accountingCombo = new ComboBox<String>();
        accountingCombo.getItems().addAll("0", "1", "2", "3", "4", "5");
        accountingCombo.setValue("5");
        grid.add(accountingCombo, 1, 1);

        grid.add(new Label("Broker Relations Level:"), 0, 2);
        var brokerCombo = new ComboBox<String>();
        brokerCombo.getItems().addAll("0", "1", "2", "3", "4", "5");
        brokerCombo.setValue("5");
        grid.add(brokerCombo, 1, 2);

        grid.add(new Label("Corp Standing:"), 0, 3);
        var corpStandingField = new TextField("0.0");
        grid.add(corpStandingField, 1, 3);

        grid.add(new Label("Faction Standing:"), 0, 4);
        var factionStandingField = new TextField("0.0");
        grid.add(factionStandingField, 1, 4);

        var calcBtn = new Button("Calculate");
        grid.add(calcBtn, 1, 5);

        var separator = new Separator();
        grid.add(separator, 0, 6, 2, 1);

        grid.add(new Label("Sales Tax:"), 0, 7);
        salesTaxResultLabel = new Label("--");
        salesTaxResultLabel.setStyle("-fx-text-fill: #CCCCCC;");
        grid.add(salesTaxResultLabel, 1, 7);

        grid.add(new Label("Broker Fee:"), 0, 8);
        brokerFeeResultLabel = new Label("--");
        brokerFeeResultLabel.setStyle("-fx-text-fill: #CCCCCC;");
        grid.add(brokerFeeResultLabel, 1, 8);

        grid.add(new Label("Total Fees:"), 0, 9);
        totalFeesLabel = new Label("--");
        totalFeesLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #F44747;");
        grid.add(totalFeesLabel, 1, 9);

        grid.add(new Label("Net Amount:"), 0, 10);
        netAmountLabel = new Label("--");
        netAmountLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #4EC9B0;");
        grid.add(netAmountLabel, 1, 10);

        calcBtn.setOnAction(e -> calculateTax(
                amountField.getText(),
                accountingCombo.getValue(),
                brokerCombo.getValue(),
                corpStandingField.getText(),
                factionStandingField.getText()
        ));

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    private void calculateTax(String amountStr, String accountingStr, String brokerStr,
                              String corpStandingStr, String factionStandingStr) {
        try {
            double amount = Double.parseDouble(amountStr.replace(",", ""));
            int accountingLevel = Integer.parseInt(accountingStr);
            int brokerLevel = Integer.parseInt(brokerStr);
            double corpStanding = Double.parseDouble(corpStandingStr);
            double factionStanding = Double.parseDouble(factionStandingStr);

            double salesTax = TaxService.calculateSalesTax(amount, accountingLevel);
            double brokerFee = TaxService.calculateBrokerFee(amount, brokerLevel,
                    factionStanding, corpStanding);
            double totalFees = salesTax + brokerFee;
            double netAmount = amount - totalFees;

            salesTaxResultLabel.setText(formatIsk(salesTax));
            brokerFeeResultLabel.setText(formatIsk(brokerFee));
            totalFeesLabel.setText(formatIsk(totalFees));
            netAmountLabel.setText(formatIsk(netAmount));
        } catch (NumberFormatException ex) {
            salesTaxResultLabel.setText("Invalid input");
            brokerFeeResultLabel.setText("--");
            totalFeesLabel.setText("--");
            netAmountLabel.setText("--");
        }
    }

    private Tab createReportsTab() {
        var tab = new Tab("Reports");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var reportType = new ComboBox<String>();
        reportType.getItems().addAll("Daily Summary", "Weekly Summary",
                "Monthly Summary", "Item Profitability", "Activity Summary");
        reportType.setValue("Daily Summary");

        var fromDate = new DatePicker();
        fromDate.setPromptText("From");
        var toDate = new DatePicker();
        toDate.setPromptText("To");
        var generateBtn = new Button("Generate Report");

        var controlBox = new HBox(10);
        controlBox.getChildren().addAll(
                new Label("Report:"), reportType,
                new Label("From:"), fromDate,
                new Label("To:"), toDate,
                generateBtn
        );

        var reportArea = new TextArea();
        reportArea.setEditable(false);
        reportArea.setPromptText("Report output will appear here...");
        VBox.setVgrow(reportArea, Priority.ALWAYS);

        vbox.getChildren().addAll(controlBox, reportArea);
        tab.setContent(vbox);
        return tab;
    }

    private VBox createSummaryCard(String title, String value, String color) {
        var card = new VBox(5);
        card.setPadding(new Insets(10));
        card.setStyle("-fx-background-color: #252526; -fx-background-radius: 4; " +
                "-fx-border-color: #434346; -fx-border-radius: 4;");
        card.setPrefWidth(200);

        var titleLabel = new Label(title);
        titleLabel.setStyle("-fx-text-fill: #AAAAAA; -fx-font-size: 11;");
        var valueLabel = new Label(value);
        valueLabel.setStyle("-fx-text-fill: " + color + "; -fx-font-size: 18; -fx-font-weight: bold;");

        card.getChildren().addAll(titleLabel, valueLabel);
        return card;
    }

    private static String formatIsk(double amount) {
        if (Math.abs(amount) >= 1_000_000_000) {
            return String.format("%.2fB ISK", amount / 1_000_000_000.0);
        } else if (Math.abs(amount) >= 1_000_000) {
            return String.format("%.2fM ISK", amount / 1_000_000.0);
        } else if (Math.abs(amount) >= 1_000) {
            return String.format("%.2fK ISK", amount / 1_000.0);
        }
        return String.format("%.2f ISK", amount);
    }

    @Override
    public String getTitle() { return "Accounting"; }

    @Override
    public void onActivated() {
        log.debug("Accounting workspace activated");
        int charId = appState.getSelectedCharacterId();
        if (charId > 0 && recentEntries.isEmpty()) {
            onCharacterChanged(charId);
        }
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Accounting: character changed to {}", characterId);
        if (characterId <= 0) {
            recentEntries.clear();
            profitList.clear();
            totalBalanceLabel.setText("--");
            income30dLabel.setText("--");
            expenses30dLabel.setText("--");
            netProfit30dLabel.setText("--");
            balanceChart.getData().clear();
            return;
        }

        // Load journal entries for overview
        dataService.getJournalEntries(characterId)
                .thenAccept(entries -> Platform.runLater(() -> {
                    recentEntries.setAll(entries);
                    updateOverviewSummary(entries);
                    updateBalanceChart(entries);
                }))
                .exceptionally(ex -> {
                    log.error("Failed to load journal entries", ex);
                    return null;
                });
    }

    private void updateOverviewSummary(List<JournalEntry> entries) {
        if (entries.isEmpty()) {
            totalBalanceLabel.setText("0 ISK");
            income30dLabel.setText("0 ISK");
            expenses30dLabel.setText("0 ISK");
            netProfit30dLabel.setText("0 ISK");
            return;
        }

        // Latest balance from most recent entry
        double latestBalance = entries.get(0).balance();
        totalBalanceLabel.setText(formatIsk(latestBalance));

        // Sum income and expenses from all loaded entries
        double income = 0;
        double expenses = 0;
        for (var entry : entries) {
            if (entry.amount() > 0) {
                income += entry.amount();
            } else {
                expenses += Math.abs(entry.amount());
            }
        }
        income30dLabel.setText(formatIsk(income));
        expenses30dLabel.setText(formatIsk(expenses));
        netProfit30dLabel.setText(formatIsk(income - expenses));
    }

    @SuppressWarnings("unchecked")
    private void updateBalanceChart(List<JournalEntry> entries) {
        balanceChart.getData().clear();
        if (entries.isEmpty()) return;

        var series = new XYChart.Series<String, Number>();
        series.setName("Balance");

        // Show last 30 entries in chronological order (entries are typically newest-first)
        int count = Math.min(entries.size(), 30);
        for (int i = count - 1; i >= 0; i--) {
            var entry = entries.get(i);
            String dateStr = entry.date() != null
                    ? entry.date().toLocalDate().toString() : "?";
            series.getData().add(new XYChart.Data<>(dateStr, entry.balance()));
        }
        balanceChart.getData().add(series);
    }
}

