152	    private void applyJobFilters() {
153	        String activity = activityFilter.getValue();
154	        String status = statusFilter.getValue();
155	        filteredJobs.setPredicate(job -> {
156	            if (!"All".equals(activity)) {
157	                var act = IndustryActivityType.fromValue(job.activityId());
158	                if (!act.name().replace("_", " ").equalsIgnoreCase(
159	                        activity.replace("-", " ").replace("Researching ", "RESEARCH_"))) {
160	                    // Simplified matching
161	                    String actName = act.name();
162	                    boolean match = switch (activity) {
163	                        case "Manufacturing" -> actName.equals("MANUFACTURING");
164	                        case "Researching Time Efficiency" -> actName.equals("RESEARCH_TE");
165	                        case "Researching Material Efficiency" -> actName.equals("RESEARCH_ME");
166	                        case "Copying" -> actName.equals("COPYING");
167	                        case "Invention" -> actName.equals("INVENTION");
168	                        case "Reaction" -> actName.equals("REACTIONS");
169	                        default -> true;
170	                    };
171	                    if (!match) return false;
172	                }
173	            }
174	            if (!"All".equals(status)) {
175	                var jobStatus = IndustryJobStatus.fromValue(job.status());
176	                if (!jobStatus.name().equalsIgnoreCase(status)) return false;
177	            }
178	            return true;
179	        });
180	    }
