package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.enums.IndustryActivityType;
import com.sampleapp.core.enums.IndustryJobStatus;
import com.sampleapp.core.model.BlueprintModel;
import com.sampleapp.core.model.IndustryJob;
import com.sampleapp.core.model.MiningLedger;
import com.sampleapp.core.model.TypeMaterial;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.collections.transformation.FilteredList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Industry workspace with 6 tabs: Jobs, Blueprints, Calculator, Mining Ledger,
 * Reprocessing, and Production Ledger.
 * Entire workspace is feature-gated (requires INDUSTRY feature set).
 */
public class IndustryWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    // Jobs tab
    private final ObservableList<IndustryJob> jobsList = FXCollections.observableArrayList();
    private FilteredList<IndustryJob> filteredJobs;
    private ComboBox<String> activityFilter;
    private ComboBox<String> statusFilter;

    // Blueprints tab
    private final ObservableList<BlueprintModel> blueprintsList = FXCollections.observableArrayList();
    private TextField bpSearchField;
    private ComboBox<String> bpTypeFilter;

    // Mining ledger tab
    private final ObservableList<MiningLedger> miningList = FXCollections.observableArrayList();

    // Calculator tab
    private final ObservableList<TypeMaterial> materialsList = FXCollections.observableArrayList();
    private Label calcCostLabel;
    private Label calcProfitLabel;

    // Reprocessing tab
    private final ObservableList<TypeMaterial> reprocessList = FXCollections.observableArrayList();
    private Label reprocessTotalLabel;

    public IndustryWorkspace(AppState appState, FeatureGate featureGate,
                             WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        if (!featureGate.isEnabled(FeatureSet.INDUSTRY)) {
            setCenter(new FeatureLockedPane("Industry", "Professional"));
        } else {
            tabPane.getTabs().addAll(
                    createJobsTab(),
                    createBlueprintsTab(),
                    createCalculatorTab(),
                    createMiningLedgerTab(),
                    createReprocessingTab(),
                    createProductionLedgerTab()
            );
        }
    }

    @SuppressWarnings("unchecked")
    private Tab createJobsTab() {
        var tab = new Tab("Jobs");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var filterBox = new HBox(10);
        activityFilter = new ComboBox<>();
        activityFilter.getItems().addAll("All", "Manufacturing", "Researching Time Efficiency",
                "Researching Material Efficiency", "Copying", "Invention", "Reaction");
        activityFilter.setValue("All");
        statusFilter = new ComboBox<>();
        statusFilter.getItems().addAll("All", "Active", "Paused", "Ready", "Delivered", "Cancelled");
        statusFilter.setValue("Active");
        filterBox.getChildren().addAll(
                new Label("Activity:"), activityFilter,
                new Label("Status:"), statusFilter
        );

        filteredJobs = new FilteredList<>(jobsList, p -> true);
        activityFilter.setOnAction(e -> applyJobFilters());
        statusFilter.setOnAction(e -> applyJobFilters());

        var table = new TableView<IndustryJob>();
        var actCol = new TableColumn<IndustryJob, String>("Activity");
        actCol.setPrefWidth(120);
        actCol.setCellValueFactory(c -> new SimpleStringProperty(
                IndustryActivityType.fromValue(c.getValue().activityId()).name()));
        var bpCol = new TableColumn<IndustryJob, String>("Blueprint");
        bpCol.setPrefWidth(200);
        bpCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Type #" + c.getValue().blueprintTypeId());
            dataService.resolveTypeName(c.getValue().blueprintTypeId())
