    private void applyJobFilters() {
        String activity = activityFilter.getValue();
        String status = statusFilter.getValue();
        filteredJobs.setPredicate(job -> {
            if (!"All".equals(activity)) {
                var act = IndustryActivityType.fromValue(job.activityId());
                if (!act.name().replace("_", " ").equalsIgnoreCase(
                        activity.replace("-", " ").replace("Researching ", "RESEARCH_"))) {
                    // Simplified matching
                    String actName = act.name();
                    boolean match = switch (activity) {
                        case "Manufacturing" -> actName.equals("MANUFACTURING");
                        case "Researching Time Efficiency" -> actName.equals("RESEARCH_TE");
                        case "Researching Material Efficiency" -> actName.equals("RESEARCH_ME");
                        case "Copying" -> actName.equals("COPYING");
                        case "Invention" -> actName.equals("INVENTION");
                        case "Reaction" -> actName.equals("REACTIONS");
                        default -> true;
                    };
                    if (!match) return false;
                }
            }
            if (!"All".equals(status)) {
                var jobStatus = IndustryJobStatus.fromValue(job.status());
                if (!jobStatus.name().equalsIgnoreCase(status)) return false;
            }
            return true;
        });
    }

