    @Override
    public String getTitle() { return "Industry"; }

    @Override
    public void onActivated() {
        log.debug("Industry workspace activated");
        int charId = appState.getSelectedCharacterId();
        if (charId > 0 && jobsList.isEmpty()) {
            onCharacterChanged(charId);
        }
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Industry: character changed to {}", characterId);
        if (!featureGate.isEnabled(FeatureSet.INDUSTRY)) return;
        if (characterId <= 0) {
            jobsList.clear();
            blueprintsList.clear();
            miningList.clear();
            return;
        }

        // Load industry jobs
        dataService.getIndustryJobs(characterId)
                .thenAccept(jobs -> Platform.runLater(() -> jobsList.setAll(jobs)))
                .exceptionally(ex -> {
                    log.error("Failed to load industry jobs", ex);
                    return null;
                });

        // Load blueprints
        dataService.getBlueprints(characterId)
                .thenAccept(bps -> Platform.runLater(() -> blueprintsList.setAll(bps)))
                .exceptionally(ex -> {
                    log.error("Failed to load blueprints", ex);
                    return null;
                });
    }
