package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.data.repository.ContractRepository;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Contracts workspace with Personal and Corporation tabs.
 * Corporation contracts require Standard+ subscription.
 * Populates from ContractRepository data.
 */
public class ContractsWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final FeatureGate featureGate;
    private final AppServices appServices;

    private TableView<ContractRepository.ContractRow> personalTable;

    public ContractsWorkspace(AppState appState, FeatureGate featureGate, AppServices appServices) {
        super(appState);
        this.featureGate = featureGate;
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createPersonalTab(),
                createCorporationTab()
        );

        appServices.onSyncCompleted(syncType -> {
            if ("contracts".equalsIgnoreCase(syncType) || "full".equalsIgnoreCase(syncType)) {
                refreshData(appState.getSelectedCharacterId());
            }
        });
    }

    @SuppressWarnings("unchecked")
    private Tab createPersonalTab() {
        var tab = new Tab("Personal");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Filter bar
        var filterBox = new HBox(10);
        var typeFilter = new ComboBox<String>();
        typeFilter.getItems().addAll("All", "Item Exchange", "Auction", "Courier");
        typeFilter.setValue("All");
        var statusFilter = new ComboBox<String>();
        statusFilter.getItems().addAll("All", "Outstanding", "In Progress",
                "Completed", "Expired", "Deleted");
        statusFilter.setValue("All");
        var refreshBtn = new Button("Refresh");
        filterBox.getChildren().addAll(
                new Label("Type:"), typeFilter,
                new Label("Status:"), statusFilter,
                refreshBtn
        );

        // Wire refresh
        refreshBtn.setOnAction(e -> refreshData(appState.getSelectedCharacterId()));

        // Contracts table
        personalTable = new TableView<>();

        var typeCol = new TableColumn<ContractRepository.ContractRow, String>("Type");
        typeCol.setPrefWidth(100);
        typeCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().type() != null ? cd.getValue().type() : "--"));

        var statusCol = new TableColumn<ContractRepository.ContractRow, String>("Status");
        statusCol.setPrefWidth(100);
        statusCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().status() != null ? cd.getValue().status() : "--"));

        var titleCol = new TableColumn<ContractRepository.ContractRow, String>("Title");
        titleCol.setPrefWidth(200);
        titleCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().title() != null ? cd.getValue().title() : "--"));

        var priceCol = new TableColumn<ContractRepository.ContractRow, Number>("Price");
        priceCol.setPrefWidth(120);
        priceCol.setCellValueFactory(cd -> new SimpleDoubleProperty(cd.getValue().price()));

        var issuerCol = new TableColumn<ContractRepository.ContractRow, String>("Issuer");
        issuerCol.setPrefWidth(150);
        issuerCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().issuerId() != null ? "ID: " + cd.getValue().issuerId() : "--"));

        var assigneeCol = new TableColumn<ContractRepository.ContractRow, String>("Assignee");
        assigneeCol.setPrefWidth(150);
        assigneeCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().availability() != null ? cd.getValue().availability() : "--"));

        var issuedCol = new TableColumn<ContractRepository.ContractRow, String>("Issued");
        issuedCol.setPrefWidth(130);
        issuedCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().dateIssued() != null ? cd.getValue().dateIssued().format(DT_FMT) : "--"));

        var expiresCol = new TableColumn<ContractRepository.ContractRow, String>("Expires");
        expiresCol.setPrefWidth(130);
        expiresCol.setCellValueFactory(cd -> new SimpleStringProperty(
                cd.getValue().dateExpired() != null ? cd.getValue().dateExpired().format(DT_FMT) : "--"));

        personalTable.getColumns().addAll(typeCol, statusCol, titleCol, priceCol,
                issuerCol, assigneeCol, issuedCol, expiresCol);
        personalTable.setPlaceholder(new Label("No personal contracts"));
        VBox.setVgrow(personalTable, Priority.ALWAYS);

        vbox.getChildren().addAll(filterBox, personalTable);
        tab.setContent(vbox);
        return tab;
    }

    private Tab createCorporationTab() {
        var tab = new Tab("Corporation");

        if (!featureGate.isFeatureAvailable(FeatureSet.CORPORATION_CONTRACTS,
                SubscriptionTier.STANDARD)) {
            tab.setContent(new FeatureLockedPane(
                    "Corporation Contracts", "Standard"));
        } else {
            var vbox = new VBox(10);
            vbox.setPadding(new Insets(10));

            var table = new TableView<>();
            var typeCol = new TableColumn<>("Type");
            typeCol.setPrefWidth(100);
            var statusCol = new TableColumn<>("Status");
            statusCol.setPrefWidth(100);
            var titleCol = new TableColumn<>("Title");
            titleCol.setPrefWidth(200);
            var priceCol = new TableColumn<>("Price");
            priceCol.setPrefWidth(120);
            var issuerCol = new TableColumn<>("Issuer");
            issuerCol.setPrefWidth(150);
            var issuedCol = new TableColumn<>("Issued");
            issuedCol.setPrefWidth(130);

            table.getColumns().addAll(typeCol, statusCol, titleCol, priceCol,
                    issuerCol, issuedCol);
            table.setPlaceholder(new Label("No corporation contracts"));
            VBox.setVgrow(table, Priority.ALWAYS);

            vbox.getChildren().add(table);
            tab.setContent(vbox);
        }

        return tab;
    }

    private void refreshData(int characterId) {
        if (characterId <= 0) {
            personalTable.setItems(FXCollections.observableArrayList());
            return;
        }

        Thread.ofVirtual().name("contracts-load").start(() -> {
            try {
                List<ContractRepository.ContractRow> contracts =
                        appServices.getContractRepository().findByCharacter(characterId);

                Platform.runLater(() ->
                        personalTable.setItems(FXCollections.observableArrayList(contracts)));
            } catch (Exception e) {
                log.error("Failed to load contracts for character {}", characterId, e);
            }
        });
    }

    @Override
    public String getTitle() { return "Contracts"; }

    @Override
    public void onActivated() {
        log.debug("Contracts workspace activated");
        refreshData(appState.getSelectedCharacterId());
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Contracts: character changed to {}", characterId);
        refreshData(characterId);
    }
}

