package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.core.model.HubPrices;
import com.sampleapp.core.model.MarketOrder;
import com.sampleapp.core.model.MarketPrice;
import com.sampleapp.core.model.MarketStatistics;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.chart.CategoryAxis;
import javafx.scene.chart.LineChart;
import javafx.scene.chart.NumberAxis;
import javafx.scene.chart.XYChart;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;

/**
 * Market workspace with tabs for Search, Appraisal, and Browser.
 * Appraisal multi-hub feature is gated to Professional tier.
 */
public class MarketWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    // Search tab
    private final ObservableList<MarketPrice> searchResults = FXCollections.observableArrayList();
    private LineChart<String, Number> priceChart;

    // Appraisal tab
    private final ObservableList<HubPrices> appraisalResults = FXCollections.observableArrayList();

    // Browser tab
    private final ObservableList<MarketOrder> sellOrders = FXCollections.observableArrayList();
    private final ObservableList<MarketOrder> buyOrders = FXCollections.observableArrayList();

    public MarketWorkspace(AppState appState, FeatureGate featureGate,
                           WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createSearchTab(),
                createAppraisalTab(),
                createBrowserTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createSearchTab() {
        var tab = new Tab("Search");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Search controls
        var searchBox = new HBox(10);
        var searchField = new TextField();
        searchField.setPromptText("Search items...");
        searchField.setPrefWidth(300);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("The Forge", "Domain", "Sinq Laison",
                "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        var searchButton = new Button("Search");
        searchBox.getChildren().addAll(searchField, regionCombo, searchButton);

        // Results table
        var table = new TableView<MarketPrice>();
        var nameCol = new TableColumn<MarketPrice, String>("Item");
        nameCol.setPrefWidth(250);
        nameCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
            dataService.resolveTypeName(c.getValue().typeId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var buyCol = new TableColumn<MarketPrice, Number>("Buy Price");
        buyCol.setPrefWidth(120);
        buyCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().buyPrice()));
        var sellCol = new TableColumn<MarketPrice, Number>("Sell Price");
        sellCol.setPrefWidth(120);
        sellCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().sellPrice()));
        var volumeCol = new TableColumn<MarketPrice, String>("Hub");
        volumeCol.setPrefWidth(100);
        volumeCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Hub #" + c.getValue().hubId());
            dataService.resolveLocationName(c.getValue().hubId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var spreadCol = new TableColumn<MarketPrice, String>("Spread");
        spreadCol.setPrefWidth(80);
        spreadCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            double sell = c.getValue().sellPrice();
            double spread = sell > 0 ? ((sell - buy) / sell) * 100.0 : 0;
            return new SimpleStringProperty(String.format("%.1f%%", spread));
        });

        table.getColumns().addAll(nameCol, buyCol, sellCol, volumeCol, spreadCol);
        table.setItems(searchResults);
        table.setPlaceholder(new Label("Search for market items"));
        VBox.setVgrow(table, Priority.ALWAYS);

        // Price history chart
        var xAxis = new CategoryAxis();
        xAxis.setLabel("Date");
        var yAxis = new NumberAxis();
        yAxis.setLabel("Price (ISK)");
        priceChart = new LineChart<>(xAxis, yAxis);
        priceChart.setTitle("Price History");
        priceChart.setPrefHeight(200);
        priceChart.setCreateSymbols(false);

        searchButton.setOnAction(e -> {
            String query = searchField.getText();
            if (query == null || query.isBlank()) return;
            searchButton.setDisable(true);
            int regionId = regionNameToId(regionCombo.getValue());
            dataService.searchMarket(query, regionId)
                    .thenAccept(data -> Platform.runLater(() -> {
                        searchResults.setAll(data);
                        searchButton.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Market search failed", ex);
                            searchButton.setDisable(false);
                        });
                        return null;
                    });
        });

        // When a search result is selected, load price history
        table.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null) return;
            int regionId = regionNameToId(regionCombo.getValue());
            dataService.getMarketHistory(sel.typeId(), regionId)
                    .thenAccept(history -> Platform.runLater(() -> updatePriceChart(history)))
                    .exceptionally(ex -> {
                        log.error("Failed to load price history", ex);
                        return null;
                    });
        });

        vbox.getChildren().addAll(searchBox, table, priceChart);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private void updatePriceChart(java.util.List<MarketStatistics> history) {
        priceChart.getData().clear();
        if (history.isEmpty()) return;

        var avgSeries = new XYChart.Series<String, Number>();
        avgSeries.setName("Average");
        var lowSeries = new XYChart.Series<String, Number>();
        lowSeries.setName("Low");
        var highSeries = new XYChart.Series<String, Number>();
        highSeries.setName("High");

        int count = Math.min(history.size(), 60);
        for (int i = count - 1; i >= 0; i--) {
            var stat = history.get(i);
            String dateStr = stat.date() != null ? stat.date().toString() : "?";
            double avg = (stat.open() + stat.close()) / 2.0;
            avgSeries.getData().add(new XYChart.Data<>(dateStr, avg));
            lowSeries.getData().add(new XYChart.Data<>(dateStr, stat.low()));
            highSeries.getData().add(new XYChart.Data<>(dateStr, stat.high()));
        }
        priceChart.getData().addAll(avgSeries, lowSeries, highSeries);
    }

    @SuppressWarnings("unchecked")
    private Tab createAppraisalTab() {
        var tab = new Tab("Appraisal");

        boolean multiHub = featureGate.isFeatureAvailable(FeatureSet.MULTI_HUB_APPRAISAL,
                SubscriptionTier.PROFESSIONAL);

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var pasteArea = new TextArea();
        pasteArea.setPromptText("Paste items here (one per line, or EVE format)...");
        pasteArea.setPrefRowCount(8);

        var hubCombo = new ComboBox<String>();
        if (multiHub) {
            hubCombo.getItems().addAll(
                    "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                    "Amarr VIII (Oris) - Emperor Family Academy",
                    "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                    "Rens VI - Moon 8 - Brutor Tribe Treasury",
                    "Hek VIII - Moon 12 - Boundless Creation Factory"
            );
        } else {
            hubCombo.getItems().add("Jita IV - Moon 4 - Caldari Navy Assembly Plant");
            hubCombo.setDisable(true);
        }
        hubCombo.setValue("Jita IV - Moon 4 - Caldari Navy Assembly Plant");

        var appraise = new Button("Appraise");

        if (!multiHub) {
            var lockedNote = new Label("Multi-hub appraisal requires Professional subscription");
            lockedNote.setStyle("-fx-text-fill: #888888; -fx-font-style: italic;");
            vbox.getChildren().add(lockedNote);
        }

        if (multiHub) {
            // Full multi-hub appraisal table
            var resultTable = new TableView<HubPrices>();
            var itemCol = new TableColumn<HubPrices, String>("Item");
            itemCol.setPrefWidth(200);
            itemCol.setCellValueFactory(c -> {
                var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
                dataService.resolveTypeName(c.getValue().typeId())
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            });
            var jitaCol = new TableColumn<HubPrices, Number>("Jita");
            jitaCol.setPrefWidth(110);
            jitaCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().jitaSell()));
            var amarrCol = new TableColumn<HubPrices, Number>("Amarr");
            amarrCol.setPrefWidth(110);
            amarrCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().amarrSell()));
            var dodixieCol = new TableColumn<HubPrices, Number>("Dodixie");
            dodixieCol.setPrefWidth(110);
            dodixieCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dodixieSell()));
            var bestCol = new TableColumn<HubPrices, String>("Best Hub");
            bestCol.setPrefWidth(120);
            bestCol.setCellValueFactory(c -> {
                var hp = c.getValue();
                double max = Math.max(hp.jitaSell(), Math.max(hp.amarrSell(), hp.dodixieSell()));
                String best = max == hp.jitaSell() ? "Jita" :
                        max == hp.amarrSell() ? "Amarr" : "Dodixie";
                return new SimpleStringProperty(best);
            });
            resultTable.getColumns().addAll(itemCol, jitaCol, amarrCol, dodixieCol, bestCol);
            resultTable.setItems(appraisalResults);
            resultTable.setPlaceholder(new Label("Paste items to appraise across hubs"));
            VBox.setVgrow(resultTable, Priority.ALWAYS);

            appraise.setOnAction(e -> {
                // Parse pasted text to type IDs (simplified)
                appraise.setDisable(true);
                appraisalResults.clear();
                // In real impl, parse item names/IDs from paste area
                appraise.setDisable(false);
            });

            vbox.getChildren().addAll(pasteArea, new HBox(10, hubCombo, appraise), resultTable);
        } else {
            // Simple single-hub appraisal
            var resultTable = new TableView<MarketPrice>();
            var itemCol = new TableColumn<MarketPrice, String>("Item");
            itemCol.setPrefWidth(250);
            itemCol.setCellValueFactory(c -> {
                var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
                dataService.resolveTypeName(c.getValue().typeId())
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            });
            var buyCol = new TableColumn<MarketPrice, Number>("Buy");
            buyCol.setPrefWidth(120);
            buyCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().buyPrice()));
            var sellCol = new TableColumn<MarketPrice, Number>("Sell");
            sellCol.setPrefWidth(120);
            sellCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().sellPrice()));
            resultTable.getColumns().addAll(itemCol, buyCol, sellCol);
            resultTable.setPlaceholder(new Label("Paste items to appraise"));
            VBox.setVgrow(resultTable, Priority.ALWAYS);

            vbox.getChildren().addAll(pasteArea, new HBox(10, hubCombo, appraise), resultTable);
        }

        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createBrowserTab() {
        var tab = new Tab("Browser");

        var splitPane = new SplitPane();

        // Left: market group tree
        var treeView = new TreeView<String>();
        treeView.setRoot(new TreeItem<>("Market"));
        treeView.getRoot().setExpanded(true);

        String[] groups = {"Ships", "Ammunition & Charges", "Drones", "Ship Equipment",
                "Blueprints & Reactions", "Manufacture & Research", "Planetary Commodities",
                "Ship Modifications", "Implants & Boosters", "Skills", "Trade Goods"};
        for (var group : groups) {
            treeView.getRoot().getChildren().add(new TreeItem<>(group));
        }

        // Right: orders for selected type
        var rightPane = new VBox(5);

        var sellLabel = new Label("Sell Orders");
        sellLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");

        var sellTable = new TableView<MarketOrder>();
        var sPriceCol = new TableColumn<MarketOrder, Number>("Price");
        sPriceCol.setPrefWidth(120);
        sPriceCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().price()));
        var sVolCol = new TableColumn<MarketOrder, Number>("Volume");
        sVolCol.setPrefWidth(80);
        sVolCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().volumeRemain()));
        var sLocCol = new TableColumn<MarketOrder, String>("Location");
        sLocCol.setPrefWidth(200);
        sLocCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Location #" + c.getValue().locationId());
            dataService.resolveLocationName(c.getValue().locationId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var sExpCol = new TableColumn<MarketOrder, String>("Issued");
        sExpCol.setPrefWidth(100);
        sExpCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().issued() != null ? c.getValue().issued().toLocalDate().toString() : "--"));
        sellTable.getColumns().addAll(sPriceCol, sVolCol, sLocCol, sExpCol);
        sellTable.setItems(sellOrders);

        var buyLabel = new Label("Buy Orders");
        buyLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");

        var buyTable = new TableView<MarketOrder>();
        var bPriceCol = new TableColumn<MarketOrder, Number>("Price");
        bPriceCol.setPrefWidth(120);
        bPriceCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().price()));
        var bVolCol = new TableColumn<MarketOrder, Number>("Volume");
        bVolCol.setPrefWidth(80);
        bVolCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().volumeRemain()));
        var bLocCol = new TableColumn<MarketOrder, String>("Location");
        bLocCol.setPrefWidth(200);
        bLocCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Location #" + c.getValue().locationId());
            dataService.resolveLocationName(c.getValue().locationId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var bRangeCol = new TableColumn<MarketOrder, String>("Duration");
        bRangeCol.setPrefWidth(80);
        bRangeCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().duration() + "d"));
        buyTable.getColumns().addAll(bPriceCol, bVolCol, bLocCol, bRangeCol);
        buyTable.setItems(buyOrders);

        VBox.setVgrow(sellTable, Priority.ALWAYS);
        VBox.setVgrow(buyTable, Priority.ALWAYS);
        rightPane.getChildren().addAll(sellLabel, sellTable, buyLabel, buyTable);

        splitPane.getItems().addAll(treeView, rightPane);
        splitPane.setDividerPositions(0.25);

        tab.setContent(splitPane);
        return tab;
    }

    private static int regionNameToId(String name) {
        return switch (name) {
            case "The Forge" -> 10000002;
            case "Domain" -> 10000043;
            case "Sinq Laison" -> 10000032;
            case "Metropolis" -> 10000042;
            case "Heimatar" -> 10000030;
            default -> 10000002;
        };
    }

    @Override
    public String getTitle() { return "Market"; }

    @Override
    public void onActivated() { log.debug("Market workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Market: character changed to {}", characterId);
        // Market workspace is largely search-driven, not character-specific
        // Clear results on character change for clean state
        if (characterId <= 0) {
            searchResults.clear();
            sellOrders.clear();
            buyOrders.clear();
            priceChart.getData().clear();
        }
    }
}

