1	package com.sampleapp.ui.workspace;
2	
3	import com.sampleapp.core.app.AppState;
4	import javafx.application.Platform;
5	import javafx.beans.property.SimpleStringProperty;
6	import javafx.collections.FXCollections;
7	import javafx.collections.ObservableList;
8	import javafx.geometry.Insets;
9	import javafx.scene.control.*;
10	import javafx.scene.layout.*;
11	
12	import java.util.List;
13	import java.util.Map;
14	import java.util.stream.Collectors;
15	
16	/**
17	 * Fleet workspace for viewing fleet composition and members.
18	 */
19	public class FleetWorkspace extends Workspace {
20	
21	    private final WorkspaceDataService dataService;
22	
23	    private final ObservableList<WorkspaceDataService.FleetMemberInfo> fleetMembers =
24	            FXCollections.observableArrayList();
25	    private TreeView<String> fleetTree;
26	    private Label fcLabel;
27	    private Label membersLabel;
28	    private Label wingsLabel;
29	    private Label squadsLabel;
30	
31	    public FleetWorkspace(AppState appState, WorkspaceDataService dataService) {
32	        super(appState);
33	        this.dataService = dataService;
34	
35	        tabPane.getTabs().add(createFleetTab());
36	    }
37	
38	    @SuppressWarnings("unchecked")
39	    private Tab createFleetTab() {
40	        var tab = new Tab("Fleet Composition");
41	
42	        var vbox = new VBox(10);
43	        vbox.setPadding(new Insets(10));
44	
45	        // Fleet info bar
46	        var infoBox = new HBox(20);
47	        infoBox.setPadding(new Insets(5));
48	        infoBox.setStyle("-fx-background-color: #252526; -fx-background-radius: 4;");
49	
50	        var fcPair = createInfoPair("Fleet Commander:", "--");
51	        fcLabel = (Label) fcPair.getChildren().get(1);
52	        var membersPair = createInfoPair("Members:", "--");
53	        membersLabel = (Label) membersPair.getChildren().get(1);
54	        var wingsPair = createInfoPair("Wings:", "--");
55	        wingsLabel = (Label) wingsPair.getChildren().get(1);
56	        var squadsPair = createInfoPair("Squads:", "--");
57	        squadsLabel = (Label) squadsPair.getChildren().get(1);
58	
59	        infoBox.getChildren().addAll(fcPair, membersPair, wingsPair, squadsPair);
60	
61	        // Fleet tree (hierarchical)
62	        var splitPane = new SplitPane();
63	
64	        fleetTree = new TreeView<>();
65	        fleetTree.setRoot(new TreeItem<>("Fleet"));
66	        fleetTree.getRoot().setExpanded(true);
67	
68	        // Member details table
69	        var table = new TableView<WorkspaceDataService.FleetMemberInfo>();
70	        var nameCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Character");
71	        nameCol.setPrefWidth(150);
72	        nameCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().characterName()));
73	        var shipCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Ship");
74	        shipCol.setPrefWidth(150);
75	        shipCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().shipName()));
76	        var typeCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Ship Type");
77	        typeCol.setPrefWidth(120);
