80	        systemCol.setPrefWidth(120);
81	        systemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().solarSystemName()));
82	        var roleCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Role");
83	        roleCol.setPrefWidth(100);
84	        roleCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().role()));
85	        var squadCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Squad");
86	        squadCol.setPrefWidth(100);
87	        squadCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().squadName()));
88	
89	        table.getColumns().addAll(nameCol, shipCol, typeCol, systemCol, roleCol, squadCol);
90	        table.setItems(fleetMembers);
91	        table.setPlaceholder(new Label("Not in a fleet"));
92	
93	        splitPane.getItems().addAll(fleetTree, table);
94	        splitPane.setDividerPositions(0.3);
95	        VBox.setVgrow(splitPane, Priority.ALWAYS);
96	
97	        var refreshBtn = new Button("Refresh Fleet");
98	        refreshBtn.setOnAction(e -> {
99	            int charId = appState.getSelectedCharacterId();
100	            if (charId > 0) {
101	                refreshFleetData(charId, refreshBtn);
102	            }
103	        });
104	
105	        vbox.getChildren().addAll(infoBox, splitPane, refreshBtn);
106	        tab.setContent(vbox);
107	        return tab;
108	    }
109	
110	    private void refreshFleetData(int characterId, Button refreshBtn) {
111	        refreshBtn.setDisable(true);
112	        dataService.getFleetMembers(characterId)
113	                .thenAccept(members -> Platform.runLater(() -> {
114	                    fleetMembers.setAll(members);
115	                    updateFleetTree(members);
116	                    updateFleetInfo(members);
117	                    refreshBtn.setDisable(false);
118	                }))
119	                .exceptionally(ex -> {
120	                    Platform.runLater(() -> {
121	                        log.error("Failed to load fleet data", ex);
122	                        refreshBtn.setDisable(false);
123	                    });
124	                    return null;
125	                });
126	    }
127	
128	    private void updateFleetTree(List<WorkspaceDataService.FleetMemberInfo> members) {
129	        var root = new TreeItem<>("Fleet (" + members.size() + " members)");
130	        root.setExpanded(true);
131	
132	        // Group by wing, then by squad
133	        Map<String, List<WorkspaceDataService.FleetMemberInfo>> byWing = members.stream()
134	                .collect(Collectors.groupingBy(m ->
135	                        m.wingName() != null ? m.wingName() : "Wing 1"));
136	
137	        for (var wingEntry : byWing.entrySet()) {
138	            var wingItem = new TreeItem<>(wingEntry.getKey());
139	            wingItem.setExpanded(true);
140	
141	            Map<String, List<WorkspaceDataService.FleetMemberInfo>> bySquad = wingEntry.getValue().stream()
142	                    .collect(Collectors.groupingBy(m ->
143	                            m.squadName() != null ? m.squadName() : "Squad 1"));
144	
145	            for (var squadEntry : bySquad.entrySet()) {
146	                var squadItem = new TreeItem<>(squadEntry.getKey());
147	                squadItem.setExpanded(true);
148	                for (var member : squadEntry.getValue()) {
149	                    squadItem.getChildren().add(new TreeItem<>(
150	                            member.characterName() + " (" + member.shipTypeName() + ")"));
151	                }
152	                wingItem.getChildren().add(squadItem);
153	            }
154	            root.getChildren().add(wingItem);
155	        }
156	
157	        fleetTree.setRoot(root);
