import java.time.format.DateTimeFormatter;

/**
 * Public Contracts workspace with a single tab for browsing public contracts.
 */
public class PublicContractsWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final WorkspaceDataService dataService;

    private final ObservableList<ContractModel> contractsList = FXCollections.observableArrayList();

    public PublicContractsWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().add(createPublicContractsTab());
    }

    @SuppressWarnings("unchecked")
    private Tab createPublicContractsTab() {
        var tab = new Tab("Public Contracts");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Search/filter controls
        var filterBox = new HBox(10);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("All Regions", "The Forge", "Domain",
                "Sinq Laison", "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        var typeFilter = new ComboBox<String>();
        typeFilter.getItems().addAll("All", "Item Exchange", "Auction", "Courier");
        typeFilter.setValue("All");
