package com.sampleapp.app.service;
import com.sampleapp.core.service.EventBus;
import com.sampleapp.core.service.TaxService;

import com.sampleapp.core.model.EgressModel;
import com.sampleapp.core.model.IngressModel;
import com.sampleapp.core.model.ProfitModel;
import com.sampleapp.data.repository.MarketTransactionRepository;
import com.google.inject.Inject;
import com.google.inject.Singleton;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;
import java.util.Queue;

/**
 * FIFO cost-basis profit tracking.
 * <p>
 * Mirrors the decompiled C# {@code ProfitTrackerLogic}:
 * <ol>
 *   <li>Query sell transactions (egress) for the period</li>
 *   <li>Query buy transactions (ingress) for matching type IDs</li>
 *   <li>FIFO-match: earliest acquisitions consumed by earliest sales</li>
 *   <li>Apply taxes/fees via {@link TaxService}</li>
 *   <li>Profit = Revenue - Cost - Taxes</li>
 *   <li>Flag {@code missingIngress} for sells without recorded buys</li>
 * </ol>
 */
@Singleton
public class ProfitTrackerLogic {

    private final MarketTransactionRepository transactionRepo;

    @Inject
    public ProfitTrackerLogic(MarketTransactionRepository transactionRepo) {
        this.transactionRepo = transactionRepo;
    }

    // ----------------------------------------------------------------
    // Inner records
    // ----------------------------------------------------------------

    public record FifoMatch(
            EgressModel sell,
            List<ConsumingModel> consumedBuys,
            boolean missingIngress
    ) {}

    public record ConsumingModel(
            IngressModel source,
            int quantityConsumed
    ) {}

    // ----------------------------------------------------------------
    // Public API
    // ----------------------------------------------------------------

    /**
     * Calculate profits for a character over a date range using FIFO matching.
     */
    public List<ProfitModel> calculateProfits(int characterId,
                                              LocalDateTime from, LocalDateTime to,
                                              int accountingLevel, int brokerRelationsLevel,
                                              double factionStanding, double corpStanding) {

        // Retrieve all transactions for the period
        var allTransactions = transactionRepo.findByCharacterAndDateRange(characterId, from, to);

        // Split into sells (egress) and buys (ingress)
        List<EgressModel> sells = new ArrayList<>();
        List<IngressModel> buys = new ArrayList<>();

        for (var txn : allTransactions) {
            if (!txn.isBuy()) {
                sells.add(new EgressModel(
                        txn.transactionId(), txn.date(), txn.typeId(),
                        txn.quantity(), txn.unitPrice(), txn.locationId()
                ));
            } else {
                buys.add(new IngressModel(
                        txn.transactionId(), txn.date(), txn.typeId(),
                        txn.quantity(), txn.unitPrice(), txn.locationId(),
                        txn.quantity()
                ));
            }
        }

        // FIFO match
        List<FifoMatch> matches = matchFifo(buys, sells);

        // Convert matches to profit models with tax calculations
        List<ProfitModel> results = new ArrayList<>(matches.size());
        for (FifoMatch match : matches) {
            EgressModel sell = match.sell();
            double grossRevenue = sell.unitPrice() * sell.quantity();

            double salesTax = TaxService.calculateSalesTax(grossRevenue, accountingLevel);
            double sellBrokerFee = TaxService.calculateBrokerFee(grossRevenue, brokerRelationsLevel,
                    factionStanding, corpStanding);

            double totalCost = 0.0;
            double buyBrokerFees = 0.0;
            for (ConsumingModel consumed : match.consumedBuys()) {
                double buyCost = consumed.source().unitPrice() * consumed.quantityConsumed();
                totalCost += buyCost;
                buyBrokerFees += TaxService.calculateBrokerFee(buyCost, brokerRelationsLevel,
                        factionStanding, corpStanding);
            }

            double totalTaxes = salesTax + sellBrokerFee + buyBrokerFees;
            double netRevenue = grossRevenue - salesTax - sellBrokerFee;
            double profit = netRevenue - totalCost - buyBrokerFees;

            results.add(new ProfitModel(
                    grossRevenue,
                    totalCost,
                    totalTaxes,
                    profit,
                    sell.typeId(),
                    "Type-" + sell.typeId()  // typeName lookup would need ItemTypeCache
            ));
        }

        return results;
    }

    // ----------------------------------------------------------------
    // FIFO matching
    // ----------------------------------------------------------------

    private List<FifoMatch> matchFifo(List<IngressModel> buys, List<EgressModel> sells) {
        Map<Integer, Queue<MutableIngress>> buyQueues = new HashMap<>();
        buys.stream()
                .sorted(Comparator.comparing(IngressModel::date))
                .forEach(buy -> buyQueues
                        .computeIfAbsent(buy.typeId(), k -> new LinkedList<>())
                        .add(new MutableIngress(buy, buy.quantity())));

        List<EgressModel> sortedSells = sells.stream()
                .sorted(Comparator.comparing(EgressModel::date))
                .toList();

        List<FifoMatch> matches = new ArrayList<>(sortedSells.size());

        for (EgressModel sell : sortedSells) {
            Queue<MutableIngress> queue = buyQueues.get(sell.typeId());
            List<ConsumingModel> consumed = new ArrayList<>();
            int remaining = sell.quantity();
            boolean missingIngress = false;

            while (remaining > 0 && queue != null && !queue.isEmpty()) {
                MutableIngress head = queue.peek();
                int take = Math.min(remaining, head.remainingQty);

                consumed.add(new ConsumingModel(head.source, take));
                head.remainingQty -= take;
                remaining -= take;

                if (head.remainingQty <= 0) {
                    queue.poll();
                }
            }

            if (remaining > 0) {
                missingIngress = true;
            }

            matches.add(new FifoMatch(sell, consumed, missingIngress));
        }

        return matches;
    }

    private static class MutableIngress {
        final IngressModel source;
        int remainingQty;

        MutableIngress(IngressModel source, int remainingQty) {
            this.source = source;
            this.remainingQty = remainingQty;
        }
    }
}

package com.sampleapp.core.service;

/**
 * Static trading tax and fee calculations based on EVE Online formulas.
 * <p>
 * All formulas are derived from the decompiled C# TaxService.
 * Base rates reflect EVE Online defaults as of the Equinox expansion.
 */
public final class TaxService {

    // Base rates (EVE Online defaults)
    private static final double BASE_SALES_TAX = 0.08;   // 8%
    private static final double BASE_BROKER_FEE = 0.03;  // 3%

    private TaxService() {
        // Utility class — no instantiation
    }

    // ----------------------------------------------------------------
    // Factor calculations (multiply by price to get net amount)
    // ----------------------------------------------------------------

    /**
     * Factor for selling via a Sell Order (includes sales tax + broker fee).
     * <pre>
     * factor = 1.0 - (BaseSalesTax * (1 - 0.11 * AccountingLevel)
     *               + BaseBrokerFee
     *               - 0.003 * BrokerRelationsLevel
     *               - 0.0003 * FactionStanding
     *               - 0.0002 * CorpStanding)
     * </pre>
     *
     * @param accountingLevel      Accounting skill level (0–5)
     * @param brokerRelationsLevel Broker Relations skill level (0–5)
     * @param factionStanding      faction standing with the station owner (-10 to +10)
     * @param corpStanding         corporation standing with the station owner (-10 to +10)
     * @return multiplier to apply to the sell price for net revenue
     */
    public static double sellOrderFactor(int accountingLevel, int brokerRelationsLevel,
                                         double factionStanding, double corpStanding) {
        double salesTax = BASE_SALES_TAX * (1.0 - 0.11 * accountingLevel);
        double brokerFee = BASE_BROKER_FEE
                - 0.003 * brokerRelationsLevel
                - 0.0003 * factionStanding
                - 0.0002 * corpStanding;
        return 1.0 - (salesTax + brokerFee);
    }

    /**
     * Factor for selling directly to an existing Buy Order (sales tax only, no broker fee).
     * <pre>
     * factor = 1.0 - BaseSalesTax * (1 - 0.11 * AccountingLevel)
     * </pre>
     *
     * @param accountingLevel Accounting skill level (0–5)
     * @return multiplier to apply to the sale price for net revenue
     */
    public static double sellToBuyFactor(int accountingLevel) {
        double salesTax = BASE_SALES_TAX * (1.0 - 0.11 * accountingLevel);
        return 1.0 - salesTax;
    }

    /**
     * Factor for placing a Buy Order (broker fee only, no sales tax).
     * <pre>
     * factor = 1.0 + (BaseBrokerFee
     *               - 0.003 * BrokerRelationsLevel
     *               - 0.0003 * FactionStanding
     *               - 0.0002 * CorpStanding)
     * </pre>
     *
     * @param brokerRelationsLevel Broker Relations skill level (0–5)
     * @param factionStanding      faction standing with the station owner
     * @param corpStanding         corporation standing with the station owner
     * @return multiplier to apply to the buy price for total cost
     */
    public static double buyOrderFactor(int brokerRelationsLevel,
                                        double factionStanding, double corpStanding) {
        double brokerFee = BASE_BROKER_FEE
                - 0.003 * brokerRelationsLevel
                - 0.0003 * factionStanding
                - 0.0002 * corpStanding;
        return 1.0 + brokerFee;
    }

    /**
     * Factor for the relist (order modification) discount.
     * <pre>
     * factor = 1.0 - (0.5 + 0.06 * AdvancedBrokerRelationsLevel)
     * </pre>
     * The result represents the fraction of the original broker fee that is charged
     * when modifying an existing order.
     *
     * @param advancedBrokerRelationsLevel Advanced Broker Relations skill level (0–5)
     * @return discount multiplier for relisting
     */
    public static double relistDiscount(int advancedBrokerRelationsLevel) {
        return 1.0 - (0.5 + 0.06 * advancedBrokerRelationsLevel);
    }

    // ----------------------------------------------------------------
    // Convenience: absolute ISK amounts
    // ----------------------------------------------------------------

    /**
     * Calculate the sales tax amount in ISK.
     *
     * @param price           order price in ISK
     * @param accountingLevel Accounting skill level (0–5)
     * @return sales tax amount (always >= 0)
     */
    public static double calculateSalesTax(double price, int accountingLevel) {
        double rate = BASE_SALES_TAX * (1.0 - 0.11 * accountingLevel);
        return Math.max(0.0, price * rate);
    }

    /**
     * Calculate the broker fee amount in ISK.
     *
     * @param price                order price in ISK
     * @param brokerRelationsLevel Broker Relations skill level (0–5)
     * @param factionStanding      faction standing
     * @param corpStanding         corporation standing
     * @return broker fee amount (always >= 0)
     */
    public static double calculateBrokerFee(double price, int brokerRelationsLevel,
                                            double factionStanding, double corpStanding) {
        double rate = BASE_BROKER_FEE
                - 0.003 * brokerRelationsLevel
                - 0.0003 * factionStanding
                - 0.0002 * corpStanding;
        return Math.max(0.0, price * rate);
    }

    /**
     * Calculate net revenue after all taxes and fees for a Sell Order.
     *
     * @param price                sell price in ISK
     * @param accountingLevel      Accounting skill level (0–5)
     * @param brokerRelationsLevel Broker Relations skill level (0–5)
     * @param factionStanding      faction standing
     * @param corpStanding         corporation standing
     * @return net ISK received after deductions
     */
    public static double calculateNetRevenue(double price, int accountingLevel,
                                             int brokerRelationsLevel,
                                             double factionStanding, double corpStanding) {
        return price * sellOrderFactor(accountingLevel, brokerRelationsLevel,
                factionStanding, corpStanding);
    }

    /**
     * Calculate total cost of placing a Buy Order (price + broker fee).
     *
     * @param price                buy price in ISK
     * @param brokerRelationsLevel Broker Relations skill level (0–5)
     * @param factionStanding      faction standing
     * @param corpStanding         corporation standing
     * @return total ISK spent including broker fee
     */
    public static double calculateTotalBuyCost(double price, int brokerRelationsLevel,
                                               double factionStanding, double corpStanding) {
        return price * buyOrderFactor(brokerRelationsLevel, factionStanding, corpStanding);
    }
}

