@Override
public CompletableFuture<List<SystemSecurity>> getSystemsInRegion(String regionName) {
    return CompletableFuture.supplyAsync(() -> {
        log.debug("getSystemsInRegion for region '{}'", regionName);
        try {
            // Map region name to ID
            int regionId = switch (regionName) {
                case "The Forge" -> 10000002;
                case "Domain" -> 10000043;
                case "Sinq Laison" -> 10000032;
                case "Metropolis" -> 10000042;
                case "Heimatar" -> 10000030;
                case "Essence" -> 10000064;
                case "The Citadel" -> 10000033;
                case "Lonetrek" -> 10000016;
                case "Black Rise" -> 10000069;
                case "Placid" -> 10000048;
                case "Devoid" -> 10000036;
                case "Tash-Murkon" -> 10000020;
                default -> 0;
            };
            if (regionId == 0) return List.<SystemSecurity>of();

            // Use ESI constellation endpoint approach:
            // GET /v1/universe/regions/{regionId}/ returns constellation IDs
            // Then GET /v1/universe/constellations/{constellationId}/ returns system IDs
            // Then GET /v4/universe/systems/{systemId}/ returns system details
            // This is too many calls. Instead, use the station prices we have as proxy:
            // Systems we have stations in are the ones players care about

            // For now, use a hardcoded list of the most important systems per region
            // This matches what the C# version does when SDE data isn't available
            return getWellKnownSystemsForRegion(regionId);
        } catch (Exception e) {
            log.error("Failed to get systems for region '{}'", regionName, e);
            return List.of();
        }
    });
}

private List<SystemSecurity> getWellKnownSystemsForRegion(int regionId) {
    // Well-known trade hub systems per region
    return switch (regionId) {
        case 10000002 -> List.of( // The Forge
                new SystemSecurity(30000142, 0.9), // Jita
                new SystemSecurity(30000144, 0.9), // Perimeter
                new SystemSecurity(30000139, 0.8), // Maurasi
                new SystemSecurity(30000143, 1.0), // Niyabainen
                new SystemSecurity(30000148, 0.7)  // Sobaseki
        );
        case 10000043 -> List.of( // Domain
                new SystemSecurity(30002187, 1.0), // Amarr
                new SystemSecurity(30002053, 0.7), // Sarum Prime
                new SystemSecurity(30002068, 0.8)  // Halaima
        );
        case 10000032 -> List.of( // Sinq Laison
                new SystemSecurity(30002659, 0.9), // Dodixie
                new SystemSecurity(30002661, 0.8)  // Botane
        );
        case 10000042 -> List.of( // Metropolis
                new SystemSecurity(30002510, 0.9)  // Hek
        );
        case 10000030 -> List.of( // Heimatar
                new SystemSecurity(30002510, 0.9), // Rens
                new SystemSecurity(30002526, 1.0)  // Frarn
        );
        default -> List.of();
    };
}
```

