    // ================================================================
    // Trader
    // ================================================================

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
            try {
                // Derive regionId from the station prices table; use the station as a location filter
                List<StationPriceRepository.StationPriceRow> stationPrices = stationPriceRepo.findByLocation(stationId);
                List<TradeOpportunity> opportunities = new ArrayList<>();

                for (var price : stationPrices) {
                    if (price.sellPrice() <= 0 || price.buyPrice() <= 0) {
                        continue;
                    }
                    double margin = (price.sellPrice() - price.buyPrice()) / price.sellPrice();
                    double profit = price.sellPrice() - price.buyPrice();
                    if (profit >= minProfit) {
                        String typeName = typeCacheRepo.findNameById(price.typeId()).orElse("Unknown");
                        opportunities.add(new TradeOpportunity(
                                price.typeId(),
                                typeName,
                                price.buyPrice(),
                                price.sellPrice(),
                                margin,
                                0L,
                                0.0
                        ));
                    }
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan station trades for station {}", stationId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
                                                                        double minMargin, double maxCargo, double budget) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
            try {
                // Get prices from both regions (using region IDs as location IDs for station-level data)
                List<StationPriceRepository.StationPriceRow> fromPrices = stationPriceRepo.findByLocation(fromRegionId);
                List<StationPriceRepository.StationPriceRow> toPrices = stationPriceRepo.findByLocation(toRegionId);

                // Index destination prices by typeId for fast lookup
                var toPriceMap = toPrices.stream()
                        .collect(Collectors.toMap(
                                StationPriceRepository.StationPriceRow::typeId,
                                p -> p,
                                (a, b) -> a
                        ));

                List<TradeOpportunity> opportunities = new ArrayList<>();
                for (var fromPrice : fromPrices) {
                    var toPrice = toPriceMap.get(fromPrice.typeId());
                    if (toPrice == null) continue;

                    // Buy at source sell price, sell at destination buy price
                    double buyCost = fromPrice.sellPrice();
                    double sellRevenue = toPrice.buyPrice();

                    if (buyCost <= 0 || sellRevenue <= 0) continue;

                    double margin = (sellRevenue - buyCost) / sellRevenue;
                    if (margin < minMargin) continue;

                    // Check cargo volume constraint
                    var typeInfo = typeCacheRepo.findById(fromPrice.typeId());
                    if (typeInfo.isPresent() && maxCargo > 0) {
                        double vol = typeInfo.get().packagedVolume() > 0
                                ? typeInfo.get().packagedVolume()
                                : typeInfo.get().volume();
                        if (vol > maxCargo) continue;
                    }

                    // Check budget constraint
                    if (budget > 0 && buyCost > budget) continue;

                    String typeName = typeInfo.map(TypeCacheRepository.TypeCacheRow::name).orElse("Unknown");
                    opportunities.add(new TradeOpportunity(
                            fromPrice.typeId(),
                            typeName,
                            buyCost,
                            sellRevenue,
                            margin,
                            0L,
                            0.0
                    ));
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
                return List.of();
            }
        });
    }

