package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.core.model.TradeOpportunity;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

/**
 * Trader workspace with feature-gated tabs:
 * - Station Trader (requires STATION_TRADER + Professional)
 * - Regional Day-Trader (requires REGIONAL_DAY_TRADER + Professional)
 * Shows "subscription required" message for locked features.
 */
public class TraderWorkspace extends Workspace {

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    private final ObservableList<TradeOpportunity> stationOpportunities = FXCollections.observableArrayList();
    private final ObservableList<TradeOpportunity> regionalOpportunities = FXCollections.observableArrayList();

    // Regional summary labels
    private Label totalInvestmentLabel;
    private Label totalProfitLabel;
    private Label roiLabel;
    private Label cargoUsedLabel;

    public TraderWorkspace(AppState appState, FeatureGate featureGate,
                           WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createStationTraderTab(),
                createRegionalDayTraderTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createStationTraderTab() {
        var tab = new Tab("Station Trader");

        if (!featureGate.isFeatureAvailable(FeatureSet.STATION_TRADER,
                SubscriptionTier.PROFESSIONAL)) {
            tab.setContent(new FeatureLockedPane(
                    "Station Trader", "Professional"));
            return tab;
        }

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Hub selection
        var hubBox = new HBox(10);
        var hubCombo = new ComboBox<String>();
        hubCombo.getItems().addAll(
                "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                "Amarr VIII (Oris) - Emperor Family Academy",
                "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                "Rens VI - Moon 8 - Brutor Tribe Treasury"
        );
        hubCombo.setValue("Jita IV - Moon 4 - Caldari Navy Assembly Plant");
        var scanBtn = new Button("Scan Market");
        var importBtn = new Button("Import Orders");
        hubBox.getChildren().addAll(new Label("Hub:"), hubCombo, scanBtn, importBtn);

        // Filter controls
        var filterBox = new HBox(10);
        var minProfitField = new TextField("1000000");
        minProfitField.setPrefWidth(120);
        var minVolumeField = new TextField("10");
        minVolumeField.setPrefWidth(80);
        var maxInvestField = new TextField("100000000");
        maxInvestField.setPrefWidth(120);
        filterBox.getChildren().addAll(
                new Label("Min Profit:"), minProfitField,
                new Label("Min Volume:"), minVolumeField,
                new Label("Max Investment:"), maxInvestField
        );

        // Opportunities table
        var table = new TableView<TradeOpportunity>();
        var itemCol = new TableColumn<TradeOpportunity, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));
        var buyCol = new TableColumn<TradeOpportunity, Number>("Buy Price");
        buyCol.setPrefWidth(110);
        buyCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().buyPrice()));
        var sellCol = new TableColumn<TradeOpportunity, Number>("Sell Price");
        sellCol.setPrefWidth(110);
        sellCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().sellPrice()));
        var profitCol = new TableColumn<TradeOpportunity, Number>("Profit/Unit");
        profitCol.setPrefWidth(100);
        profitCol.setCellValueFactory(c -> new SimpleDoubleProperty(
                c.getValue().sellPrice() - c.getValue().buyPrice()));
        var marginCol = new TableColumn<TradeOpportunity, String>("Margin %");
        marginCol.setPrefWidth(80);
        marginCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.1f%%", c.getValue().margin() * 100.0)));
        var dailyVolCol = new TableColumn<TradeOpportunity, Number>("Daily Vol");
        dailyVolCol.setPrefWidth(80);
        dailyVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));
        var dailyProfitCol = new TableColumn<TradeOpportunity, Number>("Daily Profit");
        dailyProfitCol.setPrefWidth(110);
        dailyProfitCol.setCellValueFactory(c -> new SimpleDoubleProperty(
                (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().dailyVolume()));
        var competCol = new TableColumn<TradeOpportunity, Number>("Orders");
        competCol.setPrefWidth(80);
        competCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));

        table.getColumns().addAll(itemCol, buyCol, sellCol, profitCol, marginCol,
                dailyVolCol, dailyProfitCol, competCol);
        table.setItems(stationOpportunities);
        table.setPlaceholder(new Label("Click Scan Market to find opportunities"));
        VBox.setVgrow(table, Priority.ALWAYS);

        scanBtn.setOnAction(e -> {
            scanBtn.setDisable(true);
            double minProfit;
            int minVolume;
            try {
                minProfit = Double.parseDouble(minProfitField.getText().replace(",", ""));
                minVolume = Integer.parseInt(minVolumeField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                scanBtn.setDisable(false);
                return;
            }
            // Use station ID 60003760 for Jita as default
            long stationId = 60003760L;
            dataService.scanStationTrades(stationId, minProfit, minVolume)
                    .thenAccept(data -> Platform.runLater(() -> {
                        stationOpportunities.setAll(data);
                        scanBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to scan station trades", ex);
                            scanBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(hubBox, filterBox, table);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createRegionalDayTraderTab() {
        var tab = new Tab("Regional Day-Trader");

        if (!featureGate.isFeatureAvailable(FeatureSet.REGIONAL_DAY_TRADER,
                SubscriptionTier.PROFESSIONAL)) {
            tab.setContent(new FeatureLockedPane(
                    "Regional Day-Trader", "Professional"));
            return tab;
        }

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Route selection
        var routeBox = new HBox(10);
        var fromCombo = new ComboBox<String>();
        fromCombo.getItems().addAll("Jita", "Amarr", "Dodixie", "Rens", "Hek");
        fromCombo.setValue("Jita");
        var toCombo = new ComboBox<String>();
        toCombo.getItems().addAll("Jita", "Amarr", "Dodixie", "Rens", "Hek");
        toCombo.setValue("Amarr");
        var scanBtn = new Button("Find Opportunities");
        routeBox.getChildren().addAll(
                new Label("From:"), fromCombo,
                new Label("To:"), toCombo,
                scanBtn
        );

        // Settings
        var settingsBox = new HBox(10);
        var cargoField = new TextField("60000");
        cargoField.setPrefWidth(80);
        var budgetField = new TextField("500000000");
        budgetField.setPrefWidth(120);
        var minMarginField = new TextField("10");
        minMarginField.setPrefWidth(60);
        settingsBox.getChildren().addAll(
                new Label("Cargo (m3):"), cargoField,
                new Label("Budget:"), budgetField,
                new Label("Min Margin %:"), minMarginField
        );

        // Opportunities table
        var table = new TableView<TradeOpportunity>();
        var itemCol = new TableColumn<TradeOpportunity, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));
        var buyPriceCol = new TableColumn<TradeOpportunity, Number>("Buy (Source)");
        buyPriceCol.setPrefWidth(110);
        buyPriceCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().buyPrice()));
        var sellPriceCol = new TableColumn<TradeOpportunity, Number>("Sell (Dest)");
        sellPriceCol.setPrefWidth(110);
        sellPriceCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().sellPrice()));
        var profitCol = new TableColumn<TradeOpportunity, Number>("Profit/Unit");
        profitCol.setPrefWidth(100);
        profitCol.setCellValueFactory(c -> new SimpleDoubleProperty(
                c.getValue().sellPrice() - c.getValue().buyPrice()));
        var volumeCol = new TableColumn<TradeOpportunity, Number>("Volume");
        volumeCol.setPrefWidth(80);
        volumeCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));
        var qtyCol = new TableColumn<TradeOpportunity, Number>("Daily Vol");
        qtyCol.setPrefWidth(60);
        qtyCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));
        var totalProfitCol = new TableColumn<TradeOpportunity, Number>("Total Profit");
        totalProfitCol.setPrefWidth(120);
        totalProfitCol.setCellValueFactory(c -> new SimpleDoubleProperty(
                (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().volume()));
        var marginCol = new TableColumn<TradeOpportunity, String>("Margin %");
        marginCol.setPrefWidth(80);
        marginCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.1f%%", c.getValue().margin() * 100.0)));

        table.getColumns().addAll(itemCol, buyPriceCol, sellPriceCol, profitCol,
                volumeCol, qtyCol, totalProfitCol, marginCol);
        table.setItems(regionalOpportunities);
        table.setPlaceholder(new Label("Select route and click Find Opportunities"));
        VBox.setVgrow(table, Priority.ALWAYS);

        // Trip summary
        var summaryBox = new HBox(20);
        summaryBox.setPadding(new Insets(5));
        summaryBox.setStyle("-fx-background-color: #252526;");
        totalInvestmentLabel = new Label("Total Investment: --");
        totalProfitLabel = new Label("Total Profit: --");
        roiLabel = new Label("ROI: --");
        cargoUsedLabel = new Label("Cargo Used: --");
        summaryBox.getChildren().addAll(totalInvestmentLabel, totalProfitLabel, roiLabel, cargoUsedLabel);

        scanBtn.setOnAction(e -> {
            scanBtn.setDisable(true);
            double minMargin;
            double maxCargo;
            double budget;
            try {
                minMargin = Double.parseDouble(minMarginField.getText()) / 100.0;
                maxCargo = Double.parseDouble(cargoField.getText().replace(",", ""));
                budget = Double.parseDouble(budgetField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                scanBtn.setDisable(false);
                return;
            }
            // Region IDs: The Forge=10000002, Domain=10000043
            int fromRegion = hubToRegionId(fromCombo.getValue());
            int toRegion = hubToRegionId(toCombo.getValue());
            dataService.scanRegionalTrades(fromRegion, toRegion, minMargin, maxCargo, budget)
                    .thenAccept(data -> Platform.runLater(() -> {
                        regionalOpportunities.setAll(data);
                        updateRegionalSummary(data);
                        scanBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to scan regional trades", ex);
                            scanBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(routeBox, settingsBox, table, summaryBox);
        tab.setContent(vbox);
        return tab;
    }

    private void updateRegionalSummary(java.util.List<TradeOpportunity> data) {
        double totalInvest = 0;
        double totalProfit = 0;
        for (var opp : data) {
            totalInvest += opp.buyPrice() * opp.volume();
            totalProfit += (opp.sellPrice() - opp.buyPrice()) * opp.volume();
        }
        totalInvestmentLabel.setText(String.format("Total Investment: %.0f ISK", totalInvest));
        totalProfitLabel.setText(String.format("Total Profit: %.0f ISK", totalProfit));
        roiLabel.setText(String.format("ROI: %.1f%%", totalInvest > 0 ? (totalProfit / totalInvest) * 100 : 0));
        cargoUsedLabel.setText("Cargo Used: --");
    }

    private static int hubToRegionId(String hub) {
        return switch (hub) {
            case "Jita" -> 10000002;
            case "Amarr" -> 10000043;
