package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.LoyaltyOffer;
import com.sampleapp.core.model.LoyaltyPoints;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.collections.transformation.FilteredList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * LP Store browser workspace for browsing loyalty point store offers.
 */
public class LpStoreWorkspace extends Workspace {

    private final WorkspaceDataService dataService;

    private final ObservableList<LoyaltyOffer> offersList = FXCollections.observableArrayList();
    private Label balanceLabel;
    private TextField searchField;
    private final Map<Integer, Integer> lpBalances = new HashMap<>();

    public LpStoreWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().add(createLpStoreTab());
    }

    @SuppressWarnings("unchecked")
    private Tab createLpStoreTab() {
        var tab = new Tab("LP Store");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Corporation selector
        var controlBox = new HBox(10);
        var corpCombo = new ComboBox<String>();
        corpCombo.getItems().addAll("Caldari Navy", "Federation Navy",
                "Imperial Navy", "Republic Fleet", "Sisters of EVE",
                "Thukker Tribe", "CreoDron", "Lai Dai Corporation",
                "Kaalakiota Corporation", "Ishukone Corporation");
        corpCombo.setPromptText("Select corporation...");

        searchField = new TextField();
        searchField.setPromptText("Filter items...");
        searchField.setPrefWidth(200);

        var sortCombo = new ComboBox<String>();
        sortCombo.getItems().addAll("ISK/LP (Best)", "LP Cost", "Item Name", "ISK Cost");
        sortCombo.setValue("ISK/LP (Best)");

        controlBox.getChildren().addAll(
                new Label("Corporation:"), corpCombo,
                searchField,
                new Label("Sort:"), sortCombo
        );

        // LP balance display
        var balanceBox = new HBox(10);
        balanceBox.setPadding(new Insets(5));
        balanceBox.setStyle("-fx-background-color: #252526; -fx-background-radius: 4;");
        balanceLabel = new Label("LP Balance: --");
        balanceLabel.setStyle("-fx-font-size: 14; -fx-font-weight: bold; -fx-text-fill: #4EC9B0;");
        balanceBox.getChildren().add(balanceLabel);

        // Offers table
        var filtered = new FilteredList<>(offersList, p -> true);
        searchField.textProperty().addListener((obs, old, val) -> {
            String filter = val != null ? val.toLowerCase() : "";
            filtered.setPredicate(offer -> filter.isEmpty()); // Basic filter; name resolution needed for full
        });

        var table = new TableView<LoyaltyOffer>();
        var itemCol = new TableColumn<LoyaltyOffer, String>("Item");
        itemCol.setPrefWidth(250);
        itemCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
            dataService.resolveTypeName(c.getValue().typeId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var lpCol = new TableColumn<LoyaltyOffer, Number>("LP Cost");
        lpCol.setPrefWidth(80);
        lpCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().lpCost()));
        var iskCol = new TableColumn<LoyaltyOffer, Number>("ISK Cost");
        iskCol.setPrefWidth(120);
        iskCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().iskCost()));
        var reqCol = new TableColumn<LoyaltyOffer, String>("Requirements");
        reqCol.setPrefWidth(200);
        reqCol.setCellValueFactory(c -> {
            var reqs = c.getValue().requiredItems();
            if (reqs == null || reqs.isEmpty()) return new SimpleStringProperty("None");
            StringBuilder sb = new StringBuilder();
            for (var req : reqs) {
                if (sb.length() > 0) sb.append(", ");
                sb.append(req.quantity()).append("x Type#").append(req.typeId());
            }
            return new SimpleStringProperty(sb.toString());
        });
        var sellCol = new TableColumn<LoyaltyOffer, String>("Sell Price");
        sellCol.setPrefWidth(120);
        sellCol.setCellValueFactory(c -> new SimpleStringProperty("--"));
        var profitCol = new TableColumn<LoyaltyOffer, String>("Profit");
        profitCol.setPrefWidth(120);
        profitCol.setCellValueFactory(c -> new SimpleStringProperty("--"));
        var iskPerLpCol = new TableColumn<LoyaltyOffer, String>("ISK/LP");
        iskPerLpCol.setPrefWidth(80);
        iskPerLpCol.setCellValueFactory(c -> new SimpleStringProperty("--"));

        table.getColumns().addAll(itemCol, lpCol, iskCol, reqCol, sellCol, profitCol, iskPerLpCol);
        table.setItems(filtered);
        table.setPlaceholder(new Label("Select a corporation"));
        VBox.setVgrow(table, Priority.ALWAYS);

        // Load offers when corporation is selected
        corpCombo.setOnAction(e -> {
            String corp = corpCombo.getValue();
            if (corp == null) return;
            int corpId = corpNameToId(corp);
            if (corpId <= 0) return;

            // Update LP balance display
            Integer balance = lpBalances.get(corpId);
            balanceLabel.setText("LP Balance: " + (balance != null ? balance + " LP" : "--"));

            // Load offers
            dataService.getLpStoreOffers(corpId)
                    .thenAccept(data -> Platform.runLater(() -> offersList.setAll(data)))
                    .exceptionally(ex -> {
                        log.error("Failed to load LP store offers", ex);
                        return null;
                    });
        });

        vbox.getChildren().addAll(controlBox, balanceBox, table);
        tab.setContent(vbox);
        return tab;
    }

    private static int corpNameToId(String name) {
        return switch (name) {
            case "Caldari Navy" -> 1000035;
            case "Federation Navy" -> 1000120;
            case "Imperial Navy" -> 1000080;
            case "Republic Fleet" -> 1000180;
            case "Sisters of EVE" -> 1000130;
            case "Thukker Tribe" -> 1000170;
            case "CreoDron" -> 1000060;
            case "Lai Dai Corporation" -> 1000047;
            case "Kaalakiota Corporation" -> 1000049;
            case "Ishukone Corporation" -> 1000041;
            default -> 0;
        };
    }

    @Override
    public String getTitle() { return "LP Store"; }

    @Override
    public void onActivated() {
        log.debug("LP Store workspace activated");
        int charId = appState.getSelectedCharacterId();
        if (charId > 0 && lpBalances.isEmpty()) {
            onCharacterChanged(charId);
        }
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("LP Store: character changed to {}", characterId);
        if (characterId <= 0) {
            offersList.clear();
            lpBalances.clear();
            balanceLabel.setText("LP Balance: --");
            return;
        }

        // Load LP balances for this character
        dataService.getLoyaltyPoints(characterId)
                .thenAccept(points -> Platform.runLater(() -> {
                    lpBalances.clear();
                    for (var lp : points) {
                        lpBalances.put(lp.corporationId(), lp.loyaltyPoints());
                    }
                }))
                .exceptionally(ex -> {
                    log.error("Failed to load loyalty points", ex);
                    return null;
                });
    }
}

