package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import javafx.application.Platform;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

/**
 * Fleet workspace for viewing fleet composition and members.
 */
public class FleetWorkspace extends Workspace {

    private final WorkspaceDataService dataService;

    private final ObservableList<WorkspaceDataService.FleetMemberInfo> fleetMembers =
            FXCollections.observableArrayList();
    private TreeView<String> fleetTree;
    private Label fcLabel;
    private Label membersLabel;
    private Label wingsLabel;
    private Label squadsLabel;

    public FleetWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().add(createFleetTab());
    }

    @SuppressWarnings("unchecked")
    private Tab createFleetTab() {
        var tab = new Tab("Fleet Composition");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Fleet info bar
        var infoBox = new HBox(20);
        infoBox.setPadding(new Insets(5));
        infoBox.setStyle("-fx-background-color: #252526; -fx-background-radius: 4;");

        var fcPair = createInfoPair("Fleet Commander:", "--");
        fcLabel = (Label) fcPair.getChildren().get(1);
        var membersPair = createInfoPair("Members:", "--");
        membersLabel = (Label) membersPair.getChildren().get(1);
        var wingsPair = createInfoPair("Wings:", "--");
        wingsLabel = (Label) wingsPair.getChildren().get(1);
        var squadsPair = createInfoPair("Squads:", "--");
        squadsLabel = (Label) squadsPair.getChildren().get(1);

        infoBox.getChildren().addAll(fcPair, membersPair, wingsPair, squadsPair);

        // Fleet tree (hierarchical)
        var splitPane = new SplitPane();

        fleetTree = new TreeView<>();
        fleetTree.setRoot(new TreeItem<>("Fleet"));
        fleetTree.getRoot().setExpanded(true);

        // Member details table
        var table = new TableView<WorkspaceDataService.FleetMemberInfo>();
        var nameCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Character");
        nameCol.setPrefWidth(150);
        nameCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().characterName()));
        var shipCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Ship");
        shipCol.setPrefWidth(150);
        shipCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().shipName()));
        var typeCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Ship Type");
        typeCol.setPrefWidth(120);
        typeCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().shipTypeName()));
        var systemCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("System");
        systemCol.setPrefWidth(120);
        systemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().solarSystemName()));
        var roleCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Role");
        roleCol.setPrefWidth(100);
        roleCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().role()));
        var squadCol = new TableColumn<WorkspaceDataService.FleetMemberInfo, String>("Squad");
        squadCol.setPrefWidth(100);
        squadCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().squadName()));

        table.getColumns().addAll(nameCol, shipCol, typeCol, systemCol, roleCol, squadCol);
        table.setItems(fleetMembers);
        table.setPlaceholder(new Label("Not in a fleet"));

        splitPane.getItems().addAll(fleetTree, table);
        splitPane.setDividerPositions(0.3);
        VBox.setVgrow(splitPane, Priority.ALWAYS);

        var refreshBtn = new Button("Refresh Fleet");
        refreshBtn.setOnAction(e -> {
            int charId = appState.getSelectedCharacterId();
            if (charId > 0) {
                refreshFleetData(charId, refreshBtn);
            }
        });

        vbox.getChildren().addAll(infoBox, splitPane, refreshBtn);
        tab.setContent(vbox);
        return tab;
    }

    private void refreshFleetData(int characterId, Button refreshBtn) {
        refreshBtn.setDisable(true);
        dataService.getFleetMembers(characterId)
                .thenAccept(members -> Platform.runLater(() -> {
                    fleetMembers.setAll(members);
                    updateFleetTree(members);
                    updateFleetInfo(members);
                    refreshBtn.setDisable(false);
                }))
                .exceptionally(ex -> {
                    Platform.runLater(() -> {
                        log.error("Failed to load fleet data", ex);
                        refreshBtn.setDisable(false);
                    });
                    return null;
                });
    }

    private void updateFleetTree(List<WorkspaceDataService.FleetMemberInfo> members) {
        var root = new TreeItem<>("Fleet (" + members.size() + " members)");
        root.setExpanded(true);

        // Group by wing, then by squad
        Map<String, List<WorkspaceDataService.FleetMemberInfo>> byWing = members.stream()
                .collect(Collectors.groupingBy(m ->
                        m.wingName() != null ? m.wingName() : "Wing 1"));

        for (var wingEntry : byWing.entrySet()) {
            var wingItem = new TreeItem<>(wingEntry.getKey());
            wingItem.setExpanded(true);

            Map<String, List<WorkspaceDataService.FleetMemberInfo>> bySquad = wingEntry.getValue().stream()
                    .collect(Collectors.groupingBy(m ->
                            m.squadName() != null ? m.squadName() : "Squad 1"));

            for (var squadEntry : bySquad.entrySet()) {
                var squadItem = new TreeItem<>(squadEntry.getKey());
                squadItem.setExpanded(true);
                for (var member : squadEntry.getValue()) {
                    squadItem.getChildren().add(new TreeItem<>(
                            member.characterName() + " (" + member.shipTypeName() + ")"));
                }
                wingItem.getChildren().add(squadItem);
            }
            root.getChildren().add(wingItem);
        }

        fleetTree.setRoot(root);
    }

    private void updateFleetInfo(List<WorkspaceDataService.FleetMemberInfo> members) {
        membersLabel.setText(String.valueOf(members.size()));

        // Find fleet commander
        String fc = members.stream()
                .filter(m -> "fleet_commander".equals(m.role()))
                .map(WorkspaceDataService.FleetMemberInfo::characterName)
                .findFirst()
                .orElse("--");
        fcLabel.setText(fc);

        long wings = members.stream()
                .map(m -> m.wingName() != null ? m.wingName() : "Wing 1")
                .distinct().count();
        wingsLabel.setText(String.valueOf(wings));

        long squads = members.stream()
                .map(m -> m.squadName() != null ? m.squadName() : "Squad 1")
                .distinct().count();
        squadsLabel.setText(String.valueOf(squads));
    }

    private HBox createInfoPair(String label, String value) {
        var box = new HBox(5);
        var lbl = new Label(label);
        lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
        var val = new Label(value);
        val.setStyle("-fx-text-fill: #CCCCCC;");
        box.getChildren().addAll(lbl, val);
        return box;
    }

    @Override
    public String getTitle() { return "Fleet"; }

    @Override
    public void onActivated() {
        log.debug("Fleet workspace activated");
        int charId = appState.getSelectedCharacterId();
        if (charId > 0 && fleetMembers.isEmpty()) {
            onCharacterChanged(charId);
        }
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Fleet: character changed to {}", characterId);
        if (characterId <= 0) {
            fleetMembers.clear();
            fleetTree.setRoot(new TreeItem<>("Fleet"));
            fcLabel.setText("--");
            membersLabel.setText("--");
            wingsLabel.setText("--");
            squadsLabel.setText("--");
            return;
        }

        dataService.getFleetMembers(characterId)
                .thenAccept(members -> Platform.runLater(() -> {
                    fleetMembers.setAll(members);
                    updateFleetTree(members);
                    updateFleetInfo(members);
                }))
                .exceptionally(ex -> {
                    log.error("Failed to load fleet data", ex);
                    return null;
                });
    }
}

