package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.SystemSecurity;
import javafx.application.Platform;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.util.List;

/**
 * Universe Browser workspace for browsing systems, constellations, regions, and stations.
 */
public class UniverseBrowserWorkspace extends Workspace {

    private final WorkspaceDataService dataService;

    private TreeView<String> treeView;
    private Label nameLabel;
    private Label[] detailValues;
    private final ObservableList<StationInfo> stationList = FXCollections.observableArrayList();

    public UniverseBrowserWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().add(createBrowserTab());
    }

    @SuppressWarnings("unchecked")
    private Tab createBrowserTab() {
        var tab = new Tab("Universe Browser");

        var splitPane = new SplitPane();

        // Left: universe tree
        treeView = new TreeView<>();
        var root = new TreeItem<>("New Eden");
        root.setExpanded(true);

        String[] regions = {"The Forge", "Domain", "Sinq Laison", "Metropolis",
                "Heimatar", "Essence", "The Citadel", "Lonetrek",
                "Black Rise", "Placid", "Devoid", "Tash-Murkon"};
        for (var region : regions) {
            var regionItem = new TreeItem<>(region);
            regionItem.getChildren().add(new TreeItem<>("Loading..."));
            root.getChildren().add(regionItem);
        }
        treeView.setRoot(root);

        // Lazy-load systems when a region node is expanded
        treeView.getRoot().getChildren().forEach(regionItem ->
                regionItem.expandedProperty().addListener((obs, wasExpanded, isNow) -> {
                    if (isNow && regionItem.getChildren().size() == 1
                            && "Loading...".equals(regionItem.getChildren().get(0).getValue())) {
                        loadSystemsForRegion(regionItem, regionItem.getValue());
                    }
                })
        );

        // Search bar above tree
        var searchField = new TextField();
        searchField.setPromptText("Search systems, stations...");
        var leftPane = new VBox(5);
        leftPane.getChildren().addAll(searchField, treeView);
        VBox.setVgrow(treeView, Priority.ALWAYS);

        // Right: details panel
        var rightPane = new VBox(10);
        rightPane.setPadding(new Insets(10));

        nameLabel = new Label("--");
        nameLabel.setStyle("-fx-font-size: 18; -fx-font-weight: bold; -fx-text-fill: #CCCCCC;");

        var detailGrid = new GridPane();
        detailGrid.setHgap(10);
        detailGrid.setVgap(8);

        String[] fields = {"Type:", "Region:", "Constellation:", "Security Status:",
                "Sovereignty:", "Stations:", "Stargates:"};
        detailValues = new Label[fields.length];
        for (int i = 0; i < fields.length; i++) {
            var lbl = new Label(fields[i]);
            lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
            detailGrid.add(lbl, 0, i);
            detailValues[i] = new Label("--");
            detailValues[i].setStyle("-fx-text-fill: #CCCCCC;");
            detailGrid.add(detailValues[i], 1, i);
        }

        // Stations list
        var stationsLabel = new Label("Stations");
        stationsLabel.setStyle("-fx-font-weight: bold; -fx-font-size: 14; -fx-text-fill: #CCCCCC;");

        var stationTable = new TableView<StationInfo>();
        var stationNameCol = new TableColumn<StationInfo, String>("Station");
        stationNameCol.setPrefWidth(300);
        stationNameCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().name()));
        var ownerCol = new TableColumn<StationInfo, String>("Owner");
        ownerCol.setPrefWidth(150);
        ownerCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().owner()));
        var servicesCol = new TableColumn<StationInfo, String>("Services");
        servicesCol.setPrefWidth(200);
        servicesCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().services()));
        stationTable.getColumns().addAll(stationNameCol, ownerCol, servicesCol);
        stationTable.setItems(stationList);
        stationTable.setPlaceholder(new Label("Select a system"));
        VBox.setVgrow(stationTable, Priority.ALWAYS);

        rightPane.getChildren().addAll(nameLabel, detailGrid,
                new Separator(), stationsLabel, stationTable);

        // When a tree item is selected, update the detail panel
        treeView.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null) return;
            nameLabel.setText(sel.getValue());
            // Determine if it's a region or system
            TreeItem<String> parent = sel.getParent();
            if (parent != null && parent == treeView.getRoot()) {
                // It's a region
                detailValues[0].setText("Region");
                detailValues[1].setText(sel.getValue());
                for (int i = 2; i < detailValues.length; i++) {
                    detailValues[i].setText("--");
                }
                stationList.clear();
            } else if (parent != null) {
                // It's a system
                detailValues[0].setText("Solar System");
                detailValues[1].setText(parent.getValue());
                // Security would be loaded from the data
                for (int i = 2; i < detailValues.length; i++) {
                    detailValues[i].setText("--");
                }
                stationList.clear();
            }
        });

        splitPane.getItems().addAll(leftPane, rightPane);
        splitPane.setDividerPositions(0.3);

        tab.setContent(splitPane);
        return tab;
    }

    private void loadSystemsForRegion(TreeItem<String> regionItem, String regionName) {
        dataService.getSystemsInRegion(regionName)
                .thenAccept(systems -> Platform.runLater(() -> {
                    regionItem.getChildren().clear();
                    if (systems.isEmpty()) {
                        regionItem.getChildren().add(new TreeItem<>("No systems found"));
                        return;
                    }
                    for (var system : systems) {
                        String label = String.format("System #%d (%.1f)",
                                system.systemId(), system.securityStatus());
                        // Try to resolve the system name
                        var sysItem = new TreeItem<>(label);
                        dataService.resolveSystemName(system.systemId())
                                .thenAccept(name -> Platform.runLater(() ->
                                        sysItem.setValue(String.format("%s (%.1f)",
                                                name, system.securityStatus()))));
                        regionItem.getChildren().add(sysItem);
                    }
                }))
                .exceptionally(ex -> {
                    Platform.runLater(() -> {
                        regionItem.getChildren().clear();
                        regionItem.getChildren().add(new TreeItem<>("Failed to load"));
                        log.error("Failed to load systems for region {}", regionName, ex);
                    });
                    return null;
                });
    }

    /**
     * Simple record for station display.
     */
    record StationInfo(String name, String owner, String services) {}

    @Override
    public String getTitle() { return "Universe Browser"; }

    @Override
    public void onActivated() { log.debug("Universe Browser workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        // Universe browser is not character-specific
    }
}

