231	    private void updateAnalyzerStats(java.util.List<MarketStatistics> data) {
232	        if (data.isEmpty()) {
233	            for (Label val : statsValues) val.setText("--");
234	            return;
235	        }
236	        double sumAvg = 0, min = Double.MAX_VALUE, max = 0, sumVol = 0;
237	        for (var s : data) {
238	            double avg = (s.open() + s.close()) / 2.0;
239	            sumAvg += avg;
240	            min = Math.min(min, s.low());
241	            max = Math.max(max, s.high());
242	            sumVol += s.volume();
243	        }
244	        double avgPrice = sumAvg / data.size();
245	        double avgVol = sumVol / data.size();
246	
247	        // Volatility: std dev of avg prices
248	        double sumSqDiff = 0;
249	        for (var s : data) {
250	            double avg = (s.open() + s.close()) / 2.0;
251	            sumSqDiff += (avg - avgPrice) * (avg - avgPrice);
252	        }
253	        double volatility = Math.sqrt(sumSqDiff / data.size()) / avgPrice * 100.0;
254	
255	        // Trend: compare first half average to second half
256	        int half = data.size() / 2;
257	        double firstHalf = 0, secondHalf = 0;
258	        for (int i = 0; i < data.size(); i++) {
259	            double avg = (data.get(i).open() + data.get(i).close()) / 2.0;
260	            if (i < half) firstHalf += avg;
261	            else secondHalf += avg;
262	        }
263	        firstHalf /= Math.max(half, 1);
264	        secondHalf /= Math.max(data.size() - half, 1);
265	        String trend = secondHalf > firstHalf * 1.02 ? "Up" :
266	                secondHalf < firstHalf * 0.98 ? "Down" : "Stable";
267	
268	        statsValues[0].setText(String.format("%.2f ISK", avgPrice));
269	        statsValues[1].setText(String.format("%.2f ISK", min));
270	        statsValues[2].setText(String.format("%.2f ISK", max));
271	        statsValues[3].setText(String.format("%.0f", avgVol));
272	        statsValues[4].setText(String.format("%.1f%%", volatility));
273	        statsValues[5].setText(trend);
274	    }
