package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.LoyaltyOffer;
import com.sampleapp.core.model.MarketStatistics;
import com.sampleapp.core.model.ProfitModel;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

/**
 * Tools workspace with 4 tabs: LP Calculator, Market Analyzer, Profit Tracker, Route Planner.
 */
public class ToolsWorkspace extends Workspace {

    private final WorkspaceDataService dataService;

    // LP Calculator
    private final ObservableList<LoyaltyOffer> lpOffers = FXCollections.observableArrayList();

    // Market Analyzer
    private final ObservableList<MarketStatistics> marketHistory = FXCollections.observableArrayList();
    private Label[] statsValues;

    // Profit Tracker
    private final ObservableList<ProfitModel> profitData = FXCollections.observableArrayList();

    // Route Planner
    private final ObservableList<RouteStep> routeSteps = FXCollections.observableArrayList();
    private Label routeSummaryLabel;

    public ToolsWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createLpCalculatorTab(),
                createMarketAnalyzerTab(),
                createProfitTrackerTab(),
                createRoutePlannerTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createLpCalculatorTab() {
        var tab = new Tab("LP Calculator");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Corporation selector
        var corpBox = new HBox(10);
        var corpCombo = new ComboBox<String>();
        corpCombo.getItems().addAll("Caldari Navy", "Federation Navy",
                "Imperial Navy", "Republic Fleet", "Sisters of EVE",
                "Thukker Tribe", "CreoDron", "Lai Dai Corporation");
        corpCombo.setPromptText("Select corporation...");
        var lpField = new TextField();
        lpField.setPromptText("LP amount");
        lpField.setPrefWidth(120);
        var calcBtn = new Button("Calculate");
        corpBox.getChildren().addAll(new Label("Corporation:"), corpCombo,
                new Label("LP:"), lpField, calcBtn);

        // Results table
        var table = new TableView<LoyaltyOffer>();
        var itemCol = new TableColumn<LoyaltyOffer, String>("Item");
        itemCol.setPrefWidth(200);
        itemCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
            dataService.resolveTypeName(c.getValue().typeId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var lpCostCol = new TableColumn<LoyaltyOffer, Number>("LP Cost");
        lpCostCol.setPrefWidth(80);
        lpCostCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().lpCost()));
        var iskCostCol = new TableColumn<LoyaltyOffer, Number>("ISK Cost");
        iskCostCol.setPrefWidth(120);
        iskCostCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().iskCost()));
        var sellCol = new TableColumn<LoyaltyOffer, String>("Sell Price");
        sellCol.setPrefWidth(120);
        sellCol.setCellValueFactory(c -> new SimpleStringProperty("--"));
        var profitCol = new TableColumn<LoyaltyOffer, String>("Profit");
        profitCol.setPrefWidth(120);
        profitCol.setCellValueFactory(c -> new SimpleStringProperty("--"));
        var iskPerLpCol = new TableColumn<LoyaltyOffer, String>("ISK/LP");
        iskPerLpCol.setPrefWidth(80);
        iskPerLpCol.setCellValueFactory(c -> new SimpleStringProperty("--"));

        table.getColumns().addAll(itemCol, lpCostCol, iskCostCol, sellCol, profitCol, iskPerLpCol);
        table.setItems(lpOffers);
        table.setPlaceholder(new Label("Select a corporation to see LP store items"));
        VBox.setVgrow(table, Priority.ALWAYS);

        calcBtn.setOnAction(e -> {
            String corp = corpCombo.getValue();
            if (corp == null || corp.isBlank()) return;
            calcBtn.setDisable(true);
            // Use corporation name to look up offers; corp ID mapping would be in real impl
            int corpId = corpNameToId(corp);
            dataService.getLpStoreOffers(corpId)
                    .thenAccept(data -> Platform.runLater(() -> {
                        lpOffers.setAll(data);
                        calcBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to load LP offers", ex);
                            calcBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(corpBox, table);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createMarketAnalyzerTab() {
        var tab = new Tab("Market Analyzer");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var controlBox = new HBox(10);
        var itemField = new TextField();
        itemField.setPromptText("Item name...");
        itemField.setPrefWidth(250);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("The Forge", "Domain", "Sinq Laison",
                "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        var daysCombo = new ComboBox<String>();
        daysCombo.getItems().addAll("7 days", "30 days", "90 days", "365 days");
        daysCombo.setValue("30 days");
        var analyzeBtn = new Button("Analyze");
        controlBox.getChildren().addAll(itemField, regionCombo, daysCombo, analyzeBtn);

        // Stats grid
        var statsGrid = new GridPane();
        statsGrid.setHgap(20);
        statsGrid.setVgap(8);
        statsGrid.setPadding(new Insets(10));
        statsGrid.setStyle("-fx-background-color: #252526; -fx-background-radius: 4;");

        String[] statNames = {"Avg Price:", "Min Price:", "Max Price:",
                "Avg Volume:", "Volatility:", "Trend:"};
        statsValues = new Label[statNames.length];
        for (int i = 0; i < statNames.length; i++) {
            var lbl = new Label(statNames[i]);
            lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
            statsGrid.add(lbl, (i % 3) * 2, i / 3);
            statsValues[i] = new Label("--");
            statsValues[i].setStyle("-fx-text-fill: #CCCCCC;");
            statsGrid.add(statsValues[i], (i % 3) * 2 + 1, i / 3);
        }

        // History table
        var table = new TableView<MarketStatistics>();
        var dateCol = new TableColumn<MarketStatistics, String>("Date");
        dateCol.setPrefWidth(100);
        dateCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().date() != null ? c.getValue().date().toString() : "--"));
        var avgCol = new TableColumn<MarketStatistics, String>("Average");
        avgCol.setPrefWidth(120);
        avgCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.2f", (c.getValue().open() + c.getValue().close()) / 2.0)));
        var lowCol = new TableColumn<MarketStatistics, Number>("Lowest");
        lowCol.setPrefWidth(120);
        lowCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().low()));
        var highCol = new TableColumn<MarketStatistics, Number>("Highest");
        highCol.setPrefWidth(120);
        highCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().high()));
        var volCol = new TableColumn<MarketStatistics, Number>("Volume");
        volCol.setPrefWidth(100);
        volCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));
        var orderCol = new TableColumn<MarketStatistics, Number>("Order Count");
        orderCol.setPrefWidth(100);
        orderCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().orderCount()));

        table.getColumns().addAll(dateCol, avgCol, lowCol, highCol, volCol, orderCol);
        table.setItems(marketHistory);
        table.setPlaceholder(new Label("Enter an item to analyze"));
        VBox.setVgrow(table, Priority.ALWAYS);

        analyzeBtn.setOnAction(e -> {
            String item = itemField.getText();
            if (item == null || item.isBlank()) return;
            analyzeBtn.setDisable(true);
            int regionId = regionNameToId(regionCombo.getValue());
            // In real impl, resolve item name to typeId then fetch history
            // For now, search market first to get a typeId
            dataService.searchMarket(item, regionId)
                    .thenCompose(prices -> {
                        if (prices.isEmpty()) {
                            return java.util.concurrent.CompletableFuture.completedFuture(
                                    java.util.List.<MarketStatistics>of());
                        }
                        int typeId = prices.get(0).typeId();
                        return dataService.getMarketHistory(typeId, regionId);
                    })
                    .thenAccept(data -> Platform.runLater(() -> {
                        marketHistory.setAll(data);
                        updateAnalyzerStats(data);
                        analyzeBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Market analysis failed", ex);
                            analyzeBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(controlBox, statsGrid, table);
        tab.setContent(vbox);
        return tab;
    }

    private void updateAnalyzerStats(java.util.List<MarketStatistics> data) {
        if (data.isEmpty()) {
            for (Label val : statsValues) val.setText("--");
            return;
        }
        double sumAvg = 0, min = Double.MAX_VALUE, max = 0, sumVol = 0;
        for (var s : data) {
            double avg = (s.open() + s.close()) / 2.0;
            sumAvg += avg;
            min = Math.min(min, s.low());
            max = Math.max(max, s.high());
            sumVol += s.volume();
        }
        double avgPrice = sumAvg / data.size();
        double avgVol = sumVol / data.size();

        // Volatility: std dev of avg prices
        double sumSqDiff = 0;
        for (var s : data) {
            double avg = (s.open() + s.close()) / 2.0;
            sumSqDiff += (avg - avgPrice) * (avg - avgPrice);
        }
        double volatility = Math.sqrt(sumSqDiff / data.size()) / avgPrice * 100.0;

        // Trend: compare first half average to second half
        int half = data.size() / 2;
        double firstHalf = 0, secondHalf = 0;
        for (int i = 0; i < data.size(); i++) {
            double avg = (data.get(i).open() + data.get(i).close()) / 2.0;
            if (i < half) firstHalf += avg;
            else secondHalf += avg;
        }
        firstHalf /= Math.max(half, 1);
        secondHalf /= Math.max(data.size() - half, 1);
        String trend = secondHalf > firstHalf * 1.02 ? "Up" :
                secondHalf < firstHalf * 0.98 ? "Down" : "Stable";

        statsValues[0].setText(String.format("%.2f ISK", avgPrice));
        statsValues[1].setText(String.format("%.2f ISK", min));
        statsValues[2].setText(String.format("%.2f ISK", max));
        statsValues[3].setText(String.format("%.0f", avgVol));
        statsValues[4].setText(String.format("%.1f%%", volatility));
        statsValues[5].setText(trend);
    }

    @SuppressWarnings("unchecked")
    private Tab createProfitTrackerTab() {
        var tab = new Tab("Profit Tracker");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var controlBox = new HBox(10);
        var fromDate = new DatePicker();
        fromDate.setPromptText("From");
        var toDate = new DatePicker();
        toDate.setPromptText("To");
        var groupCombo = new ComboBox<String>();
        groupCombo.getItems().addAll("All", "Trading", "Manufacturing",
                "Mining", "Ratting", "Other");
        groupCombo.setValue("All");
        var calcBtn = new Button("Calculate");
        controlBox.getChildren().addAll(
                new Label("From:"), fromDate,
                new Label("To:"), toDate,
                new Label("Group:"), groupCombo,
                calcBtn
        );

        var table = new TableView<ProfitModel>();
        var nameCol = new TableColumn<ProfitModel, String>("Item");
        nameCol.setPrefWidth(200);
        nameCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().typeName() != null ? c.getValue().typeName() : "Type #" + c.getValue().typeId()));
        var incomeCol = new TableColumn<ProfitModel, Number>("Revenue");
        incomeCol.setPrefWidth(120);
        incomeCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().revenue()));
        var expenseCol = new TableColumn<ProfitModel, Number>("Cost");
        expenseCol.setPrefWidth(120);
        expenseCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().cost()));
        var profitCol = new TableColumn<ProfitModel, Number>("Profit");
        profitCol.setPrefWidth(120);
        profitCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().profit()));
        var taxCol = new TableColumn<ProfitModel, Number>("Taxes");
        taxCol.setPrefWidth(120);
        taxCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().taxes()));

        table.getColumns().addAll(nameCol, incomeCol, expenseCol, profitCol, taxCol);
        table.setItems(profitData);
        table.setPlaceholder(new Label("Set date range and click Calculate"));
        VBox.setVgrow(table, Priority.ALWAYS);

        calcBtn.setOnAction(e -> {
            int charId = appState.getSelectedCharacterId();
            if (charId <= 0) return;
            calcBtn.setDisable(true);
            dataService.getProfitSummary(charId, fromDate.getValue(), toDate.getValue())
                    .thenAccept(data -> Platform.runLater(() -> {
                        profitData.setAll(data);
                        calcBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to calculate profit", ex);
                            calcBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        vbox.getChildren().addAll(controlBox, table);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private Tab createRoutePlannerTab() {
        var tab = new Tab("Route Planner");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var routeBox = new HBox(10);
        var fromField = new TextField();
