package com.sampleapp.app;

import com.sampleapp.app.service.BusinessLogic;
import com.sampleapp.app.service.StationTradeService;
import com.sampleapp.app.service.SyncService;
import com.sampleapp.app.service.WorkspaceDataServiceImpl;
import com.sampleapp.core.app.AppConfig;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.DevMode;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.service.EventBus;
import com.sampleapp.data.DatabaseManager;
import com.sampleapp.data.StationStatsDatabase;
import com.sampleapp.data.cache.*;
import com.sampleapp.data.repository.*;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.EveSsoAuth;
import com.sampleapp.esi.TokenManager;
import com.sampleapp.ui.AppServices;
import com.sampleapp.ui.MainWindow;
import com.google.inject.AbstractModule;
import com.google.inject.Provides;
import jakarta.inject.Named;
import jakarta.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.nio.file.Path;

/**
 * Guice dependency injection module for the Sample App application.
 * Binds all core singletons, services, repositories, caches, and ESI clients.
 */
public class AppModule extends AbstractModule {

    private static final Logger log = LoggerFactory.getLogger(AppModule.class);

    private final AppConfig config;
    private final Path dataDir;
    private final boolean devMode;

    public AppModule(AppConfig config, Path dataDir, boolean devMode) {
        this.config = config;
        this.dataDir = dataDir;
        this.devMode = devMode;
    }

    @Override
    protected void configure() {
        log.info("Configuring Guice module");

        // Configuration
        bind(AppConfig.class).toInstance(config);
        bind(Path.class).annotatedWith(DataDir.class).toInstance(dataDir);

        // Core singletons
        bind(AppState.class).in(Singleton.class);
        bind(EventBus.class).in(Singleton.class);
        bind(FeatureGate.class).in(Singleton.class);

        // Also bind the core.service.AppConfig as a singleton for AppState(service)
        bind(com.sampleapp.core.service.AppConfig.class).in(Singleton.class);

        // Also bind common.AppConfig for FeatureGate (core.subscription)
        bind(com.sampleapp.common.AppConfig.class).in(Singleton.class);

        // Also bind the core.subscription.FeatureGate for services that use it
        bind(com.sampleapp.core.subscription.FeatureGate.class).in(Singleton.class);

        // ESI (TokenManager, EsiClient, EveSsoAuth provided via @Provides methods)

        // Repositories (all take DatabaseManager as constructor arg, auto-injected)
        bind(CharacterRepository.class).in(Singleton.class);
        bind(MarketTransactionRepository.class).in(Singleton.class);
        bind(MarketOrderRepository.class).in(Singleton.class);
        bind(ContractRepository.class).in(Singleton.class);
        bind(IndustryJobRepository.class).in(Singleton.class);
        bind(AssetRepository.class).in(Singleton.class);
        bind(BlueprintRepository.class).in(Singleton.class);
        bind(WalletRepository.class).in(Singleton.class);
        bind(LoyaltyRepository.class).in(Singleton.class);
        bind(AccountingRepository.class).in(Singleton.class);
        bind(StationPriceRepository.class).in(Singleton.class);
        bind(MarketStatisticsRepository.class).in(Singleton.class);
        bind(TypeCacheRepository.class).in(Singleton.class);

        // Caches (all no-arg constructors, @Singleton annotated)
        bind(MarketPriceCache.class).in(Singleton.class);
        bind(ItemTypeCache.class).in(Singleton.class);
        bind(AdjustedPricesCache.class).in(Singleton.class);
        bind(MarketOrdersCache.class).in(Singleton.class);
        bind(SystemSecurityCache.class).in(Singleton.class);
        bind(TaggedTypesCache.class).in(Singleton.class);
        bind(TypeMaterialCache.class).in(Singleton.class);

        // Services
        bind(BusinessLogic.class).in(Singleton.class);
        bind(SyncService.class).in(Singleton.class);

        // App-level service state (lifecycle manager)
        bind(com.sampleapp.app.service.AppState.class).in(Singleton.class);

        // UI services bridge
        bind(AppServices.class).to(AppServicesImpl.class).in(Singleton.class);
        bind(WorkspaceDataServiceImpl.class).in(Singleton.class);

        // UI
        bind(MainWindow.class).in(Singleton.class);
    }

    @Provides
    @Singleton
    @DevMode
    boolean provideDevMode() {
        return devMode;
    }

    @Provides
    @Singleton
    @Named("dataFolder")
    String provideDataFolder() {
        return dataDir.resolve("db").toString();
    }

    @Provides
    @Singleton
    DatabaseManager provideDatabaseManager(@Named("dataFolder") String dataFolder) {
        return new DatabaseManager(dataFolder);
    }

    @Provides
    @Singleton
    StationStatsDatabase provideStationStatsDatabase(@Named("dataFolder") String dataFolder) {
        return new StationStatsDatabase(dataFolder);
    }

    @Provides
    @Singleton
    TokenManager provideTokenManager() {
        return new TokenManager();
    }

    @Provides
    @Singleton
    EsiClient provideEsiClient(TokenManager tokenManager) {
        return new EsiClient(tokenManager);
    }

    @Provides
    @Singleton
    EveSsoAuth provideEveSsoAuth(EsiClient esiClient) {
        return esiClient.createSsoAuth();
    }

    @Provides
    @Singleton
    StationTradeService provideStationTradeService(
            StationStatsDatabase stationStatsDb,
            com.sampleapp.core.subscription.FeatureGate featureGate,
            EventBus eventBus,
            @DataDir Path dataFolder) {
        return new StationTradeService(stationStatsDb, featureGate, eventBus, dataFolder);
    }
}

