package com.sampleapp.ui.workspace;

import com.sampleapp.core.model.*;

import java.time.LocalDate;
import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * Service interface for workspace data access.
 * Implementations provide database and ESI data to workspace UI panels.
 * All methods return CompletableFuture so they run off the FX thread.
 */
public interface WorkspaceDataService {

    // --- Industry ---
    CompletableFuture<List<IndustryJob>> getIndustryJobs(int characterId);
    CompletableFuture<List<BlueprintModel>> getBlueprints(int characterId);
    CompletableFuture<List<MiningLedger>> getMiningLedger(int characterId, LocalDate from, LocalDate to);
    CompletableFuture<List<TypeMaterial>> getBlueprintMaterials(int blueprintTypeId);

    // --- Accounting / Wallet ---
    CompletableFuture<List<JournalEntry>> getJournalEntries(int characterId);
    CompletableFuture<List<MarketTransaction>> getTransactions(int characterId);
    CompletableFuture<List<ProfitModel>> getProfitSummary(int characterId, LocalDate from, LocalDate to);

    // --- Market ---
    CompletableFuture<List<MarketPrice>> searchMarket(String query, int regionId);
    CompletableFuture<List<MarketStatistics>> getMarketHistory(int typeId, int regionId);
    CompletableFuture<List<MarketOrder>> getRegionOrders(int typeId, int regionId);
    CompletableFuture<List<HubPrices>> appraiseItems(List<Integer> typeIds);

    // --- Trader ---
    CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume);
    CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
                                                                  double minMargin, double maxCargo, double budget);

    // --- LP Store ---
    CompletableFuture<List<LoyaltyOffer>> getLpStoreOffers(int corporationId);
    CompletableFuture<List<LoyaltyPoints>> getLoyaltyPoints(int characterId);

    // --- Public Contracts ---
    CompletableFuture<List<ContractModel>> getPublicContracts(int regionId, String typeFilter);

    // --- Fleet ---
    CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId);

    // --- Universe ---
    CompletableFuture<List<SystemSecurity>> getSystemsInRegion(String regionName);

    // --- Resolve names ---
    CompletableFuture<String> resolveTypeName(int typeId);
    CompletableFuture<String> resolveLocationName(long locationId);
    CompletableFuture<String> resolveSystemName(int systemId);

    /**
     * Simple fleet member info record.
     */
    record FleetMemberInfo(
            int characterId,
            String characterName,
            String shipName,
            String shipTypeName,
            String solarSystemName,
            String role,
            String squadName,
            String wingName
    ) {}
}

