26	/**
27	 * Left sidebar navigation with character picker and labelled buttons for each workspace.
28	 * Wide sidebar (180px) with icon + text for every entry.
29	 */
30	public class NavigationBar extends VBox {
31	
32	    private static final Logger log = LoggerFactory.getLogger(NavigationBar.class);
33	
34	    /**
35	     * All available workspace types, corresponding to navigation buttons.
36	     */
37	    public enum WorkspaceType {
38	        CHARACTER("Character", "\u263A"),           // ☺
39	        SKILLS("Skills", "\u2B50"),                 // ⭐
40	        ASSETS("Assets", "\uD83D\uDCE6"),           // 📦
41	        MARKET("Market Browser", "\uD83D\uDCCA"),    // 📊
42	        MARKET_ORDERS("Market Orders", "\uD83D\uDCCB"), // 📋
43	        WALLET("Wallet", "\uD83D\uDCB0"),           // 💰
44	        CONTRACTS("Contracts", "\uD83D\uDCDD"),      // 📝
45	        PUBLIC_CONTRACTS("Public Contracts", "\uD83C\uDF10"), // 🌐
46	        INDUSTRY("Industry", "\u2699"),              // ⚙
47	        ACCOUNTING("Accounting", "\uD83D\uDCB1"),    // 💱
48	        TRADER("Trader", "\uD83D\uDCC8"),            // 📈
49	        TOOLS("Tools", "\uD83D\uDD27"),              // 🔧
50	        FLEET("Fleet", "\uD83D\uDE80"),              // 🚀
51	        LP_STORE("LP Store", "\uD83C\uDFAA"),        // 🎪
52	        UNIVERSE_BROWSER("Universe", "\uD83C\uDF0C"), // 🌌
53	        SETTINGS("Settings", "\u2699\uFE0F");        // ⚙️
54	
55	        private final String label;
56	        private final String icon;
57	
58	        WorkspaceType(String label, String icon) {
59	            this.label = label;
60	            this.icon = icon;
61	        }
62	
63	        public String getLabel() { return label; }
64	        public String getIcon() { return icon; }
65	    }
66	
67	    private static final double NAV_WIDTH = 180;
68	
69	    private final Map<WorkspaceType, Button> buttons = new EnumMap<>(WorkspaceType.class);
70	    private final ComboBox<AppState.CharacterInfo> characterPicker;
71	    private final ImageView portraitView;
72	    private WorkspaceType selected;
73	
74	    public NavigationBar(AppState appState, Consumer<WorkspaceType> onNavigate, Runnable onAddCharacter) {
75	        getStyleClass().add("nav-bar");
76	        setAlignment(Pos.TOP_LEFT);
77	        setPadding(new Insets(8, 6, 8, 6));
78	        setSpacing(2);
79	        setPrefWidth(NAV_WIDTH);
80	        setMinWidth(NAV_WIDTH);
81	        setMaxWidth(NAV_WIDTH);
82	
83	        // --- Character picker section ---
84	        var charLabel = new Label("CHARACTER");
85	        charLabel.getStyleClass().add("nav-section-label");
86	
87	        characterPicker = new ComboBox<>(appState.getCharacters());
88	        characterPicker.getStyleClass().add("char-picker-wide");
89	        characterPicker.setPrefWidth(NAV_WIDTH - 12);
90	        characterPicker.setMaxWidth(NAV_WIDTH - 12);
91	        characterPicker.setPromptText("Select character...");
92	        characterPicker.setButtonCell(new CharacterButtonCellWide());
93	        characterPicker.setCellFactory(lv -> new CharacterListCell());
94	        characterPicker.setConverter(new StringConverter<>() {
95	            @Override
96	            public String toString(AppState.CharacterInfo info) {
97	                return info == null ? "" : info.name();
98	            }
99	
100	            @Override
101	            public AppState.CharacterInfo fromString(String s) {
102	                return null;
103	            }
104	        });
105	
106	        // Character portrait displayed above the picker
107	        portraitView = new ImageView();
108	        portraitView.setFitWidth(64);
109	        portraitView.setFitHeight(64);
110	        portraitView.setPreserveRatio(true);
111	        portraitView.setSmooth(true);
112	
113	        characterPicker.valueProperty().addListener((obs, oldVal, newVal) -> {
114	            if (newVal != null) {
115	                appState.setSelectedCharacterId(newVal.characterId());
116	                appState.setSelectedCharacterName(newVal.name());
117	                log.info("Selected character: {} ({})", newVal.name(), newVal.characterId());
118	                Image portrait = new Image(
119	                        "https://images.evetech.net/characters/" + newVal.characterId() + "/portrait?size=128",
120	                        64, 64, true, true, true);
121	                portraitView.setImage(portrait);
122	            } else {
123	                portraitView.setImage(null);
124	            }
125	        });
126	
127	        int currentId = appState.getSelectedCharacterId();
128	        if (currentId > 0) {
129	            appState.getCharacters().stream()
130	                    .filter(c -> c.characterId() == currentId)
131	                    .findFirst()
132	                    .ifPresent(c -> {
133	                        characterPicker.setValue(c);
134	                        Image portrait = new Image(
135	                                "https://images.evetech.net/characters/" + c.characterId() + "/portrait?size=128",
136	                                64, 64, true, true, true);
137	                        portraitView.setImage(portrait);
138	                    });
139	        }
140	
141	        appState.getCharacters().addListener(
142	                (javafx.collections.ListChangeListener<AppState.CharacterInfo>) change -> {
143	                    if (characterPicker.getValue() == null && !appState.getCharacters().isEmpty()) {
144	                        characterPicker.setValue(appState.getCharacters().getFirst());
145	                    }
146	                });
147	
148	        // "Add Character" button - full width with text
149	        var addCharBtn = new Button("+ Add Character");
150	        addCharBtn.getStyleClass().addAll("nav-add-char-button");
151	        addCharBtn.setPrefWidth(NAV_WIDTH - 12);
152	        addCharBtn.setMaxWidth(NAV_WIDTH - 12);
153	        addCharBtn.setOnAction(e -> onAddCharacter.run());
154	
155	        getChildren().addAll(charLabel, portraitView, characterPicker, addCharBtn);
156	
157	        // Separator after character section
158	        getChildren().add(createNavSeparator());
159	
160	        // Section: Navigation
161	        var navLabel = new Label("NAVIGATION");
162	        navLabel.getStyleClass().add("nav-section-label");
163	        getChildren().add(navLabel);
164	
165	        // Add main navigation buttons
166	        for (var type : WorkspaceType.values()) {
167	            if (type == WorkspaceType.SETTINGS) continue;
168	            addNavButton(type, onNavigate);
169	        }
170	
171	        // Spacer to push settings to bottom
172	        var spacer = new Region();
173	        VBox.setVgrow(spacer, Priority.ALWAYS);
174	        getChildren().add(spacer);
175	
176	        getChildren().add(createNavSeparator());
177	
178	        // Settings button at bottom
179	        addNavButton(WorkspaceType.SETTINGS, onNavigate);
180	    }
