182	    private void addNavButton(WorkspaceType type, Consumer<WorkspaceType> onNavigate) {
183	        var button = new Button(type.getIcon() + "  " + type.getLabel());
184	        button.getStyleClass().add("nav-button-wide");
185	        button.setPrefWidth(NAV_WIDTH - 12);
186	        button.setMaxWidth(NAV_WIDTH - 12);
187	        button.setPrefHeight(30);
188	        button.setMinHeight(30);
189	        button.setMaxHeight(30);
190	        button.setAlignment(Pos.CENTER_LEFT);
191	        button.setOnAction(event -> onNavigate.accept(type));
192	        buttons.put(type, button);
193	        getChildren().add(button);
194	    }
195	
196	    private Separator createNavSeparator() {
197	        var sep = new Separator();
198	        sep.getStyleClass().add("nav-separator");
199	        sep.setPadding(new Insets(4, 0, 4, 0));
200	        return sep;
201	    }
202	
203	    /**
204	     * Update the selected state of navigation buttons.
205	     */
206	    public void setSelected(WorkspaceType type) {
207	        if (selected != null && buttons.containsKey(selected)) {
208	            buttons.get(selected).getStyleClass().remove("nav-button-selected");
209	        }
210	        selected = type;
211	        if (buttons.containsKey(type)) {
212	            buttons.get(type).getStyleClass().add("nav-button-selected");
213	        }
214	    }
215	
216	    /**
217	     * Wide button cell showing the full character name.
218	     */
219	    private static class CharacterButtonCellWide extends ListCell<AppState.CharacterInfo> {
220	        @Override
221	        protected void updateItem(AppState.CharacterInfo item, boolean empty) {
222	            super.updateItem(item, empty);
223	            if (empty || item == null) {
224	                setText("Select character...");
225	                setStyle("-fx-text-fill: #666666;");
226	            } else {
227	                setText(item.name());
228	                setStyle("-fx-text-fill: #CCCCCC;");
229	            }
230	        }
231	    }
232	
233	    /**
234	     * Dropdown cell showing full character name and corporation.
235	     */
236	    private static class CharacterListCell extends ListCell<AppState.CharacterInfo> {
237	        @Override
238	        protected void updateItem(AppState.CharacterInfo item, boolean empty) {
