package com.sampleapp.ui;

import com.sampleapp.core.app.AppState;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.ComboBox;
import javafx.scene.control.Label;
import javafx.scene.control.ListCell;
import javafx.scene.control.Separator;
import javafx.scene.control.Tooltip;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.util.StringConverter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.EnumMap;
import java.util.Map;
import java.util.function.Consumer;

/**
 * Left sidebar navigation with character picker and labelled buttons for each workspace.
 * Wide sidebar (180px) with icon + text for every entry.
 */
public class NavigationBar extends VBox {

    private static final Logger log = LoggerFactory.getLogger(NavigationBar.class);

    /**
     * All available workspace types, corresponding to navigation buttons.
     */
    public enum WorkspaceType {
        CHARACTER("Character", "\u263A"),           // ☺
        SKILLS("Skills", "\u2B50"),                 // ⭐
        ASSETS("Assets", "\uD83D\uDCE6"),           // 📦
        MARKET("Market Browser", "\uD83D\uDCCA"),    // 📊
        MARKET_ORDERS("Market Orders", "\uD83D\uDCCB"), // 📋
        WALLET("Wallet", "\uD83D\uDCB0"),           // 💰
        CONTRACTS("Contracts", "\uD83D\uDCDD"),      // 📝
        PUBLIC_CONTRACTS("Public Contracts", "\uD83C\uDF10"), // 🌐
        INDUSTRY("Industry", "\u2699"),              // ⚙
        ACCOUNTING("Accounting", "\uD83D\uDCB1"),    // 💱
        TRADER("Trader", "\uD83D\uDCC8"),            // 📈
        TOOLS("Tools", "\uD83D\uDD27"),              // 🔧
        FLEET("Fleet", "\uD83D\uDE80"),              // 🚀
        LP_STORE("LP Store", "\uD83C\uDFAA"),        // 🎪
        UNIVERSE_BROWSER("Universe", "\uD83C\uDF0C"), // 🌌
        SETTINGS("Settings", "\u2699\uFE0F");        // ⚙️

        private final String label;
        private final String icon;

        WorkspaceType(String label, String icon) {
            this.label = label;
            this.icon = icon;
        }

        public String getLabel() { return label; }
        public String getIcon() { return icon; }
    }

    private static final double NAV_WIDTH = 180;

    private final Map<WorkspaceType, Button> buttons = new EnumMap<>(WorkspaceType.class);
    private final ComboBox<AppState.CharacterInfo> characterPicker;
    private final ImageView portraitView;
    private WorkspaceType selected;

    public NavigationBar(AppState appState, Consumer<WorkspaceType> onNavigate, Runnable onAddCharacter) {
        getStyleClass().add("nav-bar");
        setAlignment(Pos.TOP_LEFT);
        setPadding(new Insets(8, 6, 8, 6));
        setSpacing(2);
        setPrefWidth(NAV_WIDTH);
        setMinWidth(NAV_WIDTH);
        setMaxWidth(NAV_WIDTH);

        // --- Character picker section ---
        var charLabel = new Label("CHARACTER");
        charLabel.getStyleClass().add("nav-section-label");

        characterPicker = new ComboBox<>(appState.getCharacters());
        characterPicker.getStyleClass().add("char-picker-wide");
        characterPicker.setPrefWidth(NAV_WIDTH - 12);
        characterPicker.setMaxWidth(NAV_WIDTH - 12);
        characterPicker.setPromptText("Select character...");
        characterPicker.setButtonCell(new CharacterButtonCellWide());
        characterPicker.setCellFactory(lv -> new CharacterListCell());
        characterPicker.setConverter(new StringConverter<>() {
            @Override
            public String toString(AppState.CharacterInfo info) {
                return info == null ? "" : info.name();
            }

            @Override
            public AppState.CharacterInfo fromString(String s) {
                return null;
            }
        });

        // Character portrait displayed above the picker
        portraitView = new ImageView();
        portraitView.setFitWidth(64);
        portraitView.setFitHeight(64);
        portraitView.setPreserveRatio(true);
        portraitView.setSmooth(true);

        characterPicker.valueProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                appState.setSelectedCharacterId(newVal.characterId());
                appState.setSelectedCharacterName(newVal.name());
                log.info("Selected character: {} ({})", newVal.name(), newVal.characterId());
                Image portrait = new Image(
                        "https://images.evetech.net/characters/" + newVal.characterId() + "/portrait?size=128",
                        64, 64, true, true, true);
                portraitView.setImage(portrait);
            } else {
                portraitView.setImage(null);
            }
        });

        int currentId = appState.getSelectedCharacterId();
        if (currentId > 0) {
            appState.getCharacters().stream()
                    .filter(c -> c.characterId() == currentId)
                    .findFirst()
                    .ifPresent(c -> {
                        characterPicker.setValue(c);
                        Image portrait = new Image(
                                "https://images.evetech.net/characters/" + c.characterId() + "/portrait?size=128",
                                64, 64, true, true, true);
                        portraitView.setImage(portrait);
                    });
        }

        appState.getCharacters().addListener(
                (javafx.collections.ListChangeListener<AppState.CharacterInfo>) change -> {
                    if (characterPicker.getValue() == null && !appState.getCharacters().isEmpty()) {
                        characterPicker.setValue(appState.getCharacters().getFirst());
                    }
                });

        // "Add Character" button - full width with text
        var addCharBtn = new Button("+ Add Character");
        addCharBtn.getStyleClass().addAll("nav-add-char-button");
        addCharBtn.setPrefWidth(NAV_WIDTH - 12);
        addCharBtn.setMaxWidth(NAV_WIDTH - 12);
        addCharBtn.setOnAction(e -> onAddCharacter.run());

        getChildren().addAll(charLabel, portraitView, characterPicker, addCharBtn);

        // Separator after character section
        getChildren().add(createNavSeparator());

        // Section: Navigation
        var navLabel = new Label("NAVIGATION");
        navLabel.getStyleClass().add("nav-section-label");
        getChildren().add(navLabel);

        // Add main navigation buttons
        for (var type : WorkspaceType.values()) {
            if (type == WorkspaceType.SETTINGS) continue;
            addNavButton(type, onNavigate);
        }

        // Spacer to push settings to bottom
        var spacer = new Region();
        VBox.setVgrow(spacer, Priority.ALWAYS);
        getChildren().add(spacer);

        getChildren().add(createNavSeparator());

        // Settings button at bottom
        addNavButton(WorkspaceType.SETTINGS, onNavigate);
    }

    private void addNavButton(WorkspaceType type, Consumer<WorkspaceType> onNavigate) {
        var button = new Button(type.getIcon() + "  " + type.getLabel());
        button.getStyleClass().add("nav-button-wide");
        button.setPrefWidth(NAV_WIDTH - 12);
        button.setMaxWidth(NAV_WIDTH - 12);
        button.setPrefHeight(30);
        button.setMinHeight(30);
        button.setMaxHeight(30);
        button.setAlignment(Pos.CENTER_LEFT);
        button.setOnAction(event -> onNavigate.accept(type));
        buttons.put(type, button);
        getChildren().add(button);
    }

    private Separator createNavSeparator() {
        var sep = new Separator();
        sep.getStyleClass().add("nav-separator");
        sep.setPadding(new Insets(4, 0, 4, 0));
        return sep;
    }

    /**
     * Update the selected state of navigation buttons.
     */
    public void setSelected(WorkspaceType type) {
        if (selected != null && buttons.containsKey(selected)) {
            buttons.get(selected).getStyleClass().remove("nav-button-selected");
        }
        selected = type;
        if (buttons.containsKey(type)) {
            buttons.get(type).getStyleClass().add("nav-button-selected");
        }
    }

    /**
     * Wide button cell showing the full character name.
     */
    private static class CharacterButtonCellWide extends ListCell<AppState.CharacterInfo> {
        @Override
        protected void updateItem(AppState.CharacterInfo item, boolean empty) {
            super.updateItem(item, empty);
            if (empty || item == null) {
                setText("Select character...");
                setStyle("-fx-text-fill: #666666;");
            } else {
                setText(item.name());
                setStyle("-fx-text-fill: #CCCCCC;");
            }
        }
    }

    /**
     * Dropdown cell showing full character name and corporation.
     */
    private static class CharacterListCell extends ListCell<AppState.CharacterInfo> {
        @Override
        protected void updateItem(AppState.CharacterInfo item, boolean empty) {
            super.updateItem(item, empty);
            if (empty || item == null) {
                setText(null);
            } else {
                String text = item.name();
                if (item.corporationName() != null && !item.corporationName().isEmpty()) {
                    text += " [" + item.corporationName() + "]";
                }
                setText(text);
            }
        }
    }
}

