package com.sampleapp.ui;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.ui.NavigationBar.WorkspaceType;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;
import javafx.application.Platform;
import javafx.scene.control.Alert;
import javafx.scene.layout.BorderPane;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Primary application window containing the navigation bar, workspace container, and status bar.
 */
@Singleton
public class MainWindow extends BorderPane {

    private static final Logger log = LoggerFactory.getLogger(MainWindow.class);

    private final AppState appState;
    private final FeatureGate featureGate;
    private final AppServices appServices;
    private final NavigationBar navigationBar;
    private final WorkspaceContainer workspaceContainer;
    private final StatusBar statusBar;

    @Inject
    public MainWindow(AppState appState, FeatureGate featureGate, AppServices appServices) {
        this.appState = appState;
        this.featureGate = featureGate;
        this.appServices = appServices;

        getStyleClass().add("main-window");

        // Create components
        this.navigationBar = new NavigationBar(appState, this::onNavigate, this::onAddCharacter);
        this.workspaceContainer = new WorkspaceContainer(appState, featureGate, appServices);
        this.statusBar = new StatusBar(appState, appServices);

        // Layout
        setLeft(navigationBar);
        setCenter(workspaceContainer);
        setBottom(statusBar);

        // Default to character workspace
        onNavigate(WorkspaceType.CHARACTER);

        log.info("MainWindow created");
    }

    private void onNavigate(WorkspaceType type) {
        log.debug("Navigating to workspace: {}", type);
        navigationBar.setSelected(type);
        workspaceContainer.showWorkspace(type);
    }

    private void onAddCharacter() {
        log.info("Add Character requested from navigation bar");
        appServices.addCharacter()
                .thenAccept(charId -> Platform.runLater(() ->
                        log.info("Character {} added via nav bar", charId)))
                .exceptionally(ex -> {
                    Platform.runLater(() -> {
                        log.error("Failed to add character from nav bar", ex);
                        var alert = new Alert(Alert.AlertType.ERROR,
                                "Failed to add character: " + ex.getMessage());
                        alert.setTitle("EVE SSO Error");
                        alert.showAndWait();
                    });
                    return null;
                });
    }
}

