package com.sampleapp.common;

import java.text.DecimalFormat;
import java.text.NumberFormat;
import java.util.Locale;

public final class IskFormatter {

    private static final NumberFormat FULL_FORMAT = NumberFormat.getNumberInstance(Locale.US);
    private static final DecimalFormat SHORT_FORMAT = new DecimalFormat("#,##0.##");

    static {
        FULL_FORMAT.setMinimumFractionDigits(2);
        FULL_FORMAT.setMaximumFractionDigits(2);
    }

    private IskFormatter() {
        // Prevent instantiation
    }

    /**
     * Formats an ISK value with full precision.
     * Example: 1234567.89 → "1,234,567.89 ISK"
     */
    public static String format(double value) {
        return FULL_FORMAT.format(value) + " ISK";
    }

    /**
     * Formats an ISK value using shorthand notation.
     * Example: 1_500_000_000 → "1.5B ISK", 2_300_000 → "2.3M ISK"
     */
    public static String formatShort(double value) {
        double abs = Math.abs(value);
        String sign = value < 0 ? "-" : "";

        if (abs >= 1_000_000_000_000.0) {
            return sign + SHORT_FORMAT.format(abs / 1_000_000_000_000.0) + "T ISK";
        } else if (abs >= 1_000_000_000.0) {
            return sign + SHORT_FORMAT.format(abs / 1_000_000_000.0) + "B ISK";
        } else if (abs >= 1_000_000.0) {
            return sign + SHORT_FORMAT.format(abs / 1_000_000.0) + "M ISK";
        } else if (abs >= 1_000.0) {
            return sign + SHORT_FORMAT.format(abs / 1_000.0) + "K ISK";
        } else {
            return format(value);
        }
    }

    /**
     * Formats an ISK value without the "ISK" suffix.
     */
    public static String formatRaw(double value) {
        return FULL_FORMAT.format(value);
    }
}

