1	package com.sampleapp.ui;
2	
3	import com.sampleapp.core.app.AppState;
4	import com.sampleapp.core.app.FeatureGate;
5	import com.sampleapp.ui.NavigationBar.WorkspaceType;
6	import com.sampleapp.ui.workspace.*;
7	import javafx.scene.layout.StackPane;
8	import org.slf4j.Logger;
9	import org.slf4j.LoggerFactory;
10	
11	import java.util.EnumMap;
12	import java.util.Map;
13	
14	/**
15	 * Center panel manager that lazy-creates and caches workspace instances.
16	 * Only one workspace is visible at a time.
17	 */
18	public class WorkspaceContainer extends StackPane {
19	
20	    private static final Logger log = LoggerFactory.getLogger(WorkspaceContainer.class);
21	
22	    private final Map<WorkspaceType, Workspace> workspaces = new EnumMap<>(WorkspaceType.class);
23	    private final AppState appState;
24	    private final FeatureGate featureGate;
25	    private final AppServices appServices;
26	    private WorkspaceType currentType;
27	
28	    public WorkspaceContainer(AppState appState, FeatureGate featureGate, AppServices appServices) {
29	        this.appState = appState;
30	        this.featureGate = featureGate;
31	        this.appServices = appServices;
32	        getStyleClass().add("workspace-container");
33	    }
34	
35	    /**
36	     * Show the workspace for the given type. Creates the workspace on first access.
37	     */
38	    public void showWorkspace(WorkspaceType type) {
39	        var workspace = workspaces.computeIfAbsent(type, this::createWorkspace);
40	
41	        // Hide all, show selected
42	        getChildren().forEach(node -> node.setVisible(false));
43	        if (!getChildren().contains(workspace)) {
44	            getChildren().add(workspace);
45	        }
46	        workspace.setVisible(true);
47	        workspace.onActivated();
48	        currentType = type;
49	
50	        log.debug("Showing workspace: {} ({})", type, workspace.getTitle());
51	    }
52	
53	    private Workspace createWorkspace(WorkspaceType type) {
54	        log.info("Creating workspace: {}", type);
55	        return switch (type) {
56	            case CHARACTER -> new CharacterWorkspace(appState, appServices);
57	            case SKILLS -> new SkillsWorkspace(appState, appServices);
58	            case ASSETS -> new AssetsWorkspace(appState, appServices);
59	            case MARKET -> new MarketWorkspace(appState, featureGate, appServices.getWorkspaceDataService());
60	            case MARKET_ORDERS -> new MarketOrdersWorkspace(appState, appServices);
61	            case WALLET -> new WalletWorkspace(appState, featureGate, appServices);
