/*
 * Sample App Dark Theme
 * Matches the original application's dark color scheme.
 * Primary background: #1C1C1C
 * Secondary background: #252526
 * Tertiary background: #2D2D30
 * Accent: #007ACC
 * Text: #CCCCCC
 * Muted text: #888888
 */

/* ========== Root ========== */
.root {
    -fx-base: #1C1C1C;
    -fx-background: #1C1C1C;
    -fx-control-inner-background: #252526;
    -fx-accent: #007ACC;
    -fx-focus-color: #007ACC;
    -fx-faint-focus-color: transparent;
    -fx-text-fill: #CCCCCC;
    -fx-font-family: "Segoe UI";
    -fx-font-size: 12px;
}

/* ========== Main Window ========== */
.main-window {
    -fx-background-color: #1C1C1C;
}

/* ========== Navigation Bar ========== */
.nav-bar {
    -fx-background-color: #2D2D30;
    -fx-pref-width: 180;
    -fx-min-width: 180;
    -fx-max-width: 180;
    -fx-padding: 8 6;
    -fx-spacing: 2;
}

/* Section labels (CHARACTER, NAVIGATION) */
.nav-section-label {
    -fx-text-fill: #888888;
    -fx-font-size: 10px;
    -fx-font-weight: bold;
    -fx-padding: 4 4 2 4;
}

/* Wide nav buttons with icon + text */
.nav-button-wide {
    -fx-background-color: transparent;
    -fx-text-fill: #AAAAAA;
    -fx-font-size: 12px;
    -fx-background-radius: 4;
    -fx-cursor: hand;
    -fx-padding: 4 8;
    -fx-alignment: center-left;
}

.nav-button-wide:hover {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #FFFFFF;
}

.nav-button-wide:pressed {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.nav-button-wide.nav-button-selected {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.nav-separator {
    -fx-padding: 4 0;
}

.nav-separator .line {
    -fx-border-color: #434346;
    -fx-border-width: 1 0 0 0;
}

/* ========== Character Picker (wide) ========== */
.char-picker-wide {
    -fx-background-color: #3E3E42;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 4;
    -fx-background-radius: 4;
    -fx-pref-height: 30;
    -fx-font-size: 12px;
    -fx-cursor: hand;
}

.char-picker-wide .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: transparent;
    -fx-padding: 2 6;
}

.char-picker-wide .arrow-button {
    -fx-background-color: transparent;
}

.char-picker-wide .arrow {
    -fx-background-color: #AAAAAA;
}

.char-picker-wide:hover {
    -fx-background-color: #505050;
    -fx-border-color: #007ACC;
}

.char-picker-wide:showing {
    -fx-background-color: #007ACC;
}

.char-picker-wide:showing .list-cell {
    -fx-text-fill: #FFFFFF;
}

/* Add Character button */
.nav-add-char-button {
    -fx-background-color: transparent;
    -fx-text-fill: #4EC9B0;
    -fx-font-size: 11px;
    -fx-background-radius: 4;
    -fx-cursor: hand;
    -fx-padding: 4 8;
    -fx-alignment: center-left;
}

.nav-add-char-button:hover {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #FFFFFF;
}

/* ========== Workspace Container ========== */
.workspace-container {
    -fx-background-color: #1C1C1C;
}

/* ========== Tab Pane ========== */
.tab-pane {
    -fx-tab-min-height: 28;
    -fx-tab-max-height: 28;
}

.tab-pane > .tab-header-area {
    -fx-background-color: #2D2D30;
    -fx-padding: 0;
}

.tab-pane > .tab-header-area > .headers-region > .tab {
    -fx-background-color: #2D2D30;
    -fx-background-insets: 0;
    -fx-background-radius: 0;
    -fx-padding: 4 12;
}

.tab-pane > .tab-header-area > .headers-region > .tab .tab-label {
    -fx-text-fill: #AAAAAA;
    -fx-font-size: 12px;
}

.tab-pane > .tab-header-area > .headers-region > .tab:selected {
    -fx-background-color: #1C1C1C;
}

.tab-pane > .tab-header-area > .headers-region > .tab:selected .tab-label {
    -fx-text-fill: #FFFFFF;
}

.tab-pane > .tab-header-area > .headers-region > .tab:hover:!selected {
    -fx-background-color: #3E3E42;
}

.tab-pane > .tab-header-area > .headers-region > .tab:hover:!selected .tab-label {
    -fx-text-fill: #CCCCCC;
}

.tab-pane > .tab-header-area > .tab-header-background {
    -fx-background-color: #2D2D30;
}

.tab-pane > .tab-content-area {
    -fx-background-color: #1C1C1C;
    -fx-padding: 0;
}

/* ========== Table View ========== */
.table-view {
    -fx-background-color: #1C1C1C;
    -fx-border-color: #434346;
    -fx-border-width: 1;
}

.table-view .filler {
    -fx-background-color: #2D2D30;
}

.table-view .column-header {
    -fx-background-color: #2D2D30;
    -fx-border-color: #434346;
    -fx-border-width: 0 1 1 0;
    -fx-padding: 4 8;
}

.table-view .column-header .label {
    -fx-text-fill: #CCCCCC;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
}

.table-view .column-header-background {
    -fx-background-color: #2D2D30;
}

.table-row-cell {
    -fx-background-color: #1C1C1C;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: transparent;
    -fx-cell-size: 24;
}

.table-row-cell:odd {
    -fx-background-color: #252526;
}

.table-row-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

.table-row-cell:hover:!selected {
    -fx-background-color: #2A2D2E;
}

.table-cell {
    -fx-text-fill: #CCCCCC;
    -fx-padding: 2 6;
    -fx-font-size: 11px;
}

.table-row-cell:selected .table-cell {
    -fx-text-fill: #FFFFFF;
}

.table-view .placeholder .label {
    -fx-text-fill: #666666;
}

/* ========== Status Bar ========== */
.status-bar {
    -fx-background-color: #007ACC;
    -fx-padding: 2 10;
    -fx-pref-height: 24;
    -fx-min-height: 24;
    -fx-max-height: 24;
    -fx-spacing: 10;
}

.status-bar .label,
.status-bar-label {
    -fx-text-fill: white;
    -fx-font-size: 11px;
}

.status-bar-separator {
    -fx-background-color: rgba(255, 255, 255, 0.3);
}

/* ========== Buttons ========== */
.button {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #CCCCCC;
    -fx-background-radius: 2;
    -fx-border-radius: 2;
    -fx-padding: 4 12;
    -fx-cursor: hand;
    -fx-font-size: 12px;
}

.button:hover {
    -fx-background-color: #505050;
    -fx-text-fill: #FFFFFF;
}

.button:pressed {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.button:focused {
    -fx-border-color: #007ACC;
    -fx-border-width: 1;
}

.button:disabled {
    -fx-background-color: #333337;
    -fx-text-fill: #666666;
    -fx-opacity: 0.7;
}

/* ========== Text Fields ========== */
.text-field {
    -fx-background-color: #333337;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 2;
    -fx-background-radius: 2;
    -fx-prompt-text-fill: #666666;
    -fx-padding: 4 6;
    -fx-font-size: 12px;
}

.text-field:focused {
    -fx-border-color: #007ACC;
    -fx-background-color: #333337;
}

.text-field:disabled {
    -fx-opacity: 0.5;
}

/* ========== Text Area ========== */
.text-area {
    -fx-background-color: #333337;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-prompt-text-fill: #666666;
    -fx-font-size: 12px;
}

.text-area .content {
    -fx-background-color: #333337;
}

.text-area:focused {
    -fx-border-color: #007ACC;
}

/* ========== Combo Box ========== */
.combo-box {
    -fx-background-color: #333337;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 2;
    -fx-background-radius: 2;
    -fx-font-size: 12px;
}

.combo-box .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: transparent;
    -fx-padding: 2 6;
}

.combo-box .arrow-button {
    -fx-background-color: transparent;
}

.combo-box .arrow {
    -fx-background-color: #AAAAAA;
}

.combo-box-popup .list-view {
    -fx-background-color: #252526;
    -fx-border-color: #434346;
}

.combo-box-popup .list-view .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: #252526;
    -fx-padding: 4 8;
}

.combo-box-popup .list-view .list-cell:hover {
    -fx-background-color: #2A2D2E;
}

.combo-box-popup .list-view .list-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

/* ========== Check Box ========== */
.check-box {
    -fx-text-fill: #CCCCCC;
}

.check-box .box {
    -fx-background-color: #333337;
    -fx-border-color: #434346;
    -fx-border-radius: 2;
    -fx-background-radius: 2;
}

.check-box:selected .box {
    -fx-background-color: #007ACC;
    -fx-border-color: #007ACC;
}

.check-box .mark {
    -fx-background-color: white;
}

/* ========== Scroll Bars ========== */
.scroll-bar {
    -fx-background-color: #1C1C1C;
}

.scroll-bar .thumb {
    -fx-background-color: #424242;
    -fx-background-radius: 4;
}

.scroll-bar .thumb:hover {
    -fx-background-color: #4F4F4F;
}

.scroll-bar .thumb:pressed {
    -fx-background-color: #5A5A5A;
}

.scroll-bar .increment-button,
.scroll-bar .decrement-button {
    -fx-background-color: transparent;
    -fx-padding: 0;
}

.scroll-bar .increment-arrow,
.scroll-bar .decrement-arrow {
    -fx-background-color: transparent;
    -fx-shape: "";
    -fx-padding: 0;
}

.scroll-bar .track {
    -fx-background-color: #1C1C1C;
}

/* ========== Scroll Pane ========== */
.scroll-pane {
    -fx-background-color: #1C1C1C;
    -fx-background: #1C1C1C;
}

.scroll-pane .viewport {
    -fx-background-color: #1C1C1C;
}

/* ========== Tree View ========== */
.tree-view {
    -fx-background-color: #1C1C1C;
    -fx-border-color: #434346;
    -fx-border-width: 1;
}

.tree-cell {
    -fx-background-color: transparent;
    -fx-text-fill: #CCCCCC;
    -fx-padding: 2 4;
    -fx-font-size: 12px;
}

.tree-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

.tree-cell:hover:!selected {
    -fx-background-color: #2A2D2E;
}

.tree-cell .arrow {
    -fx-background-color: #AAAAAA;
}

/* ========== List View ========== */
.list-view {
    -fx-background-color: #1C1C1C;
    -fx-border-color: #434346;
}

.list-cell {
    -fx-background-color: transparent;
    -fx-text-fill: #CCCCCC;
    -fx-padding: 4 8;
}

.list-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

.list-cell:hover:!selected {
    -fx-background-color: #2A2D2E;
}

/* ========== Split Pane ========== */
.split-pane {
    -fx-background-color: #1C1C1C;
    -fx-padding: 0;
}

.split-pane > .split-pane-divider {
    -fx-background-color: #434346;
    -fx-padding: 0 1 0 1;
}

/* ========== Separator ========== */
.separator .line {
    -fx-border-color: #434346;
    -fx-border-width: 1 0 0 0;
}

/* ========== Labels ========== */
.label {
    -fx-text-fill: #CCCCCC;
    -fx-font-size: 12px;
}

/* ========== Date Picker ========== */
.date-picker {
    -fx-background-color: #333337;
    -fx-border-color: #434346;
}

.date-picker .text-field {
    -fx-background-color: #333337;
}

.date-picker-popup {
    -fx-background-color: #252526;
    -fx-border-color: #434346;
}

.date-picker-popup .month-year-pane {
    -fx-background-color: #2D2D30;
}

.date-picker-popup .day-cell {
    -fx-background-color: transparent;
    -fx-text-fill: #CCCCCC;
}

.date-picker-popup .day-cell:hover {
    -fx-background-color: #3E3E42;
}

.date-picker-popup .selected {
    -fx-background-color: #007ACC;
    -fx-text-fill: white;
}

/* ========== Progress Bar ========== */
.progress-bar {
    -fx-indeterminate-bar-length: 60;
    -fx-indeterminate-bar-escape: true;
    -fx-indeterminate-bar-flip: true;
    -fx-indeterminate-bar-animation-time: 2;
}

.progress-bar > .bar {
    -fx-background-color: #007ACC;
    -fx-background-insets: 0;
    -fx-background-radius: 2;
    -fx-padding: 3;
}

.progress-bar > .track {
    -fx-background-color: #333337;
    -fx-background-insets: 0;
    -fx-background-radius: 2;
}

/* ========== Splash Screen ========== */
.splash {
    -fx-background-color: #1C1C1C;
}

.splash .progress-bar > .bar {
    -fx-background-color: #007ACC;
}

.splash .progress-bar > .track {
    -fx-background-color: #333337;
}

/* ========== Charts ========== */
.chart {
    -fx-background-color: #1C1C1C;
    -fx-padding: 5;
}

.chart-plot-background {
    -fx-background-color: #252526;
}

.chart-title {
    -fx-text-fill: #CCCCCC;
    -fx-font-size: 13px;
}

.chart-legend {
    -fx-background-color: #252526;
}

.chart-legend-item {
    -fx-text-fill: #CCCCCC;
}

.axis {
    -fx-tick-label-fill: #AAAAAA;
}

.axis-label {
    -fx-text-fill: #AAAAAA;
}

.chart-vertical-grid-lines,
.chart-horizontal-grid-lines {
    -fx-stroke: #333337;
}

.chart-alternative-row-fill {
    -fx-fill: transparent;
}

.chart-vertical-zero-line,
.chart-horizontal-zero-line {
    -fx-stroke: #434346;
}

.default-color0.chart-series-line { -fx-stroke: #007ACC; }
.default-color1.chart-series-line { -fx-stroke: #4EC9B0; }
.default-color2.chart-series-line { -fx-stroke: #CE9178; }
.default-color3.chart-series-line { -fx-stroke: #DCDCAA; }
.default-color4.chart-series-line { -fx-stroke: #C586C0; }

/* ========== Feature Locked Pane ========== */
.feature-locked {
    -fx-background-color: #252526;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 4;
    -fx-background-radius: 4;
}

.feature-locked .label {
    -fx-text-fill: #888888;
}

/* ========== Tooltip ========== */
.tooltip {
    -fx-background-color: #252526;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-font-size: 11px;
    -fx-padding: 4 8;
}

/* ========== Alert / Dialog ========== */
.dialog-pane {
    -fx-background-color: #252526;
}

.dialog-pane .content {
    -fx-text-fill: #CCCCCC;
}

.dialog-pane .header-panel {
    -fx-background-color: #2D2D30;
}

.dialog-pane .header-panel .label {
    -fx-text-fill: #CCCCCC;
}

/* ========== Grid Pane defaults ========== */
.grid-pane .label {
    -fx-text-fill: #CCCCCC;
}

/* ========== Login Dialog ========== */
.login-dialog {
    -fx-background-color: #1C1C1C;
}

