package com.sampleapp.ui.dock;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Serializable layout state for a workspace.
 * Captures tab order, active tab, visibility, and split pane divider positions.
 */
public class WorkspaceLayout {

    private int activeTabIndex;
    private List<TabLayout> tabs = new ArrayList<>();
    private Map<String, double[]> splitPaneDividers = new LinkedHashMap<>();

    public WorkspaceLayout() {}

    public int getActiveTabIndex() { return activeTabIndex; }
    public void setActiveTabIndex(int activeTabIndex) { this.activeTabIndex = activeTabIndex; }

    public List<TabLayout> getTabs() { return tabs; }
    public void setTabs(List<TabLayout> tabs) { this.tabs = tabs; }

    public Map<String, double[]> getSplitPaneDividers() { return splitPaneDividers; }
    public void setSplitPaneDividers(Map<String, double[]> splitPaneDividers) {
        this.splitPaneDividers = splitPaneDividers;
    }

    /**
     * Layout state for a single tab.
     */
    public static class TabLayout {
        private String id;
        private int order;
        private boolean visible;

        public TabLayout() {}

        public TabLayout(String id, int order, boolean visible) {
            this.id = id;
            this.order = order;
            this.visible = visible;
        }

        public String getId() { return id; }
        public void setId(String id) { this.id = id; }

        public int getOrder() { return order; }
        public void setOrder(int order) { this.order = order; }

        public boolean isVisible() { return visible; }
        public void setVisible(boolean visible) { this.visible = visible; }
    }
}

package com.sampleapp.ui.dock;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.Optional;

/**
 * Manages persistence of workspace layouts to JSON files.
 * Layouts are stored in {@code ~/.sampleapp/layouts/} as individual JSON files
 * named after the workspace (e.g., {@code CHARACTER.json}).
 *
 * <p>Uses a simple hand-written JSON serializer to avoid adding a JSON library dependency.
 */
public final class LayoutManager {

    private static final Logger log = LoggerFactory.getLogger(LayoutManager.class);

    private static final Path LAYOUTS_DIR = resolveLayoutsDir();

    private LayoutManager() {}

    private static Path resolveLayoutsDir() {
        Path base = Path.of(System.getProperty("user.home"), ".sampleapp", "layouts");
        try {
            Files.createDirectories(base);
        } catch (IOException e) {
            log.warn("Failed to create layouts directory: {}", base, e);
        }
        return base;
    }

    /**
     * Save a workspace layout to disk.
     */
    public static void saveLayout(String workspaceId, WorkspaceLayout layout) {
        Path file = LAYOUTS_DIR.resolve(workspaceId + ".json");
        try {
            String json = toJson(layout);
            Files.writeString(file, json);
            log.debug("Saved layout for workspace: {}", workspaceId);
        } catch (IOException e) {
            log.warn("Failed to save layout for workspace: {}", workspaceId, e);
        }
    }

    /**
     * Load a workspace layout from disk.
     */
    public static Optional<WorkspaceLayout> loadLayout(String workspaceId) {
        Path file = LAYOUTS_DIR.resolve(workspaceId + ".json");
        if (!Files.exists(file)) {
            return Optional.empty();
        }
        try {
            String json = Files.readString(file);
            WorkspaceLayout layout = fromJson(json);
            log.debug("Loaded layout for workspace: {}", workspaceId);
            return Optional.of(layout);
        } catch (Exception e) {
            log.warn("Failed to load layout for workspace: {} — deleting corrupt file", workspaceId, e);
            try { Files.deleteIfExists(file); } catch (IOException ignored) {}
            return Optional.empty();
        }
    }

    /**
     * Delete saved layout for a workspace, reverting to default.
     */
    public static void resetLayout(String workspaceId) {
        Path file = LAYOUTS_DIR.resolve(workspaceId + ".json");
        try {
            Files.deleteIfExists(file);
            log.info("Reset layout for workspace: {}", workspaceId);
        } catch (IOException e) {
            log.warn("Failed to reset layout for workspace: {}", workspaceId, e);
        }
    }

    /**
     * Delete all saved layouts, reverting all workspaces to default.
     */
    public static void resetAllLayouts() {
        try (var stream = Files.list(LAYOUTS_DIR)) {
            stream.filter(p -> p.toString().endsWith(".json"))
                    .forEach(p -> {
                        try { Files.deleteIfExists(p); } catch (IOException ignored) {}
                    });
            log.info("Reset all workspace layouts");
        } catch (IOException e) {
            log.warn("Failed to reset all layouts", e);
        }
    }

    // ---- Simple JSON serializer (no external dependency) ----

    private static String toJson(WorkspaceLayout layout) {
        var sb = new StringBuilder();
        sb.append("{\n");
        sb.append("  \"activeTabIndex\": ").append(layout.getActiveTabIndex()).append(",\n");

        // Tabs
        sb.append("  \"tabs\": [\n");
        var tabs = layout.getTabs();
        for (int i = 0; i < tabs.size(); i++) {
            var tab = tabs.get(i);
            sb.append("    {\"id\": ").append(jsonString(tab.getId()))
                    .append(", \"order\": ").append(tab.getOrder())
                    .append(", \"visible\": ").append(tab.isVisible())
                    .append("}");
            if (i < tabs.size() - 1) sb.append(",");
            sb.append("\n");
        }
        sb.append("  ],\n");

        // Split pane dividers
        sb.append("  \"splitPaneDividers\": {\n");
        var dividers = layout.getSplitPaneDividers();
        int j = 0;
        for (var entry : dividers.entrySet()) {
            sb.append("    ").append(jsonString(entry.getKey())).append(": [");
            double[] positions = entry.getValue();
            for (int k = 0; k < positions.length; k++) {
                sb.append(positions[k]);
                if (k < positions.length - 1) sb.append(", ");
            }
            sb.append("]");
            if (j < dividers.size() - 1) sb.append(",");
            sb.append("\n");
            j++;
        }
        sb.append("  }\n");
        sb.append("}");
        return sb.toString();
    }

    private static String jsonString(String value) {
        if (value == null) return "null";
        return "\"" + value.replace("\\", "\\\\").replace("\"", "\\\"") + "\"";
    }

    // ---- Simple JSON deserializer ----

    private static WorkspaceLayout fromJson(String json) {
        var layout = new WorkspaceLayout();
        json = json.trim();

        // Parse activeTabIndex
        int idx = json.indexOf("\"activeTabIndex\"");
        if (idx >= 0) {
            int colon = json.indexOf(':', idx);
            int end = findValueEnd(json, colon + 1);
            String val = json.substring(colon + 1, end).trim();
            layout.setActiveTabIndex(Integer.parseInt(val));
        }

        // Parse tabs array
        int tabsStart = json.indexOf("\"tabs\"");
        if (tabsStart >= 0) {
            int arrStart = json.indexOf('[', tabsStart);
            int arrEnd = findMatchingBracket(json, arrStart, '[', ']');
            String tabsJson = json.substring(arrStart + 1, arrEnd);
            layout.setTabs(parseTabs(tabsJson));
        }

        // Parse splitPaneDividers
        int divStart = json.indexOf("\"splitPaneDividers\"");
        if (divStart >= 0) {
            int objStart = json.indexOf('{', divStart);
            int objEnd = findMatchingBracket(json, objStart, '{', '}');
            String divJson = json.substring(objStart + 1, objEnd);
            layout.setSplitPaneDividers(parseDividers(divJson));
        }

        return layout;
    }

    private static ArrayList<WorkspaceLayout.TabLayout> parseTabs(String tabsJson) {
        var tabs = new ArrayList<WorkspaceLayout.TabLayout>();
        int pos = 0;
        while (pos < tabsJson.length()) {
            int objStart = tabsJson.indexOf('{', pos);
            if (objStart < 0) break;
            int objEnd = findMatchingBracket(tabsJson, objStart, '{', '}');
            String obj = tabsJson.substring(objStart + 1, objEnd);

            String id = extractStringValue(obj, "id");
            int order = extractIntValue(obj, "order", 0);
            boolean visible = extractBoolValue(obj, "visible", true);

            tabs.add(new WorkspaceLayout.TabLayout(id, order, visible));
            pos = objEnd + 1;
        }
        return tabs;
    }

    private static LinkedHashMap<String, double[]> parseDividers(String divJson) {
        var map = new LinkedHashMap<String, double[]>();
        int pos = 0;
        while (pos < divJson.length()) {
            int keyStart = divJson.indexOf('"', pos);
            if (keyStart < 0) break;
            int keyEnd = divJson.indexOf('"', keyStart + 1);
            String key = divJson.substring(keyStart + 1, keyEnd);

            int arrStart = divJson.indexOf('[', keyEnd);
            int arrEnd = findMatchingBracket(divJson, arrStart, '[', ']');
            String arrContent = divJson.substring(arrStart + 1, arrEnd).trim();

            if (!arrContent.isEmpty()) {
                String[] parts = arrContent.split(",");
                double[] values = new double[parts.length];
                for (int i = 0; i < parts.length; i++) {
                    values[i] = Double.parseDouble(parts[i].trim());
                }
                map.put(key, values);
            } else {
                map.put(key, new double[0]);
            }
            pos = arrEnd + 1;
        }
        return map;
    }

    private static String extractStringValue(String json, String key) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return null;
        int colon = json.indexOf(':', idx);
        int valStart = json.indexOf('"', colon + 1);
        int valEnd = json.indexOf('"', valStart + 1);
        return json.substring(valStart + 1, valEnd);
    }

    private static int extractIntValue(String json, String key, int defaultValue) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return defaultValue;
        int colon = json.indexOf(':', idx);
        int end = findValueEnd(json, colon + 1);
        try {
            return Integer.parseInt(json.substring(colon + 1, end).trim());
        } catch (NumberFormatException e) {
            return defaultValue;
        }
    }

    private static boolean extractBoolValue(String json, String key, boolean defaultValue) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return defaultValue;
        int colon = json.indexOf(':', idx);
        int end = findValueEnd(json, colon + 1);
        String val = json.substring(colon + 1, end).trim();
        return "true".equalsIgnoreCase(val);
    }

    private static int findValueEnd(String json, int from) {
        int i = from;
        while (i < json.length()) {
            char c = json.charAt(i);
            if (c == ',' || c == '}' || c == ']') return i;
            i++;
        }
        return json.length();
    }

    private static int findMatchingBracket(String json, int openPos, char open, char close) {
        int depth = 1;
        boolean inString = false;
        for (int i = openPos + 1; i < json.length(); i++) {
            char c = json.charAt(i);
            if (c == '"' && (i == 0 || json.charAt(i - 1) != '\\')) {
                inString = !inString;
            } else if (!inString) {
                if (c == open) depth++;
                else if (c == close) {
                    depth--;
                    if (depth == 0) return i;
                }
            }
        }
        return json.length() - 1;
    }
}

