package com.sampleapp.ui.dock;

import javafx.collections.ListChangeListener;
import javafx.geometry.Point2D;
import javafx.scene.Node;
import javafx.scene.control.*;
import javafx.scene.input.ClipboardContent;
import javafx.scene.input.Dragboard;
import javafx.scene.input.TransferMode;

import java.util.ArrayList;
import java.util.List;

/**
 * Enhanced TabPane that supports drag-and-drop tab reordering and
 * a right-click context menu with layout options.
 *
 * <p>Tabs can be reordered by dragging them left/right within the header area.
 * A context menu allows hiding tabs, resetting layout, and toggling tab visibility.
 */
public class DockableTabPane extends TabPane {

    private static final String DRAG_TAB_FORMAT = "dockable-tab-drag";

    private Tab draggedTab;
    private Runnable onLayoutChanged;

    public DockableTabPane() {
        setTabClosingPolicy(TabClosingPolicy.UNAVAILABLE);
        getStyleClass().add("dockable-tab-pane");

        // Install drag handlers on each tab's header when tabs are added
        getTabs().addListener((ListChangeListener<Tab>) change -> {
            while (change.next()) {
                if (change.wasAdded()) {
                    for (Tab tab : change.getAddedSubList()) {
                        installDragHandlers(tab);
                        installContextMenu(tab);
                    }
                }
            }
        });

        // Track selection changes as layout changes
        getSelectionModel().selectedItemProperty().addListener((obs, oldTab, newTab) -> {
            if (onLayoutChanged != null && newTab != null) {
                onLayoutChanged.run();
            }
        });
    }

    /**
     * Set a callback invoked whenever the layout changes (tab reorder, visibility, selection).
     */
    public void setOnLayoutChanged(Runnable callback) {
        this.onLayoutChanged = callback;
    }

    private void installDragHandlers(Tab tab) {
        // We need to get the tab header node. TabPane doesn't expose headers directly,
        // so we use a lookup after the node is rendered.
        tab.contentProperty().addListener((obs, oldContent, newContent) -> {
            // Trigger lookup on next pulse
            if (newContent != null) {
                setupDragOnTabHeader(tab);
            }
        });

        // Also try immediately in case content is already set
        if (tab.getContent() != null) {
            setupDragOnTabHeader(tab);
        }
    }

    private void setupDragOnTabHeader(Tab tab) {
        // Defer to ensure the scene graph is ready
        this.sceneProperty().addListener((obs, oldScene, newScene) -> {
            if (newScene != null) {
                configureDragForTab(tab);
            }
        });

        if (getScene() != null) {
            configureDragForTab(tab);
        }
    }

    private void configureDragForTab(Tab tab) {
        // Look up the tab header node using CSS lookup
        // Tab headers have the style class "tab"
        this.applyCss();
        this.layout();

        Node tabHeader = findTabHeader(tab);
        if (tabHeader == null) return;

        tabHeader.setOnDragDetected(event -> {
            draggedTab = tab;
            Dragboard db = tabHeader.startDragAndDrop(TransferMode.MOVE);
            ClipboardContent content = new ClipboardContent();
            content.putString(DRAG_TAB_FORMAT + ":" + tab.getText());
            db.setContent(content);
            event.consume();
        });

        tabHeader.setOnDragOver(event -> {
            if (draggedTab != null && draggedTab != tab
                    && event.getDragboard().hasString()
                    && event.getDragboard().getString().startsWith(DRAG_TAB_FORMAT)) {
                event.acceptTransferModes(TransferMode.MOVE);
            }
            event.consume();
        });

        tabHeader.setOnDragDropped(event -> {
            if (draggedTab != null && draggedTab != tab) {
                List<Tab> tabs = new ArrayList<>(getTabs());
                int draggedIdx = tabs.indexOf(draggedTab);
                int targetIdx = tabs.indexOf(tab);

                if (draggedIdx >= 0 && targetIdx >= 0) {
                    tabs.remove(draggedIdx);
                    tabs.add(targetIdx, draggedTab);
                    getTabs().setAll(tabs);
                    getSelectionModel().select(draggedTab);
                    if (onLayoutChanged != null) {
                        onLayoutChanged.run();
                    }
                }
            }
            event.setDropCompleted(true);
            event.consume();
        });

        tabHeader.setOnDragDone(event -> {
            draggedTab = null;
            event.consume();
        });
    }

    private Node findTabHeader(Tab tab) {
        // Look up all tab headers in this TabPane
        for (Node node : lookupAll(".tab")) {
            // Match by label text
            Node labelNode = node.lookup(".tab-label");
            if (labelNode instanceof Labeled labeled) {
                if (tab.getText() != null && tab.getText().equals(labeled.getText())) {
                    return node;
                }
            }
        }
        return null;
    }

    private void installContextMenu(Tab tab) {
        var menu = new ContextMenu();

        // Hide tab
        var hideItem = new MenuItem("Hide Tab");
        hideItem.setOnAction(e -> {
            if (getTabs().size() > 1) {
                getTabs().remove(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        // Move left
        var moveLeftItem = new MenuItem("Move Left");
        moveLeftItem.setOnAction(e -> {
            int idx = getTabs().indexOf(tab);
            if (idx > 0) {
                getTabs().remove(idx);
                getTabs().add(idx - 1, tab);
                getSelectionModel().select(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        // Move right
        var moveRightItem = new MenuItem("Move Right");
        moveRightItem.setOnAction(e -> {
            int idx = getTabs().indexOf(tab);
            if (idx >= 0 && idx < getTabs().size() - 1) {
                getTabs().remove(idx);
                getTabs().add(idx + 1, tab);
                getSelectionModel().select(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        menu.getItems().addAll(moveLeftItem, moveRightItem, new SeparatorMenuItem(), hideItem);
        tab.setContextMenu(menu);
    }

    /**
     * Get the tab ordering as a list of tab text/IDs.
     */
    public List<String> getTabOrder() {
        return getTabs().stream().map(Tab::getText).toList();
    }
}

