                List<Tab> tabs = new ArrayList<>(getTabs());
                int draggedIdx = tabs.indexOf(draggedTab);
                int targetIdx = tabs.indexOf(tab);

                if (draggedIdx >= 0 && targetIdx >= 0) {
                    tabs.remove(draggedIdx);
                    tabs.add(targetIdx, draggedTab);
                    getTabs().setAll(tabs);
                    getSelectionModel().select(draggedTab);
                    if (onLayoutChanged != null) {
                        onLayoutChanged.run();
                    }
                }
            }
            event.setDropCompleted(true);
            event.consume();
        });

        tabHeader.setOnDragDone(event -> {
            draggedTab = null;
            event.consume();
        });
    }

    private Node findTabHeader(Tab tab) {
        // Look up all tab headers in this TabPane
        for (Node node : lookupAll(".tab")) {
            // Match by label text
            Node labelNode = node.lookup(".tab-label");
            if (labelNode instanceof Labeled labeled) {
                if (tab.getText() != null && tab.getText().equals(labeled.getText())) {
                    return node;
                }
            }
        }
        return null;
    }

    private void installContextMenu(Tab tab) {
        var menu = new ContextMenu();

        // Hide tab
        var hideItem = new MenuItem("Hide Tab");
        hideItem.setOnAction(e -> {
            if (getTabs().size() > 1) {
                getTabs().remove(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        // Move left
        var moveLeftItem = new MenuItem("Move Left");
        moveLeftItem.setOnAction(e -> {
            int idx = getTabs().indexOf(tab);
            if (idx > 0) {
                getTabs().remove(idx);
                getTabs().add(idx - 1, tab);
                getSelectionModel().select(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        // Move right
        var moveRightItem = new MenuItem("Move Right");
        moveRightItem.setOnAction(e -> {
            int idx = getTabs().indexOf(tab);
            if (idx >= 0 && idx < getTabs().size() - 1) {
                getTabs().remove(idx);
                getTabs().add(idx + 1, tab);
                getSelectionModel().select(tab);
                if (onLayoutChanged != null) {
                    onLayoutChanged.run();
                }
            }
        });

        menu.getItems().addAll(moveLeftItem, moveRightItem, new SeparatorMenuItem(), hideItem);
        tab.setContextMenu(menu);
    }

    /**
     * Get the tab ordering as a list of tab text/IDs.
     */
    public List<String> getTabOrder() {
        return getTabs().stream().map(Tab::getText).toList();
    }
}

