package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.ui.dock.DockableTabPane;
import com.sampleapp.ui.dock.LayoutManager;
import com.sampleapp.ui.dock.WorkspaceLayout;
import javafx.scene.control.SplitPane;
import javafx.scene.control.Tab;
import javafx.scene.control.TabPane;
import javafx.scene.layout.BorderPane;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.*;

/**
 * Abstract base class for all workspace panels.
 * Each workspace contains a DockableTabPane for organizing its sub-panels
 * with support for tab reordering and layout persistence.
 */
public abstract class Workspace extends BorderPane {

    protected final Logger log = LoggerFactory.getLogger(getClass());
    protected final AppState appState;
    protected final TabPane tabPane;

    /**
     * Registered split panes whose divider positions are persisted.
     * Key is a stable identifier (e.g., "main-split"), value is the SplitPane instance.
     */
    private final Map<String, SplitPane> trackedSplitPanes = new LinkedHashMap<>();

    /**
     * Original tab list for layout reset. Populated after constructor finishes.
     */
    private List<Tab> defaultTabOrder;

    protected Workspace(AppState appState) {
        this.appState = appState;

        var dockable = new DockableTabPane();
        dockable.setOnLayoutChanged(this::onLayoutDirty);
        this.tabPane = dockable;

        setCenter(tabPane);

        // Listen for character changes
        appState.selectedCharacterIdProperty().addListener(
                (obs, oldVal, newVal) -> onCharacterChanged(newVal.intValue()));
    }

    /**
     * @return display title for this workspace
     */
    public abstract String getTitle();

    /**
     * Called when this workspace becomes the active/visible workspace.
     */
    public abstract void onActivated();

    /**
     * Called when the selected character changes.
     *
     * @param characterId the newly selected character ID, or -1 if none
     */
    public abstract void onCharacterChanged(int characterId);

    // ---- Layout persistence ----

    /**
     * Returns a stable identifier for this workspace, used as the layout file name.
     * Defaults to the simple class name. Subclasses may override.
     */
    public String getWorkspaceId() {
        return getClass().getSimpleName();
    }

    /**
     * Register a SplitPane whose divider positions should be persisted.
     * Call this in the subclass constructor after creating the SplitPane.
     *
     * @param id a stable identifier for this split pane (unique within the workspace)
     * @param splitPane the SplitPane to track
     */
    protected void registerSplitPane(String id, SplitPane splitPane) {
        trackedSplitPanes.put(id, splitPane);

        // Track divider changes
        splitPane.getDividers().forEach(divider ->
                divider.positionProperty().addListener((obs, oldVal, newVal) -> onLayoutDirty()));
    }

    /**
     * Save the current layout state to disk.
     */
    public void saveLayout() {
        try {
            var layout = captureLayout();
            LayoutManager.saveLayout(getWorkspaceId(), layout);
        } catch (Exception e) {
            log.debug("Failed to save layout for {}", getWorkspaceId(), e);
        }
    }

    /**
     * Restore layout from disk if a saved layout exists.
     * Call this after the workspace is fully constructed (all tabs and split panes added).
     */
    public void restoreLayout() {
        // Capture default tab order on first call
        if (defaultTabOrder == null) {
            defaultTabOrder = new ArrayList<>(tabPane.getTabs());
        }

        LayoutManager.loadLayout(getWorkspaceId()).ifPresent(layout -> {
            try {
                applyLayout(layout);
                log.debug("Restored layout for {}", getWorkspaceId());
            } catch (Exception e) {
                log.debug("Failed to restore layout for {}, using default", getWorkspaceId(), e);
            }
        });
    }

    /**
     * Reset this workspace's layout to the default.
     */
    public void resetLayout() {
        LayoutManager.resetLayout(getWorkspaceId());
        if (defaultTabOrder != null) {
            tabPane.getTabs().setAll(defaultTabOrder);
            if (!defaultTabOrder.isEmpty()) {
                tabPane.getSelectionModel().select(0);
            }
        }
        // Reset split pane dividers by not restoring anything
        log.info("Reset layout for {}", getWorkspaceId());
    }

    private WorkspaceLayout captureLayout() {
        var layout = new WorkspaceLayout();

        // Active tab
        layout.setActiveTabIndex(tabPane.getSelectionModel().getSelectedIndex());

        // Tab order and visibility
        var tabLayouts = new ArrayList<WorkspaceLayout.TabLayout>();
        for (int i = 0; i < tabPane.getTabs().size(); i++) {
            Tab tab = tabPane.getTabs().get(i);
            String id = tab.getText() != null ? tab.getText() : "tab-" + i;
            tabLayouts.add(new WorkspaceLayout.TabLayout(id, i, true));
        }
        layout.setTabs(tabLayouts);

        // Split pane dividers
        var dividers = new LinkedHashMap<String, double[]>();
        for (var entry : trackedSplitPanes.entrySet()) {
            SplitPane sp = entry.getValue();
            double[] positions = sp.getDividerPositions();
            dividers.put(entry.getKey(), Arrays.copyOf(positions, positions.length));
        }
        layout.setSplitPaneDividers(dividers);

        return layout;
    }

    private void applyLayout(WorkspaceLayout layout) {
        // Restore tab order
        if (!layout.getTabs().isEmpty() && !tabPane.getTabs().isEmpty()) {
            var tabsByName = new LinkedHashMap<String, Tab>();
            for (Tab tab : tabPane.getTabs()) {
                if (tab.getText() != null) {
                    tabsByName.put(tab.getText(), tab);
                }
            }

            // Sort by saved order
            var sorted = new ArrayList<>(layout.getTabs());
            sorted.sort(Comparator.comparingInt(WorkspaceLayout.TabLayout::getOrder));

            var reordered = new ArrayList<Tab>();
            for (var tabLayout : sorted) {
                Tab tab = tabsByName.remove(tabLayout.getId());
                if (tab != null && tabLayout.isVisible()) {
                    reordered.add(tab);
                }
            }
            // Add any tabs not in the saved layout (new tabs added since save)
            reordered.addAll(tabsByName.values());

            if (!reordered.isEmpty()) {
                tabPane.getTabs().setAll(reordered);
            }
        }

        // Restore active tab
        int activeIdx = layout.getActiveTabIndex();
        if (activeIdx >= 0 && activeIdx < tabPane.getTabs().size()) {
            tabPane.getSelectionModel().select(activeIdx);
        }

        // Restore split pane dividers
        for (var entry : layout.getSplitPaneDividers().entrySet()) {
            SplitPane sp = trackedSplitPanes.get(entry.getKey());
            if (sp != null) {
                double[] positions = entry.getValue();
                // Defer to ensure the split pane is laid out
                javafx.application.Platform.runLater(() -> sp.setDividerPositions(positions));
            }
        }
    }

    /**
     * Called when any tracked layout property changes.
     * Debounced — saves happen when the workspace is deactivated.
     */
    private void onLayoutDirty() {
        // Layout is saved when workspace is switched away from (in WorkspaceContainer)
        // No immediate save to avoid disk thrashing during drag operations
    }
}

