package com.sampleapp.ui;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.ui.NavigationBar.WorkspaceType;
import com.sampleapp.ui.workspace.*;
import javafx.scene.layout.StackPane;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.EnumMap;
import java.util.Map;

/**
 * Center panel manager that lazy-creates and caches workspace instances.
 * Only one workspace is visible at a time.
 * Saves workspace layout when switching away, restores when activating.
 */
public class WorkspaceContainer extends StackPane {

    private static final Logger log = LoggerFactory.getLogger(WorkspaceContainer.class);

    private final Map<WorkspaceType, Workspace> workspaces = new EnumMap<>(WorkspaceType.class);
    private final AppState appState;
    private final FeatureGate featureGate;
    private final AppServices appServices;
    private WorkspaceType currentType;

    public WorkspaceContainer(AppState appState, FeatureGate featureGate, AppServices appServices) {
        this.appState = appState;
        this.featureGate = featureGate;
        this.appServices = appServices;
        getStyleClass().add("workspace-container");
    }

    /**
     * Show the workspace for the given type. Creates the workspace on first access.
     * Saves the current workspace layout before switching.
     */
    public void showWorkspace(WorkspaceType type) {
        // Save current workspace layout before switching
        if (currentType != null) {
            Workspace current = workspaces.get(currentType);
            if (current != null) {
                current.saveLayout();
            }
        }

        boolean isNew = !workspaces.containsKey(type);
        var workspace = workspaces.computeIfAbsent(type, this::createWorkspace);

        // Hide all, show selected
        getChildren().forEach(node -> node.setVisible(false));
        if (!getChildren().contains(workspace)) {
            getChildren().add(workspace);
        }
        workspace.setVisible(true);

        // Restore layout on first show (after creation)
        if (isNew) {
            workspace.restoreLayout();
        }

        workspace.onActivated();
        currentType = type;

        log.debug("Showing workspace: {} ({})", type, workspace.getTitle());
    }

    /**
     * Save the current workspace's layout. Called on application shutdown.
     */
    public void saveCurrentLayout() {
        if (currentType != null) {
            Workspace current = workspaces.get(currentType);
            if (current != null) {
                current.saveLayout();
            }
        }
    }

    /**
     * Reset layout for all cached workspaces.
     */
    public void resetAllLayouts() {
        com.sampleapp.ui.dock.LayoutManager.resetAllLayouts();
        for (Workspace workspace : workspaces.values()) {
            workspace.resetLayout();
        }
    }

    private Workspace createWorkspace(WorkspaceType type) {
        log.info("Creating workspace: {}", type);
        return switch (type) {
            case CHARACTER -> new CharacterWorkspace(appState, appServices);
            case SKILLS -> new SkillsWorkspace(appState, appServices);
            case ASSETS -> new AssetsWorkspace(appState, appServices);
            case MARKET -> new MarketWorkspace(appState, featureGate, appServices.getWorkspaceDataService());
            case MARKET_ORDERS -> new MarketOrdersWorkspace(appState, appServices);
            case WALLET -> new WalletWorkspace(appState, featureGate, appServices);
            case CONTRACTS -> new ContractsWorkspace(appState, featureGate, appServices);
            case PUBLIC_CONTRACTS -> new PublicContractsWorkspace(appState, appServices.getWorkspaceDataService());
            case INDUSTRY -> new IndustryWorkspace(appState, featureGate, appServices.getWorkspaceDataService());
            case ACCOUNTING -> new AccountingWorkspace(appState, appServices.getWorkspaceDataService());
            case TRADER -> new TraderWorkspace(appState, featureGate, appServices.getWorkspaceDataService());
            case TOOLS -> new ToolsWorkspace(appState, appServices.getWorkspaceDataService());
            case FLEET -> new FleetWorkspace(appState, appServices.getWorkspaceDataService());
            case LP_STORE -> new LpStoreWorkspace(appState, appServices.getWorkspaceDataService());
            case UNIVERSE_BROWSER -> new UniverseBrowserWorkspace(appState, appServices.getWorkspaceDataService());
            case SETTINGS -> new SettingsWorkspace(appState, appServices);
        };
    }
}

