/*
 * Sample App Dark Theme
 * Matches the original application's dark color scheme.
 * Primary background: #1C1C1C
 * Secondary background: #252526
 * Tertiary background: #2D2D30
 * Accent: #007ACC
 * Text: #CCCCCC
 * Muted text: #888888
 */

/* ========== Root ========== */
.root {
    -fx-base: #1C1C1C;
    -fx-background: #1C1C1C;
    -fx-control-inner-background: #252526;
    -fx-accent: #007ACC;
    -fx-focus-color: #007ACC;
    -fx-faint-focus-color: transparent;
    -fx-text-fill: #CCCCCC;
    -fx-font-family: "Segoe UI";
    -fx-font-size: 12px;
}

/* ========== Main Window ========== */
.main-window {
    -fx-background-color: #1C1C1C;
}

/* ========== Navigation Bar ========== */
.nav-bar {
    -fx-background-color: #2D2D30;
    -fx-pref-width: 180;
    -fx-min-width: 180;
    -fx-max-width: 180;
    -fx-padding: 8 6;
    -fx-spacing: 2;
}

/* Section labels (CHARACTER, NAVIGATION) */
.nav-section-label {
    -fx-text-fill: #888888;
    -fx-font-size: 10px;
    -fx-font-weight: bold;
    -fx-padding: 4 4 2 4;
}

/* Wide nav buttons with icon + text */
.nav-button-wide {
    -fx-background-color: transparent;
    -fx-text-fill: #AAAAAA;
    -fx-font-size: 12px;
    -fx-background-radius: 4;
    -fx-cursor: hand;
    -fx-padding: 4 8;
    -fx-alignment: center-left;
}

.nav-button-wide:hover {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #FFFFFF;
}

.nav-button-wide:pressed {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.nav-button-wide.nav-button-selected {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.nav-separator {
    -fx-padding: 4 0;
}

.nav-separator .line {
    -fx-border-color: #434346;
    -fx-border-width: 1 0 0 0;
}

/* ========== Character Picker (wide) ========== */
.char-picker-wide {
    -fx-background-color: #3E3E42;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 4;
    -fx-background-radius: 4;
    -fx-pref-height: 30;
    -fx-font-size: 12px;
    -fx-cursor: hand;
}

.char-picker-wide .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: transparent;
    -fx-padding: 2 6;
}

.char-picker-wide .arrow-button {
    -fx-background-color: transparent;
}

.char-picker-wide .arrow {
    -fx-background-color: #AAAAAA;
}

.char-picker-wide:hover {
    -fx-background-color: #505050;
    -fx-border-color: #007ACC;
}

.char-picker-wide:showing {
    -fx-background-color: #007ACC;
}

.char-picker-wide:showing .list-cell {
    -fx-text-fill: #FFFFFF;
}

/* Add Character button */
.nav-add-char-button {
    -fx-background-color: transparent;
    -fx-text-fill: #4EC9B0;
    -fx-font-size: 11px;
    -fx-background-radius: 4;
    -fx-cursor: hand;
    -fx-padding: 4 8;
    -fx-alignment: center-left;
}

.nav-add-char-button:hover {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #FFFFFF;
}

/* ========== Workspace Container ========== */
.workspace-container {
    -fx-background-color: #1C1C1C;
}

/* ========== Tab Pane ========== */
.tab-pane {
    -fx-tab-min-height: 28;
    -fx-tab-max-height: 28;
}

.tab-pane > .tab-header-area {
    -fx-background-color: #2D2D30;
    -fx-padding: 0;
}

.tab-pane > .tab-header-area > .headers-region > .tab {
    -fx-background-color: #2D2D30;
    -fx-background-insets: 0;
    -fx-background-radius: 0;
    -fx-padding: 4 12;
}

.tab-pane > .tab-header-area > .headers-region > .tab .tab-label {
    -fx-text-fill: #AAAAAA;
    -fx-font-size: 12px;
}

.tab-pane > .tab-header-area > .headers-region > .tab:selected {
    -fx-background-color: #1C1C1C;
}

.tab-pane > .tab-header-area > .headers-region > .tab:selected .tab-label {
    -fx-text-fill: #FFFFFF;
}

.tab-pane > .tab-header-area > .headers-region > .tab:hover:!selected {
    -fx-background-color: #3E3E42;
}

.tab-pane > .tab-header-area > .headers-region > .tab:hover:!selected .tab-label {
    -fx-text-fill: #CCCCCC;
}

.tab-pane > .tab-header-area > .tab-header-background {
    -fx-background-color: #2D2D30;
}

.tab-pane > .tab-content-area {
    -fx-background-color: #1C1C1C;
    -fx-padding: 0;
}

/* ========== Table View ========== */
.table-view {
    -fx-background-color: #1C1C1C;
    -fx-border-color: #434346;
    -fx-border-width: 1;
}

.table-view .filler {
    -fx-background-color: #2D2D30;
}

.table-view .column-header {
    -fx-background-color: #2D2D30;
    -fx-border-color: #434346;
    -fx-border-width: 0 1 1 0;
    -fx-padding: 4 8;
}

.table-view .column-header .label {
    -fx-text-fill: #CCCCCC;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
}

.table-view .column-header-background {
    -fx-background-color: #2D2D30;
}

.table-row-cell {
    -fx-background-color: #1C1C1C;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: transparent;
    -fx-cell-size: 24;
}

.table-row-cell:odd {
