.table-row-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

.table-row-cell:hover:!selected {
    -fx-background-color: #2A2D2E;
}

.table-cell {
    -fx-text-fill: #CCCCCC;
    -fx-padding: 2 6;
    -fx-font-size: 11px;
}

.table-row-cell:selected .table-cell {
    -fx-text-fill: #FFFFFF;
}

.table-view .placeholder .label {
    -fx-text-fill: #666666;
}

/* ========== Status Bar ========== */
.status-bar {
    -fx-background-color: #007ACC;
    -fx-padding: 2 10;
    -fx-pref-height: 24;
    -fx-min-height: 24;
    -fx-max-height: 24;
    -fx-spacing: 10;
}

.status-bar .label,
.status-bar-label {
    -fx-text-fill: white;
    -fx-font-size: 11px;
}

.status-bar-separator {
    -fx-background-color: rgba(255, 255, 255, 0.3);
}

/* ========== Buttons ========== */
.button {
    -fx-background-color: #3E3E42;
    -fx-text-fill: #CCCCCC;
    -fx-background-radius: 2;
    -fx-border-radius: 2;
    -fx-padding: 4 12;
    -fx-cursor: hand;
    -fx-font-size: 12px;
}

.button:hover {
    -fx-background-color: #505050;
    -fx-text-fill: #FFFFFF;
}

.button:pressed {
    -fx-background-color: #007ACC;
    -fx-text-fill: #FFFFFF;
}

.button:focused {
    -fx-border-color: #007ACC;
    -fx-border-width: 1;
}

.button:disabled {
    -fx-background-color: #333337;
    -fx-text-fill: #666666;
    -fx-opacity: 0.7;
}

/* ========== Text Fields ========== */
.text-field {
    -fx-background-color: #333337;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 2;
    -fx-background-radius: 2;
    -fx-prompt-text-fill: #666666;
    -fx-padding: 4 6;
    -fx-font-size: 12px;
}

.text-field:focused {
    -fx-border-color: #007ACC;
    -fx-background-color: #333337;
}

.text-field:disabled {
    -fx-opacity: 0.5;
}

/* ========== Text Area ========== */
.text-area {
    -fx-background-color: #333337;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-prompt-text-fill: #666666;
    -fx-font-size: 12px;
}

.text-area .content {
    -fx-background-color: #333337;
}

.text-area:focused {
    -fx-border-color: #007ACC;
}

/* ========== Combo Box ========== */
.combo-box {
    -fx-background-color: #333337;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 2;
    -fx-background-radius: 2;
    -fx-font-size: 12px;
}

.combo-box .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: transparent;
    -fx-padding: 2 6;
}

.combo-box .arrow-button {
    -fx-background-color: transparent;
}

.combo-box .arrow {
    -fx-background-color: #AAAAAA;
}

.combo-box-popup .list-view {
    -fx-background-color: #252526;
    -fx-border-color: #434346;
}

.combo-box-popup .list-view .list-cell {
    -fx-text-fill: #CCCCCC;
    -fx-background-color: #252526;
    -fx-padding: 4 8;
}

.combo-box-popup .list-view .list-cell:hover {
    -fx-background-color: #2A2D2E;
}

.combo-box-popup .list-view .list-cell:selected {
    -fx-background-color: #264F78;
    -fx-text-fill: #FFFFFF;
}

/* ========== Check Box ========== */
