    -fx-background-color: #252526;
}

.chart-title {
    -fx-text-fill: #CCCCCC;
    -fx-font-size: 13px;
}

.chart-legend {
    -fx-background-color: #252526;
}

.chart-legend-item {
    -fx-text-fill: #CCCCCC;
}

.axis {
    -fx-tick-label-fill: #AAAAAA;
}

.axis-label {
    -fx-text-fill: #AAAAAA;
}

.chart-vertical-grid-lines,
.chart-horizontal-grid-lines {
    -fx-stroke: #333337;
}

.chart-alternative-row-fill {
    -fx-fill: transparent;
}

.chart-vertical-zero-line,
.chart-horizontal-zero-line {
    -fx-stroke: #434346;
}

.default-color0.chart-series-line { -fx-stroke: #007ACC; }
.default-color1.chart-series-line { -fx-stroke: #4EC9B0; }
.default-color2.chart-series-line { -fx-stroke: #CE9178; }
.default-color3.chart-series-line { -fx-stroke: #DCDCAA; }
.default-color4.chart-series-line { -fx-stroke: #C586C0; }

/* ========== Feature Locked Pane ========== */
.feature-locked {
    -fx-background-color: #252526;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-border-radius: 4;
    -fx-background-radius: 4;
}

.feature-locked .label {
    -fx-text-fill: #888888;
}

/* ========== Tooltip ========== */
.tooltip {
    -fx-background-color: #252526;
    -fx-text-fill: #CCCCCC;
    -fx-border-color: #434346;
    -fx-border-width: 1;
    -fx-font-size: 11px;
    -fx-padding: 4 8;
}

/* ========== Alert / Dialog ========== */
.dialog-pane {
    -fx-background-color: #252526;
}

.dialog-pane .content {
    -fx-text-fill: #CCCCCC;
}

.dialog-pane .header-panel {
    -fx-background-color: #2D2D30;
}

.dialog-pane .header-panel .label {
    -fx-text-fill: #CCCCCC;
}

/* ========== Grid Pane defaults ========== */
.grid-pane .label {
    -fx-text-fill: #CCCCCC;
}

/* ========== Login Dialog ========== */
.login-dialog {
    -fx-background-color: #1C1C1C;
}

