package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppConfig;
import com.sampleapp.core.app.AppState;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleStringProperty;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.scene.text.Font;
import javafx.scene.text.FontWeight;

/**
 * Settings workspace with 5 tabs: Account, Sync Settings, Market Config, Display, About.
 */
public class SettingsWorkspace extends Workspace {

    private final AppServices appServices;
    private TableView<AppState.CharacterInfo> charTable;

    public SettingsWorkspace(AppState appState, AppServices appServices) {
        super(appState);
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createAccountTab(),
                createSyncSettingsTab(),
                createMarketConfigTab(),
                createDisplayTab(),
                createAboutTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createAccountTab() {
        var tab = new Tab("Account");
        var vbox = new VBox(15);
        vbox.setPadding(new Insets(15));

        // Character management
        var charLabel = createSectionLabel("Characters");
        charTable = new TableView<>(appState.getCharacters());

        var nameCol = new TableColumn<AppState.CharacterInfo, String>("Name");
        nameCol.setPrefWidth(200);
        nameCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().name()));

        var corpCol = new TableColumn<AppState.CharacterInfo, String>("Corporation");
        corpCol.setPrefWidth(200);
        corpCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().corporationName()));

        var allianceCol = new TableColumn<AppState.CharacterInfo, String>("Alliance");
        allianceCol.setPrefWidth(200);
        allianceCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().allianceName()));

        var statusCol = new TableColumn<AppState.CharacterInfo, String>("Status");
        statusCol.setPrefWidth(100);
        statusCol.setCellValueFactory(cd -> new SimpleStringProperty("Active"));

        charTable.getColumns().addAll(nameCol, corpCol, allianceCol, statusCol);
        charTable.setPrefHeight(200);
        charTable.setPlaceholder(new Label("No characters added"));

        var charBtnBox = new HBox(10);
        var addCharBtn = new Button("Add Character (EVE SSO)");
        var removeCharBtn = new Button("Remove Selected");
        var refreshTokenBtn = new Button("Refresh Token");

        // Wire Add Character button
        addCharBtn.setOnAction(e -> {
            addCharBtn.setDisable(true);
            addCharBtn.setText("Waiting for SSO...");
            appServices.addCharacter()
                    .thenAccept(charId -> Platform.runLater(() -> {
                        addCharBtn.setDisable(false);
                        addCharBtn.setText("Add Character (EVE SSO)");
                        log.info("Character {} added successfully", charId);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            addCharBtn.setDisable(false);
                            addCharBtn.setText("Add Character (EVE SSO)");
                            var alert = new Alert(Alert.AlertType.ERROR,
                                    "Failed to add character:\n" + ex.getMessage());
                            alert.setTitle("EVE SSO Error");
                            alert.setHeaderText("Login Failed");
                            alert.showAndWait();
                        });
                        return null;
                    });
        });

        // Wire Remove Character button
        removeCharBtn.setOnAction(e -> {
            var selected = charTable.getSelectionModel().getSelectedItem();
            if (selected == null) {
                new Alert(Alert.AlertType.WARNING, "Please select a character to remove.").showAndWait();
                return;
            }
            var confirm = new Alert(Alert.AlertType.CONFIRMATION,
                    "Remove character \"" + selected.name() + "\"?\n" +
                            "This will delete all local data for this character.");
            confirm.setTitle("Confirm Removal");
            confirm.setHeaderText("Remove Character");
            confirm.showAndWait().ifPresent(result -> {
                if (result == ButtonType.OK) {
                    appServices.removeCharacter(selected.characterId());
                    log.info("Character {} removed", selected.name());
                }
            });
        });

        // Wire Refresh Token button
        refreshTokenBtn.setOnAction(e -> {
            var selected = charTable.getSelectionModel().getSelectedItem();
            if (selected == null) {
                new Alert(Alert.AlertType.WARNING, "Please select a character.").showAndWait();
                return;
            }
            refreshTokenBtn.setDisable(true);
            refreshTokenBtn.setText("Refreshing...");
            appServices.refreshCharacterToken(selected.characterId())
                    .thenRun(() -> Platform.runLater(() -> {
                        refreshTokenBtn.setDisable(false);
                        refreshTokenBtn.setText("Refresh Token");
                        new Alert(Alert.AlertType.INFORMATION, "Token refreshed successfully.").showAndWait();
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            refreshTokenBtn.setDisable(false);
                            refreshTokenBtn.setText("Refresh Token");
                            new Alert(Alert.AlertType.ERROR,
                                    "Failed to refresh token:\n" + ex.getMessage()).showAndWait();
                        });
                        return null;
                    });
        });

        charBtnBox.getChildren().addAll(addCharBtn, removeCharBtn, refreshTokenBtn);

        // Subscription
        var subLabel = createSectionLabel("Subscription");
        var subGrid = new GridPane();
        subGrid.setHgap(10);
        subGrid.setVgap(8);
        subGrid.add(new Label("Current Tier:"), 0, 0);
        var tierLabel = new Label("--");
        tierLabel.setStyle("-fx-text-fill: #4EC9B0; -fx-font-weight: bold;");
        tierLabel.textProperty().bind(appState.subscriptionTierProperty());
        subGrid.add(tierLabel, 1, 0);
        subGrid.add(new Label("Features:"), 0, 1);
        subGrid.add(new Label("--"), 1, 1);

        vbox.getChildren().addAll(charLabel, charTable, charBtnBox,
                new Separator(), subLabel, subGrid);
        tab.setContent(new ScrollPane(vbox));
        return tab;
    }

    private Tab createSyncSettingsTab() {
        var tab = new Tab("Sync Settings");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));
