    private Tab createDisplayTab() {
        var tab = new Tab("Display");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));
        var config = appServices.getAppConfig();

        int row = 0;
        grid.add(createSectionLabel("Appearance"), 0, row++, 2, 1);

        grid.add(new Label("Theme:"), 0, row);
        var themeCombo = new ComboBox<String>();
        themeCombo.getItems().addAll("Dark (Default)", "Light");
        themeCombo.setValue(config.isDarkTheme() ? "Dark (Default)" : "Light");
        grid.add(themeCombo, 1, row++);

        grid.add(new Label("Font Size:"), 0, row);
        var fontCombo = new ComboBox<String>();
        fontCombo.getItems().addAll("10", "11", "12", "13", "14", "16");
        fontCombo.setValue("12");
        grid.add(fontCombo, 1, row++);

        grid.add(new Label("Show splash screen:"), 0, row);
        var splashCheck = new CheckBox();
        splashCheck.setSelected(config.isShowSplash());
        grid.add(splashCheck, 1, row++);

        grid.add(new Label("Minimize to system tray:"), 0, row);
        var trayCheck = new CheckBox();
        grid.add(trayCheck, 1, row++);

        grid.add(new Label("ISK number format:"), 0, row);
        var formatCombo = new ComboBox<String>();
        formatCombo.getItems().addAll("1,234,567.89", "1.234.567,89", "1 234 567.89");
