        grid.add(formatCombo, 1, row++);

        grid.add(new Separator(), 0, row++, 2, 1);

        var saveBtn = new Button("Save Settings");
        grid.add(saveBtn, 0, row);

        // Wire save button
        saveBtn.setOnAction(e -> {
            config.setDarkTheme("Dark (Default)".equals(themeCombo.getValue()));
            config.setShowSplash(splashCheck.isSelected());
            config.save();
            new Alert(Alert.AlertType.INFORMATION, "Display settings saved.").showAndWait();
        });

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    private Tab createAboutTab() {
        var tab = new Tab("About");
        var vbox = new VBox(15);
        vbox.setPadding(new Insets(20));
        vbox.setStyle("-fx-alignment: center;");

        var titleLabel = new Label("Sample App");
        titleLabel.setFont(Font.font("Segoe UI", FontWeight.BOLD, 28));
        titleLabel.setStyle("-fx-text-fill: white;");

        var versionLabel = new Label("Version 2.1.245");
        versionLabel.setStyle("-fx-text-fill: #AAAAAA; -fx-font-size: 14;");

        var descLabel = new Label(
                "A comprehensive tool for EVE Online pilots.\n" +
                "Market analysis, industry planning, and more.");
        descLabel.setStyle("-fx-text-fill: #CCCCCC; -fx-font-size: 12;");
        descLabel.setWrapText(true);

        var separator = new Separator();

        var javaLabel = new Label("Java: " + System.getProperty("java.version"));
        javaLabel.setStyle("-fx-text-fill: #888888;");
        var javafxLabel = new Label("JavaFX: " + System.getProperty("javafx.version", "21"));
        javafxLabel.setStyle("-fx-text-fill: #888888;");
        var osLabel = new Label("OS: " + System.getProperty("os.name") +
                " " + System.getProperty("os.version"));
        osLabel.setStyle("-fx-text-fill: #888888;");

        var ccp = new Label("EVE Online and the EVE logo are the registered trademarks of CCP hf.");
        ccp.setStyle("-fx-text-fill: #666666; -fx-font-size: 10;");
        ccp.setWrapText(true);

        var dataDir = new Label("Data directory: " +
                System.getProperty("user.home") + "/.sampleapp");
        dataDir.setStyle("-fx-text-fill: #888888; -fx-font-size: 11;");

        vbox.getChildren().addAll(titleLabel, versionLabel, descLabel,
                separator, javaLabel, javafxLabel, osLabel, dataDir,
                new Separator(), ccp);
        tab.setContent(new ScrollPane(vbox));
        return tab;
    }

    private Label createSectionLabel(String text) {
        var label = new Label(text);
        label.setFont(Font.font("Segoe UI", FontWeight.BOLD, 16));
        label.setStyle("-fx-text-fill: #CCCCCC;");
        return label;
    }

    @Override
    public String getTitle() { return "Settings"; }

    @Override
    public void onActivated() { log.debug("Settings workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        // Settings not character-specific
    }
}

