11	import com.google.inject.Guice;
12	import com.google.inject.Injector;
13	import javafx.application.Application;
14	import javafx.application.Platform;
15	import javafx.scene.Scene;
16	import javafx.stage.Stage;
17	import javafx.stage.StageStyle;
18	import org.slf4j.Logger;
19	import org.slf4j.LoggerFactory;
20	
21	import java.nio.file.Files;
22	import java.nio.file.Path;
23	import java.util.List;
24	
25	/**
26	 * Main entry point for the Sample App application.
27	 * Handles initialization sequence: splash -> config -> database -> UI.
28	 */
29	public class SampleApp extends Application {
30	
31	    private static final Logger log = LoggerFactory.getLogger(SampleApp.class);
32	    private static final String APP_VERSION = "2.1.245";
33	
34	    private AppState appState;
35	    private Injector injector;
36	    private Path dataDir;
37	    private boolean devMode;
38	    private boolean resetConfig;
39	    private boolean portableMode;
40	
41	    // Service references for shutdown
42	    private DatabaseManager databaseManager;
43	    private StationStatsDatabase stationStatsDatabase;
44	    private SyncService syncService;
45	    private StationTradeService stationTradeService;
46	
47	    @Override
48	    public void init() {
49	        parseArguments(getParameters().getRaw());
50	    }
51	
52	    @Override
53	    public void start(Stage primaryStage) {
54	        log.info("Starting Sample App v{}", APP_VERSION);
55	
56	        // Show splash screen
57	        var splashStage = new Stage(StageStyle.UNDECORATED);
58	        var splashScreen = new SplashScreen();
59	        var splashScene = new Scene(splashScreen, 470, 270);
60	        splashScene.getStylesheets().add(
61	                getClass().getResource("/css/dark-theme.css").toExternalForm());
62	        splashStage.setScene(splashScene);
63	        splashStage.setTitle("Sample App - Loading");
64	        splashStage.centerOnScreen();
65	        splashStage.show();
66	
67	        // Run initialization on background thread
68	        Thread.ofVirtual().name("init").start(() -> {
69	            try {
70	                // Step 1: Resolve data directory
71	                splashScreen.updateStatus("Resolving data directory...", 0.05);
72	                resolveDataDir();
73	
74	                // Step 2: Load configuration
75	                splashScreen.updateStatus("Loading configuration...", 0.15);
76	                var config = loadConfig();
77	
78	                // Step 3: Initialize Guice
79	                splashScreen.updateStatus("Initializing dependency injection...", 0.25);
80	                var module = new AppModule(config, dataDir, devMode);
81	                injector = Guice.createInjector(module);
82	                appState = injector.getInstance(AppState.class);
83	
84	                // Step 4: Initialize databases
85	                splashScreen.updateStatus("Initializing databases...", 0.40);
86	                initializeDatabases();
87	
88	                // Step 5: Initialize feature gate and load characters
89	                splashScreen.updateStatus("Loading characters...", 0.55);
90	                initializeFeatureGate();
91	                loadCharacters();
92	
93	                // Step 6: Create main window
94	                splashScreen.updateStatus("Building user interface...", 0.70);
95	                Platform.runLater(() -> {
96	                    try {
97	                        createMainWindow(primaryStage, splashStage, splashScreen);
98	                    } catch (Exception e) {
99	                        log.error("Failed to create main window", e);
100	                        showErrorAndExit(e);
101	                    }
102	                });
103	            } catch (Exception e) {
104	                log.error("Initialization failed", e);
105	                Platform.runLater(() -> showErrorAndExit(e));
106	            }
107	        });
108	    }
109	
110	    private void createMainWindow(Stage primaryStage, Stage splashStage, SplashScreen splashScreen) {
111	        splashScreen.updateStatus("Preparing main window...", 0.85);
112	
113	        var mainWindow = injector.getInstance(com.sampleapp.ui.MainWindow.class);
114	        var scene = new Scene(mainWindow, 1280, 800);
115	        scene.getStylesheets().add(
116	                getClass().getResource("/css/dark-theme.css").toExternalForm());
117	
118	        primaryStage.setScene(scene);
119	        primaryStage.setTitle("Sample App v" + APP_VERSION);
120	        primaryStage.setMinWidth(960);
121	        primaryStage.setMinHeight(600);
122	
123	        // Step 7: Start background services
124	        splashScreen.updateStatus("Starting background services...", 0.95);
125	        startBackgroundServices();
126	
127	        splashScreen.updateStatus("Ready!", 1.0);
128	
129	        // Close splash and show main window
130	        splashStage.close();
131	        primaryStage.show();
132	
133	        log.info("Sample App started successfully");
134	    }
135	
136	    @Override
137	    public void stop() {
138	        log.info("Shutting down Sample App...");
139	
140	        // Stop background services
141	        if (syncService != null) {
142	            syncService.shutdown();
143	        }
144	        if (stationTradeService != null) {
145	            stationTradeService.shutdown();
146	        }
147	
148	        // Close databases
149	        if (stationStatsDatabase != null) {
150	            stationStatsDatabase.close();
151	        }
152	        if (databaseManager != null) {
153	            databaseManager.close();
154	        }
155	
156	        if (appState != null) {
157	            appState.shutdown();
158	        }
159	
160	        log.info("Sample App shutdown complete");
161	    }
162	
163	    private void parseArguments(List<String> args) {
164	        for (String arg : args) {
165	            if (arg.startsWith("--data-dir=")) {
166	                dataDir = Path.of(arg.substring("--data-dir=".length()));
167	            } else if ("--dev".equals(arg)) {
168	                devMode = true;
169	                log.info("Developer mode enabled");
170	            } else if ("--reset-config".equals(arg)) {
171	                resetConfig = true;
172	                log.info("Configuration reset requested");
173	            } else if ("--portable".equals(arg)) {
174	                portableMode = true;
175	                log.info("Portable mode enabled");
176	            }
177	        }
178	    }
179	
180	    private void resolveDataDir() {
181	        if (dataDir == null) {
182	            if (portableMode) {
183	                dataDir = Path.of(System.getProperty("user.dir"), ".sampleapp");
184	            } else {
185	                dataDir = Path.of(System.getProperty("user.home"), ".sampleapp");
186	            }
187	        }
188	        try {
189	            Files.createDirectories(dataDir);
190	            Files.createDirectories(dataDir.resolve("logs"));
191	            Files.createDirectories(dataDir.resolve("cache"));
192	            Files.createDirectories(dataDir.resolve("db"));
193	            log.info("Data directory: {}", dataDir);
194	        } catch (Exception e) {
195	            throw new RuntimeException("Failed to create data directory: " + dataDir, e);
196	        }
197	    }
198	
199	    private AppConfig loadConfig() {
200	        var configPath = dataDir.resolve("config.json");
201	        if (resetConfig) {
202	            try {
203	                Files.deleteIfExists(configPath);
204	                log.info("Configuration reset to defaults");
205	            } catch (Exception e) {
206	                log.warn("Failed to delete config file", e);
207	            }
208	        }
209	        return AppConfig.load(configPath);
210	    }
211	
212	    private void initializeDatabases() {
213	        log.info("Initializing H2 databases in {}", dataDir.resolve("db"));
214	
215	        databaseManager = injector.getInstance(DatabaseManager.class);
216	        databaseManager.initialize();
217	
218	        stationStatsDatabase = injector.getInstance(StationStatsDatabase.class);
219	        stationStatsDatabase.initialize();
220	
221	        log.info("Databases initialized successfully");
222	    }
223	
224	    private void initializeFeatureGate() {
225	        log.info("Initializing feature gates (devMode={})", devMode);
226	        // UI FeatureGate is auto-configured by Guice injection (takes AppConfig + @DevMode)
227	        injector.getInstance(com.sampleapp.core.app.FeatureGate.class);
228	
229	        // Subscription FeatureGate (used by StationTradeService) - enable all in dev mode
230	        var subscriptionGate = injector.getInstance(com.sampleapp.core.subscription.FeatureGate.class);
231	        if (devMode) {
232	            subscriptionGate.enableAll();
233	        }
234	    }
235	
236	    private void loadCharacters() {
237	        log.info("Loading existing characters from database");
238	        try {
239	            var characterRepo = injector.getInstance(CharacterRepository.class);
240	            var characters = characterRepo.findAll();
241	            for (var row : characters) {
242	                var charInfo = new AppState.CharacterInfo(
243	                        row.characterId(),
244	                        row.name(),
245	                        "", // corporationName not stored in row, resolved later
246	                        ""  // allianceName not stored in row, resolved later
247	                );
248	                appState.getCharacters().add(charInfo);
249	                log.info("Loaded character: {} (ID: {})", row.name(), row.characterId());
250	
251	                // Restore tokens from stored refresh tokens
252	                if (row.refreshToken() != null && !row.refreshToken().isBlank()) {
253	                    var tokenManager = injector.getInstance(com.sampleapp.esi.TokenManager.class);
254	                    // Store a placeholder token; it will be refreshed on first use
255	                    tokenManager.storeToken(new com.sampleapp.esi.TokenManager.TokenData(
256	                            "", // no access token yet
257	                            row.refreshToken(),
258	                            java.time.LocalDateTime.now().minusMinutes(1), // expired, will trigger refresh
259	                            row.characterId(),
260	                            row.name(),
261	                            row.ownerHash() != null ? row.ownerHash() : ""
262	                    ));
263	                }
264	            }
265	            log.info("Loaded {} characters from database", characters.size());
266	        } catch (Exception e) {
267	            log.warn("Failed to load characters from database", e);
268	        }
269	    }
270	
271	    private void startBackgroundServices() {
272	        log.info("Starting background services");
273	
274	        // Start ESI sync service
275	        syncService = injector.getInstance(SyncService.class);
276	        var config = injector.getInstance(AppConfig.class);
277	        syncService.start(config.getSyncIntervalMinutes());
278	
279	        // Start station trade import schedule
280	        stationTradeService = injector.getInstance(StationTradeService.class);
281	        stationTradeService.startScheduledImport();
282	
283	        log.info("Background services started");
284	    }
285	
286	    private void showErrorAndExit(Exception e) {
287	        log.error("Fatal error during startup", e);
288	        var alert = new javafx.scene.control.Alert(
289	                javafx.scene.control.Alert.AlertType.ERROR,
290	                "Failed to start Sample App:\n" + e.getMessage()
291	        );
292	        alert.setTitle("Sample App - Startup Error");
293	        alert.showAndWait();
294	        Platform.exit();
295	    }
296	
297	    public static void main(String[] args) {
298	        launch(args);
299	    }
300	}
