package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppConfig;
import com.sampleapp.core.app.AppState;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleStringProperty;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.scene.text.Font;
import javafx.scene.text.FontWeight;

/**
 * Settings workspace with 5 tabs: Account, Sync Settings, Market Config, Display, About.
 */
public class SettingsWorkspace extends Workspace {

    private final AppServices appServices;
    private TableView<AppState.CharacterInfo> charTable;

    public SettingsWorkspace(AppState appState, AppServices appServices) {
        super(appState);
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createAccountTab(),
                createSyncSettingsTab(),
                createMarketConfigTab(),
                createDisplayTab(),
                createAboutTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createAccountTab() {
        var tab = new Tab("Account");
        var vbox = new VBox(15);
        vbox.setPadding(new Insets(15));

        // Character management
        var charLabel = createSectionLabel("Characters");
        charTable = new TableView<>(appState.getCharacters());

        var nameCol = new TableColumn<AppState.CharacterInfo, String>("Name");
        nameCol.setPrefWidth(200);
        nameCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().name()));

        var corpCol = new TableColumn<AppState.CharacterInfo, String>("Corporation");
        corpCol.setPrefWidth(200);
        corpCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().corporationName()));

        var allianceCol = new TableColumn<AppState.CharacterInfo, String>("Alliance");
        allianceCol.setPrefWidth(200);
        allianceCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().allianceName()));

        var statusCol = new TableColumn<AppState.CharacterInfo, String>("Status");
        statusCol.setPrefWidth(100);
        statusCol.setCellValueFactory(cd -> new SimpleStringProperty("Active"));

        charTable.getColumns().addAll(nameCol, corpCol, allianceCol, statusCol);
        charTable.setPrefHeight(200);
        charTable.setPlaceholder(new Label("No characters added"));

        var charBtnBox = new HBox(10);
        var addCharBtn = new Button("Add Character (EVE SSO)");
        var removeCharBtn = new Button("Remove Selected");
        var refreshTokenBtn = new Button("Refresh Token");

        // Wire Add Character button
        addCharBtn.setOnAction(e -> {
            addCharBtn.setDisable(true);
            addCharBtn.setText("Waiting for SSO...");
            appServices.addCharacter()
                    .thenAccept(charId -> Platform.runLater(() -> {
                        addCharBtn.setDisable(false);
                        addCharBtn.setText("Add Character (EVE SSO)");
                        log.info("Character {} added successfully", charId);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            addCharBtn.setDisable(false);
                            addCharBtn.setText("Add Character (EVE SSO)");
                            var alert = new Alert(Alert.AlertType.ERROR,
                                    "Failed to add character:\n" + ex.getMessage());
                            alert.setTitle("EVE SSO Error");
                            alert.setHeaderText("Login Failed");
                            alert.showAndWait();
                        });
                        return null;
                    });
        });

        // Wire Remove Character button
        removeCharBtn.setOnAction(e -> {
            var selected = charTable.getSelectionModel().getSelectedItem();
            if (selected == null) {
                new Alert(Alert.AlertType.WARNING, "Please select a character to remove.").showAndWait();
                return;
            }
            var confirm = new Alert(Alert.AlertType.CONFIRMATION,
                    "Remove character \"" + selected.name() + "\"?\n" +
                            "This will delete all local data for this character.");
            confirm.setTitle("Confirm Removal");
            confirm.setHeaderText("Remove Character");
            confirm.showAndWait().ifPresent(result -> {
                if (result == ButtonType.OK) {
                    appServices.removeCharacter(selected.characterId());
                    log.info("Character {} removed", selected.name());
                }
            });
        });

        // Wire Refresh Token button
        refreshTokenBtn.setOnAction(e -> {
            var selected = charTable.getSelectionModel().getSelectedItem();
            if (selected == null) {
                new Alert(Alert.AlertType.WARNING, "Please select a character.").showAndWait();
                return;
            }
            refreshTokenBtn.setDisable(true);
            refreshTokenBtn.setText("Refreshing...");
            appServices.refreshCharacterToken(selected.characterId())
                    .thenRun(() -> Platform.runLater(() -> {
                        refreshTokenBtn.setDisable(false);
                        refreshTokenBtn.setText("Refresh Token");
                        new Alert(Alert.AlertType.INFORMATION, "Token refreshed successfully.").showAndWait();
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            refreshTokenBtn.setDisable(false);
                            refreshTokenBtn.setText("Refresh Token");
                            new Alert(Alert.AlertType.ERROR,
                                    "Failed to refresh token:\n" + ex.getMessage()).showAndWait();
                        });
                        return null;
                    });
        });

        charBtnBox.getChildren().addAll(addCharBtn, removeCharBtn, refreshTokenBtn);

        // Subscription
        var subLabel = createSectionLabel("Subscription");
        var subGrid = new GridPane();
        subGrid.setHgap(10);
        subGrid.setVgap(8);
        subGrid.add(new Label("Current Tier:"), 0, 0);
        var tierLabel = new Label("--");
        tierLabel.setStyle("-fx-text-fill: #4EC9B0; -fx-font-weight: bold;");
        tierLabel.textProperty().bind(appState.subscriptionTierProperty());
        subGrid.add(tierLabel, 1, 0);
        subGrid.add(new Label("Features:"), 0, 1);
        subGrid.add(new Label("--"), 1, 1);

        vbox.getChildren().addAll(charLabel, charTable, charBtnBox,
                new Separator(), subLabel, subGrid);
        tab.setContent(new ScrollPane(vbox));
        return tab;
    }

    private Tab createSyncSettingsTab() {
        var tab = new Tab("Sync Settings");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));
        var config = appServices.getAppConfig();

        int row = 0;
        grid.add(createSectionLabel("ESI Sync"), 0, row++, 2, 1);

        grid.add(new Label("Sync Interval (minutes):"), 0, row);
        var syncIntervalField = new TextField(String.valueOf(config.getSyncIntervalMinutes()));
        syncIntervalField.setPrefWidth(80);
        grid.add(syncIntervalField, 1, row++);

        grid.add(new Label("Auto-sync on startup:"), 0, row);
        var autoSyncCheck = new CheckBox();
        autoSyncCheck.setSelected(true);
        grid.add(autoSyncCheck, 1, row++);

        grid.add(new Label("Sync wallet transactions:"), 0, row);
        var syncWalletCheck = new CheckBox();
        syncWalletCheck.setSelected(true);
        grid.add(syncWalletCheck, 1, row++);

        grid.add(new Label("Sync market orders:"), 0, row);
        var syncOrdersCheck = new CheckBox();
        syncOrdersCheck.setSelected(true);
        grid.add(syncOrdersCheck, 1, row++);

        grid.add(new Label("Sync assets:"), 0, row);
        var syncAssetsCheck = new CheckBox();
        syncAssetsCheck.setSelected(true);
        grid.add(syncAssetsCheck, 1, row++);

        grid.add(new Label("Sync contracts:"), 0, row);
        var syncContractsCheck = new CheckBox();
        syncContractsCheck.setSelected(true);
        grid.add(syncContractsCheck, 1, row++);

        grid.add(new Label("Sync industry jobs:"), 0, row);
        var syncIndustryCheck = new CheckBox();
        syncIndustryCheck.setSelected(true);
        grid.add(syncIndustryCheck, 1, row++);

        grid.add(new Label("Sync skills:"), 0, row);
        var syncSkillsCheck = new CheckBox();
        syncSkillsCheck.setSelected(true);
        grid.add(syncSkillsCheck, 1, row++);

        grid.add(new Separator(), 0, row++, 2, 1);

        var saveBtn = new Button("Save Settings");
        var resetBtn = new Button("Reset to Defaults");
        var btnBox = new HBox(10, saveBtn, resetBtn);
        grid.add(btnBox, 0, row, 2, 1);

        // Wire save button
        saveBtn.setOnAction(e -> {
            try {
                config.setSyncIntervalMinutes(Integer.parseInt(syncIntervalField.getText()));
                config.save();
                new Alert(Alert.AlertType.INFORMATION, "Sync settings saved.").showAndWait();
            } catch (NumberFormatException ex) {
                new Alert(Alert.AlertType.ERROR, "Invalid sync interval value.").showAndWait();
            }
        });

        // Wire reset button
        resetBtn.setOnAction(e -> {
            syncIntervalField.setText("15");
            autoSyncCheck.setSelected(true);
            syncWalletCheck.setSelected(true);
            syncOrdersCheck.setSelected(true);
            syncAssetsCheck.setSelected(true);
            syncContractsCheck.setSelected(true);
            syncIndustryCheck.setSelected(true);
            syncSkillsCheck.setSelected(true);
        });

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    private Tab createMarketConfigTab() {
        var tab = new Tab("Market Config");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));
        var config = appServices.getAppConfig();

        int row = 0;
        grid.add(createSectionLabel("Market Settings"), 0, row++, 2, 1);

        grid.add(new Label("Default Market Hub:"), 0, row);
        var hubCombo = new ComboBox<String>();
        hubCombo.getItems().addAll(
                "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                "Amarr VIII (Oris) - Emperor Family Academy",
                "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                "Rens VI - Moon 8 - Brutor Tribe Treasury",
                "Hek VIII - Moon 12 - Boundless Creation Factory"
        );
        hubCombo.setValue(config.getDefaultMarketHub());
        grid.add(hubCombo, 1, row++);

        grid.add(new Label("Default Region:"), 0, row);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("The Forge", "Domain", "Sinq Laison",
                "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        grid.add(regionCombo, 1, row++);

        grid.add(new Label("Cache Duration (minutes):"), 0, row);
        var cacheField = new TextField(String.valueOf(config.getMarketCacheMinutes()));
        cacheField.setPrefWidth(80);
        grid.add(cacheField, 1, row++);

        grid.add(new Label("Include broker fees in calculations:"), 0, row);
        var brokerFeeCheck = new CheckBox();
        grid.add(brokerFeeCheck, 1, row++);

        grid.add(new Label("Include sales tax in calculations:"), 0, row);
        var salesTaxCheck = new CheckBox();
        grid.add(salesTaxCheck, 1, row++);

        grid.add(new Label("Default Accounting Level:"), 0, row);
        var accountingCombo = new ComboBox<String>();
        accountingCombo.getItems().addAll("0", "1", "2", "3", "4", "5");
        accountingCombo.setValue("5");
        grid.add(accountingCombo, 1, row++);

        grid.add(new Label("Default Broker Relations Level:"), 0, row);
        var brokerCombo = new ComboBox<String>();
        brokerCombo.getItems().addAll("0", "1", "2", "3", "4", "5");
        brokerCombo.setValue("5");
        grid.add(brokerCombo, 1, row++);

        grid.add(new Separator(), 0, row++, 2, 1);

        var saveBtn = new Button("Save Settings");
        grid.add(saveBtn, 0, row);

        // Wire save button
        saveBtn.setOnAction(e -> {
            try {
                config.setDefaultMarketHub(hubCombo.getValue());
                config.setMarketCacheMinutes(Integer.parseInt(cacheField.getText()));
                config.save();
                new Alert(Alert.AlertType.INFORMATION, "Market settings saved.").showAndWait();
            } catch (NumberFormatException ex) {
                new Alert(Alert.AlertType.ERROR, "Invalid cache duration value.").showAndWait();
            }
        });

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    private Tab createDisplayTab() {
        var tab = new Tab("Display");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(10);
        grid.setPadding(new Insets(15));
        var config = appServices.getAppConfig();

        int row = 0;
        grid.add(createSectionLabel("Appearance"), 0, row++, 2, 1);

        grid.add(new Label("Theme:"), 0, row);
        var themeCombo = new ComboBox<String>();
        themeCombo.getItems().addAll("Dark (Default)", "Light");
        themeCombo.setValue(config.isDarkTheme() ? "Dark (Default)" : "Light");
        grid.add(themeCombo, 1, row++);

        grid.add(new Label("Font Size:"), 0, row);
        var fontCombo = new ComboBox<String>();
        fontCombo.getItems().addAll("10", "11", "12", "13", "14", "16");
        fontCombo.setValue("12");
        grid.add(fontCombo, 1, row++);

        grid.add(new Label("Show splash screen:"), 0, row);
        var splashCheck = new CheckBox();
        splashCheck.setSelected(config.isShowSplash());
        grid.add(splashCheck, 1, row++);

        grid.add(new Label("Minimize to system tray:"), 0, row);
        var trayCheck = new CheckBox();
        grid.add(trayCheck, 1, row++);

        grid.add(new Label("ISK number format:"), 0, row);
        var formatCombo = new ComboBox<String>();
        formatCombo.getItems().addAll("1,234,567.89", "1.234.567,89", "1 234 567.89");
        formatCombo.setValue("1,234,567.89");
        grid.add(formatCombo, 1, row++);

        grid.add(new Separator(), 0, row++, 2, 1);

        var saveBtn = new Button("Save Settings");
        grid.add(saveBtn, 0, row);

        // Wire save button
        saveBtn.setOnAction(e -> {
            config.setDarkTheme("Dark (Default)".equals(themeCombo.getValue()));
            config.setShowSplash(splashCheck.isSelected());
            config.save();
            new Alert(Alert.AlertType.INFORMATION, "Display settings saved.").showAndWait();
        });

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    private Tab createAboutTab() {
        var tab = new Tab("About");
        var vbox = new VBox(15);
        vbox.setPadding(new Insets(20));
