39	/**
40	 * Google Drive station trade data sync service.
41	 * <p>
42	 * Downloads station-level market trade statistics from a shared Google Drive folder,
43	 * parses the ZIP/CSV files, and inserts them into the station stats database.
44	 */
45	@Singleton
46	public class StationTradeService {
47	
48	    private static final Logger log = LoggerFactory.getLogger(StationTradeService.class);
49	
50	    private static final String GDRIVE_API_KEY = "REDACTED_GOOGLE_API_KEY";
51	    private static final String GDRIVE_FOLDER_ID = "REDACTED_GDRIVE_FOLDER_ID";
52	
53	    private static final String LIST_URL =
54	            "https://www.googleapis.com/drive/v3/files?q=name%20contains%20%27StationTrades%27%20and%20%27"
55	                    + GDRIVE_FOLDER_ID + "%27%20in%20parents&key=" + GDRIVE_API_KEY;
56	
57	    private static final String DOWNLOAD_TEMPLATE =
58	            "https://www.googleapis.com/drive/v3/files/%s?alt=media&key=" + GDRIVE_API_KEY;
59	
60	    /** Epoch used for integer date storage: days since 2000-01-01. */
61	    private static final LocalDate BASE_DATE = LocalDate.of(2000, 1, 1);
62	
63	    private static final int MAX_RETRIES = 4;
64	    private static final int BUFFER_SIZE = 81920;
65	
66	    /** Pattern to extract date from filename: StationTrades_2024-01-15.zip */
67	    private static final Pattern FILENAME_DATE_PATTERN =
68	            Pattern.compile("StationTrades_(\\d{4}-\\d{2}-\\d{2})\\.zip");
69	
70	    private static final DateTimeFormatter DATE_FORMAT = DateTimeFormatter.ISO_LOCAL_DATE;
71	
72	    private final HttpClient httpClient;
73	    private final ObjectMapper objectMapper;
74	    private final StationStatsDatabase stationStatsDb;
75	    private final FeatureGate featureGate;
76	    private final EventBus eventBus;
77	    private final Path importDir;
78	    private final ScheduledExecutorService scheduler;
79	
80	    private ScheduledFuture<?> scheduledTask;
81	
82	    // ----------------------------------------------------------------
83	    // Google Drive API response models
84	    // ----------------------------------------------------------------
85	
86	    public record GDriveFileList(
87	            @JsonProperty("files") List<GDriveFile> files
88	    ) {}
89	
90	    public record GDriveFile(
91	            @JsonProperty("id") String id,
92	            @JsonProperty("name") String name,
93	            @JsonProperty("modifiedTime") String modifiedTime
94	    ) {}
95	
96	    // ----------------------------------------------------------------
97	    // Constructor
98	    // ----------------------------------------------------------------
99	
100	    @Inject
101	    public StationTradeService(StationStatsDatabase stationStatsDb,
102	                               FeatureGate featureGate,
103	                               EventBus eventBus,
104	                               Path dataFolder) {
105	        this.stationStatsDb = stationStatsDb;
106	        this.featureGate = featureGate;
107	        this.eventBus = eventBus;
108	        this.importDir = dataFolder.resolve("import");
109	        this.httpClient = HttpClient.newBuilder()
110	                .followRedirects(HttpClient.Redirect.NORMAL)
111	                .build();
112	        this.objectMapper = new ObjectMapper();
113	        this.scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
114	            Thread t = new Thread(r, "station-trade-scheduler");
115	            t.setDaemon(true);
116	            return t;
117	        });
118	    }
119	
120	    // ----------------------------------------------------------------
121	    // Public API
122	    // ----------------------------------------------------------------
123	
124	    public GDriveFileList listFiles() throws IOException, InterruptedException {
125	        HttpRequest request = HttpRequest.newBuilder()
126	                .uri(URI.create(LIST_URL))
127	                .GET()
128	                .build();
129	
130	        HttpResponse<String> response = httpClient.send(request,
131	                HttpResponse.BodyHandlers.ofString());
132	
133	        if (response.statusCode() != 200) {
134	            throw new IOException("Google Drive API returned status " + response.statusCode()
135	                    + ": " + response.body());
136	        }
137	
138	        return objectMapper.readValue(response.body(), GDriveFileList.class);
139	    }
140	
141	    public Path downloadFile(GDriveFile file) throws IOException, InterruptedException {
142	        Files.createDirectories(importDir);
143	        Path target = importDir.resolve(file.name());
144	
145	        String url = String.format(DOWNLOAD_TEMPLATE, file.id());
146	        HttpRequest request = HttpRequest.newBuilder()
147	                .uri(URI.create(url))
148	                .GET()
149	                .build();
150	
151	        IOException lastException = null;
152	        for (int attempt = 0; attempt <= MAX_RETRIES; attempt++) {
153	            try {
154	                HttpResponse<Path> response = httpClient.send(request,
155	                        HttpResponse.BodyHandlers.ofFile(target));
156	
157	                if (response.statusCode() == 200) {
158	                    log.debug("Downloaded {} ({} bytes)", file.name(), Files.size(target));
159	                    return target;
160	                }
161	
162	                lastException = new IOException(
163	                        "Download returned status " + response.statusCode());
164	                log.warn("Download attempt {} failed for {}: status {}",
165	                        attempt + 1, file.name(), response.statusCode());
166	            } catch (IOException e) {
167	                lastException = e;
168	                log.warn("Download attempt {} failed for {}: {}",
169	                        attempt + 1, file.name(), e.getMessage());
170	            }
171	
172	            if (attempt < MAX_RETRIES) {
173	                Thread.sleep(1000L * (1L << attempt));
174	            }
175	        }
176	
177	        throw new IOException("Failed to download " + file.name()
178	                + " after " + (MAX_RETRIES + 1) + " attempts", lastException);
179	    }
180	
181	    public static LocalDate parseDateFromFilename(String filename) {
182	        Matcher matcher = FILENAME_DATE_PATTERN.matcher(filename);
183	        if (matcher.find()) {
184	            return LocalDate.parse(matcher.group(1), DATE_FORMAT);
185	        }
186	        return null;
187	    }
188	
189	    /**
190	     * Parse a ZIP file containing semicolon-delimited CSV station trade data.
191	     */
192	    public List<MarketTrade> parseZip(Path zipPath) throws IOException {
193	        List<MarketTrade> trades = new ArrayList<>();
194	
195	        try (ZipInputStream zis = new ZipInputStream(Files.newInputStream(zipPath))) {
196	            ZipEntry entry;
197	            while ((entry = zis.getNextEntry()) != null) {
198	                if (entry.isDirectory()) {
199	                    continue;
200	                }
201	
202	                try (BufferedReader reader = new BufferedReader(
203	                        new InputStreamReader(zis), BUFFER_SIZE)) {
204	                    String line;
205	                    boolean firstLine = true;
206	
207	                    while ((line = reader.readLine()) != null) {
208	                        if (firstLine) {
209	                            firstLine = false;
210	                            if (line.startsWith("LocationId") || line.startsWith("locationId")) {
211	                                continue;
212	                            }
213	                        }
214	
215	                        String[] parts = line.split(";");
216	                        if (parts.length < 8) {
217	                            continue;
218	                        }
219	
220	                        try {
221	                            long locationId = Long.parseLong(parts[0].trim());
222	                            int regionId = Integer.parseInt(parts[1].trim());
223	                            int daysSinceBase = Integer.parseInt(parts[2].trim());
224	                            int typeId = Integer.parseInt(parts[3].trim());
225	                            long buyUnits = Long.parseLong(parts[4].trim());
226	                            long sellUnits = Long.parseLong(parts[5].trim());
227	                            int buyTransactions = Integer.parseInt(parts[6].trim());
228	                            int sellTransactions = Integer.parseInt(parts[7].trim());
229	
230	                            trades.add(new MarketTrade(
231	                                    daysSinceBase, locationId, typeId, regionId,
232	                                    buyUnits, sellUnits, buyTransactions, sellTransactions
