package com.sampleapp.app.service;
import com.sampleapp.core.service.EventBus;

import com.sampleapp.core.subscription.FeatureGate;
import com.sampleapp.core.subscription.FeatureSet;
import com.sampleapp.data.MarketTrade;
import com.sampleapp.data.StationStatsDatabase;
import com.fasterxml.jackson.annotation.JsonProperty;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.google.inject.Inject;
import com.google.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.function.Consumer;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

/**
 * Google Drive station trade data sync service.
 * <p>
 * Downloads station-level market trade statistics from a shared Google Drive folder,
 * parses the ZIP/CSV files, and inserts them into the station stats database.
 */
@Singleton
public class StationTradeService {

    private static final Logger log = LoggerFactory.getLogger(StationTradeService.class);

    private static final String GDRIVE_API_KEY = "REDACTED_GOOGLE_API_KEY";
    private static final String GDRIVE_FOLDER_ID = "REDACTED_GDRIVE_FOLDER_ID";

    private static final String LIST_URL =
            "https://www.googleapis.com/drive/v3/files?q=name%20contains%20%27StationTrades%27%20and%20%27"
                    + GDRIVE_FOLDER_ID + "%27%20in%20parents&key=" + GDRIVE_API_KEY;

    private static final String DOWNLOAD_TEMPLATE =
            "https://www.googleapis.com/drive/v3/files/%s?alt=media&key=" + GDRIVE_API_KEY;

    /** Epoch used for integer date storage: days since 2000-01-01. */
    private static final LocalDate BASE_DATE = LocalDate.of(2000, 1, 1);

    private static final int MAX_RETRIES = 4;
    private static final int BUFFER_SIZE = 81920;

    /** Pattern to extract date from filename: StationTrades_2024-01-15.zip */
    private static final Pattern FILENAME_DATE_PATTERN =
            Pattern.compile("StationTrades_(\\d{4}-\\d{2}-\\d{2})\\.zip");

    private static final DateTimeFormatter DATE_FORMAT = DateTimeFormatter.ISO_LOCAL_DATE;

    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;
    private final StationStatsDatabase stationStatsDb;
    private final FeatureGate featureGate;
    private final EventBus eventBus;
    private final Path importDir;
    private final ScheduledExecutorService scheduler;

    private ScheduledFuture<?> scheduledTask;

    // ----------------------------------------------------------------
    // Google Drive API response models
    // ----------------------------------------------------------------

    public record GDriveFileList(
            @JsonProperty("files") List<GDriveFile> files
    ) {}

    public record GDriveFile(
            @JsonProperty("id") String id,
            @JsonProperty("name") String name,
            @JsonProperty("modifiedTime") String modifiedTime
    ) {}

    // ----------------------------------------------------------------
    // Constructor
    // ----------------------------------------------------------------

    @Inject
    public StationTradeService(StationStatsDatabase stationStatsDb,
                               FeatureGate featureGate,
                               EventBus eventBus,
                               Path dataFolder) {
        this.stationStatsDb = stationStatsDb;
        this.featureGate = featureGate;
        this.eventBus = eventBus;
        this.importDir = dataFolder.resolve("import");
        this.httpClient = HttpClient.newBuilder()
                .followRedirects(HttpClient.Redirect.NORMAL)
                .build();
        this.objectMapper = new ObjectMapper();
        this.scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "station-trade-scheduler");
            t.setDaemon(true);
            return t;
        });
    }

    // ----------------------------------------------------------------
    // Public API
    // ----------------------------------------------------------------

    public GDriveFileList listFiles() throws IOException, InterruptedException {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(LIST_URL))
                .GET()
                .build();

        HttpResponse<String> response = httpClient.send(request,
                HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() != 200) {
            throw new IOException("Google Drive API returned status " + response.statusCode()
                    + ": " + response.body());
        }

        return objectMapper.readValue(response.body(), GDriveFileList.class);
    }

    public Path downloadFile(GDriveFile file) throws IOException, InterruptedException {
        Files.createDirectories(importDir);
        Path target = importDir.resolve(file.name());

        String url = String.format(DOWNLOAD_TEMPLATE, file.id());
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .GET()
                .build();

        IOException lastException = null;
        for (int attempt = 0; attempt <= MAX_RETRIES; attempt++) {
            try {
                HttpResponse<Path> response = httpClient.send(request,
                        HttpResponse.BodyHandlers.ofFile(target));

                if (response.statusCode() == 200) {
                    log.debug("Downloaded {} ({} bytes)", file.name(), Files.size(target));
                    return target;
                }

                lastException = new IOException(
                        "Download returned status " + response.statusCode());
                log.warn("Download attempt {} failed for {}: status {}",
                        attempt + 1, file.name(), response.statusCode());
            } catch (IOException e) {
                lastException = e;
                log.warn("Download attempt {} failed for {}: {}",
                        attempt + 1, file.name(), e.getMessage());
            }

            if (attempt < MAX_RETRIES) {
                Thread.sleep(1000L * (1L << attempt));
            }
        }

        throw new IOException("Failed to download " + file.name()
                + " after " + (MAX_RETRIES + 1) + " attempts", lastException);
    }

    public static LocalDate parseDateFromFilename(String filename) {
        Matcher matcher = FILENAME_DATE_PATTERN.matcher(filename);
        if (matcher.find()) {
            return LocalDate.parse(matcher.group(1), DATE_FORMAT);
        }
        return null;
    }

    /**
     * Parse a ZIP file containing semicolon-delimited CSV station trade data.
     */
    public List<MarketTrade> parseZip(Path zipPath) throws IOException {
        List<MarketTrade> trades = new ArrayList<>();

        try (ZipInputStream zis = new ZipInputStream(Files.newInputStream(zipPath))) {
            ZipEntry entry;
            while ((entry = zis.getNextEntry()) != null) {
                if (entry.isDirectory()) {
                    continue;
                }

                try (BufferedReader reader = new BufferedReader(
                        new InputStreamReader(zis), BUFFER_SIZE)) {
                    String line;
                    boolean firstLine = true;

                    while ((line = reader.readLine()) != null) {
                        if (firstLine) {
                            firstLine = false;
                            if (line.startsWith("LocationId") || line.startsWith("locationId")) {
                                continue;
                            }
                        }

                        String[] parts = line.split(";");
                        if (parts.length < 8) {
                            continue;
                        }

                        try {
                            long locationId = Long.parseLong(parts[0].trim());
                            int regionId = Integer.parseInt(parts[1].trim());
                            int daysSinceBase = Integer.parseInt(parts[2].trim());
                            int typeId = Integer.parseInt(parts[3].trim());
                            long buyUnits = Long.parseLong(parts[4].trim());
                            long sellUnits = Long.parseLong(parts[5].trim());
                            int buyTransactions = Integer.parseInt(parts[6].trim());
                            int sellTransactions = Integer.parseInt(parts[7].trim());

                            trades.add(new MarketTrade(
                                    daysSinceBase, locationId, typeId, regionId,
                                    buyUnits, sellUnits, buyTransactions, sellTransactions
                            ));
                        } catch (NumberFormatException e) {
                            log.trace("Skipping malformed CSV line: {}", line);
                        }
                    }
                }
            }
        }

        log.debug("Parsed {} trades from {}", trades.size(), zipPath.getFileName());
        return trades;
    }

    /**
     * Full import pipeline: list files on Google Drive, filter by date,
     * download new files, parse, and insert into the database.
     */
    public int importTrades(Consumer<Integer> progress)
            throws IOException, InterruptedException {

        LocalDate latestInDb = stationStatsDb.getLatestTradeDate();
        if (latestInDb == null) {
            latestInDb = BASE_DATE;
        }

        GDriveFileList fileList = listFiles();
        if (fileList.files() == null || fileList.files().isEmpty()) {
            log.info("No station trade files found on Google Drive");
            return 0;
        }

        int totalImported = 0;

        final LocalDate cutoff = latestInDb;
        List<GDriveFile> newFiles = fileList.files().stream()
                .filter(f -> {
                    LocalDate fileDate = parseDateFromFilename(f.name());
                    return fileDate != null && fileDate.isAfter(cutoff);
                })
                .sorted((a, b) -> {
                    LocalDate da = parseDateFromFilename(a.name());
                    LocalDate db = parseDateFromFilename(b.name());
                    return da.compareTo(db);
                })
                .toList();

        log.info("Found {} new station trade files to import", newFiles.size());

        for (GDriveFile file : newFiles) {
            try {
                Path downloaded = downloadFile(file);
                List<MarketTrade> trades = parseZip(downloaded);
                int imported = stationStatsDb.importMarketTrades(trades, progress);
                totalImported += imported;

                Files.deleteIfExists(downloaded);
                log.info("Imported {} trades from {}", imported, file.name());
            } catch (Exception e) {
                log.error("Failed to import file {}", file.name(), e);
            }
        }

        if (totalImported > 0) {
            eventBus.publish(EventBus.Event.STATION_TRADES_IMPORTED, totalImported);
        }

        return totalImported;
    }

    /**
     * Start hourly import schedule.
     */
    public void startScheduledImport() {
        if (!featureGate.hasFeature(FeatureSet.STATION_TRADER)) {
            log.info("Station trader feature not enabled -- scheduled import will not start");
            return;
        }

        if (scheduledTask != null) {
            log.warn("Scheduled import is already running");
            return;
        }

        log.info("Starting hourly station trade import schedule");
        scheduledTask = scheduler.scheduleAtFixedRate(() -> {
            try {
                importTrades(null);
            } catch (Exception e) {
                log.error("Scheduled station trade import failed", e);
            }
        }, 1, 60, TimeUnit.MINUTES);
    }

    public void stopScheduledImport() {
        if (scheduledTask != null) {
            scheduledTask.cancel(false);
            scheduledTask = null;
            log.info("Station trade import schedule stopped");
        }
    }

    public CompletableFuture<Integer> importNow() {
        return CompletableFuture.supplyAsync(() -> {
            try {
                return importTrades(null);
            } catch (Exception e) {
                log.error("Manual station trade import failed", e);
                throw new RuntimeException("Import failed", e);
            }
        });
    }

    public void shutdown() {
        stopScheduledImport();
        scheduler.shutdownNow();
    }
}

