11	import java.sql.*;
12	import java.time.LocalDate;
13	import java.util.ArrayList;
14	import java.util.List;
15	import java.util.function.Consumer;
16	
17	/**
18	 * Separate H2 database for station trade statistics, mirroring the original
19	 * egStationStats.sdf SQL CE database. Dates are stored as integer day offsets
20	 * from 2000-01-01 to match the original C# representation.
21	 */
22	@Singleton
23	public class StationStatsDatabase {
24	
25	    private static final Logger LOG = LoggerFactory.getLogger(StationStatsDatabase.class);
26	    private static final String DB_URL_TEMPLATE = "jdbc:h2:file:%s/egStationStats";
27	
28	    /** Epoch used for day-offset date encoding (matching C# original). */
29	    private static final LocalDate EPOCH = LocalDate.of(2000, 1, 1);
30	
31	    private final String dataFolder;
32	    private HikariDataSource dataSource;
33	
34	    @Inject
35	    public StationStatsDatabase(@Named("dataFolder") String dataFolder) {
36	        this.dataFolder = dataFolder;
37	    }
38	
39	    /**
40	     * Initialises the station stats database, creating the schema if it
41	     * does not already exist.
42	     */
43	    public void initialize() {
44	        String jdbcUrl = String.format(DB_URL_TEMPLATE, dataFolder.replace('\\', '/'));
45	        LOG.info("Initialising station stats database at {}", jdbcUrl);
46	
47	        HikariConfig config = new HikariConfig();
48	        config.setJdbcUrl(jdbcUrl);
49	        config.setMaximumPoolSize(5);
50	        config.setMinimumIdle(1);
51	        config.setPoolName("sampleapp-stationstats");
52	
53	        dataSource = new HikariDataSource(config);
54	
55	        try (Connection conn = dataSource.getConnection();
56	             Statement stmt = conn.createStatement()) {
57	
58	            stmt.execute("""
59	                    CREATE TABLE IF NOT EXISTS MarketTrades (
60	                        "DAY" INT NOT NULL,
61	                        LocationId BIGINT NOT NULL,
62	                        TypeId INT NOT NULL,
63	                        RegionId INT NOT NULL,
64	                        BuyUnits BIGINT NOT NULL DEFAULT 0,
65	                        SellUnits BIGINT NOT NULL DEFAULT 0,
66	                        BuyTransactions INT NOT NULL DEFAULT 0,
67	                        SellTransactions INT NOT NULL DEFAULT 0,
68	                        PRIMARY KEY ("DAY", LocationId, TypeId)
69	                    )
70	                    """);
71	
72	            stmt.execute("""
73	                    CREATE INDEX IF NOT EXISTS IDX_MarketTrades_RegionDayType
74	                        ON MarketTrades (RegionId, "DAY", TypeId)
75	                    """);
76	
77	            LOG.info("Station stats database initialised successfully");
78	        } catch (SQLException e) {
79	            throw new RuntimeException("Failed to initialise station stats database", e);
80	        }
81	    }
82	
83	    /**
84	     * Obtains a connection from the station-stats pool.
85	     */
86	    public Connection getConnection() throws SQLException {
87	        if (dataSource == null || dataSource.isClosed()) {
88	            throw new IllegalStateException("Station stats database has not been initialised");
89	        }
90	        return dataSource.getConnection();
91	    }
92	
93	    /**
94	     * Returns the most recent trade date stored in the database, or {@code null}
95	     * if the table is empty.
96	     */
97	    public LocalDate getLatestTradeDate() {
98	        String sql = "SELECT MAX(\"DAY\") FROM MarketTrades";
99	        try (Connection conn = getConnection();
100	             PreparedStatement ps = conn.prepareStatement(sql);
101	             ResultSet rs = ps.executeQuery()) {
102	
103	            if (rs.next()) {
104	                int day = rs.getInt(1);
105	                if (!rs.wasNull()) {
106	                    return EPOCH.plusDays(day);
107	                }
108	            }
109	            return null;
110	        } catch (SQLException e) {
111	            throw new RuntimeException("Failed to query latest trade date", e);
112	        }
113	    }
114	
115	    /**
116	     * Bulk-imports market trades using batch inserts. The {@code progress}
117	     * callback receives the number of rows inserted so far after every batch.
118	     *
119	     * @return total rows inserted
120	     */
121	    public int importMarketTrades(List<MarketTrade> trades, Consumer<Integer> progress) {
122	        if (trades == null || trades.isEmpty()) {
123	            return 0;
124	        }
125	
126	        String sql = """
127	                MERGE INTO MarketTrades ("DAY", LocationId, TypeId, RegionId,
128	                    BuyUnits, SellUnits, BuyTransactions, SellTransactions)
129	                KEY ("DAY", LocationId, TypeId)
130	                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
131	                """;
132	
133	        int batchSize = 1000;
134	        int total = 0;
135	
136	        try (Connection conn = getConnection()) {
137	            conn.setAutoCommit(false);
138	
139	            try (PreparedStatement ps = conn.prepareStatement(sql)) {
140	                for (int i = 0; i < trades.size(); i++) {
141	                    MarketTrade t = trades.get(i);
142	                    ps.setInt(1, t.day());
143	                    ps.setLong(2, t.locationId());
144	                    ps.setInt(3, t.typeId());
145	                    ps.setInt(4, t.regionId());
146	                    ps.setLong(5, t.buyUnits());
147	                    ps.setLong(6, t.sellUnits());
148	                    ps.setInt(7, t.buyTransactions());
149	                    ps.setInt(8, t.sellTransactions());
150	                    ps.addBatch();
151	
152	                    if ((i + 1) % batchSize == 0) {
153	                        int[] results = ps.executeBatch();
154	                        total += results.length;
155	                        if (progress != null) {
156	                            progress.accept(total);
157	                        }
158	                    }
159	                }
160	
161	                // Flush remaining
162	                int[] results = ps.executeBatch();
163	                total += results.length;
164	
165	                conn.commit();
166	
167	                if (progress != null) {
168	                    progress.accept(total);
169	                }
170	            } catch (SQLException e) {
171	                conn.rollback();
172	                throw e;
173	            }
174	        } catch (SQLException e) {
175	            throw new RuntimeException("Failed to import market trades", e);
176	        }
177	
178	        return total;
179	    }
180	
181	    /**
182	     * Retrieves trades for a specific item type in a region within a date range.
183	     */
184	    public List<MarketTrade> getTradesForType(int typeId, int regionId,
185	                                               LocalDate from, LocalDate to) {
186	        String sql = """
187	                SELECT "DAY", LocationId, TypeId, RegionId,
188	                       BuyUnits, SellUnits, BuyTransactions, SellTransactions
189	                FROM MarketTrades
190	                WHERE TypeId = ? AND RegionId = ? AND "DAY" >= ? AND "DAY" <= ?
191	                ORDER BY "DAY"
192	                """;
193	
194	        int fromDay = (int) EPOCH.until(from, java.time.temporal.ChronoUnit.DAYS);
195	        int toDay = (int) EPOCH.until(to, java.time.temporal.ChronoUnit.DAYS);
196	
197	        List<MarketTrade> result = new ArrayList<>();
198	        try (Connection conn = getConnection();
199	             PreparedStatement ps = conn.prepareStatement(sql)) {
200	
201	            ps.setInt(1, typeId);
202	            ps.setInt(2, regionId);
203	            ps.setInt(3, fromDay);
204	            ps.setInt(4, toDay);
205	
206	            try (ResultSet rs = ps.executeQuery()) {
207	                while (rs.next()) {
208	                    result.add(mapTrade(rs));
209	                }
210	            }
211	        } catch (SQLException e) {
212	            throw new RuntimeException("Failed to query trades for type", e);
213	        }
214	        return result;
215	    }
216	
217	    /**
218	     * Retrieves trades for a specific location (station/structure) within a date range.
219	     */
220	    public List<MarketTrade> getTradesForLocation(long locationId,
221	                                                   LocalDate from, LocalDate to) {
222	        String sql = """
223	                SELECT "DAY", LocationId, TypeId, RegionId,
224	                       BuyUnits, SellUnits, BuyTransactions, SellTransactions
225	                FROM MarketTrades
226	                WHERE LocationId = ? AND "DAY" >= ? AND "DAY" <= ?
227	                ORDER BY "DAY"
228	                """;
229	
230	        int fromDay = (int) EPOCH.until(from, java.time.temporal.ChronoUnit.DAYS);
231	        int toDay = (int) EPOCH.until(to, java.time.temporal.ChronoUnit.DAYS);
232	
233	        List<MarketTrade> result = new ArrayList<>();
234	        try (Connection conn = getConnection();
235	             PreparedStatement ps = conn.prepareStatement(sql)) {
236	
237	            ps.setLong(1, locationId);
238	            ps.setInt(2, fromDay);
239	            ps.setInt(3, toDay);
240	
241	            try (ResultSet rs = ps.executeQuery()) {
242	                while (rs.next()) {
243	                    result.add(mapTrade(rs));
244	                }
245	            }
246	        } catch (SQLException e) {
247	            throw new RuntimeException("Failed to query trades for location", e);
248	        }
249	        return result;
250	    }
251	
252	    /**
253	     * Shuts down the station stats connection pool.
254	     */
255	    public void close() {
256	        if (dataSource != null && !dataSource.isClosed()) {
257	            LOG.info("Closing station stats database connection pool");
258	            dataSource.close();
259	        }
260	    }
261	
262	    // ---- helpers ----
263	
264	    private MarketTrade mapTrade(ResultSet rs) throws SQLException {
265	        return new MarketTrade(
266	                rs.getInt("DAY"),
267	                rs.getLong("LocationId"),
268	                rs.getInt("TypeId"),
269	                rs.getInt("RegionId"),
270	                rs.getLong("BuyUnits"),
271	                rs.getLong("SellUnits"),
272	                rs.getInt("BuyTransactions"),
273	                rs.getInt("SellTransactions")
274	        );
