package com.sampleapp.data;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import jakarta.inject.Inject;
import jakarta.inject.Named;
import jakarta.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.*;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;

/**
 * Separate H2 database for station trade statistics, mirroring the original
 * egStationStats.sdf SQL CE database. Dates are stored as integer day offsets
 * from 2000-01-01 to match the original C# representation.
 */
@Singleton
public class StationStatsDatabase {

    private static final Logger LOG = LoggerFactory.getLogger(StationStatsDatabase.class);
    private static final String DB_URL_TEMPLATE = "jdbc:h2:file:%s/egStationStats";

    /** Epoch used for day-offset date encoding (matching C# original). */
    private static final LocalDate EPOCH = LocalDate.of(2000, 1, 1);

    private final String dataFolder;
    private HikariDataSource dataSource;

    @Inject
    public StationStatsDatabase(@Named("dataFolder") String dataFolder) {
        this.dataFolder = dataFolder;
    }

    /**
     * Initialises the station stats database, creating the schema if it
     * does not already exist.
     */
    public void initialize() {
        String jdbcUrl = String.format(DB_URL_TEMPLATE, dataFolder.replace('\\', '/'));
        LOG.info("Initialising station stats database at {}", jdbcUrl);

        HikariConfig config = new HikariConfig();
        config.setJdbcUrl(jdbcUrl);
        config.setMaximumPoolSize(5);
        config.setMinimumIdle(1);
        config.setPoolName("sampleapp-stationstats");

        dataSource = new HikariDataSource(config);

        try (Connection conn = dataSource.getConnection();
             Statement stmt = conn.createStatement()) {

            stmt.execute("""
                    CREATE TABLE IF NOT EXISTS MarketTrades (
                        "DAY" INT NOT NULL,
                        LocationId BIGINT NOT NULL,
                        TypeId INT NOT NULL,
                        RegionId INT NOT NULL,
                        BuyUnits BIGINT NOT NULL DEFAULT 0,
                        SellUnits BIGINT NOT NULL DEFAULT 0,
                        BuyTransactions INT NOT NULL DEFAULT 0,
                        SellTransactions INT NOT NULL DEFAULT 0,
                        PRIMARY KEY ("DAY", LocationId, TypeId)
                    )
                    """);

            stmt.execute("""
                    CREATE INDEX IF NOT EXISTS IDX_MarketTrades_RegionDayType
                        ON MarketTrades (RegionId, "DAY", TypeId)
                    """);

            LOG.info("Station stats database initialised successfully");
        } catch (SQLException e) {
            throw new RuntimeException("Failed to initialise station stats database", e);
        }
    }

    /**
     * Obtains a connection from the station-stats pool.
     */
    public Connection getConnection() throws SQLException {
        if (dataSource == null || dataSource.isClosed()) {
            throw new IllegalStateException("Station stats database has not been initialised");
        }
        return dataSource.getConnection();
    }

    /**
     * Returns the most recent trade date stored in the database, or {@code null}
     * if the table is empty.
     */
    public LocalDate getLatestTradeDate() {
        String sql = "SELECT MAX(\"DAY\") FROM MarketTrades";
        try (Connection conn = getConnection();
             PreparedStatement ps = conn.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {

            if (rs.next()) {
                int day = rs.getInt(1);
                if (!rs.wasNull()) {
                    return EPOCH.plusDays(day);
                }
            }
            return null;
        } catch (SQLException e) {
            throw new RuntimeException("Failed to query latest trade date", e);
        }
    }

    /**
     * Bulk-imports market trades using batch inserts. The {@code progress}
     * callback receives the number of rows inserted so far after every batch.
     *
     * @return total rows inserted
     */
    public int importMarketTrades(List<MarketTrade> trades, Consumer<Integer> progress) {
        if (trades == null || trades.isEmpty()) {
            return 0;
        }

        String sql = """
                MERGE INTO MarketTrades ("DAY", LocationId, TypeId, RegionId,
                    BuyUnits, SellUnits, BuyTransactions, SellTransactions)
                KEY ("DAY", LocationId, TypeId)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """;

        int batchSize = 1000;
        int total = 0;

        try (Connection conn = getConnection()) {
            conn.setAutoCommit(false);

            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                for (int i = 0; i < trades.size(); i++) {
                    MarketTrade t = trades.get(i);
                    ps.setInt(1, t.day());
                    ps.setLong(2, t.locationId());
                    ps.setInt(3, t.typeId());
                    ps.setInt(4, t.regionId());
                    ps.setLong(5, t.buyUnits());
                    ps.setLong(6, t.sellUnits());
                    ps.setInt(7, t.buyTransactions());
                    ps.setInt(8, t.sellTransactions());
                    ps.addBatch();

                    if ((i + 1) % batchSize == 0) {
                        int[] results = ps.executeBatch();
                        total += results.length;
                        if (progress != null) {
                            progress.accept(total);
                        }
                    }
                }

                // Flush remaining
                int[] results = ps.executeBatch();
                total += results.length;

                conn.commit();

                if (progress != null) {
                    progress.accept(total);
                }
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Failed to import market trades", e);
        }

        return total;
    }

    /**
     * Retrieves trades for a specific item type in a region within a date range.
     */
    public List<MarketTrade> getTradesForType(int typeId, int regionId,
                                               LocalDate from, LocalDate to) {
        String sql = """
                SELECT "DAY", LocationId, TypeId, RegionId,
                       BuyUnits, SellUnits, BuyTransactions, SellTransactions
                FROM MarketTrades
                WHERE TypeId = ? AND RegionId = ? AND "DAY" >= ? AND "DAY" <= ?
                ORDER BY "DAY"
                """;

        int fromDay = (int) EPOCH.until(from, java.time.temporal.ChronoUnit.DAYS);
        int toDay = (int) EPOCH.until(to, java.time.temporal.ChronoUnit.DAYS);

        List<MarketTrade> result = new ArrayList<>();
        try (Connection conn = getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {

            ps.setInt(1, typeId);
            ps.setInt(2, regionId);
            ps.setInt(3, fromDay);
            ps.setInt(4, toDay);

            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    result.add(mapTrade(rs));
                }
            }
        } catch (SQLException e) {
            throw new RuntimeException("Failed to query trades for type", e);
        }
        return result;
    }

    /**
     * Retrieves trades for a specific location (station/structure) within a date range.
     */
    public List<MarketTrade> getTradesForLocation(long locationId,
                                                   LocalDate from, LocalDate to) {
        String sql = """
                SELECT "DAY", LocationId, TypeId, RegionId,
                       BuyUnits, SellUnits, BuyTransactions, SellTransactions
                FROM MarketTrades
                WHERE LocationId = ? AND "DAY" >= ? AND "DAY" <= ?
                ORDER BY "DAY"
                """;

        int fromDay = (int) EPOCH.until(from, java.time.temporal.ChronoUnit.DAYS);
        int toDay = (int) EPOCH.until(to, java.time.temporal.ChronoUnit.DAYS);

        List<MarketTrade> result = new ArrayList<>();
        try (Connection conn = getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {

            ps.setLong(1, locationId);
            ps.setInt(2, fromDay);
            ps.setInt(3, toDay);

            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    result.add(mapTrade(rs));
                }
            }
        } catch (SQLException e) {
            throw new RuntimeException("Failed to query trades for location", e);
        }
        return result;
    }

    /**
     * Shuts down the station stats connection pool.
     */
    public void close() {
        if (dataSource != null && !dataSource.isClosed()) {
            LOG.info("Closing station stats database connection pool");
            dataSource.close();
        }
    }

    // ---- helpers ----

    private MarketTrade mapTrade(ResultSet rs) throws SQLException {
        return new MarketTrade(
                rs.getInt("DAY"),
                rs.getLong("LocationId"),
                rs.getInt("TypeId"),
                rs.getInt("RegionId"),
                rs.getLong("BuyUnits"),
                rs.getLong("SellUnits"),
                rs.getInt("BuyTransactions"),
                rs.getInt("SellTransactions")
        );
    }

    // ---- Static helpers for date conversion ----

    /**
     * Converts a {@link LocalDate} to day offset from 2000-01-01.
     */
    public static int toDay(LocalDate date) {
        return (int) EPOCH.until(date, java.time.temporal.ChronoUnit.DAYS);
    }

    /**
     * Converts a day offset from 2000-01-01 to a {@link LocalDate}.
     */
    public static LocalDate fromDay(int day) {
        return EPOCH.plusDays(day);
    }
}

