package com.sampleapp.esi;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.net.InetSocketAddress;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.Base64;
import java.util.List;
import java.util.UUID;
import java.util.concurrent.CompletableFuture;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * EVE SSO OAuth 2.0 PKCE authentication flow.
 */
public class EveSsoAuth {

    private static final Logger LOG = Logger.getLogger(EveSsoAuth.class.getName());

    private static final String AUTH_URL = "https://login.eveonline.com/v2/oauth/authorize/";
    private static final String TOKEN_URL = "https://login.eveonline.com/v2/oauth/token";
    private static final String CLIENT_ID = "REDACTED_ESI_CLIENT_ID";
    private static final String CALLBACK_URI = "http://localhost:63886/callback/";
    private static final int CALLBACK_PORT = 63886;

    /** All ESI scopes used by Sample App (matches .NET SsoScopes.AllScopes). */
    public static final List<String> ALL_SCOPES = List.of(
            "publicData",
            "esi-assets.read_assets.v1",
            "esi-universe.read_structures.v1",
            "esi-markets.read_character_orders.v1",
            "esi-markets.structure_markets.v1",
            "esi-assets.read_corporation_assets.v1",
            "esi-ui.open_window.v1",
            "esi-wallet.read_character_wallet.v1",
            "esi-contracts.read_character_contracts.v1",
            "esi-contracts.read_corporation_contracts.v1",
            "esi-wallet.read_corporation_wallets.v1",
            "esi-characters.read_loyalty.v1",
            "esi-markets.read_corporation_orders.v1",
            "esi-characters.read_blueprints.v1",
            "esi-corporations.read_blueprints.v1",
            "esi-characters.read_corporation_roles.v1",
            "esi-fleets.read_fleet.v1",
            "esi-industry.read_character_mining.v1",
            "esi-industry.read_character_jobs.v1",
            "esi-industry.read_corporation_jobs.v1",
            "esi-skills.read_skills.v1",
            "esi-skills.read_skillqueue.v1",
            "esi-characters.read_agents_research.v1",
            "esi-characters.read_standings.v1",
            "esi-search.search_structures.v1"
    );

    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;
    private final TokenManager tokenManager;

    public EveSsoAuth(HttpClient httpClient, ObjectMapper objectMapper, TokenManager tokenManager) {
        this.httpClient = httpClient;
        this.objectMapper = objectMapper;
        this.tokenManager = tokenManager;
        this.tokenManager.setRefreshCallback(this::refreshToken);
    }

    // ---- PKCE helpers ----

    /**
     * Generate a PKCE code verifier: 32 random bytes encoded as base64url (no padding).
     */
    public String generateCodeVerifier() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    /**
     * Generate a PKCE code challenge: SHA-256 hash of verifier encoded as base64url (no padding).
     */
    public String generateCodeChallenge(String verifier) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(verifier.getBytes(StandardCharsets.US_ASCII));
            return Base64.getUrlEncoder().withoutPadding().encodeToString(hash);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    /**
     * Build the full authorization URL to redirect the user to.
     */
    public String buildAuthUrl(String codeChallenge, String state, List<String> scopes) {
        String scopeStr = URLEncoder.encode(String.join(" ", scopes), StandardCharsets.UTF_8);
        return AUTH_URL + "?" +
                "response_type=code" +
                "&redirect_uri=" + URLEncoder.encode(CALLBACK_URI, StandardCharsets.UTF_8) +
                "&client_id=" + CLIENT_ID +
                "&scope=" + scopeStr +
                "&code_challenge=" + URLEncoder.encode(codeChallenge, StandardCharsets.UTF_8) +
                "&code_challenge_method=S256" +
                "&state=" + URLEncoder.encode(state, StandardCharsets.UTF_8);
    }

    /**
     * Start a lightweight HTTP server on the callback port and wait for the OAuth redirect.
     *
     * @return a future that completes with the authorization code from the callback
     */
    public CompletableFuture<String> startCallbackServer() {
        CompletableFuture<String> future = new CompletableFuture<>();
        try {
            HttpServer server = HttpServer.create(new InetSocketAddress("localhost", CALLBACK_PORT), 0);
            server.createContext("/callback/", exchange -> {
                try {
                    String query = exchange.getRequestURI().getQuery();
                    String code = null;
                    if (query != null) {
                        for (String param : query.split("&")) {
                            String[] kv = param.split("=", 2);
                            if ("code".equals(kv[0]) && kv.length == 2) {
                                code = kv[1];
                            }
                        }
                    }

                    String responseBody = code != null
                            ? "<html><body><h2>Login successful!</h2><p>You can close this window.</p></body></html>"
                            : "<html><body><h2>Login failed</h2><p>No authorization code received.</p></body></html>";

                    byte[] responseBytes = responseBody.getBytes(StandardCharsets.UTF_8);
                    exchange.getResponseHeaders().set("Content-Type", "text/html; charset=utf-8");
                    exchange.sendResponseHeaders(200, responseBytes.length);
                    exchange.getResponseBody().write(responseBytes);
                    exchange.getResponseBody().close();

                    if (code != null) {
                        future.complete(code);
                    } else {
                        future.completeExceptionally(new IOException("No authorization code in callback"));
                    }
                } catch (Exception e) {
                    future.completeExceptionally(e);
                } finally {
                    server.stop(1);
                }
            });
            server.start();
            LOG.info("Callback server listening on port " + CALLBACK_PORT);
        } catch (IOException e) {
            future.completeExceptionally(e);
        }
        return future;
    }

    /**
     * Exchange an authorization code for access/refresh tokens.
     */
    public CompletableFuture<TokenManager.TokenData> exchangeCode(String code, String codeVerifier) {
        String body = "grant_type=authorization_code" +
                "&code=" + URLEncoder.encode(code, StandardCharsets.UTF_8) +
                "&client_id=" + CLIENT_ID +
                "&code_verifier=" + URLEncoder.encode(codeVerifier, StandardCharsets.UTF_8);

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(TOKEN_URL))
                .header("Content-Type", "application/x-www-form-urlencoded")
                .POST(HttpRequest.BodyPublishers.ofString(body))
                .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApply(response -> parseTokenResponse(response.body()));
    }

    /**
     * Refresh an expired access token using the refresh token.
     */
    public CompletableFuture<TokenManager.TokenData> refreshToken(String refreshToken) {
        String body = "grant_type=refresh_token" +
                "&refresh_token=" + URLEncoder.encode(refreshToken, StandardCharsets.UTF_8) +
                "&client_id=" + CLIENT_ID;

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(TOKEN_URL))
                .header("Content-Type", "application/x-www-form-urlencoded")
                .POST(HttpRequest.BodyPublishers.ofString(body))
                .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApply(response -> parseTokenResponse(response.body()));
    }

    /**
     * Full login flow: generate PKCE, open browser, listen for callback, exchange code.
     */
    public CompletableFuture<TokenManager.TokenData> login(List<String> scopes) {
        String verifier = generateCodeVerifier();
        String challenge = generateCodeChallenge(verifier);
        String state = UUID.randomUUID().toString();

        CompletableFuture<String> callbackFuture = startCallbackServer();

        String authUrl = buildAuthUrl(challenge, state, scopes);
        LOG.info("Opening browser for EVE SSO login: " + authUrl);
        openBrowser(authUrl);

        return callbackFuture
                .thenCompose(code -> exchangeCode(code, verifier))
                .thenApply(tokenData -> {
                    tokenManager.storeToken(tokenData);
                    LOG.info("Login successful for character " + tokenData.characterName() +
                            " (ID: " + tokenData.characterId() + ")");
                    return tokenData;
                });
    }

    // ---- Private helpers ----

    private TokenManager.TokenData parseTokenResponse(String responseBody) {
        try {
            JsonNode root = objectMapper.readTree(responseBody);
            String accessToken = root.get("access_token").asText();
            String refreshTokenValue = root.get("refresh_token").asText();
            int expiresIn = root.get("expires_in").asInt();
            LocalDateTime expiresAt = LocalDateTime.now().plusSeconds(expiresIn);

            // Decode the JWT access token to extract character info
            String[] jwtParts = accessToken.split("\\.");
            if (jwtParts.length < 2) {
                throw new IOException("Invalid JWT token format");
            }
            String payload = new String(Base64.getUrlDecoder().decode(jwtParts[1]), StandardCharsets.UTF_8);
            JsonNode jwt = objectMapper.readTree(payload);

            // Subject format: "CHARACTER:EVE:<character_id>"
            String sub = jwt.get("sub").asText();
            String[] subParts = sub.split(":");
            int characterId = Integer.parseInt(subParts[2]);
            String characterName = jwt.get("name").asText();
            String ownerHash = jwt.has("owner") ? jwt.get("owner").asText() : "";

            return new TokenManager.TokenData(
                    accessToken, refreshTokenValue, expiresAt,
                    characterId, characterName, ownerHash
            );
        } catch (Exception e) {
            throw new RuntimeException("Failed to parse SSO token response: " + e.getMessage(), e);
        }
    }

    private void openBrowser(String url) {
        try {
            String os = System.getProperty("os.name", "").toLowerCase();
            if (os.contains("win")) {
                Runtime.getRuntime().exec(new String[]{"rundll32", "url.dll,FileProtocolHandler", url});
            } else if (os.contains("mac")) {
                Runtime.getRuntime().exec(new String[]{"open", url});
            } else {
                Runtime.getRuntime().exec(new String[]{"xdg-open", url});
            }
        } catch (IOException e) {
            LOG.log(Level.WARNING, "Could not open browser automatically. Please visit: " + url, e);
        }
    }
}

