package com.sampleapp.core.app;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

/**
 * Application configuration loaded from config.json.
 * Provides defaults for all settings and persists changes.
 */
public class AppConfig {

    private static final Logger log = LoggerFactory.getLogger(AppConfig.class);

    private Path configPath;
    private String esiBaseUrl = "https://esi.evetech.net/latest";
    private String ssoCallbackUrl = "http://localhost:20123/callback";
    private String clientId = "";
    private int syncIntervalMinutes = 15;
    private int marketCacheMinutes = 5;
    private boolean showSplash = true;
    private String defaultMarketHub = "Jita IV - Moon 4 - Caldari Navy Assembly Plant";
    private int defaultRegionId = 10000002; // The Forge
    private String subscriptionTier = "Free";
    private boolean darkTheme = true;

    private AppConfig() {}

    /**
     * Load configuration from a JSON file, or create defaults if not present.
     */
    public static AppConfig load(Path configPath) {
        var config = new AppConfig();
        config.configPath = configPath;

        if (Files.exists(configPath)) {
            try {
                var json = Files.readString(configPath);
                config.parseJson(json);
                log.info("Configuration loaded from {}", configPath);
            } catch (IOException e) {
                log.warn("Failed to read config file, using defaults", e);
            }
        } else {
            log.info("No config file found, using defaults");
            config.save();
        }

        return config;
    }

    private void parseJson(String json) {
        // Simple string-based JSON parsing without external dependencies.
        // Extracts known keys from a flat JSON object.
        esiBaseUrl = extractString(json, "esiBaseUrl", esiBaseUrl);
        ssoCallbackUrl = extractString(json, "ssoCallbackUrl", ssoCallbackUrl);
        clientId = extractString(json, "clientId", clientId);
        syncIntervalMinutes = extractInt(json, "syncIntervalMinutes", syncIntervalMinutes);
        marketCacheMinutes = extractInt(json, "marketCacheMinutes", marketCacheMinutes);
        showSplash = extractBoolean(json, "showSplash", showSplash);
        defaultMarketHub = extractString(json, "defaultMarketHub", defaultMarketHub);
        defaultRegionId = extractInt(json, "defaultRegionId", defaultRegionId);
        subscriptionTier = extractString(json, "subscriptionTier", subscriptionTier);
        darkTheme = extractBoolean(json, "darkTheme", darkTheme);
    }

    private static String extractString(String json, String key, String defaultValue) {
        // Matches: "key": "value"
        String pattern = "\"" + key + "\"\\s*:\\s*\"";
        int start = json.indexOf(pattern.replace("\\s*", ""));
        // Try with flexible whitespace
        if (start < 0) {
            int keyIdx = json.indexOf("\"" + key + "\"");
            if (keyIdx < 0) return defaultValue;
            int colonIdx = json.indexOf(':', keyIdx + key.length() + 2);
            if (colonIdx < 0) return defaultValue;
            int quoteStart = json.indexOf('"', colonIdx + 1);
            if (quoteStart < 0) return defaultValue;
            int quoteEnd = json.indexOf('"', quoteStart + 1);
            if (quoteEnd < 0) return defaultValue;
            return json.substring(quoteStart + 1, quoteEnd);
        }
        int valueStart = start + pattern.replace("\\s*", "").length();
        int valueEnd = json.indexOf('"', valueStart);
        if (valueEnd < 0) return defaultValue;
        return json.substring(valueStart, valueEnd);
    }

    private static int extractInt(String json, String key, int defaultValue) {
        int keyIdx = json.indexOf("\"" + key + "\"");
        if (keyIdx < 0) return defaultValue;
        int colonIdx = json.indexOf(':', keyIdx + key.length() + 2);
        if (colonIdx < 0) return defaultValue;
        int start = colonIdx + 1;
        // Skip whitespace
        while (start < json.length() && Character.isWhitespace(json.charAt(start))) {
            start++;
        }
        int end = start;
        while (end < json.length() && (Character.isDigit(json.charAt(end)) || json.charAt(end) == '-')) {
            end++;
        }
        if (end == start) return defaultValue;
        try {
            return Integer.parseInt(json.substring(start, end));
        } catch (NumberFormatException e) {
            return defaultValue;
        }
    }

    private static boolean extractBoolean(String json, String key, boolean defaultValue) {
        int keyIdx = json.indexOf("\"" + key + "\"");
        if (keyIdx < 0) return defaultValue;
        int colonIdx = json.indexOf(':', keyIdx + key.length() + 2);
        if (colonIdx < 0) return defaultValue;
        String rest = json.substring(colonIdx + 1).trim();
        if (rest.startsWith("true")) return true;
        if (rest.startsWith("false")) return false;
        return defaultValue;
    }

    /**
     * Persist current configuration to disk.
     */
    public void save() {
        if (configPath == null) return;
        try {
            var json = toJson();
            Files.createDirectories(configPath.getParent());
            Files.writeString(configPath, json);
            log.debug("Configuration saved to {}", configPath);
        } catch (IOException e) {
            log.error("Failed to save configuration", e);
        }
    }

    private String toJson() {
        return """
                {
                  "esiBaseUrl": "%s",
                  "ssoCallbackUrl": "%s",
                  "clientId": "%s",
                  "syncIntervalMinutes": %d,
                  "marketCacheMinutes": %d,
                  "showSplash": %b,
                  "defaultMarketHub": "%s",
                  "defaultRegionId": %d,
                  "subscriptionTier": "%s",
                  "darkTheme": %b
                }
                """.formatted(esiBaseUrl, ssoCallbackUrl, clientId,
                syncIntervalMinutes, marketCacheMinutes, showSplash,
                defaultMarketHub, defaultRegionId, subscriptionTier, darkTheme);
    }

    // Getters and setters

    public String getEsiBaseUrl() { return esiBaseUrl; }
    public void setEsiBaseUrl(String esiBaseUrl) { this.esiBaseUrl = esiBaseUrl; }

    public String getSsoCallbackUrl() { return ssoCallbackUrl; }
    public void setSsoCallbackUrl(String ssoCallbackUrl) { this.ssoCallbackUrl = ssoCallbackUrl; }

    public String getClientId() { return clientId; }
    public void setClientId(String clientId) { this.clientId = clientId; }

    public int getSyncIntervalMinutes() { return syncIntervalMinutes; }
    public void setSyncIntervalMinutes(int syncIntervalMinutes) { this.syncIntervalMinutes = syncIntervalMinutes; }

    public int getMarketCacheMinutes() { return marketCacheMinutes; }
    public void setMarketCacheMinutes(int marketCacheMinutes) { this.marketCacheMinutes = marketCacheMinutes; }

    public boolean isShowSplash() { return showSplash; }
    public void setShowSplash(boolean showSplash) { this.showSplash = showSplash; }

    public String getDefaultMarketHub() { return defaultMarketHub; }
    public void setDefaultMarketHub(String defaultMarketHub) { this.defaultMarketHub = defaultMarketHub; }

    public int getDefaultRegionId() { return defaultRegionId; }
    public void setDefaultRegionId(int defaultRegionId) { this.defaultRegionId = defaultRegionId; }

    public String getSubscriptionTier() { return subscriptionTier; }
    public void setSubscriptionTier(String subscriptionTier) { this.subscriptionTier = subscriptionTier; }

    public boolean isDarkTheme() { return darkTheme; }
    public void setDarkTheme(boolean darkTheme) { this.darkTheme = darkTheme; }
}

