213	    /**
214	     * Find trade opportunities in a region based on margin and volume thresholds.
215	     */
216	    public List<TradeOpportunity> findTradeOpportunities(int regionId,
217	                                                         double minMargin,
218	                                                         long minVolume) {
219	        List<StationPriceRepository.StationPriceRow> prices = priceRepo.findByLocation(regionId);
220	        List<TradeOpportunity> opportunities = new ArrayList<>();
221	
222	        for (var price : prices) {
223	            if (price.sellPrice() <= 0 || price.buyPrice() <= 0) {
224	                continue;
225	            }
226	
227	            double margin = (price.sellPrice() - price.buyPrice()) / price.sellPrice();
228	            if (margin >= minMargin) {
229	                String typeName = typeCache.getName(price.typeId()).orElse("Unknown");
230	                opportunities.add(new TradeOpportunity(
231	                        price.typeId(),
232	                        typeName,
233	                        price.buyPrice(),
234	                        price.sellPrice(),
235	                        margin,
236	                        0L, // volume would need separate lookup
237	                        0.0 // dailyVolume placeholder
238	                ));
239	            }
240	        }
241	
242	        opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
243	        return opportunities;
244	    }
