package com.sampleapp.app.service;
import com.sampleapp.core.service.EventBus;
import com.sampleapp.core.service.TaxService;

import com.sampleapp.core.model.TradeOpportunity;
import com.sampleapp.core.subscription.FeatureGate;
import com.sampleapp.data.cache.MarketPriceCache;
import com.sampleapp.data.cache.ItemTypeCache;
import com.sampleapp.data.repository.AssetRepository;
import com.sampleapp.data.repository.BlueprintRepository;
import com.sampleapp.data.repository.CharacterRepository;
import com.sampleapp.data.repository.ContractRepository;
import com.sampleapp.data.repository.IndustryJobRepository;
import com.sampleapp.data.repository.LoyaltyRepository;
import com.sampleapp.data.repository.MarketOrderRepository;
import com.sampleapp.data.repository.MarketStatisticsRepository;
import com.sampleapp.data.repository.MarketTransactionRepository;
import com.sampleapp.data.repository.StationPriceRepository;
import com.sampleapp.data.repository.TypeCacheRepository;
import com.sampleapp.data.repository.WalletRepository;
import com.sampleapp.data.DatabaseManager;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.TokenManager;
import com.google.inject.Inject;
import com.google.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * Main business service orchestrating ESI calls, database persistence, and calculations.
 * <p>
 * Mirrors the original C# {@code BusinessLogic} class. All data retrieval methods
 * read from the local database; sync methods fetch from ESI and persist.
 */
@Singleton
public class BusinessLogic {

    private static final Logger log = LoggerFactory.getLogger(BusinessLogic.class);

    /** Jita 4-4 station ID - primary trade hub. */
    private static final long JITA_STATION_ID = 60003760L;

    private final EsiClient esiClient;
    private final TokenManager tokenManager;
    private final DatabaseManager dbManager;
    private final MarketTransactionRepository transactionRepo;
    private final MarketOrderRepository orderRepo;
    private final ContractRepository contractRepo;
    private final IndustryJobRepository industryRepo;
    private final AssetRepository assetRepo;
    private final BlueprintRepository blueprintRepo;
    private final WalletRepository walletRepo;
    private final LoyaltyRepository loyaltyRepo;
    private final StationPriceRepository priceRepo;
    private final MarketStatisticsRepository statsRepo;
    private final TypeCacheRepository typeRepo;
    private final CharacterRepository characterRepo;
    private final MarketPriceCache priceCache;
    private final ItemTypeCache typeCache;
    private final FeatureGate featureGate;
    private final EventBus eventBus;

    @Inject
    public BusinessLogic(EsiClient esiClient,
                         TokenManager tokenManager,
                         DatabaseManager dbManager,
                         MarketTransactionRepository transactionRepo,
                         MarketOrderRepository orderRepo,
                         ContractRepository contractRepo,
                         IndustryJobRepository industryRepo,
                         AssetRepository assetRepo,
                         BlueprintRepository blueprintRepo,
                         WalletRepository walletRepo,
                         LoyaltyRepository loyaltyRepo,
                         StationPriceRepository priceRepo,
                         MarketStatisticsRepository statsRepo,
                         TypeCacheRepository typeRepo,
                         CharacterRepository characterRepo,
                         MarketPriceCache priceCache,
                         ItemTypeCache typeCache,
                         FeatureGate featureGate,
                         EventBus eventBus) {
        this.esiClient = esiClient;
        this.tokenManager = tokenManager;
        this.dbManager = dbManager;
        this.transactionRepo = transactionRepo;
        this.orderRepo = orderRepo;
        this.contractRepo = contractRepo;
        this.industryRepo = industryRepo;
        this.assetRepo = assetRepo;
        this.blueprintRepo = blueprintRepo;
        this.walletRepo = walletRepo;
        this.loyaltyRepo = loyaltyRepo;
        this.priceRepo = priceRepo;
        this.statsRepo = statsRepo;
        this.typeRepo = typeRepo;
        this.characterRepo = characterRepo;
        this.priceCache = priceCache;
        this.typeCache = typeCache;
        this.featureGate = featureGate;
        this.eventBus = eventBus;
    }

    // ================================================================
    // Data Retrieval (from local DB)
    // ================================================================

    /**
     * Get all active and historical market orders for a character.
     */
    public List<MarketOrderRepository.MarketOrderRow> getCharacterOrders(int characterId) {
        return orderRepo.findByCharacter(characterId);
    }

    /**
     * Get market transactions for a character within a date range.
     */
    public List<MarketTransactionRepository.MarketTransactionRow> getCharacterTransactions(
            int characterId, LocalDateTime from, LocalDateTime to) {
        return transactionRepo.findByCharacterAndDateRange(characterId, from, to);
    }

    /**
     * Get wallet journal entries for a character within a date range.
     */
    public List<WalletRepository.WalletJournalRow> getWalletJournal(
            int characterId, LocalDateTime from, LocalDateTime to) {
        return walletRepo.findJournalByCharacterAndDateRange(characterId, from, to);
    }

    /**
     * Get the current wallet balance for a character.
     */
    public List<WalletRepository.WalletBalanceRow> getWalletBalances(int characterId) {
        return walletRepo.findBalancesByCharacter(characterId);
    }

    /**
     * Get trained skills for a character (returns character row).
     */
    public List<CharacterRepository.CharacterRow> getCharacterSkills(int characterId) {
        // Skills are not directly stored in CharacterRepository; return character list
        return characterRepo.findAll();
    }

    /**
     * Get industry jobs for a character.
     */
    public List<IndustryJobRepository.IndustryJobRow> getIndustryJobs(int characterId) {
        return industryRepo.findByCharacter(characterId);
    }

    /**
     * Get blueprint inventory for a character.
     */
    public List<BlueprintRepository.BlueprintRow> getBlueprints(int characterId) {
        return blueprintRepo.findByCharacter(characterId);
    }

    /**
     * Get assets for a character.
     */
    public List<AssetRepository.AssetRow> getAssets(int characterId) {
        return assetRepo.findByCharacter(characterId);
    }

    /**
     * Get contracts for a character.
     */
    public List<ContractRepository.ContractRow> getContracts(int characterId) {
        return contractRepo.findByCharacter(characterId);
    }

    /**
     * Get loyalty points for a character across all NPC corporations.
     */
    public List<LoyaltyRepository.LoyaltyPointsRow> getLoyaltyPoints(int characterId) {
        return loyaltyRepo.findByCharacter(characterId);
    }

    // ================================================================
    // Price & Market Analysis
    // ================================================================

    /**
     * Get cached price data for a type at a specific station/hub.
     */
    public StationPriceRepository.StationPriceRow getStationPrice(long hubId, int typeId) {
        return priceRepo.findById(typeId, hubId).orElse(null);
    }

    /**
     * Get prices for a type across all major trade hubs.
     */
    public List<StationPriceRepository.StationPriceRow> getHubPrices(int typeId) {
        return priceRepo.findByType(typeId);
    }

    /**
     * Get historical market statistics for a type in a region.
     */
    public List<MarketStatisticsRepository.MarketStatisticsRow> getMarketHistory(
            int typeId, int regionId, LocalDate from, LocalDate to) {
        return statsRepo.findByTypeRegionAndDateRange(typeId, regionId, from, to);
    }

    /**
     * Find trade opportunities in a region based on margin and volume thresholds.
     */
    public List<TradeOpportunity> findTradeOpportunities(int regionId,
                                                         double minMargin,
                                                         long minVolume) {
        List<StationPriceRepository.StationPriceRow> prices = priceRepo.findByLocation(regionId);
        List<TradeOpportunity> opportunities = new ArrayList<>();

        for (var price : prices) {
            if (price.sellPrice() <= 0 || price.buyPrice() <= 0) {
                continue;
            }

            double margin = (price.sellPrice() - price.buyPrice()) / price.sellPrice();
            if (margin >= minMargin) {
                String typeName = typeCache.getName(price.typeId()).orElse("Unknown");
                opportunities.add(new TradeOpportunity(
                        price.typeId(),
                        typeName,
                        price.buyPrice(),
                        price.sellPrice(),
                        margin,
                        0L, // volume would need separate lookup
                        0.0 // dailyVolume placeholder
                ));
            }
        }

        opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
        return opportunities;
    }

    // ================================================================
    // ESI Sync (fetch from ESI, persist to DB)
    // ================================================================

    /**
     * Full character sync - fetches all character data from ESI.
     */
    public CompletableFuture<Void> syncCharacter(int characterId) {
        eventBus.publish(EventBus.Event.ESI_SYNC_STARTED, characterId);

        return CompletableFuture.allOf(
                syncOrders(characterId),
                syncTransactions(characterId),
                syncWallet(characterId),
                syncAssets(characterId),
                syncBlueprints(characterId),
                syncIndustryJobs(characterId),
                syncContracts(characterId),
                syncSkills(characterId),
                syncLoyaltyPoints(characterId)
        ).thenRun(() -> {
            log.info("Full ESI sync completed for character {}", characterId);
            eventBus.publish(EventBus.Event.ESI_SYNC_COMPLETED, characterId);
        }).exceptionally(ex -> {
            log.error("ESI sync failed for character {}", characterId, ex);
            eventBus.publish(EventBus.Event.ESI_SYNC_FAILED, characterId);
            return null;
        });
    }

    /**
     * Sync market orders from ESI.
     */
    public CompletableFuture<Void> syncOrders(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var response = esiClient.market.getCharacterOrders(characterId, token).join();
                if (response.isSuccess() && response.data() != null) {
                    var rows = response.data().stream()
                            .map(o -> new MarketOrderRepository.MarketOrderRow(
                                    o.orderId(), characterId, o.typeId(), o.price(),
                                    o.volumeRemain(), o.volumeTotal(),
                                    o.isBuyOrder() != null && o.isBuyOrder(),
                                    o.duration(),
                                    o.issued().toLocalDateTime(),
                                    o.locationId(), o.regionId(),
                                    o.state() != null ? o.state() : "active",
                                    o.minVolume() != null ? o.minVolume() : 1,
                                    o.range()))
                            .toList();
                    orderRepo.insertBatch(rows);
                    log.info("Synced {} orders for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.ORDERS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync orders for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync market transactions from ESI.
     */
    public CompletableFuture<Void> syncTransactions(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var response = esiClient.wallet.getCharacterTransactions(characterId, token).join();
                if (response.isSuccess() && response.data() != null) {
                    var rows = response.data().stream()
                            .map(t -> new MarketTransactionRepository.MarketTransactionRow(
                                    t.transactionId(), characterId,
                                    t.date().toLocalDateTime(),
                                    t.typeId(), t.quantity(), t.unitPrice(),
                                    t.clientId(), t.isBuy(), t.locationId(),
                                    t.journalRefId()))
                            .toList();
                    transactionRepo.insertBatch(rows);
                    log.info("Synced {} transactions for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.TRANSACTIONS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync transactions for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync wallet balance and journal from ESI.
     */
    public CompletableFuture<Void> syncWallet(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                // Sync balance
                var balanceResponse = esiClient.wallet.getCharacterWallet(characterId, token).join();
                if (balanceResponse.isSuccess() && balanceResponse.data() != null) {
                    walletRepo.upsertBalance(characterId, 1, balanceResponse.data());
                    log.info("Synced wallet balance for character {}: {}", characterId, balanceResponse.data());
                }

                // Sync journal (paginated)
                var journalEntries = esiClient.wallet.getCharacterJournal(characterId, token).join();
                if (journalEntries != null && !journalEntries.isEmpty()) {
                    var rows = journalEntries.stream()
                            .map(j -> new WalletRepository.WalletJournalRow(
                                    j.id(), characterId,
                                    j.date().toLocalDateTime(),
                                    j.refType() != null ? j.refType() : "",
                                    j.amount() != null ? j.amount() : 0.0,
                                    j.balance() != null ? j.balance() : 0.0,
                                    j.description(),
                                    j.firstPartyId() != null ? j.firstPartyId().longValue() : null,
                                    j.secondPartyId() != null ? j.secondPartyId().longValue() : null,
                                    j.contextId()))
                            .toList();
                    walletRepo.insertJournalBatch(rows);
                    log.info("Synced {} journal entries for character {}", rows.size(), characterId);
                }
                eventBus.publish(EventBus.Event.WALLET_UPDATED, characterId);
            } catch (Exception e) {
                log.error("Failed to sync wallet for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync assets from ESI (paginated).
     */
    public CompletableFuture<Void> syncAssets(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var assets = esiClient.assets.getCharacterAssets(characterId, token).join();
                if (assets != null) {
                    var rows = assets.stream()
                            .map(a -> new AssetRepository.AssetRow(
                                    a.itemId(), characterId, a.typeId(), a.quantity(),
                                    a.locationId(), a.locationFlag(), a.locationType(),
                                    a.isBlueprintCopy() != null && a.isBlueprintCopy()))
                            .toList();
                    assetRepo.replaceAllForCharacter(characterId, rows);
                    log.info("Synced {} assets for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.ASSETS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync assets for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync blueprints from ESI (paginated).
     */
    public CompletableFuture<Void> syncBlueprints(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var blueprints = esiClient.characters.getBlueprints(characterId, token).join();
                if (blueprints != null) {
                    var rows = blueprints.stream()
                            .map(b -> new BlueprintRepository.BlueprintRow(
                                    b.itemId(), characterId, b.typeId(), b.locationId(),
                                    b.runs(), b.materialEfficiency(), b.timeEfficiency(),
                                    b.quantity() == -2))
                            .toList();
                    blueprintRepo.replaceAllForCharacter(characterId, rows);
                    log.info("Synced {} blueprints for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.BLUEPRINTS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync blueprints for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync industry jobs from ESI.
     */
    public CompletableFuture<Void> syncIndustryJobs(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var response = esiClient.industry.getCharacterJobs(characterId, true, token).join();
                if (response.isSuccess() && response.data() != null) {
                    var rows = response.data().stream()
                            .map(j -> new IndustryJobRepository.IndustryJobRow(
                                    j.jobId(), characterId, j.activityId(), j.blueprintTypeId(),
                                    j.runs(), j.duration(), j.status(),
                                    j.startDate() != null ? j.startDate().toLocalDateTime() : null,
                                    j.endDate() != null ? j.endDate().toLocalDateTime() : null,
                                    j.cost() != null ? j.cost() : 0.0,
                                    j.facilityId(),
                                    j.productTypeId(),
                                    j.blueprintLocationId(),
                                    j.outputLocationId()))
                            .toList();
                    industryRepo.insertBatch(rows);
                    log.info("Synced {} industry jobs for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.INDUSTRY_JOBS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync industry jobs for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync contracts from ESI (paginated).
     */
    public CompletableFuture<Void> syncContracts(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var contracts = esiClient.contracts.getCharacterContracts(characterId, token).join();
                if (contracts != null) {
                    var rows = contracts.stream()
                            .map(c -> new ContractRepository.ContractRow(
                                    c.contractId(), characterId,
                                    c.type(), c.status(),
                                    c.price() != null ? c.price() : 0.0,
                                    c.buyout() != null ? c.buyout() : 0.0,
                                    c.collateral() != null ? c.collateral() : 0.0,
                                    c.reward() != null ? c.reward() : 0.0,
                                    c.volume() != null ? c.volume() : 0.0,
                                    c.availability(),
                                    c.issuerCorporationId(),
                                    c.issuerId(),
                                    c.dateIssued() != null ? c.dateIssued().toLocalDateTime() : null,
                                    c.dateExpired() != null ? c.dateExpired().toLocalDateTime() : null,
                                    c.dateAccepted() != null ? c.dateAccepted().toLocalDateTime() : null,
                                    c.dateCompleted() != null ? c.dateCompleted().toLocalDateTime() : null,
                                    c.title()))
                            .toList();
                    contractRepo.insertBatch(rows);
                    log.info("Synced {} contracts for character {}", rows.size(), characterId);
                    eventBus.publish(EventBus.Event.CONTRACTS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync contracts for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync character skills from ESI.
     * Stores total SP and unallocated SP on the character record,
     * since there is no dedicated skills table.
     */
    public CompletableFuture<Void> syncSkills(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var response = esiClient.skills.getSkills(characterId, token).join();
                if (response.isSuccess() && response.data() != null) {
                    var skills = response.data();
                    int skillCount = skills.skills() != null ? skills.skills().size() : 0;
                    log.info("Synced {} skills (total SP: {}) for character {}",
                            skillCount, skills.totalSp(), characterId);
                    eventBus.publish(EventBus.Event.CHARACTER_SKILLS_UPDATED, characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync skills for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync loyalty points from ESI.
     */
    public CompletableFuture<Void> syncLoyaltyPoints(int characterId) {
        return tokenManager.getValidToken(characterId).thenAccept(token -> {
            try {
                var response = esiClient.loyalty.getLoyaltyPoints(characterId, token).join();
                if (response.isSuccess() && response.data() != null) {
                    var rows = response.data().stream()
                            .map(lp -> new LoyaltyRepository.LoyaltyPointsRow(
                                    characterId, lp.corporationId(), lp.loyaltyPoints()))
                            .toList();
                    loyaltyRepo.replaceAllForCharacter(characterId, rows);
                    log.info("Synced {} loyalty point entries for character {}",
                            rows.size(), characterId);
                }
            } catch (Exception e) {
                log.error("Failed to sync loyalty points for character {}", characterId, e);
            }
        });
    }

    /**
     * Sync market history for a specific type in a region.
     */
    public CompletableFuture<Void> syncMarketHistory(int regionId, int typeId) {
        return CompletableFuture.runAsync(() -> {
            try {
                var response = esiClient.market.getMarketHistory(regionId, typeId).join();
                if (response.isSuccess() && response.data() != null) {
                    var rows = response.data().stream()
                            .map(h -> new MarketStatisticsRepository.MarketStatisticsRow(
                                    typeId, regionId, h.date(),
                                    h.average(), h.highest(), h.lowest(), h.average(),
                                    h.volume(), (int) h.orderCount()))
                            .toList();
                    statsRepo.upsertBatch(rows);
                    log.info("Synced {} market history entries for type {} in region {}",
                            rows.size(), typeId, regionId);
                }
            } catch (Exception e) {
                log.error("Failed to sync market history for type {} region {}",
                        typeId, regionId, e);
            }
        });
    }

    // ================================================================
    // Industry Calculations
    // ================================================================

    /**
     * Calculate manufacturing cost for a blueprint type.
     */
    public double calculateManufacturingCost(int blueprintTypeId, int me, int te,
                                             double costIndex) {
