package com.sampleapp.core.app;

import javafx.beans.property.*;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Global application state, observable by UI components.
 * All properties are JavaFX observable so the UI updates automatically.
 */
@Singleton
public class AppState {

    private static final Logger log = LoggerFactory.getLogger(AppState.class);

    private final StringProperty connectionStatus = new SimpleStringProperty("Disconnected");
    private final StringProperty statusMessage = new SimpleStringProperty("Ready");
    private final IntegerProperty selectedCharacterId = new SimpleIntegerProperty(-1);
    private final StringProperty selectedCharacterName = new SimpleStringProperty("");
    private final ObservableList<CharacterInfo> characters = FXCollections.observableArrayList();
    private final BooleanProperty syncing = new SimpleBooleanProperty(false);
    private final StringProperty subscriptionTier = new SimpleStringProperty("Free");
    private final BooleanProperty devMode = new SimpleBooleanProperty(false);

    private volatile boolean shuttingDown = false;

    @Inject
    public AppState(AppConfig config, @DevMode boolean devMode) {
        // Local build: all features enabled
        this.subscriptionTier.set("Enterprise");
        this.devMode.set(true);
        log.info("AppState initialized (all features enabled, local build)");
    }

    /**
     * Shut down all background tasks and clean up resources.
     */
    public void shutdown() {
        log.info("AppState shutting down");
        shuttingDown = true;
    }

    public boolean isShuttingDown() { return shuttingDown; }

    // Observable properties

    public StringProperty connectionStatusProperty() { return connectionStatus; }
    public String getConnectionStatus() { return connectionStatus.get(); }
    public void setConnectionStatus(String status) { connectionStatus.set(status); }

    public StringProperty statusMessageProperty() { return statusMessage; }
    public String getStatusMessage() { return statusMessage.get(); }
    public void setStatusMessage(String message) { statusMessage.set(message); }

    public IntegerProperty selectedCharacterIdProperty() { return selectedCharacterId; }
    public int getSelectedCharacterId() { return selectedCharacterId.get(); }
    public void setSelectedCharacterId(int id) { selectedCharacterId.set(id); }

    public StringProperty selectedCharacterNameProperty() { return selectedCharacterName; }
    public String getSelectedCharacterName() { return selectedCharacterName.get(); }
    public void setSelectedCharacterName(String name) { selectedCharacterName.set(name); }

    public ObservableList<CharacterInfo> getCharacters() { return characters; }

    public BooleanProperty syncingProperty() { return syncing; }
    public boolean isSyncing() { return syncing.get(); }
    public void setSyncing(boolean syncing) { this.syncing.set(syncing); }

    public StringProperty subscriptionTierProperty() { return subscriptionTier; }
    public String getSubscriptionTier() { return subscriptionTier.get(); }
    public void setSubscriptionTier(String tier) { subscriptionTier.set(tier); }

    public BooleanProperty devModeProperty() { return devMode; }
    public boolean isDevMode() { return devMode.get(); }

    /**
     * Basic character info stored in app state.
     */
    public record CharacterInfo(
            int characterId,
            String name,
            String corporationName,
            String allianceName
    ) {}
}

