19	
20	/**
21	 * Bottom status bar showing connection status, version, subscription tier,
22	 * EVE time (UTC), and local time. Updates every second.
23	 * Listens to sync events via AppServices to reflect current sync state.
24	 */
25	public class StatusBar extends HBox {
26	
27	    private static final DateTimeFormatter TIME_FORMAT = DateTimeFormatter.ofPattern("HH:mm:ss");
28	    private static final String APP_VERSION = "v2.1.245";
29	
30	    private final Label statusLabel;
31	    private final Label versionLabel;
32	    private final Label licenseLabel;
33	    private final Label eveTimeLabel;
34	    private final Label localTimeLabel;
35	
36	    public StatusBar(AppState appState, AppServices appServices) {
37	        getStyleClass().add("status-bar");
38	        setAlignment(Pos.CENTER_LEFT);
39	        setSpacing(10);
40	        setPadding(new Insets(2, 10, 2, 10));
41	        setPrefHeight(24);
42	
43	        // Connection status
44	        statusLabel = new Label("Disconnected");
45	        statusLabel.getStyleClass().add("status-bar-label");
46	        statusLabel.textProperty().bind(appState.connectionStatusProperty());
47	
48	        var sep1 = createSeparator();
49	
50	        // Version
51	        versionLabel = new Label(APP_VERSION);
52	        versionLabel.getStyleClass().add("status-bar-label");
53	
54	        var sep2 = createSeparator();
55	
56	        // Subscription tier
57	        licenseLabel = new Label();
58	        licenseLabel.getStyleClass().add("status-bar-label");
59	        licenseLabel.textProperty().bind(appState.subscriptionTierProperty());
60	
61	        // Spacer
62	        var spacer = new Region();
63	        HBox.setHgrow(spacer, Priority.ALWAYS);
64	
65	        // EVE Time (UTC)
66	        eveTimeLabel = new Label("EVE: --:--:--");
67	        eveTimeLabel.getStyleClass().add("status-bar-label");
68	
69	        var sep3 = createSeparator();
70	
71	        // Local time
72	        localTimeLabel = new Label("Local: --:--:--");
73	        localTimeLabel.getStyleClass().add("status-bar-label");
74	
75	        getChildren().addAll(
76	                statusLabel, sep1,
77	                versionLabel, sep2,
78	                licenseLabel, spacer,
79	                eveTimeLabel, sep3,
80	                localTimeLabel
81	        );
82	
83	        // Update clocks every second
84	        var clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), k -> updateClocks()));
85	        clockTimeline.setCycleCount(Animation.INDEFINITE);
86	        clockTimeline.play();
87	        updateClocks(); // Initial update
88	
89	        // Wire sync events to connection status
90	        appState.syncingProperty().addListener((obs, wasSyncing, isSyncing) -> {
91	            if (isSyncing) {
92	                appState.setConnectionStatus("Syncing...");
93	            } else {
94	                appState.setConnectionStatus("Connected");
95	            }
96	        });
97	
98	        // Listen for sync completion via AppServices
99	        appServices.onSyncCompleted(syncType ->
100	                appState.setStatusMessage("Sync completed: " + syncType));
101	
102	        // Set initial status based on character state
103	        if (!appState.getCharacters().isEmpty()) {
104	            appState.setConnectionStatus("Connected");
105	        }
106	    }
107	
108	    private void updateClocks() {
109	        var now = LocalDateTime.now();
110	        var utcNow = LocalDateTime.now(ZoneOffset.UTC);
111	        eveTimeLabel.setText("EVE: " + utcNow.format(TIME_FORMAT));
112	        localTimeLabel.setText("Local: " + now.format(TIME_FORMAT));
113	    }
114	
115	    private Separator createSeparator() {
116	        var sep = new Separator();
117	        sep.setOrientation(javafx.geometry.Orientation.VERTICAL);
118	        sep.getStyleClass().add("status-bar-separator");
119	        return sep;
120	    }
121	}
