package com.sampleapp.app.service;
import com.sampleapp.core.service.EventBus;

import com.sampleapp.core.subscription.FeatureGate;
import com.sampleapp.core.subscription.FeatureSet;
import com.sampleapp.data.repository.CharacterRepository;
import com.google.inject.Inject;
import com.google.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.List;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;

/**
 * Background ESI data polling service with configurable scheduling.
 * <p>
 * Periodically syncs all registered characters via {@link BusinessLogic#syncCharacter(int)}.
 * Mirrors the C# hourly timer from {@code BusinessEvents.StartClocks()}.
 */
@Singleton
public class SyncService {

    private static final Logger log = LoggerFactory.getLogger(SyncService.class);

    private final BusinessLogic businessLogic;
    private final CharacterRepository characterRepo;
    private final FeatureGate featureGate;
    private final EventBus eventBus;
    private final ScheduledExecutorService scheduler;

    private volatile boolean running = false;
    private ScheduledFuture<?> scheduledTask;

    @Inject
    public SyncService(BusinessLogic businessLogic,
                       CharacterRepository characterRepo,
                       FeatureGate featureGate,
                       EventBus eventBus) {
        this.businessLogic = businessLogic;
        this.characterRepo = characterRepo;
        this.featureGate = featureGate;
        this.eventBus = eventBus;
        this.scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "esi-sync-scheduler");
            t.setDaemon(true);
            return t;
        });
    }

    /**
     * Start periodic ESI sync for all registered characters.
     *
     * @param intervalMinutes interval between sync cycles in minutes
     */
    public void start(int intervalMinutes) {
        if (running) {
            log.warn("SyncService is already running");
            return;
        }

        if (!featureGate.hasFeature(FeatureSet.ESI_SYNC)) {
            log.info("ESI sync feature not enabled -- SyncService will not start");
            return;
        }

        running = true;
        log.info("Starting ESI sync service with {}min interval", intervalMinutes);

        // Initial sync after 1 minute, then every intervalMinutes
        scheduledTask = scheduler.scheduleAtFixedRate(
                this::syncAll,
                1,
                intervalMinutes,
                TimeUnit.MINUTES
        );
    }

    /**
     * Stop the periodic sync.
     */
    public void stop() {
        if (!running) {
            return;
        }

        running = false;
        if (scheduledTask != null) {
            scheduledTask.cancel(false);
            scheduledTask = null;
        }
        log.info("ESI sync service stopped");
    }

    /**
     * Whether the sync service is currently running.
     */
    public boolean isRunning() {
        return running;
    }

    /**
     * Sync all registered characters. Called by the scheduler.
     */
    private void syncAll() {
        if (!running) {
            return;
        }

        try {
            List<CharacterRepository.CharacterRow> characters = characterRepo.findAll();
            if (characters.isEmpty()) {
                log.debug("No characters registered -- skipping sync cycle");
                return;
            }

            log.info("Starting ESI sync cycle for {} characters", characters.size());
            eventBus.publish(EventBus.Event.ESI_SYNC_STARTED);

            for (var character : characters) {
                if (!running) {
                    log.info("Sync interrupted -- service stopped");
                    return;
                }

                try {
                    businessLogic.syncCharacter(character.characterId()).join();
                } catch (Exception e) {
                    log.error("Failed to sync character {} ({})",
                            character.name(), character.characterId(), e);
                }
            }

            eventBus.publish(EventBus.Event.ESI_SYNC_COMPLETED);
            log.info("ESI sync cycle completed for {} characters", characters.size());
        } catch (Exception e) {
            log.error("Unexpected error during sync cycle", e);
            eventBus.publish(EventBus.Event.ESI_SYNC_FAILED);
        }
    }

    /**
     * Shut down the scheduler thread pool. Call on application exit.
     */
    public void shutdown() {
        stop();
        scheduler.shutdownNow();
    }
}

