26	/**
27	 * Implementation of {@link AppServices} bridging the UI with backend services.
28	 */
29	@Singleton
30	public class AppServicesImpl implements AppServices {
31	
32	    private static final Logger log = LoggerFactory.getLogger(AppServicesImpl.class);
33	
34	    private final AppState appState;
35	    private final AppConfig appConfig;
36	    private final BusinessLogic businessLogic;
