53	                           AppConfig appConfig,
54	                           BusinessLogic businessLogic,
55	                           EveSsoAuth ssoAuth,
56	                           EsiClient esiClient,
57	                           TokenManager tokenManager,
58	                           CharacterRepository characterRepo,
59	                           WalletRepository walletRepo,
60	                           AssetRepository assetRepo,
61	                           MarketOrderRepository marketOrderRepo,
62	                           ContractRepository contractRepo,
63	                           ItemTypeCache itemTypeCache,
64	                           EventBus eventBus,
65	                           WorkspaceDataServiceImpl workspaceDataService) {
66	        this.appState = appState;
67	        this.appConfig = appConfig;
68	        this.businessLogic = businessLogic;
69	        this.ssoAuth = ssoAuth;
70	        this.esiClient = esiClient;
