73	        this.walletRepo = walletRepo;
74	        this.assetRepo = assetRepo;
75	        this.marketOrderRepo = marketOrderRepo;
76	        this.contractRepo = contractRepo;
77	        this.itemTypeCache = itemTypeCache;
78	        this.eventBus = eventBus;
79	        this.workspaceDataService = workspaceDataService;
80	
81	        // Wire event bus to sync listeners
82	        eventBus.subscribe(EventBus.Event.ESI_SYNC_COMPLETED, evt -> {
83	            Platform.runLater(() -> {
84	                for (var listener : syncListeners) {
85	                    listener.accept("ESI_SYNC");
86	                }
87	            });
88	        });
89	    }
