91	    @Override
92	    public CompletableFuture<Integer> addCharacter() {
93	        log.info("Starting EVE SSO login flow");
94	        return ssoAuth.login(EveSsoAuth.ALL_SCOPES)
95	                .thenCompose(tokenData -> {
96	                    int charId = tokenData.characterId();
97	                    String charName = tokenData.characterName();
98	
99	                    // Persist character to DB
100	                    characterRepo.upsert(new CharacterRepository.CharacterRow(
101	                            charId, charName, tokenData.ownerHash(),
102	                            null, null, tokenData.refreshToken(), null
103	                    ));
104	
105	                    // Fetch corp/alliance from ESI (public endpoint)
106	                    return esiClient.characters.getCharacter(charId)
107	                            .thenApply(esiResp -> {
108	                                String corpName = "";
109	                                String allianceName = "";
110	                                if (esiResp.isSuccess() && esiResp.data() != null) {
111	                                    int corpId = esiResp.data().corporationId();
112	                                    Integer allianceId = esiResp.data().allianceId();
113	                                    characterRepo.updateCorporationAndAlliance(charId, corpId, allianceId);
114	                                }
115	
116	                                // Update AppState on FX thread
117	                                Platform.runLater(() -> {
118	                                    // Remove existing if re-adding
119	                                    appState.getCharacters().removeIf(c -> c.characterId() == charId);
120	                                    appState.getCharacters().add(new AppState.CharacterInfo(
121	                                            charId, charName, corpName, allianceName));
122	                                    // Auto-select the new character
123	                                    appState.setSelectedCharacterId(charId);
124	                                    appState.setSelectedCharacterName(charName);
125	                                });
126	
127	                                log.info("Character added: {} (ID: {})", charName, charId);
128	
129	                                // Trigger initial ESI sync in background
130	                                businessLogic.syncCharacter(charId)
131	                                        .whenComplete((v, ex) -> {
132	                                            if (ex != null) {
133	                                                log.warn("Initial sync failed for character {}", charId, ex);
134	                                            } else {
135	                                                log.info("Initial sync completed for character {}", charId);
136	                                            }
137	                                        });
138	
139	                                return charId;
140	                            });
141	                });
142	    }
143	
144	    @Override
145	    public void removeCharacter(int characterId) {
146	        log.info("Removing character: {}", characterId);
147	        characterRepo.delete(characterId);
148	        tokenManager.removeToken(characterId);
149	
150	        Platform.runLater(() -> {
151	            appState.getCharacters().removeIf(c -> c.characterId() == characterId);
152	            if (appState.getSelectedCharacterId() == characterId) {
153	                var remaining = appState.getCharacters();
154	                if (!remaining.isEmpty()) {
155	                    appState.setSelectedCharacterId(remaining.getFirst().characterId());
156	                    appState.setSelectedCharacterName(remaining.getFirst().name());
157	                } else {
158	                    appState.setSelectedCharacterId(-1);
159	                    appState.setSelectedCharacterName("");
160	                }
161	            }
162	        });
163	    }
164	
165	    @Override
166	    public CompletableFuture<Void> refreshCharacterToken(int characterId) {
167	        log.info("Refreshing token for character: {}", characterId);
168	        return tokenManager.getValidToken(characterId)
169	                .thenAccept(token -> log.info("Token refreshed for character {}", characterId));
170	    }
171	
172	    @Override
173	    public CompletableFuture<Void> syncCharacter(int characterId) {
174	        return businessLogic.syncCharacter(characterId);
175	    }
176	
177	    @Override
178	    public CharacterRepository getCharacterRepository() { return characterRepo; }
179	
180	    @Override
181	    public WalletRepository getWalletRepository() { return walletRepo; }
182	
183	    @Override
