package com.sampleapp.core.service;

import com.google.inject.Singleton;

import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.function.Consumer;

/**
 * Simple publish/subscribe event bus for decoupled communication between services.
 * <p>
 * Replaces the C# {@code BusinessEvents} and per-service event delegates.
 * All listener invocations occur on the publishing thread; listeners that need
 * UI-thread dispatch should marshal accordingly.
 */
@Singleton
public class EventBus {

    /**
     * All application-level events.
     */
    public enum Event {
        ASSETS_UPDATED,
        BLUEPRINTS_UPDATED,
        INDUSTRY_JOBS_UPDATED,
        CHARACTER_SKILLS_UPDATED,
        CHARACTER_STANDINGS_UPDATED,
        ESI_SYNC_COMPLETED,
        ESI_SYNC_STARTED,
        ESI_SYNC_FAILED,
        ORDERS_UPDATED,
        TRANSACTIONS_UPDATED,
        WALLET_UPDATED,
        CONTRACTS_UPDATED,
        MARKET_PRICES_UPDATED,
        STATION_TRADES_IMPORTED,
        CHARACTER_ADDED,
        CHARACTER_REMOVED,
        ACCOUNT_STATUS_CHANGED
    }

    /**
     * Payload wrapper for event data.
     *
     * @param event   the event type
     * @param payload optional data (may be {@code null})
     */
    public record EventData(Event event, Object payload) {}

    private final ConcurrentHashMap<Event, List<Consumer<EventData>>> listeners =
            new ConcurrentHashMap<>();

    /**
     * Subscribe to a specific event.
     *
     * @param event    the event to listen for
     * @param listener callback invoked when the event is published
     */
    public void subscribe(Event event, Consumer<EventData> listener) {
        listeners.computeIfAbsent(event, k -> new CopyOnWriteArrayList<>())
                .add(listener);
    }

    /**
     * Unsubscribe a previously registered listener.
     *
     * @param event    the event type
     * @param listener the listener to remove
     */
    public void unsubscribe(Event event, Consumer<EventData> listener) {
        List<Consumer<EventData>> subs = listeners.get(event);
        if (subs != null) {
            subs.remove(listener);
        }
    }

    /**
     * Publish an event with no payload.
     *
     * @param event the event to fire
     */
    public void publish(Event event) {
        publish(event, null);
    }

    /**
     * Publish an event with a payload.
     *
     * @param event   the event to fire
     * @param payload data to include with the event
     */
    public void publish(Event event, Object payload) {
        List<Consumer<EventData>> subs = listeners.get(event);
        if (subs != null) {
            EventData data = new EventData(event, payload);
            for (Consumer<EventData> listener : subs) {
                try {
                    listener.accept(data);
                } catch (Exception e) {
                    // Log but do not propagate — one bad listener should not block others
                    System.err.println("EventBus: listener for " + event + " threw " + e.getMessage());
                }
            }
        }
    }
}

