/**
 * Full character sync - fetches all character data from ESI.
 * Publishes SYNC_STATUS events with human-readable messages for each step.
 */
public CompletableFuture<Void> syncCharacter(int characterId) {
    eventBus.publish(EventBus.Event.ESI_SYNC_STARTED, characterId);

    // Run sync steps sequentially so status messages are meaningful
    return CompletableFuture.runAsync(() -> {
        publishStatus("Updating market orders...");
        syncOrders(characterId).join();

        publishStatus("Updating market transactions...");
        syncTransactions(characterId).join();

        publishStatus("Updating wallet...");
        syncWallet(characterId).join();

        publishStatus("Updating assets...");
        syncAssets(characterId).join();

        publishStatus("Updating blueprints...");
        syncBlueprints(characterId).join();

        publishStatus("Updating industry jobs...");
        syncIndustryJobs(characterId).join();

        publishStatus("Updating contracts...");
        syncContracts(characterId).join();

        publishStatus("Updating skills...");
        syncSkills(characterId).join();

        publishStatus("Updating loyalty points...");
        syncLoyaltyPoints(characterId).join();

        publishStatus("");
        log.info("Full ESI sync completed for character {}", characterId);
        eventBus.publish(EventBus.Event.ESI_SYNC_COMPLETED, characterId);
    }).exceptionally(ex -> {
        log.error("ESI sync failed for character {}", characterId, ex);
        publishStatus("");
        eventBus.publish(EventBus.Event.ESI_SYNC_FAILED, characterId);
        return null;
    });
}

private void publishStatus(String message) {
    eventBus.publish(EventBus.Event.SYNC_STATUS, message);
}

