package com.sampleapp.app;

import com.sampleapp.app.service.BusinessLogic;
import com.sampleapp.app.service.WorkspaceDataServiceImpl;
import com.sampleapp.core.app.AppConfig;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.service.EventBus;
import com.sampleapp.data.cache.ItemTypeCache;
import com.sampleapp.data.repository.*;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.EveSsoAuth;
import com.sampleapp.esi.TokenManager;
import com.sampleapp.ui.AppServices;
import com.sampleapp.ui.workspace.WorkspaceDataService;
import com.google.inject.Inject;
import jakarta.inject.Singleton;
import javafx.application.Platform;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.function.Consumer;

/**
 * Implementation of {@link AppServices} bridging the UI with backend services.
 */
@Singleton
public class AppServicesImpl implements AppServices {

    private static final Logger log = LoggerFactory.getLogger(AppServicesImpl.class);

    private final AppState appState;
    private final AppConfig appConfig;
    private final BusinessLogic businessLogic;
    private final EveSsoAuth ssoAuth;
    private final EsiClient esiClient;
    private final TokenManager tokenManager;
    private final CharacterRepository characterRepo;
    private final WalletRepository walletRepo;
    private final AssetRepository assetRepo;
    private final MarketOrderRepository marketOrderRepo;
    private final ContractRepository contractRepo;
    private final ItemTypeCache itemTypeCache;
    private final EventBus eventBus;
    private final WorkspaceDataService workspaceDataService;

    private final List<Consumer<String>> syncListeners = new CopyOnWriteArrayList<>();

    @Inject
    public AppServicesImpl(AppState appState,
                           AppConfig appConfig,
                           BusinessLogic businessLogic,
                           EveSsoAuth ssoAuth,
                           EsiClient esiClient,
                           TokenManager tokenManager,
                           CharacterRepository characterRepo,
                           WalletRepository walletRepo,
                           AssetRepository assetRepo,
                           MarketOrderRepository marketOrderRepo,
                           ContractRepository contractRepo,
                           ItemTypeCache itemTypeCache,
                           EventBus eventBus,
                           WorkspaceDataServiceImpl workspaceDataService) {
        this.appState = appState;
        this.appConfig = appConfig;
        this.businessLogic = businessLogic;
        this.ssoAuth = ssoAuth;
        this.esiClient = esiClient;
        this.tokenManager = tokenManager;
        this.characterRepo = characterRepo;
        this.walletRepo = walletRepo;
        this.assetRepo = assetRepo;
        this.marketOrderRepo = marketOrderRepo;
        this.contractRepo = contractRepo;
        this.itemTypeCache = itemTypeCache;
        this.eventBus = eventBus;
        this.workspaceDataService = workspaceDataService;

        // Wire event bus to sync listeners
        eventBus.subscribe(EventBus.Event.ESI_SYNC_COMPLETED, evt -> {
            Platform.runLater(() -> {
                for (var listener : syncListeners) {
                    listener.accept("ESI_SYNC");
                }
            });
        });
    }

    @Override
    public CompletableFuture<Integer> addCharacter() {
        log.info("Starting EVE SSO login flow");
        return ssoAuth.login(EveSsoAuth.ALL_SCOPES)
                .thenCompose(tokenData -> {
                    int charId = tokenData.characterId();
                    String charName = tokenData.characterName();

                    // Persist character to DB
                    characterRepo.upsert(new CharacterRepository.CharacterRow(
                            charId, charName, tokenData.ownerHash(),
                            null, null, tokenData.refreshToken(), null
                    ));

                    // Fetch corp/alliance from ESI (public endpoint)
                    return esiClient.characters.getCharacter(charId)
                            .thenApply(esiResp -> {
                                String corpName = "";
                                String allianceName = "";
                                if (esiResp.isSuccess() && esiResp.data() != null) {
                                    int corpId = esiResp.data().corporationId();
                                    Integer allianceId = esiResp.data().allianceId();
                                    characterRepo.updateCorporationAndAlliance(charId, corpId, allianceId);
                                }

                                // Update AppState on FX thread
                                Platform.runLater(() -> {
                                    // Remove existing if re-adding
                                    appState.getCharacters().removeIf(c -> c.characterId() == charId);
                                    appState.getCharacters().add(new AppState.CharacterInfo(
                                            charId, charName, corpName, allianceName));
                                    // Auto-select the new character
                                    appState.setSelectedCharacterId(charId);
                                    appState.setSelectedCharacterName(charName);
                                });

                                log.info("Character added: {} (ID: {})", charName, charId);

                                // Trigger initial ESI sync in background
                                businessLogic.syncCharacter(charId)
                                        .whenComplete((v, ex) -> {
                                            if (ex != null) {
                                                log.warn("Initial sync failed for character {}", charId, ex);
                                            } else {
                                                log.info("Initial sync completed for character {}", charId);
                                            }
                                        });

                                return charId;
                            });
                });
    }

    @Override
    public void removeCharacter(int characterId) {
        log.info("Removing character: {}", characterId);
        characterRepo.delete(characterId);
        tokenManager.removeToken(characterId);

        Platform.runLater(() -> {
            appState.getCharacters().removeIf(c -> c.characterId() == characterId);
            if (appState.getSelectedCharacterId() == characterId) {
                var remaining = appState.getCharacters();
                if (!remaining.isEmpty()) {
                    appState.setSelectedCharacterId(remaining.getFirst().characterId());
                    appState.setSelectedCharacterName(remaining.getFirst().name());
                } else {
                    appState.setSelectedCharacterId(-1);
                    appState.setSelectedCharacterName("");
                }
            }
        });
    }

    @Override
    public CompletableFuture<Void> refreshCharacterToken(int characterId) {
        log.info("Refreshing token for character: {}", characterId);
        return tokenManager.getValidToken(characterId)
                .thenAccept(token -> log.info("Token refreshed for character {}", characterId));
    }

    @Override
    public CompletableFuture<Void> syncCharacter(int characterId) {
        return businessLogic.syncCharacter(characterId);
    }

    @Override
    public CharacterRepository getCharacterRepository() { return characterRepo; }

    @Override
    public WalletRepository getWalletRepository() { return walletRepo; }

    @Override
    public AssetRepository getAssetRepository() { return assetRepo; }

    @Override
    public MarketOrderRepository getMarketOrderRepository() { return marketOrderRepo; }

    @Override
    public ContractRepository getContractRepository() { return contractRepo; }

    @Override
    public ItemTypeCache getItemTypeCache() { return itemTypeCache; }

    @Override
    public WorkspaceDataService getWorkspaceDataService() { return workspaceDataService; }

    @Override
    public EsiClient getEsiClient() { return esiClient; }

    @Override
    public TokenManager getTokenManager() { return tokenManager; }

    @Override
    public AppConfig getAppConfig() { return appConfig; }

    @Override
    public void onSyncCompleted(Consumer<String> callback) {
        syncListeners.add(callback);
    }
}

