package com.sampleapp.ui;

import com.sampleapp.core.app.AppState;
import javafx.animation.Animation;
import javafx.animation.KeyFrame;
import javafx.animation.Timeline;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Label;
import javafx.scene.control.Separator;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.util.Duration;

import java.time.LocalDateTime;
import java.time.ZoneOffset;
import java.time.format.DateTimeFormatter;

/**
 * Bottom status bar showing connection status, version, subscription tier,
 * EVE time (UTC), and local time. Updates every second.
 * Listens to sync events via AppServices to reflect current sync state.
 */
public class StatusBar extends HBox {

    private static final DateTimeFormatter TIME_FORMAT = DateTimeFormatter.ofPattern("HH:mm:ss");
    private static final String APP_VERSION = "v2.1.245";

    private final Label statusLabel;
    private final Label versionLabel;
    private final Label licenseLabel;
    private final Label eveTimeLabel;
    private final Label localTimeLabel;

    public StatusBar(AppState appState, AppServices appServices) {
        getStyleClass().add("status-bar");
        setAlignment(Pos.CENTER_LEFT);
        setSpacing(10);
        setPadding(new Insets(2, 10, 2, 10));
        setPrefHeight(24);

        // Connection status
        statusLabel = new Label("Disconnected");
        statusLabel.getStyleClass().add("status-bar-label");
        statusLabel.textProperty().bind(appState.connectionStatusProperty());

        var sep1 = createSeparator();

        // Version
        versionLabel = new Label(APP_VERSION);
        versionLabel.getStyleClass().add("status-bar-label");

        var sep2 = createSeparator();

        // Subscription tier
        licenseLabel = new Label();
        licenseLabel.getStyleClass().add("status-bar-label");
        licenseLabel.textProperty().bind(appState.subscriptionTierProperty());

        // Spacer
        var spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        // EVE Time (UTC)
        eveTimeLabel = new Label("EVE: --:--:--");
        eveTimeLabel.getStyleClass().add("status-bar-label");

        var sep3 = createSeparator();

        // Local time
        localTimeLabel = new Label("Local: --:--:--");
        localTimeLabel.getStyleClass().add("status-bar-label");

        getChildren().addAll(
                statusLabel, sep1,
                versionLabel, sep2,
                licenseLabel, spacer,
                eveTimeLabel, sep3,
                localTimeLabel
        );

        // Update clocks every second
        var clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), k -> updateClocks()));
        clockTimeline.setCycleCount(Animation.INDEFINITE);
        clockTimeline.play();
        updateClocks(); // Initial update

        // Wire sync events to connection status
        appState.syncingProperty().addListener((obs, wasSyncing, isSyncing) -> {
            if (isSyncing) {
                appState.setConnectionStatus("Syncing...");
            } else {
                appState.setConnectionStatus("Connected");
            }
        });

        // Listen for sync completion via AppServices
        appServices.onSyncCompleted(syncType ->
                appState.setStatusMessage("Sync completed: " + syncType));

        // Set initial status based on character state
        if (!appState.getCharacters().isEmpty()) {
            appState.setConnectionStatus("Connected");
        }
    }

    private void updateClocks() {
        var now = LocalDateTime.now();
        var utcNow = LocalDateTime.now(ZoneOffset.UTC);
        eveTimeLabel.setText("EVE: " + utcNow.format(TIME_FORMAT));
        localTimeLabel.setText("Local: " + now.format(TIME_FORMAT));
    }

    private Separator createSeparator() {
        var sep = new Separator();
        sep.setOrientation(javafx.geometry.Orientation.VERTICAL);
        sep.getStyleClass().add("status-bar-separator");
        return sep;
    }
}

