package com.sampleapp.data.cache;

import com.sampleapp.core.model.ItemType;
import jakarta.inject.Singleton;

import java.util.Collection;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Thread-safe cache for EVE item type metadata, keyed by type ID.
 */
@Singleton
public class ItemTypeCache {

    private final ConcurrentHashMap<Integer, ItemType> cache = new ConcurrentHashMap<>();

    public Optional<ItemType> get(int typeId) {
        return Optional.ofNullable(cache.get(typeId));
    }

    public void put(int typeId, ItemType type) {
        if (type != null) {
            cache.put(typeId, type);
        }
    }

    public void putAll(Collection<ItemType> types) {
        for (ItemType type : types) {
            cache.put(type.typeId(), type);
        }
    }

    public Optional<String> getName(int typeId) {
        ItemType type = cache.get(typeId);
        return type != null ? Optional.ofNullable(type.name()) : Optional.empty();
    }

    public boolean contains(int typeId) {
        return cache.containsKey(typeId);
    }

    public void evict(int typeId) {
        cache.remove(typeId);
    }

    public void invalidate() {
        cache.clear();
    }

    public int size() {
        return cache.size();
    }

    public Collection<ItemType> getAll() {
        return cache.values();
    }
}

