335	    @Override
336	    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
337	        return CompletableFuture.supplyAsync(() -> {
338	            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
339	            try {
340	                // Derive regionId from the station prices table; use the station as a location filter
341	                List<StationPriceRepository.StationPriceRow> stationPrices = stationPriceRepo.findByLocation(stationId);
342	                List<TradeOpportunity> opportunities = new ArrayList<>();
343	
344	                for (var price : stationPrices) {
345	                    if (price.sellPrice() <= 0 || price.buyPrice() <= 0) {
346	                        continue;
347	                    }
348	                    double margin = (price.sellPrice() - price.buyPrice()) / price.sellPrice();
349	                    double profit = price.sellPrice() - price.buyPrice();
350	                    if (profit >= minProfit) {
351	                        String typeName = typeCacheRepo.findNameById(price.typeId()).orElse("Unknown");
352	                        opportunities.add(new TradeOpportunity(
353	                                price.typeId(),
354	                                typeName,
355	                                price.buyPrice(),
356	                                price.sellPrice(),
357	                                margin,
358	                                0L,
359	                                0.0
360	                        ));
361	                    }
362	                }
363	
364	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
365	                return opportunities;
366	            } catch (Exception e) {
367	                log.error("Failed to scan station trades for station {}", stationId, e);
368	                return List.of();
369	            }
370	        });
371	    }
