373	    @Override
374	    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
375	                                                                        double minMargin, double maxCargo, double budget) {
376	        return CompletableFuture.supplyAsync(() -> {
377	            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
378	                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
379	            try {
380	                // Get prices from both regions (using region IDs as location IDs for station-level data)
381	                List<StationPriceRepository.StationPriceRow> fromPrices = stationPriceRepo.findByLocation(fromRegionId);
382	                List<StationPriceRepository.StationPriceRow> toPrices = stationPriceRepo.findByLocation(toRegionId);
383	
384	                // Index destination prices by typeId for fast lookup
385	                var toPriceMap = toPrices.stream()
386	                        .collect(Collectors.toMap(
387	                                StationPriceRepository.StationPriceRow::typeId,
388	                                p -> p,
389	                                (a, b) -> a
390	                        ));
391	
392	                List<TradeOpportunity> opportunities = new ArrayList<>();
393	                for (var fromPrice : fromPrices) {
394	                    var toPrice = toPriceMap.get(fromPrice.typeId());
395	                    if (toPrice == null) continue;
396	
397	                    // Buy at source sell price, sell at destination buy price
398	                    double buyCost = fromPrice.sellPrice();
399	                    double sellRevenue = toPrice.buyPrice();
400	
401	                    if (buyCost <= 0 || sellRevenue <= 0) continue;
402	
403	                    double margin = (sellRevenue - buyCost) / sellRevenue;
404	                    if (margin < minMargin) continue;
405	
406	                    // Check cargo volume constraint
407	                    var typeInfo = typeCacheRepo.findById(fromPrice.typeId());
408	                    if (typeInfo.isPresent() && maxCargo > 0) {
409	                        double vol = typeInfo.get().packagedVolume() > 0
410	                                ? typeInfo.get().packagedVolume()
411	                                : typeInfo.get().volume();
412	                        if (vol > maxCargo) continue;
413	                    }
414	
415	                    // Check budget constraint
416	                    if (budget > 0 && buyCost > budget) continue;
417	
418	                    String typeName = typeInfo.map(TypeCacheRepository.TypeCacheRow::name).orElse("Unknown");
419	                    opportunities.add(new TradeOpportunity(
420	                            fromPrice.typeId(),
421	                            typeName,
422	                            buyCost,
423	                            sellRevenue,
424	                            margin,
425	                            0L,
426	                            0.0
427	                    ));
428	                }
429	
430	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
431	                return opportunities;
432	            } catch (Exception e) {
433	                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
434	                return List.of();
435	            }
436	        });
437	    }
