501	    @Override
502	    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
503	        return CompletableFuture.supplyAsync(() -> {
504	            log.debug("getFleetMembers for character {}", characterId);
505	            try {
506	                String token = tokenManager.getValidToken(characterId).join();
507	                // First get the character's fleet ID
508	                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
509	                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
510	                    return List.<FleetMemberInfo>of();
511	                }
512	                long fleetId = fleetInfoResp.data().fleetId();
513	
514	                // Get fleet members
515	                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
516	                if (!membersResp.isSuccess() || membersResp.data() == null) {
517	                    return List.<FleetMemberInfo>of();
518	                }
519	
520	                // Get fleet wings for wing/squad names
521	                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
522	                Map<Long, String> wingNames = new HashMap<>();
523	                Map<Long, String> squadNames = new HashMap<>();
524	                if (wingsResp.isSuccess() && wingsResp.data() != null) {
525	                    for (var wing : wingsResp.data()) {
526	                        wingNames.put(wing.id(), wing.name());
527	                        if (wing.squads() != null) {
528	                            for (var squad : wing.squads()) {
529	                                squadNames.put(squad.id(), squad.name());
530	                            }
531	                        }
532	                    }
533	                }
534	
535	                // Resolve character names via universe names
536	                List<Integer> charIds = membersResp.data().stream()
537	                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
538	                        .toList();
539	                Map<Integer, String> charNames = new HashMap<>();
540	                if (!charIds.isEmpty()) {
541	                    try {
542	                        var namesResp = esiClient.universe.getNames(charIds).join();
543	                        if (namesResp.isSuccess() && namesResp.data() != null) {
544	                            for (var name : namesResp.data()) {
545	                                charNames.put(name.id(), name.name());
546	                            }
547	                        }
548	                    } catch (Exception e) {
549	                        log.warn("Failed to resolve fleet member names", e);
550	                    }
551	                }
552	
553	                return membersResp.data().stream()
554	                        .map(m -> new FleetMemberInfo(
555	                                m.characterId(),
556	                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
557	                                "", // ship name not available from ESI fleet members
558	                                "Ship Type #" + m.shipTypeId(),
559	                                "System #" + m.solarSystemId(),
560	                                m.role() != null ? m.role() : "--",
561	                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
562	                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
563	                        ))
564	                        .toList();
565	            } catch (Exception e) {
566	                log.error("Failed to load fleet members for character {}", characterId, e);
567	                return List.of();
568	            }
569	        });
570	    }
