package com.sampleapp.data.repository;

import com.sampleapp.data.DatabaseManager;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;

import java.util.List;
import java.util.Optional;

/**
 * Repository for the TypeCache table (item type metadata).
 */
@Singleton
public class TypeCacheRepository extends BaseRepository {

    public record TypeCacheRow(
            int typeId, String name, Integer groupId, Integer categoryId,
            double volume, double packagedVolume, boolean published
    ) {}

    private static final RowMapper<TypeCacheRow> MAPPER = rs -> new TypeCacheRow(
            rs.getInt("TypeId"),
            rs.getString("Name"),
            rs.getObject("GroupId") != null ? rs.getInt("GroupId") : null,
            rs.getObject("CategoryId") != null ? rs.getInt("CategoryId") : null,
            rs.getDouble("Volume"),
            rs.getDouble("PackagedVolume"),
            rs.getBoolean("Published")
    );

    @Inject
    public TypeCacheRepository(DatabaseManager db) {
        super(db);
    }

    public Optional<TypeCacheRow> findById(int typeId) {
        return queryOne("SELECT * FROM TypeCache WHERE TypeId = ?", MAPPER, typeId);
    }

    public Optional<String> findNameById(int typeId) {
        return queryOne("SELECT Name FROM TypeCache WHERE TypeId = ?",
                rs -> rs.getString("Name"), typeId);
    }

    public List<TypeCacheRow> findByName(String namePart) {
        return query("SELECT * FROM TypeCache WHERE LOWER(Name) LIKE ? AND Published = TRUE",
                MAPPER, "%" + namePart.toLowerCase() + "%");
    }

    public List<TypeCacheRow> findByGroupId(int groupId) {
        return query("SELECT * FROM TypeCache WHERE GroupId = ?", MAPPER, groupId);
    }

    public List<TypeCacheRow> findByCategoryId(int categoryId) {
        return query("SELECT * FROM TypeCache WHERE CategoryId = ?", MAPPER, categoryId);
    }

    public List<TypeCacheRow> findAll() {
        return query("SELECT * FROM TypeCache ORDER BY Name", MAPPER);
    }

    public void upsert(TypeCacheRow row) {
        update("""
                MERGE INTO TypeCache
                (TypeId, Name, GroupId, CategoryId, Volume, PackagedVolume, Published)
                KEY (TypeId)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                row.typeId(), row.name(), row.groupId(), row.categoryId(),
                row.volume(), row.packagedVolume(), row.published());
    }

    /**
     * Bulk loads type cache entries. Suitable for initial SDE import.
     */
    public void bulkLoad(List<TypeCacheRow> rows) {
        String sql = """
                MERGE INTO TypeCache
                (TypeId, Name, GroupId, CategoryId, Volume, PackagedVolume, Published)
                KEY (TypeId)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """;
        List<Object[]> params = rows.stream()
                .map(r -> new Object[]{
                        r.typeId(), r.name(), r.groupId(), r.categoryId(),
                        r.volume(), r.packagedVolume(), r.published()
                })
                .toList();
        batchInsert(sql, params);
    }

    public int count() {
        return queryOne("SELECT COUNT(*) AS cnt FROM TypeCache",
                rs -> rs.getInt("cnt"))
                .orElse(0);
    }

    public int deleteAll() {
        return update("DELETE FROM TypeCache");
    }
}

