569	    private void loadItemOrders(TradeOpportunity item, String hubName) {
570	        detailItemLabel.setText("Loading orders for: " + item.typeName() + "...");
571	        buyOrdersTable.getItems().clear();
572	        sellOrdersTable.getItems().clear();
573	
574	        int regionId = hubToRegionIdFromFullName(hubName);
575	        Thread.ofVirtual().name("trader-load-orders").start(() ->
576	                dataService.getRegionOrders(item.typeId(), regionId)
577	                        .thenAccept(orders -> Platform.runLater(() -> {
578	                            detailItemLabel.setText("Orders for: " + item.typeName());
579	                            var buyOrders = orders.stream()
580	                                    .filter(MarketOrder::isBuyOrder)
581	                                    .sorted(Comparator.comparingDouble(MarketOrder::price).reversed())
582	                                    .toList();
583	                            var sellOrders = orders.stream()
584	                                    .filter(o -> !o.isBuyOrder())
585	                                    .sorted(Comparator.comparingDouble(MarketOrder::price))
586	                                    .toList();
587	                            buyOrdersTable.getItems().setAll(buyOrders);
588	                            sellOrdersTable.getItems().setAll(sellOrders);
589	                        }))
590	                        .exceptionally(ex -> {
591	                            Platform.runLater(() -> {
592	                                detailItemLabel.setText("Failed to load orders for: " + item.typeName());
593	                                log.error("Failed to load item orders", ex);
594	                            });
595	                            return null;
596	                        })
597	        );
598	    }
