946	    // -----------------------------------------------------------------------
947	
948	    private ContextMenu createTradeContextMenu(TableRow<TradeOpportunity> row,
949	                                                ObservableList<Integer> favorites,
950	                                                ObservableList<Integer> blacklist) {
951	        var contextMenu = new ContextMenu();
952	
953	        var openInGameItem = new MenuItem("Open in Game");
954	        openInGameItem.setOnAction(e -> {
955	            var opp = row.getItem();
956	            if (opp != null) {
957	                // Copy showinfo link to clipboard for in-game use
958	                String showInfo = "showinfo:" + opp.typeId();
959	                var content = new ClipboardContent();
960	                content.putString(showInfo);
961	                Clipboard.getSystemClipboard().setContent(content);
962	                log.info("Copied showinfo link for {} to clipboard", opp.typeName());
963	            }
964	        });
965	
966	        var addToFavoritesItem = new MenuItem("Add to Favorites");
967	        addToFavoritesItem.setOnAction(e -> {
968	            var opp = row.getItem();
969	            if (opp != null && !favorites.contains(opp.typeId())) {
970	                favorites.add(opp.typeId());
971	            }
972	        });
973	
974	        var addToBlacklistItem = new MenuItem("Add to Blacklist");
975	        addToBlacklistItem.setOnAction(e -> {
976	            var opp = row.getItem();
977	            if (opp != null && !blacklist.contains(opp.typeId())) {
978	                blacklist.add(opp.typeId());
979	            }
980	        });
981	
982	        contextMenu.getItems().addAll(openInGameItem, addToFavoritesItem, addToBlacklistItem);
983	        return contextMenu;
984	    }
