1016	
1017	    private void updateRegionalSummary(List<TradeOpportunity> data, double shippingRate) {
1018	        double totalInvest = 0;
1019	        double totalProfit = 0;
1020	        double totalShipping = 0;
1021	        for (var opp : data) {
1022	            totalInvest += opp.buyPrice() * opp.volume();
1023	            double unitProfit = opp.sellPrice() - opp.buyPrice();
1024	            totalProfit += unitProfit * opp.volume();
1025	            // Shipping cost: rate * volume (assume 1 m3/unit)
1026	            totalShipping += shippingRate * opp.volume();
1027	        }
1028	        double netProfit = totalProfit - totalShipping;
1029	        totalInvestmentLabel.setText("Total Investment: " + IskFormatter.format(totalInvest));
1030	        totalProfitLabel.setText("Total Profit: " + IskFormatter.format(netProfit));
1031	        double roi = totalInvest > 0 ? (netProfit / totalInvest) * 100.0 : 0;
1032	        roiLabel.setText(String.format("ROI: %.1f%%", roi));
1033	        cargoUsedLabel.setText(String.format("Cargo Used: %,d m3",
1034	                data.stream().mapToLong(TradeOpportunity::volume).sum()));
1035	    }
