1041	    private static int hubToRegionId(String hub) {
1042	        return switch (hub) {
1043	            case "Jita" -> 10000002;
1044	            case "Amarr" -> 10000043;
1045	            case "Dodixie" -> 10000032;
1046	            case "Rens" -> 10000030;
1047	            case "Hek" -> 10000042;
1048	            default -> 10000002;
1049	        };
1050	    }
1051	
1052	    /**
1053	     * Comparator for ISK-formatted strings so table columns sort numerically.
1054	     */
1055	    private static int compareIskStrings(String a, String b) {
1056	        try {
1057	            double va = Double.parseDouble(a.replace(",", "").replace("%", "").replace("--", "0").trim());
1058	            double vb = Double.parseDouble(b.replace(",", "").replace("%", "").replace("--", "0").trim());
1059	            return Double.compare(va, vb);
1060	        } catch (NumberFormatException e) {
1061	            return a.compareTo(b);
1062	        }
1063	    }
1064	
1065	    @Override
1066	    public String getTitle() { return "Trader"; }
1067	
1068	    @Override
1069	    public void onActivated() { log.debug("Trader workspace activated"); }
1070	
1071	    @Override
1072	    public void onCharacterChanged(int characterId) {
1073	        log.debug("Trader: character changed to {}", characterId);
1074	        if (characterId <= 0) {
1075	            stationOpportunities.clear();
1076	            regionalOpportunities.clear();
1077	            inTransitItems.clear();
1078	        }
1079	    }
