package com.sampleapp.ui.workspace;

import com.sampleapp.common.IskFormatter;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.core.model.MarketOrder;
import com.sampleapp.core.model.TradeOpportunity;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.collections.transformation.FilteredList;
import javafx.collections.transformation.SortedList;
import javafx.geometry.Insets;
import javafx.geometry.Orientation;
import javafx.geometry.Pos;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.*;

/**
 * Trader workspace with feature-gated tabs:
 * - Station Trader (requires STATION_TRADER + Professional)
 * - Regional Day-Trader (requires REGIONAL_DAY_TRADER + Professional)
 * Shows "subscription required" message for locked features.
 */
public class TraderWorkspace extends Workspace {

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    private final ObservableList<TradeOpportunity> stationOpportunities = FXCollections.observableArrayList();
    private final ObservableList<TradeOpportunity> regionalOpportunities = FXCollections.observableArrayList();

    // Station trader favorites and blacklist
    private final ObservableList<Integer> favoriteTypeIds = FXCollections.observableArrayList();
    private final ObservableList<Integer> blacklistTypeIds = FXCollections.observableArrayList();

    // Regional in-transit items
    private final ObservableList<TradeOpportunity> inTransitItems = FXCollections.observableArrayList();

    // Regional summary labels
    private Label totalInvestmentLabel;
    private Label totalProfitLabel;
    private Label roiLabel;
    private Label cargoUsedLabel;

    // Station detail panel
    private TableView<MarketOrder> buyOrdersTable;
    private TableView<MarketOrder> sellOrdersTable;
    private Label detailItemLabel;

    // Hub station ID mapping
    private static final Map<String, Long> HUB_STATION_IDS = Map.of(
            "Jita IV - Moon 4 - Caldari Navy Assembly Plant", 60003760L,
            "Amarr VIII (Oris) - Emperor Family Academy", 60008494L,
            "Dodixie IX - Moon 20 - Federation Navy Assembly Plant", 60011866L,
            "Rens VI - Moon 8 - Brutor Tribe Treasury", 60004588L,
            "Hek VIII - Moon 12 - Boundless Creation Factory", 60005686L
    );

    // Hub name to region ID mapping
    private static final Map<String, Integer> HUB_REGION_IDS = Map.of(
            "Jita", 10000002,
            "Amarr", 10000043,
            "Dodixie", 10000032,
            "Rens", 10000030,
            "Hek", 10000042
    );

    public TraderWorkspace(AppState appState, FeatureGate featureGate,
                           WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createStationTraderTab(),
                createRegionalDayTraderTab()
        );
    }

    // -----------------------------------------------------------------------
    // Station Trader Tab
    // -----------------------------------------------------------------------

    @SuppressWarnings("unchecked")
    private Tab createStationTraderTab() {
        var tab = new Tab("Station Trader");

        if (!featureGate.isFeatureAvailable(FeatureSet.STATION_TRADER,
                SubscriptionTier.PROFESSIONAL)) {
            tab.setContent(new FeatureLockedPane(
                    "Station Trader", "Professional"));
            return tab;
        }

        // --- Top bar: Hub selection + Scan ---
        var hubBox = new HBox(10);
        hubBox.setPadding(new Insets(5));
        hubBox.setAlignment(Pos.CENTER_LEFT);
        var hubCombo = new ComboBox<String>();
        hubCombo.getItems().addAll(
                "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                "Amarr VIII (Oris) - Emperor Family Academy",
                "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                "Rens VI - Moon 8 - Brutor Tribe Treasury",
                "Hek VIII - Moon 12 - Boundless Creation Factory"
        );
        hubCombo.setValue("Jita IV - Moon 4 - Caldari Navy Assembly Plant");
        var scanBtn = new Button("Scan Market");
        var importBtn = new Button("Import Orders");
        hubBox.getChildren().addAll(new Label("Hub:"), hubCombo, scanBtn, importBtn);

        // --- Side panel with accordion-style TitledPanes ---
        var sidePanel = new VBox(5);
        sidePanel.setPrefWidth(260);
        sidePanel.setPadding(new Insets(5));

        // Filters pane
        var filtersGrid = new GridPane();
        filtersGrid.setHgap(8);
        filtersGrid.setVgap(6);
        filtersGrid.setPadding(new Insets(8));

        var minProfitField = new TextField("1000000");
        minProfitField.setPrefWidth(130);
        var minMarginField = new TextField("5");
        minMarginField.setPrefWidth(130);
        var minDailyDemandField = new TextField("10");
        minDailyDemandField.setPrefWidth(130);
        var priceHistoryCombo = new ComboBox<Integer>();
        priceHistoryCombo.getItems().addAll(7, 14, 30, 60, 90);
        priceHistoryCombo.setValue(30);
        priceHistoryCombo.setPrefWidth(130);
        var minPeriodRoiField = new TextField("5");
        minPeriodRoiField.setPrefWidth(130);
        var flagExtremePricesCheck = new CheckBox("Flag Extreme Prices");

        filtersGrid.add(new Label("Min Profit:"), 0, 0);
        filtersGrid.add(minProfitField, 1, 0);
        filtersGrid.add(new Label("Min Margin %:"), 0, 1);
        filtersGrid.add(minMarginField, 1, 1);
        filtersGrid.add(new Label("Min Daily Demand:"), 0, 2);
        filtersGrid.add(minDailyDemandField, 1, 2);
        filtersGrid.add(new Label("Price History Days:"), 0, 3);
        filtersGrid.add(priceHistoryCombo, 1, 3);
        filtersGrid.add(new Label("Min Period ROI %:"), 0, 4);
        filtersGrid.add(minPeriodRoiField, 1, 4);
        filtersGrid.add(flagExtremePricesCheck, 0, 5, 2, 1);

        var filtersTitledPane = new TitledPane("Filters", filtersGrid);
        filtersTitledPane.setExpanded(true);

        // Assets/Orders pane
        var assetsGrid = new GridPane();
        assetsGrid.setHgap(8);
        assetsGrid.setVgap(6);
        assetsGrid.setPadding(new Insets(8));

        var assetsScopeCombo = new ComboBox<String>();
        assetsScopeCombo.getItems().addAll("All", "Station", "Region");
        assetsScopeCombo.setValue("All");
        assetsScopeCombo.setPrefWidth(130);
        var activeOrdersCombo = new ComboBox<String>();
        activeOrdersCombo.getItems().addAll("All", "Character", "Station");
        activeOrdersCombo.setValue("All");
        activeOrdersCombo.setPrefWidth(130);

        assetsGrid.add(new Label("Assets Scope:"), 0, 0);
        assetsGrid.add(assetsScopeCombo, 1, 0);
        assetsGrid.add(new Label("Active Orders:"), 0, 1);
        assetsGrid.add(activeOrdersCombo, 1, 1);

        var assetsTitledPane = new TitledPane("Assets / Orders", assetsGrid);
        assetsTitledPane.setExpanded(false);

        // Purchase Volume pane
        var purchaseGrid = new GridPane();
        purchaseGrid.setHgap(8);
        purchaseGrid.setVgap(6);
        purchaseGrid.setPadding(new Insets(8));

        var daysOfSupplySpinner = new Spinner<Integer>(1, 30, 3);
        daysOfSupplySpinner.setPrefWidth(130);
        daysOfSupplySpinner.setEditable(true);

        purchaseGrid.add(new Label("Days of Supply:"), 0, 0);
        purchaseGrid.add(daysOfSupplySpinner, 1, 0);

        var purchaseTitledPane = new TitledPane("Purchase Volume", purchaseGrid);
        purchaseTitledPane.setExpanded(false);

        sidePanel.getChildren().addAll(filtersTitledPane, assetsTitledPane, purchaseTitledPane);

        // --- Favorites tab ---
        var favoritesListView = new ListView<>(favoriteTypeIds);
        favoritesListView.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Integer typeId, boolean empty) {
                super.updateItem(typeId, empty);
                if (empty || typeId == null) {
                    setText(null);
                } else {
                    setText("Type ID: " + typeId);
                    dataService.resolveTypeName(typeId).thenAccept(name ->
                            Platform.runLater(() -> setText(name + " (" + typeId + ")")));
                }
            }
        });
        var addFavoriteField = new TextField();
        addFavoriteField.setPromptText("Type ID");
        addFavoriteField.setPrefWidth(100);
        var addFavoriteBtn = new Button("Add");
        addFavoriteBtn.setOnAction(e -> {
            try {
                int id = Integer.parseInt(addFavoriteField.getText().trim());
                if (!favoriteTypeIds.contains(id)) {
                    favoriteTypeIds.add(id);
                }
                addFavoriteField.clear();
            } catch (NumberFormatException ignored) {
                // invalid input, ignore
            }
        });
        var removeFavoriteBtn = new Button("Remove");
        removeFavoriteBtn.setOnAction(e -> {
            var selected = favoritesListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                favoriteTypeIds.remove(selected);
            }
        });
        var favBtnBox = new HBox(5, addFavoriteField, addFavoriteBtn, removeFavoriteBtn);
        favBtnBox.setPadding(new Insets(5));
        var favoritesContent = new VBox(5, favoritesListView, favBtnBox);
        VBox.setVgrow(favoritesListView, Priority.ALWAYS);

        // --- Blacklist tab ---
        var blacklistListView = new ListView<>(blacklistTypeIds);
        blacklistListView.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Integer typeId, boolean empty) {
                super.updateItem(typeId, empty);
                if (empty || typeId == null) {
                    setText(null);
                } else {
                    setText("Type ID: " + typeId);
                    dataService.resolveTypeName(typeId).thenAccept(name ->
                            Platform.runLater(() -> setText(name + " (" + typeId + ")")));
                }
            }
        });
        var addBlacklistField = new TextField();
        addBlacklistField.setPromptText("Type ID");
        addBlacklistField.setPrefWidth(100);
        var addBlacklistBtn = new Button("Add");
        addBlacklistBtn.setOnAction(e -> {
            try {
                int id = Integer.parseInt(addBlacklistField.getText().trim());
                if (!blacklistTypeIds.contains(id)) {
                    blacklistTypeIds.add(id);
                }
                addBlacklistField.clear();
            } catch (NumberFormatException ignored) {
                // invalid input, ignore
            }
        });
        var removeBlacklistBtn = new Button("Remove");
        removeBlacklistBtn.setOnAction(e -> {
            var selected = blacklistListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                blacklistTypeIds.remove(selected);
            }
        });
        var blBtnBox = new HBox(5, addBlacklistField, addBlacklistBtn, removeBlacklistBtn);
        blBtnBox.setPadding(new Insets(5));
        var blacklistContent = new VBox(5, blacklistListView, blBtnBox);
        VBox.setVgrow(blacklistListView, Priority.ALWAYS);

        // Side TabPane for Filters / Favorites / Blacklist
        var sideTabPane = new TabPane();
        sideTabPane.setTabClosingPolicy(TabPane.TabClosingPolicy.UNAVAILABLE);
        sideTabPane.setPrefWidth(270);
        var filtersTab = new Tab("Filters", sidePanel);
        var favoritesTab = new Tab("Favorites", favoritesContent);
        var blacklistTab = new Tab("Blacklist", blacklistContent);
        sideTabPane.getTabs().addAll(filtersTab, favoritesTab, blacklistTab);

        // --- Search / filter field for table ---
        var searchField = new TextField();
        searchField.setPromptText("Search items...");
        searchField.setPrefWidth(300);
        var searchBar = new HBox(10, new Label("Filter:"), searchField);
        searchBar.setPadding(new Insets(5));
        searchBar.setAlignment(Pos.CENTER_LEFT);

        // --- Opportunities table ---
        var filteredList = new FilteredList<>(stationOpportunities, p -> true);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            String filterText = newVal == null ? "" : newVal.toLowerCase();
            filteredList.setPredicate(opp -> {
                if (filterText.isEmpty()) return true;
                return opp.typeName().toLowerCase().contains(filterText);
            });
        });
        var sortedList = new SortedList<>(filteredList);

        var table = new TableView<TradeOpportunity>();
        sortedList.comparatorProperty().bind(table.comparatorProperty());
        table.setItems(sortedList);

        var itemCol = new TableColumn<TradeOpportunity, String>("Item");
        itemCol.setPrefWidth(180);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));

        var buyCol = new TableColumn<TradeOpportunity, String>("Buy Price");
        buyCol.setPrefWidth(110);
        buyCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().buyPrice())));
        buyCol.setComparator(TraderWorkspace::compareIskStrings);

        var sellCol = new TableColumn<TradeOpportunity, String>("Sell Price");
        sellCol.setPrefWidth(110);
        sellCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().sellPrice())));
        sellCol.setComparator(TraderWorkspace::compareIskStrings);

        var profitCol = new TableColumn<TradeOpportunity, String>("Profit/Unit");
        profitCol.setPrefWidth(100);
        profitCol.setCellValueFactory(c -> {
            double profit = c.getValue().sellPrice() - c.getValue().buyPrice();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        profitCol.setComparator(TraderWorkspace::compareIskStrings);

        var marginCol = new TableColumn<TradeOpportunity, String>("Margin %");
        marginCol.setPrefWidth(75);
        marginCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.1f%%", c.getValue().margin() * 100.0)));

        var dailyVolCol = new TableColumn<TradeOpportunity, Number>("Daily Vol");
        dailyVolCol.setPrefWidth(75);
        dailyVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var dailyProfitCol = new TableColumn<TradeOpportunity, String>("Daily Profit");
        dailyProfitCol.setPrefWidth(110);
        dailyProfitCol.setCellValueFactory(c -> {
            double profit = (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().dailyVolume();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        dailyProfitCol.setComparator(TraderWorkspace::compareIskStrings);

        var competCol = new TableColumn<TradeOpportunity, Number>("Orders");
        competCol.setPrefWidth(60);
        competCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));

        // Additional columns from C# feature set
        int daysOfSupply = daysOfSupplySpinner.getValue();

        var purchaseUnitsCol = new TableColumn<TradeOpportunity, Number>("Purchase Units");
        purchaseUnitsCol.setPrefWidth(100);
        purchaseUnitsCol.setCellValueFactory(c -> {
            long units = Math.round(c.getValue().dailyVolume() * daysOfSupplySpinner.getValue());
            return new SimpleLongProperty(units);
        });

        var dailyTradableCol = new TableColumn<TradeOpportunity, Number>("Daily Tradable");
        dailyTradableCol.setPrefWidth(95);
        dailyTradableCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var dailyBuyUnitsCol = new TableColumn<TradeOpportunity, Number>("Daily Buy Units");
        dailyBuyUnitsCol.setPrefWidth(100);
        dailyBuyUnitsCol.setCellValueFactory(c -> {
            long buyUnits = Math.round(c.getValue().dailyVolume() * 0.5);
            return new SimpleLongProperty(buyUnits);
        });

        var dailySellUnitsCol = new TableColumn<TradeOpportunity, Number>("Daily Sell Units");
        dailySellUnitsCol.setPrefWidth(100);
        dailySellUnitsCol.setCellValueFactory(c -> {
            long sellUnits = Math.round(c.getValue().dailyVolume() * 0.5);
            return new SimpleLongProperty(sellUnits);
        });

        var buyVsSellRatioCol = new TableColumn<TradeOpportunity, String>("Buy/Sell Ratio");
        buyVsSellRatioCol.setPrefWidth(85);
        buyVsSellRatioCol.setCellValueFactory(c -> {
            double sellPrice = c.getValue().sellPrice();
            double ratio = sellPrice > 0 ? c.getValue().buyPrice() / sellPrice : 0;
            return new SimpleStringProperty(String.format("%.2f", ratio));
        });

        var regionAvgTradeVolCol = new TableColumn<TradeOpportunity, Number>("Rgn Avg Trade Vol");
        regionAvgTradeVolCol.setPrefWidth(110);
        regionAvgTradeVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var capitalRequiredCol = new TableColumn<TradeOpportunity, String>("Capital Required");
        capitalRequiredCol.setPrefWidth(110);
        capitalRequiredCol.setCellValueFactory(c -> {
            double capital = c.getValue().buyPrice() * Math.round(c.getValue().dailyVolume() * daysOfSupplySpinner.getValue());
            return new SimpleStringProperty(IskFormatter.formatRaw(capital));
        });
        capitalRequiredCol.setComparator(TraderWorkspace::compareIskStrings);

        var roiNowCol = new TableColumn<TradeOpportunity, String>("ROI Now %");
        roiNowCol.setPrefWidth(80);
        roiNowCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            double roi = buy > 0 ? ((c.getValue().sellPrice() - buy) / buy) * 100.0 : 0;
            return new SimpleStringProperty(String.format("%.1f%%", roi));
        });

        var roiPeriodCol = new TableColumn<TradeOpportunity, String>("ROI Period %");
        roiPeriodCol.setPrefWidth(85);
        roiPeriodCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            int days = priceHistoryCombo.getValue();
            double dailyRoi = buy > 0 ? ((c.getValue().sellPrice() - buy) / buy) : 0;
            double periodRoi = dailyRoi * days * 100.0;
            return new SimpleStringProperty(String.format("%.1f%%", periodRoi));
        });

        table.getColumns().addAll(itemCol, buyCol, sellCol, profitCol, marginCol,
                dailyVolCol, dailyProfitCol, competCol, purchaseUnitsCol, dailyTradableCol,
                dailyBuyUnitsCol, dailySellUnitsCol, buyVsSellRatioCol, regionAvgTradeVolCol,
                capitalRequiredCol, roiNowCol, roiPeriodCol);
        table.setPlaceholder(new Label("Click Scan Market to find opportunities"));

        // Context menu for table rows
        table.setRowFactory(tv -> {
            var row = new TableRow<TradeOpportunity>();
            var contextMenu = createTradeContextMenu(row, favoriteTypeIds, blacklistTypeIds);
            row.setContextMenu(contextMenu);
            return row;
        });

        // --- Item detail panel (regional buy/sell orders for selected item) ---
        detailItemLabel = new Label("Select an item to view regional orders");
        detailItemLabel.setStyle("-fx-font-weight: bold; -fx-padding: 5;");

        buyOrdersTable = createMarketOrderTable("Buy Orders");
        sellOrdersTable = createMarketOrderTable("Sell Orders");

        var buyOrdersPane = new TitledPane("Buy Orders", buyOrdersTable);
        buyOrdersPane.setExpanded(true);
        var sellOrdersPane = new TitledPane("Sell Orders", sellOrdersTable);
        sellOrdersPane.setExpanded(true);

        var detailContent = new VBox(5, detailItemLabel, buyOrdersPane, sellOrdersPane);
        detailContent.setPadding(new Insets(5));
        detailContent.setPrefHeight(200);

        // Load orders when a table row is selected
        table.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                loadItemOrders(newVal, hubCombo.getValue());
            } else {
                detailItemLabel.setText("Select an item to view regional orders");
                buyOrdersTable.getItems().clear();
                sellOrdersTable.getItems().clear();
            }
        });

