        scanBtn.setOnAction(e -> {
            scanBtn.setDisable(true);
            double minProfit;
            int minVolume;
            try {
                minProfit = Double.parseDouble(minProfitField.getText().replace(",", ""));
                minVolume = Integer.parseInt(minDailyDemandField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                scanBtn.setDisable(false);
                return;
            }
            long stationId = HUB_STATION_IDS.getOrDefault(hubCombo.getValue(), 60003760L);
            Thread.ofVirtual().name("trader-station-scan").start(() ->
                    dataService.scanStationTrades(stationId, minProfit, minVolume)
                            .thenAccept(data -> Platform.runLater(() -> {
                                // Filter out blacklisted items
                                var filtered = data.stream()
                                        .filter(opp -> !blacklistTypeIds.contains(opp.typeId()))
                                        .toList();
