                                    log.error("Failed to scan station trades", ex);
                                    scanBtn.setDisable(false);
                                });
                                return null;
                            })
            );
        });

        // --- Main layout: side panel + table area ---
        var mainSplit = new SplitPane();
        mainSplit.setOrientation(Orientation.HORIZONTAL);
        mainSplit.setDividerPositions(0.2);
        mainSplit.getItems().addAll(sideTabPane, tableSplit);
        SplitPane.setResizableWithParent(sideTabPane, false);

        var root = new VBox(hubBox, mainSplit);
        VBox.setVgrow(mainSplit, Priority.ALWAYS);

        tab.setContent(root);
        return tab;
    }

