package com.sampleapp.data.repository;

import com.sampleapp.data.DatabaseManager;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;

import java.sql.Timestamp;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

/**
 * Repository for the StationPrices table (cached hub prices).
 */
@Singleton
public class StationPriceRepository extends BaseRepository {

    public record StationPriceRow(
            int typeId, long locationId, double buyPrice, double sellPrice,
            LocalDateTime lastUpdated
    ) {}

    private static final RowMapper<StationPriceRow> MAPPER = rs -> new StationPriceRow(
            rs.getInt("TypeId"),
            rs.getLong("LocationId"),
            rs.getDouble("BuyPrice"),
            rs.getDouble("SellPrice"),
            rs.getTimestamp("LastUpdated") != null ? rs.getTimestamp("LastUpdated").toLocalDateTime() : null
    );

    @Inject
    public StationPriceRepository(DatabaseManager db) {
        super(db);
    }

    public Optional<StationPriceRow> findById(int typeId, long locationId) {
        return queryOne("SELECT * FROM StationPrices WHERE TypeId = ? AND LocationId = ?",
                MAPPER, typeId, locationId);
    }

    public List<StationPriceRow> findByLocation(long locationId) {
        return query("SELECT * FROM StationPrices WHERE LocationId = ?", MAPPER, locationId);
    }

    public List<StationPriceRow> findByType(int typeId) {
        return query("SELECT * FROM StationPrices WHERE TypeId = ?", MAPPER, typeId);
    }

    /**
     * Inserts or updates a price entry for a type at a location.
     */
    public void upsert(int typeId, long locationId, double buyPrice, double sellPrice) {
        update("""
                MERGE INTO StationPrices (TypeId, LocationId, BuyPrice, SellPrice, LastUpdated)
                KEY (TypeId, LocationId)
                VALUES (?, ?, ?, ?, ?)
                """, typeId, locationId, buyPrice, sellPrice,
                Timestamp.valueOf(LocalDateTime.now()));
    }

    /**
     * Batch upsert station prices.
     */
    public void upsertBatch(List<StationPriceRow> rows) {
        String sql = """
                MERGE INTO StationPrices (TypeId, LocationId, BuyPrice, SellPrice, LastUpdated)
                KEY (TypeId, LocationId)
                VALUES (?, ?, ?, ?, ?)
                """;
        Timestamp now = Timestamp.valueOf(LocalDateTime.now());
        List<Object[]> params = rows.stream()
                .map(r -> new Object[]{r.typeId(), r.locationId(), r.buyPrice(), r.sellPrice(), now})
                .toList();
        batchInsert(sql, params);
    }

    public int deleteByLocation(long locationId) {
        return update("DELETE FROM StationPrices WHERE LocationId = ?", locationId);
    }

    public int deleteAll() {
        return update("DELETE FROM StationPrices");
    }
}

